-- Poems batch 340
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0da67934-1922-46a1-a6a5-8eb8dfae778d','寄豫章公三首  其一','陳師道','宋','宋诗','song-poetry','','[]','密雲不雨卧烏龍，已是人間第一功。',32,'全唐诗/poet.song.62000.json','["密雲不雨卧烏龍，已是人間第一功。", "得諾向來輕季子，打門何日走周公。"]'),
('5d45f545-136e-44c6-9b42-f437510c062d','寄豫章公三首  其二','陳師道','宋','宋诗','song-poetry','','[]','愧無一縷破雙團，慣下薑鹽枉肺肝。',32,'全唐诗/poet.song.62000.json','["愧無一縷破雙團，慣下薑鹽枉肺肝。", "誓酒不應忘此老，論詩寧肯乞麤官。"]'),
('4b06cba3-6392-451b-9927-59dc0875b25f','寄豫章公三首  其三','陳師道','宋','宋诗','song-poetry','','[]','生須百斛買雙鬟，水截龍章試虎斑。',32,'全唐诗/poet.song.62000.json','["生須百斛買雙鬟，水截龍章試虎斑。", "老覺才粗渾不稱，自携雲月瀉湲潺。"]'),
('78e20ee1-8078-4c81-ab52-cfe3f00d3bdd','贈秦覯兼簡蘇迨二首  其一','陳師道','宋','宋诗','song-poetry','','[]','兩秦並立難爲下，萬里長驅在此初。',32,'全唐诗/poet.song.62000.json','["兩秦並立難爲下，萬里長驅在此初。", "別後未忘三日語，人來肯作數行書。"]'),
('e1964a9d-57f4-4f8a-9f76-92ab33276587','贈秦覯兼簡蘇迨二首  其二','陳師道','宋','宋诗','song-poetry','','[]','文章從古不同時，詩語驚人筆益奇。',32,'全唐诗/poet.song.62000.json','["文章從古不同時，詩語驚人筆益奇。", "過與阿平應絕倒，世間能有幾人知。"]'),
('b1b470da-1914-4e16-9072-3f1ae20e9757','送趙朝請赴蘇幕','陳師道','宋','宋诗','song-poetry','','[]','好合同黄卷，情新更白頭。',48,'全唐诗/poet.song.62000.json','["好合同黄卷，情新更白頭。", "胡然落丹墨，不坐致公侯。", "沙軟留徐步，潮迴趁急流。", "平生湖海興，日夜逐行舟。"]'),
('1f4e1373-554e-45c9-8b3d-4cbbb7b62da3','絕句','陳師道','宋','宋诗','song-poetry','','[]','斫水水可斷，續弦弦可完。',24,'全唐诗/poet.song.62000.json','["斫水水可斷，續弦弦可完。", "如何鄭公客，不作百年看。"]'),
('7178bffc-60fc-4b74-b312-a60b18a01b8d','山口阻風','陳師道','宋','宋诗','song-poetry','','[]','夕風朝未回，來雲去爲雨。',240,'全唐诗/poet.song.62000.json','["夕風朝未回，來雲去爲雨。", "繫舟直山口，天意遽如許。", "濤風兩方鬭，丘原莫當怒。", "兩山爲俯仰，一鳥不得度。", "臨深負高枕，偷生寧得所。", "歷歷數過帆，當塗氣如虎。", "快意亦適然，淹泊豈吾取。", "泝洄更去留，未易相爾汝。", "行登東山顛，壯觀前未睹。", "九澤不滿眼，五丈才一縷。", "茲山昔誰游，巨野傳自古。", "菰魚無凶年，末利猶不禦。", "荷隩活萬人，梨埒視千戶。", "東方富絲麻，小市藏百賈。", "連檣自南北，行談雜秦楚。", "向晚風力微，湖清魚可數。", "空倉鳥烏樂，外舍窗扉語。", "身非天下惜，家無十金聚。", "欲留盜賊迫，欲去波濤怒。", "兩者爾何從，一死吾未與。"]'),
('0efd331f-72e0-44e8-a3d5-e11565179238','登冥山','陳師道','宋','宋诗','song-poetry','','[]','東山如覆盆，石塔仍數層。',108,'全唐诗/poet.song.62000.json','["東山如覆盆，石塔仍數層。", "昔人行樂處，時過名不稱。", "秋風變草木，樵徑餘薪蒸。", "四顧一水間，不復知淄澠。", "菰蒲萬世利，煙火千人罾。", "平生登山脚，歲晚如不勝。", "求田君勿問，撫髀吾何能。", "飛鴻將目遠，秋水留心澄。", "茲游豈不朽，作歌記吾曾。"]'),
('068b070d-4f2c-4690-a10b-2b7a804eb60c','和蘇公洞庭春色','陳師道','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭千木奴，寸絲不挂手。',120,'全唐诗/poet.song.62000.json','["洞庭千木奴，寸絲不挂手。", "來輸步兵厨，釀作青田酒。", "王家玉東西，未覺歲華走。", "方從羅浮山，已作南陽壽。", "還將甕頭春，慰子雪入牖。", "我方縛禪律，一舉煩屢嗅。", "東坡酒中仙，醉墨粲星斗。", "詩成以屬我，千金須弊帚。", "何曾樽俎間，著客面黧黝。", "定須笑美人，蘸甲不濡口。"]'),
('529ebf2e-e9e9-46df-99d1-bf3cc41c0eb5','擬古','陳師道','宋','宋诗','song-poetry','','[]','盎中有聲囊不癭，嚥息不如带加緊。',64,'全唐诗/poet.song.62000.json','["盎中有聲囊不癭，嚥息不如带加緊。", "人生七十今已半，一飽無時何可忍。", "公侯早歲有如此，奴婢蓐食支夜永。", "向來糠籺之子孫，居鄰無僧家有井。"]'),
('02e244ef-7297-47a9-923f-a8da2f5de275','嘲無咎文潛','陳師道','宋','宋诗','song-poetry','','[]','詩人要瘦君則肥，便然偉觀詩不宜。',64,'全唐诗/poet.song.62000.json','["詩人要瘦君則肥，便然偉觀詩不宜。", "詩亦於人不相累，黄金九鐶腰十圍。", "一饑緣我不緣渠，身作賈孟行詩圖。", "窮人乃工君未可，早據要路肩安輿。"]'),
('dc0f29b7-86f6-446b-a493-83354278afa0','次韵夜雨','陳師道','宋','宋诗','song-poetry','','[]','暗雨來何急，寒房客自醒。',48,'全唐诗/poet.song.62000.json','["暗雨來何急，寒房客自醒。", "驟看燈閃閃，擬對竹青青。", "聲到江干盡，風回葉上聽。", "更長那得曉，欹側想儀形。"]'),
('fd4016d9-d670-4825-bae6-3b908172ce5d','晦日','陳師道','宋','宋诗','song-poetry','','[]','人老時情薄，春深花意微。',48,'全唐诗/poet.song.62000.json','["人老時情薄，春深花意微。", "暄寒南北異，風俗古今違。", "即事無同異，旁觀有是非。", "食蔬如許瘦，飽肉未須肥。"]'),
('d383e7fc-a936-48dd-b5a7-9dac7107fc57','登城樓','陳師道','宋','宋诗','song-poetry','','[]','城郭春容晚，因行可當遊。',48,'全唐诗/poet.song.62000.json','["城郭春容晚，因行可當遊。", "飛來雙蛺蝶，目盡一浮鷗。", "峽嶮山將合，江平水却流。", "同來端興盡，且爲小遲留。"]'),
('e8881be8-ebdc-486a-bc8d-7bc5c6af9f4f','奉賀陳聖予','陳師道','宋','宋诗','song-poetry','','[]','合譜兒童歲，爲僚一再秋。',48,'全唐诗/poet.song.62000.json','["合譜兒童歲，爲僚一再秋。", "初聞消息報，已作別離憂。", "急雪將無路，寒江欲斷流。", "相逢寧易得，端爲小遲留。"]'),
('c4bfcf8e-b452-4388-b78d-d9162431f72a','和王子安至日三首  其一','陳師道','宋','宋诗','song-poetry','','[]','近節翻多事，爲家不亦難。',48,'全唐诗/poet.song.62000.json','["近節翻多事，爲家不亦難。", "老成須藥力，愁絕向誰寬。", "凍雨能妨夢，朝霜故作寒。", "衰顔心自了，不待鏡中看。"]'),
('f3016973-a7d4-4a8a-a00a-1de8e64541ed','和王子安至日三首  其二','陳師道','宋','宋诗','song-poetry','','[]','物理有終極，人情從往還。',48,'全唐诗/poet.song.62000.json','["物理有終極，人情從往還。", "陰陽消長際，老疾去留間。", "申白徒懷惠，巢由不買山。", "更歌吾和汝，風日稍侵顔。"]'),
('b5550f94-972d-404d-a11d-0e91ef448c97','和王子安至日三首  其三','陳師道','宋','宋诗','song-poetry','','[]','晨起公私迫，昏歸鳥雀催。',48,'全唐诗/poet.song.62000.json','["晨起公私迫，昏歸鳥雀催。", "百年忙裏盡，萬事醉間來。", "竹雨深宜晚，江梅半欲開。", "風燈挑不燄，寒火撥成灰。"]'),
('a339a5c5-3551-4843-8ede-a412ac2b7bbf','次韵少游春江秋野圖二首  其一','陳師道','宋','宋诗','song-poetry','','[]','翰墨功名裏，江山富貴人。',24,'全唐诗/poet.song.62000.json','["翰墨功名裏，江山富貴人。", "倏看雙鳥下，已負百年身。"]'),
('3becbbf8-31cb-4e7f-a60a-23992c3f6a1a','次韵少游春江秋野圖二首  其二','陳師道','宋','宋诗','song-poetry','','[]','江清風偃木，霜落雁橫空。',24,'全唐诗/poet.song.62000.json','["江清風偃木，霜落雁橫空。", "若箇丹青裏，猶須著此翁。"]'),
('fba849d4-8d44-4fbb-9a13-8f66f97e4c05','寄文潛無咎少游三學士','陳師道','宋','宋诗','song-poetry','','[]','北來消息不真傳，南度相忘更記年。',64,'全唐诗/poet.song.62000.json','["北來消息不真傳，南度相忘更記年。", "湖海一舟須此老，蓬瀛方丈自飛仙。", "數臨黄卷聊遮眼，穩上青雲小著鞭。", "李杜齊名吾豈敢，晚風無樹不鳴蟬。"]'),
('f6958700-2d1e-4db8-b385-be63a9021990','連日大雪以疾作不出聞蘇公與德麟同登女郎臺','陳師道','宋','宋诗','song-poetry','','[]','掠地衝風敵萬人，蔽天密雪幾微塵。',64,'全唐诗/poet.song.62000.json','["掠地衝風敵萬人，蔽天密雪幾微塵。", "漫山塞壑疑無地，投隙穿帷巧致身。", "晚積讀書今已老，閉門高卧不緣貧。", "遥知更上湖邊寺，一笑潛回萬室春。"]'),
('ca45494e-7299-489d-91d6-11cf28c71016','立春','陳師道','宋','宋诗','song-poetry','','[]','馬蹄殘雪未成塵，梅子梢頭已著春。',64,'全唐诗/poet.song.62000.json','["馬蹄殘雪未成塵，梅子梢頭已著春。", "巧勝向人真奈老，衰顔從俗不宜新。", "高門肯送青絲菜，下里誰思白髮人。", "共學少年天下士，獨能濡濕轍中鱗。"]'),
('6b9b8c86-fbbb-4572-b0be-f33d3516f693','贈王聿脩商子常','陳師道','宋','宋诗','song-poetry','','[]','欲作新詩挑兩公，含毫不下思先窮。',64,'全唐诗/poet.song.62000.json','["欲作新詩挑兩公，含毫不下思先窮。", "貪逢大敵能無懼，彊畫脩眉每未工。", "畏病忍狂妨痛飲，晚雲朝雨滯晴空。", "正須好句留春住，可使風飄萬點紅。"]'),
('6b3ac7ec-90aa-443e-a6ca-68fbee2c83e7','寄寇元弼','陳師道','宋','宋诗','song-poetry','','[]','朱櫻青子已嘗新，白帢黄衫見未頻。',64,'全唐诗/poet.song.62000.json','["朱櫻青子已嘗新，白帢黄衫見未頻。", "載酒對棋無俗士，閉門高枕有閑人。", "有底百年須薄祿，相看一笑却關身。", "肯留惡客開家釀，驚坐何人更姓陳。"]'),
('a769403f-63c9-4a9d-8194-35ac9afd990f','次韵敬酬元弼三兄','陳師道','宋','宋诗','song-poetry','','[]','冥冥雨力及時來，冉冉春光作意回。',64,'全唐诗/poet.song.62000.json','["冥冥雨力及時來，冉冉春光作意回。", "白髮尚堪供語笑，青衫不惜著風埃。", "林廬要自家家到，尊酒寧辭日日開。", "只恐未便文字飲，人間無夢到陽臺。"]'),
('77c69ae4-5b2d-43f1-a2eb-f306053bed98','寄都下故人示王子安','陳師道','宋','宋诗','song-poetry','','[]','湖海相忘日自疏，經年不作一行書。',32,'全唐诗/poet.song.62000.json','["湖海相忘日自疏，經年不作一行書。", "世間惟有韓康伯，肯爲淵源住歲餘。"]'),
('0f53b485-9a15-4d1c-a7eb-846b3298c77f','送張衡山','陳師道','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔別青衿子，今爲白髮翁。',48,'全唐诗/poet.song.62000.json','["昔別青衿子，今爲白髮翁。", "此行何日見，多難向來同。", "官事酣歌裏，湖山秀句中。", "風塵莫回首，留眼送歸鴻。"]'),
('7ba60ae7-d1f0-440b-906d-439e7e8a3ace','除夜對酒贈少章','陳師道','宋','宋诗','song-poetry','','["\u996e\u9152", "\u6292\u6000", "\u6625\u8282"]','歲晚身何託，燈前客未空。',48,'全唐诗/poet.song.62000.json','["歲晚身何託，燈前客未空。", "半生憂患裏，一夢有無中。", "髮短愁催白，顔衰酒借紅。", "我歌君起舞，潦倒略相同。"]'),
('13d0b958-852c-4cac-9cee-c83d0a97edee','和賈耘老春晚','陳師道','宋','宋诗','song-poetry','','[]','縈縈裊裊幾絲飛，榴葉千燈照晚暉。',64,'全唐诗/poet.song.62000.json','["縈縈裊裊幾絲飛，榴葉千燈照晚暉。", "紫翠園林鶑欲懶，黄昏簾幕燕初歸。", "花明西苑將迎幸，草綠平原正打圍。", "一卧海城春又晚，不妨閑處得真機。"]'),
('a41800cd-de06-45b6-90d0-71461f3c1691','擬漢宮詞三首  其一','陳師道','宋','宋诗','song-poetry','','[]','葉葉霜林著意紅，翩翩行騎語牆東。',32,'全唐诗/poet.song.62000.json','["葉葉霜林著意紅，翩翩行騎語牆東。", "黄金擬買長門賦，未信君恩屬畫工。"]'),
('b294f928-cb36-48ea-9aa8-e868c2b01fee','擬漢宮詞三首  其二','陳師道','宋','宋诗','song-poetry','','[]','月與秋期特地圓，花隨人意作春妍。',32,'全唐诗/poet.song.62000.json','["月與秋期特地圓，花隨人意作春妍。", "却因姊弟爭珠鳳，更欲君王意外憐。"]'),
('307e1e42-40d8-4b64-a0ee-45dbce13bc5e','擬漢宮詞三首  其三','陳師道','宋','宋诗','song-poetry','','[]','帳底吹煙香自薰，鏡前含笑意生春。',32,'全唐诗/poet.song.62000.json','["帳底吹煙香自薰，鏡前含笑意生春。", "經年不道君恩薄，却是恩深更誤人。"]'),
('23c1c351-8ada-4c09-aaa6-83c7a63afbeb','擬李義山柳枝詞五首  其一','陳師道','宋','宋诗','song-poetry','','[]','江青沙日暖，雄鴨雌鴛鴦。',24,'全唐诗/poet.song.62000.json','["江青沙日暖，雄鴨雌鴛鴦。", "相看不相識，花晚褪紅香。"]'),
('b0abb6c9-b024-446b-9aed-62e93112eff3','擬李義山柳枝詞五首  其二','陳師道','宋','宋诗','song-poetry','','[]','嫋嫋東門柳，重重小苑花。',24,'全唐诗/poet.song.62000.json','["嫋嫋東門柳，重重小苑花。", "爲誰須落子，著意莫藏鴉。"]'),
('22954028-6672-401c-9c17-c373fd6645ce','擬李義山柳枝詞五首  其三','陳師道','宋','宋诗','song-poetry','','[]','雨葉不自持，風花故入衣。',24,'全唐诗/poet.song.62000.json','["雨葉不自持，風花故入衣。", "飛花已無定，忍著惡風吹。"]'),
('51e0da54-221d-454d-8e86-f9d4ca80698b','擬李義山柳枝詞五首  其四','陳師道','宋','宋诗','song-poetry','','[]','伏雌將阿鶩，水陸不相直。',24,'全唐诗/poet.song.62000.json','["伏雌將阿鶩，水陸不相直。", "鴨鴨橫波去，嗝嗝呼不得。"]'),
('d5eafc29-eae1-49b2-bb2e-92ddb50d82ad','擬李義山柳枝詞五首  其五','陳師道','宋','宋诗','song-poetry','','[]','莫解丁香結，從教長苦辛。',24,'全唐诗/poet.song.62000.json','["莫解丁香結，從教長苦辛。", "却因千種恨，別作一家春。"]'),
('8f33f0c9-2165-4278-8422-7ebe032b959c','次韵鄭彥能題端禪師丈室','陳師道','宋','宋诗','song-poetry','','[]','重門傑觀屹相忘，表裏山河自一方。',64,'全唐诗/poet.song.62000.json','["重門傑觀屹相忘，表裏山河自一方。", "小市張燈歸意動，輕衫當戶晚風長。", "孤臣白首逢新政，遊子青春見故鄉。", "富貴本非吾輩事，江湖安得便相忘。"]'),
('2a71d871-6fd9-46cf-8953-69f0f3e2ff3d','庚辰三月上旬登白門閑望','陳師道','宋','宋诗','song-poetry','','[]','昔別子未仕，人言詩有神。',48,'全唐诗/poet.song.62000.json','["昔別子未仕，人言詩有神。", "預知河嶺阻，不作往來頻。", "剩喜今猶學，須知祿爲親。", "五陵花滿眼，作意莫禁春。"]'),
('7418765e-96ec-40bf-85e0-f6a1300a0d32','次韵寇秀才寄下邳家兄','陳師道','宋','宋诗','song-poetry','','[]','少共千憂老一官，中間毀譽兩茫然。',64,'全唐诗/poet.song.62000.json','["少共千憂老一官，中間毀譽兩茫然。", "去留有命真如此，俯仰從人却未然。", "故著江山供極目，正將彊健入新年。", "驚逢小杜風流勝，信有衣冠不乏賢。"]'),
('de39aed4-d09d-4598-a503-75dfa631a984','贈知命','陳師道','宋','宋诗','song-poetry','','[]','黑頭居士元方弟，不肯作公稱法嗣。',160,'全唐诗/poet.song.62000.json','["黑頭居士元方弟，不肯作公稱法嗣。", "外人怪笑那得知，他日靈山親授記。", "學詩初學杜少陵，學書不學王右軍。", "黄塵扶杖笑鄰女，白衫騎馿驚市人。", "靜中作業此何因，醉裏逃禪却甚真。", "顧我無錢呼畢曜，有人載酒尋子雲。", "君家魯直不解事，愛作文章可人意。", "一人可以窮一家，怪君又以才爲累。", "請將飲酒換吟詩，酒不窮人能引睡。", "不須無事與多愁，老不欲醒惟欲醉。"]'),
('e50596df-627d-4b69-a5bc-ab05ab19294e','次韵答少章','陳師道','宋','宋诗','song-poetry','','[]','秦郎淮海士，才大難爲弟。',96,'全唐诗/poet.song.62000.json','["秦郎淮海士，才大難爲弟。", "蔚然霜雪後，不受江漢洗。", "春畦不滿眼，采掇到芹薺。", "多病促餘年，秋光欲辭抵。", "儒林文人行，掘起三界底。", "出入銀臺門，爲米不爲醴。", "白頭容北面，斯文分一體。", "愧我無異聞，口闞不得啟。"]'),
('658838cb-e05b-440c-8224-c587602b6595','大風','陳師道','宋','宋诗','song-poetry','','[]','飛沙破面風裂石，平林隠隠傾霹靂。',64,'全唐诗/poet.song.62000.json','["飛沙破面風裂石，平林隠隠傾霹靂。", "野火燎原塵漲天，道聞馬嘶不相得。", "老翁彊欲作少年，立馬階除起無力。", "城南桃李春意動，少待明朝莫相失。"]'),
('e8f1174c-2953-49d2-a738-77a25f58111d','秦少章見過','陳師道','宋','宋诗','song-poetry','','[]','淮南小山秦氏子，舊雨不來今雨來。',32,'全唐诗/poet.song.62000.json','["淮南小山秦氏子，舊雨不來今雨來。", "風席起塵晨突冷，坐看鳥跡破蒼苔。"]'),
('c523b6a9-8d4e-456e-8f59-cef539dcf29e','送王君玉赴試','陳師道','宋','宋诗','song-poetry','','[]','汝潁諸王後，風流獨此人。',48,'全唐诗/poet.song.62000.json','["汝潁諸王後，風流獨此人。", "談鋒堅百戰，筆力舉千鈞。", "得士吾無愧，多聞子未貧。", "平生三學士，相見定相親。"]'),
('26b63b7b-94dd-4fe9-8096-920235668b43','送路糾歸老丹陽','陳師道','宋','宋诗','song-poetry','','[]','身退不待年，意足不待餘。',180,'全唐诗/poet.song.62000.json','["身退不待年，意足不待餘。", "寧聞有餘論，但問我何如。", "才名四十年，盛氣蓋諸儒。", "獨無金水力，竟與蛙黽俱。", "晚爲府中掾，直前不趑趄。", "曾何愧俯仰，頗亦困囁嚅。", "有粟尚可糊，有酒尚可娛。", "一朝脫章綬，用意不躊躇。", "富貴亦何有，惜君寧挽裾。", "人生一世間，誰得還其軀。", "謝公江海人，此計竟亦疏。", "千金一大錢，兩子雙明珠。", "妙語發幽光，東坡爲欷歔。", "不知兩疏去，能亦有此無。", "聊爲三徑資，從子並門居。"]'),
('0fe0a3b6-3888-456b-92d9-8476e8e698b3','送江季恭','陳師道','宋','宋诗','song-poetry','','[]','正學元非世，能詩新有聲。',48,'全唐诗/poet.song.62000.json','["正學元非世，能詩新有聲。", "諸公交鄭季，多士閉何生。", "泛愛經過數，移書底裏傾。", "又爲淮海別，病眼向誰明。"]'),
('1fee22bc-70e4-437f-a040-a8f7d1c4ec8e','奉送閻醇老推官','陳師道','宋','宋诗','song-poetry','','[]','古今猶異俗，鄒魯尚多儒。',48,'全唐诗/poet.song.62000.json','["古今猶異俗，鄒魯尚多儒。", "簿領三年責，雲霄一武趨。", "數過忘潦倒，惜別更斯須。", "說與晁夫子，今年錐也無。"]'),
('e74053fa-5461-4a77-94e5-a969debc72ad','回風行','陳師道','宋','宋诗','song-poetry','','[]','懸流洶洶從天來，南風五日鬭不開。',80,'全唐诗/poet.song.62000.json','["懸流洶洶從天來，南風五日鬭不開。", "御風起柂虎著翼，衝風繫纜顔死灰。", "昨日逆風今日回，萬人莫挽才浮盃。", "篙牽相賀天意得，秋聲滿帆風倒桅。", "去留異態須一怒，造物可得無嫌猜。"]'),
('1214225b-c400-4136-b73c-cd7b5120c171','答李簿','陳師道','宋','宋诗','song-poetry','','[]','老去才先盡，春來酒屢空。',48,'全唐诗/poet.song.62000.json','["老去才先盡，春來酒屢空。", "甘爲耕釣手，畏作囁嚅翁。", "與罪寧無說，言詩新有功。", "不堪須野鶩，似欲吐長虹。"]'),
('38ff19cd-7270-4623-bdd3-c01ef04cc792','謝傅監','陳師道','宋','宋诗','song-poetry','','[]','好士如好色，昔聞今則無。',204,'全唐诗/poet.song.62000.json','["好士如好色，昔聞今則無。", "平生席爲門，未識長者車。", "曠士慕林谷，羈人辱泥塗。", "願爲執鞭役，莫順下風趨。", "去年辱公先，懷刺留寓居。", "我往拜其門，鸑鷟鳴高梧。", "論交不計年，取材忘其愚。", "一寒我如此，百鎰公無餘。", "今年賀公歸，乃復過我廬。", "當使有近行，應門有長須。", "小家不耐事，雞飛犬升閭。", "莫歸自有恨，親顔一何娛。", "汝家吾無憂，能致賢大夫。", "吳公漢庭右，賈生世用疏。", "平分太倉粟，盡讀鄴侯書。", "士爲知己留，不爲食有魚。", "三言移曾母，投杼公何如。"]'),
('266700d4-1be1-48b0-ad5b-77aca4ce18e0','賀文潛','陳師道','宋','宋诗','song-poetry','','[]','飛騰無那高詹事，犇軼難甘杜拾遺。',64,'全唐诗/poet.song.62000.json','["飛騰無那高詹事，犇軼難甘杜拾遺。", "釋梵不爲寧顧計，公侯有命却隨宜。", "且留陳迹來韓愈，不用逢人說項斯。", "富貴風聲真兩得，窮人從此不因詩。"]'),
('b45fe15e-eae0-4307-be70-10fec7cb7df5','贈張文潛','陳師道','宋','宋诗','song-poetry','','[]','張侯便然腹如鼓，饑雷收聲酒如雨。',120,'全唐诗/poet.song.62000.json','["張侯便然腹如鼓，饑雷收聲酒如雨。", "讀書不計有餘處，尚著我輩千百許。", "翻湖倒海不作難，將軍百戰富善賈。", "弟子不必不如師，欲知其人視其主。", "秋來待試丞相府，穀馬礪兵吾甚武。", "商周不敵聞其語，一戰而霸在此舉。", "百年富貴要自取，人將公卿還爾汝，德如墨君誰敢侮。"]'),
('2482fd4d-8790-4785-8f33-359da1514e85','次韵答秦少章','陳師道','宋','宋诗','song-poetry','','[]','學詩如學仙，時至骨自換。',120,'全唐诗/poet.song.62000.json','["學詩如學仙，時至骨自換。", "縹緲鴻鵠上，衆目焉能玩。", "子從淮海來，一喙當百難。", "師儒有韓孟，拭目互驚惋。", "老生時在傍，縮手愧顔汗。", "黄公金華伯，莞爾回一眄。", "彼方試子難，疾前不應懦。", "要當攻石堅，切作摶沙散。", "桓璧雖具美，礲錯加璀璨。", "我老不足畏，後生何可慢。"]'),
('1fdb9495-efe8-42bb-b512-c1214f79307e','次韵答子實秦少章二首  其一','陳師道','宋','宋诗','song-poetry','','[]','英英黄金花，論時不論美。',48,'全唐诗/poet.song.62000.json','["英英黄金花，論時不論美。", "靖節骨已朽，棄捐乃其理。", "兩公意有餘，采采今未已。", "尚念白頭生，臨風嗅霜蕊。"]'),
('72236895-1aba-4389-b513-efec09e1bb0f','次韵答子實秦少章二首  其二','陳師道','宋','宋诗','song-poetry','','[]','文新情已故，室遠人則邇。',48,'全唐诗/poet.song.62000.json','["文新情已故，室遠人則邇。", "杯酒不相忘，一朝得二子。", "初花美無度，後時終可鄙。", "與汝卧秋風，看君控雙鯉。"]'),
('df336f7f-a3ce-43bb-b4a1-550ad9a7a048','九月十三日出善利門','陳師道','宋','宋诗','song-poetry','','[]','十載都城客，孤身冒百艱。',48,'全唐诗/poet.song.62000.json','["十載都城客，孤身冒百艱。", "一饑非死所，萬里有生還。", "去國吾何意，從人病不間。", "共看雙白鬢，似得半生閑。"]'),
('1fffdbf6-c6da-4385-91b5-c6d76ac3d13c','贈歐陽叔弼學士','陳師道','宋','宋诗','song-poetry','','[]','早知汝潁多能事，晚以詩書託下寮。',64,'全唐诗/poet.song.62000.json','["早知汝潁多能事，晚以詩書託下寮。", "大府禮容寬懶慢，故家文物尚嫖姚。", "只將憂患供談笑，敢望功名答聖朝。", "歲歷四三仍此地，家餘五一見今朝。"]'),
('da3a4329-6f84-41f3-a49e-7814a5a450f8','觀兖文忠公家六一堂圖書','陳師道','宋','宋诗','song-poetry','','[]','生世何用早，我已後此翁。',240,'全唐诗/poet.song.62000.json','["生世何用早，我已後此翁。", "頗識門下士，略已聞其風。", "中年見二子，已復歲一終。", "呼我過其廬，所得非所蒙。", "先朝羣玉殿，冠佩環羣公。", "神文煥王度，喜色見天容。", "御榻誰復登，帝書元自工。", "黄絹兩大字，一覽涕無從。", "似欲託其子，天意人與同。", "曆數况有歸，敢有貪天功。", "集古一千卷，明明並羣雄。", "誰爲第一手，未有百世公。", "廟器刻科斗，寶樽蟠華蟲。", "緬懷弁服士，酬獻鳴瑽瑢。", "插架一萬軸，遺子以固窮。", "素琴久絕絃，棋酒頗闕供。", "向來一瓣香，敬爲曾南豐。", "世雖嫡孫行，名在惡子中。", "斯人日已遠，千歲幸一逢。", "吾老不可待，草露濕寒蛩。"]'),
('d4adc9a3-8f9f-49cc-92b0-7652d88c3342','送蘇迨','陳師道','宋','宋诗','song-poetry','','[]','胸中歷歷著千年，筆下源源赴百川。',64,'全唐诗/poet.song.62000.json','["胸中歷歷著千年，筆下源源赴百川。", "真字飄揚今有種，清談絕倒古無傳。", "出塵悟解多爲路，隨世功名小著鞭。", "白首相逢恐無日，幾時筆札到林泉。"]'),
('b1ca9178-fa52-4b74-8ec4-c0c827788064','送黄生兼寄二謝二首  其一','陳師道','宋','宋诗','song-poetry','','[]','南第諸兄早相見，別時託子以無倦。',64,'全唐诗/poet.song.62000.json','["南第諸兄早相見，別時託子以無倦。", "百歲論交見子心，一朝取別寧吾願。", "妙歲遠游真所難，肯爲得官近長安。", "聖作詩書端有意，猶須用心科舉外。"]'),
('81f6173e-e347-46ec-acb0-83aeda631f86','送黄生兼寄二謝二首  其二','陳師道','宋','宋诗','song-poetry','','[]','城西兩謝俱能文，穰丞精悍吾所聞。',64,'全唐诗/poet.song.62000.json','["城西兩謝俱能文，穰丞精悍吾所聞。", "每讀吾詩得人意，使不能文已可人。", "我昔謝公門下士，早年妄作功名意。", "如今老寄潁河東，九泉雖深愧此公。"]'),
('dd82b10c-18ae-47e5-9eef-291eb1b5bd56','次韵蘇公西湖徙魚三首  其一','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','窮秋積雨不破塊，霜落西湖露沙背。',128,'全唐诗/poet.song.62000.json','["窮秋積雨不破塊，霜落西湖露沙背。", "大魚泥蟠小魚樂，高丘覆杯水如带。", "魚窮不作搖尾憐，公寧忍口不忍鱠。", "脩鱗失水玉參差，晚日搖光金破碎。", "咫尺波濤有生死，安知平陸無灘瀨。", "此身寧供刀几用，著意更須風雨外。", "是間相忘不爲小，濠上之意誰得會。", "枯魚雖泣悔可及，莫待西江與東海。"]'),
('ee0065ef-8081-46fc-9e3b-4cca2817901f','次韵蘇公西湖徙魚三首  其二','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','赤手取魚如拾塊，布網鳴舷攻腹背。',128,'全唐诗/poet.song.62000.json','["赤手取魚如拾塊，布網鳴舷攻腹背。", "豈知激濁與清流，恐懼駢頭牽翠带。", "居士仁心到魚鳥，會有微生化餘鱠。", "寧容網目漏吞舟，誰能烹鮮作苛碎。", "我亦江湖釣竿手，誤逐輕車從下瀨。", "生當得意落鷗邊，何用封侯墮鳶外。", "不如此魚今得所，置身暗與神明會。", "徑須作記戒鯨鯢，防有任公釣東海。"]'),
('61eb4549-a688-4e9f-83c9-29a6f9a49853','次韵蘇公西湖徙魚三首  其三','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩成筆落驥歷塊，不用安西題紙背。',128,'全唐诗/poet.song.62000.json','["詩成筆落驥歷塊，不用安西題紙背。", "小家厚歛四壁立，拆東補西裳作带。", "堂下觳觫牛何罪，太山之陽人作鱠。", "同生異趣有如此，缾懸瓽間終一碎。", "流水長者今公是，雨花散亂投金瀨。", "人言充庖須此輩，慈觀更須容度外。", "賜牆及肩人得視，公才槃槃一都會。", "有憐其窮與不朽，我亦牽聯書玉海。"]'),
('ca01b0bd-2da4-4d11-9f63-979e23a44988','次韵蘇公西湖觀月聽琴','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清湖納明月，遠覽無留雲。',96,'全唐诗/poet.song.62000.json','["清湖納明月，遠覽無留雲。", "人生亦何須，有酒與桐君。", "自醉寧問客，一樽復一樽。", "平生今不飲，意得同酣醺。", "清言冰玉質，壞衲山水紋。", "殫精有後悟，畜耳無前聞。", "潛魚避流光，歸鳥投重昏。", "信有千丈清，不如一尺渾。"]'),
('fd127553-d421-4ee4-a8b3-1beba89e492c','再次韵蘇公示兩歐陽','陳師道','宋','宋诗','song-poetry','','[]','公詩周魯後，曳曳垂天雲。',96,'全唐诗/poet.song.62000.json','["公詩周魯後，曳曳垂天雲。", "府中顧長康，風味如麴君。", "非公無此客，請壽兩山樽。", "叔季大儒後，偏醒亦同醺。", "心與柏石堅，章成綺繡紋。", "多難獨不補，少戇今無聞。", "時無古今異，智有功名昏。", "可使百尺底，不作數斗渾。"]'),
('c80b74ae-0ca6-4e5d-92cb-7e8cd647a66e','次韵蘇公涉潁','陳師道','宋','宋诗','song-poetry','','[]','衝風不成寒，脫木還自奇。',168,'全唐诗/poet.song.62000.json','["衝風不成寒，脫木還自奇。", "坐看白日晚，起行清潁湄。", "三穴未爲得，一舟不作癡。", "路暗鳥遺音，江清魚弄姿。", "宇定怪物變，意行覺舟遲。", "公與兩公子，妙語含風漪。", "但怪笑談劇，莫知賓主誰。", "得句未肯吐，鬰鬰見睫眉。", "相從能幾何，行樂當及茲。", "生忍自作難，百憂間一嬉。", "時尋赤眼老，不探黄口兒。", "解公頭上巾，一洗七年緇。", "至潔而納汙，此水真吾師。", "須公曉二子，人自窮非詩。"]'),
('3a54d42f-66e9-40be-8fea-5177d4d33512','次韵蘇公竹間亭絕句','陳師道','宋','宋诗','song-poetry','','[]','竹裏高亭燈燭光，今年復得杜襄陽。',32,'全唐诗/poet.song.62000.json','["竹裏高亭燈燭光，今年復得杜襄陽。", "倏看老蓋千年後，更想霜林百尺强。"]'),
('c4e76be5-5769-4d24-9075-513878e1fe6d','次韵蘇公勸酒與詩','陳師道','宋','宋诗','song-poetry','','[]','五士三不同，煩公以詩訴。',120,'全唐诗/poet.song.62000.json','["五士三不同，煩公以詩訴。", "强酒古所辭，妙語神其吐。", "自念每累人，舉扇毋我汙。", "復使兩歐陽，縮手不分付。", "平生西方社，努力須自度。", "不憂龜九頭，肯畏語一誤。", "頓悟而漸修，從此辭世故。", "公看萬金産，寧能一朝具。", "兩生文章家，夙記鳴蟬賦。", "請公堅城壘，兵來後無數。"]'),
('c8d13e47-0377-446b-a443-370e44f25252','次韵蘇公督兩歐陽詩','陳師道','宋','宋诗','song-poetry','','[]','吟聲正可候蟲鳴，酒面猶須作老兵。',64,'全唐诗/poet.song.62000.json','["吟聲正可候蟲鳴，酒面猶須作老兵。", "豈有文章妨要務，孰知詩律自前生。", "向來懷璧真成罪，未必含光不屢驚。", "血指汗顔終縮手，此懷端復向誰傾。"]'),
('3176aee8-1441-424c-a072-ad259f785881','次韵蘇公題歐陽叔弼息齋','陳師道','宋','宋诗','song-poetry','','[]','行者悲故里，居者愛吾廬。',120,'全唐诗/poet.song.62000.json','["行者悲故里，居者愛吾廬。", "生須著錐地，何頼汗牛書。", "丈室八尺牀，稱子閉門居。", "百爲會有還，一足不待餘。", "紛紛幼老間，失得了懸虛。", "客在醉則眠，聽我勿問渠。", "論勝已絕倒，句妙方愁予。", "竹几無留塵，霜畦有餘蔬。", "相從十五年，不爲食有魚。", "時須一俛仰，君可貸蘧篨。"]'),
('0729b4a0-2fd5-4dc5-9da1-c78589d620fb','寄參寥','陳師道','宋','宋诗','song-poetry','','[]','平生西方願，擺落區中緣。',144,'全唐诗/poet.song.62000.json','["平生西方願，擺落區中緣。", "惟於世外人，相從可忘年。", "道人贊公徒，相識幾生前。", "早作步兵語，晚參雲門禪。", "捨策孤山下，一室頗蕭然。", "林昏出幽磬，竹杪橫疏煙。", "昨日寄書至，坐想參寥泉。", "此泉如此公，遇物作清妍。", "一別今幾時，綠首成白顛。", "子亦憐我老，我豈要子憐。", "會逢萬里風，一繫五湖船。", "酌我巖下水，咽子山中篇。"]'),
('ce033d1a-716c-42ff-89c0-3917b3e549a0','北渚','陳師道','宋','宋诗','song-poetry','','[]','南蕩不可度，北渚風浪生。',24,'全唐诗/poet.song.62000.json','["南蕩不可度，北渚風浪生。", "向來狐兔迹，已復蛟鼉鳴。"]'),
('e6925916-be41-42e1-85bd-f8e45ea65932','東禪','陳師道','宋','宋诗','song-poetry','','[]','東阡急雨未成泥，度密穿青取徑微。',32,'全唐诗/poet.song.62000.json','["東阡急雨未成泥，度密穿青取徑微。", "邂逅無人成獨往，慇懃有月與同歸。"]'),
('feef0ee9-37a6-4f97-a56f-04d6391edc7f','絕句','陳師道','宋','宋诗','song-poetry','','[]','老著江湖才一得，病占風雨漫多知。',32,'全唐诗/poet.song.62000.json','["老著江湖才一得，病占風雨漫多知。", "身將白鳥同歸日，夢到黄粱未熟時。"]'),
('aab9917c-901e-4c79-9e49-93997d7dd5d7','八月十日二首  其一','陳師道','宋','宋诗','song-poetry','','[]','一夢人間四十年，只應炊竈固依然。',32,'全唐诗/poet.song.62000.json','["一夢人間四十年，只應炊竈固依然。", "兩官不辦一丘費，五字虛隨萬里船。"]'),
('e67a8b31-fba7-45fa-ab3d-6d5134eae196','八月十日二首  其二','陳師道','宋','宋诗','song-poetry','','[]','人生七十今强半，老去光陰已後身。',32,'全唐诗/poet.song.62000.json','["人生七十今强半，老去光陰已後身。", "更欲置身須世外，世間元自不關人。"]'),
('7830ff45-814a-47f2-9123-46eb9b3790db','迎新將至漕城暮歸遇雨','陳師道','宋','宋诗','song-poetry','','[]','早投林野違風雨，晚旁塵泥飽送迎。',32,'全唐诗/poet.song.62000.json','["早投林野違風雨，晚旁塵泥飽送迎。", "却愧兩街屠販子，卧聽車馬過橋聲。"]'),
('c086d70a-423e-41cf-8fb0-a6c1102295d6','即事','陳師道','宋','宋诗','song-poetry','','[]','老覺山林可避人，正須麋鹿與同羣。',32,'全唐诗/poet.song.62000.json','["老覺山林可避人，正須麋鹿與同羣。", "却嫌鳥語猶多事，强管陰晴報客聞。"]'),
('fc5fc3bb-f6dd-450d-966c-c3534ca3d7e4','齋居','陳師道','宋','宋诗','song-poetry','','[]','青奴白牯靜相宜，老罷形骸不自持。',32,'全唐诗/poet.song.62000.json','["青奴白牯靜相宜，老罷形骸不自持。", "一枕西窗深閉閤，卧聽叢竹雨來時。"]'),
('b2116fc3-880a-46df-93a2-567ebf758726','中秋夜東剎贈仁公','陳師道','宋','宋诗','song-poetry','','[]','盈盈秋月不餘分，葉露懸光可數塵。',32,'全唐诗/poet.song.62000.json','["盈盈秋月不餘分，葉露懸光可數塵。", "此地正須煩一笑，要令排戶問東鄰。"]'),
('e1363ca6-9600-4136-a380-9f3de2b68345','十五夜月','陳師道','宋','宋诗','song-poetry','','[]','向老逢清節，歸懷託素暉。',48,'全唐诗/poet.song.62000.json','["向老逢清節，歸懷託素暉。", "飛螢元失照，重露已霑衣。", "稍稍孤光動，沉沉衆籟微。", "不應明白髮，似欲勸人歸。"]'),
('056bce1c-3ca4-4490-9f59-d4bab99b0ef2','胡士彥挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','晚進違前輩，平生闕異聞。',48,'全唐诗/poet.song.62000.json','["晚進違前輩，平生闕異聞。", "吾猶識此老，天豈喪斯文。", "善學家傳業，英詞世不羣。", "固應譏尚白，官序見揚雲。"]'),
('706b9f5e-91ff-4bb7-b90a-0379eefcf4d7','胡士彥挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','此地來何晚，經年見未頻。',48,'全唐诗/poet.song.62000.json','["此地來何晚，經年見未頻。", "薦賢仍賭命，有道可辭貧。", "徒弟三千子，聲名四十春。", "襄陽耆舊內，無復姓龐人。"]'),
('8615b22f-c151-4c98-830c-4e513305745c','送趙承議','陳師道','宋','宋诗','song-poetry','','[]','先生隠德世難名，晚見諸孫也自成。',64,'全唐诗/poet.song.62000.json','["先生隠德世難名，晚見諸孫也自成。", "潁水向來須好句，道山今日有宗英。", "林湖更覺追隨盡，巾帽猶堪語笑傾。", "勤苦讀書終不補，未須牆角棄長檠。"]'),
('c6f1cba3-e6e2-4f5f-80bc-25e280200649','寄李學士','陳師道','宋','宋诗','song-poetry','','[]','眼看游舊半東都，五歲曾無一紙書。',64,'全唐诗/poet.song.62000.json','["眼看游舊半東都，五歲曾無一紙書。", "平日齊名多早達，暮年同國未情疏。", "稍尋東剎論茲事，頼有西方託後車。", "說與杜郎須著便，不應濠上始知魚。"]'),
('48e52587-4330-4953-9b33-a9d54dc7841f','雪','陳師道','宋','宋诗','song-poetry','','[]','初雪已覆地，晚風仍積威。',48,'全唐诗/poet.song.62000.json','["初雪已覆地，晚風仍積威。", "木鳴端自語，鳥起不成飛。", "寒巷聞驚犬，鄰家有夜歸。", "不無慚敗絮，未易泣牛衣。"]'),
('d36c15ae-f8b9-48c1-ae27-e4c0f0a8bfc8','晚出','陳師道','宋','宋诗','song-poetry','','[]','應俗敢辭疾，衝風寧小驅。',48,'全唐诗/poet.song.62000.json','["應俗敢辭疾，衝風寧小驅。", "聊爲一日役，不憚百金軀。", "雪路無行迹，冰枝有落烏。", "寒門閉蕭瑟，窮里聽嚱吁。"]'),
('0265b728-66cb-41de-bf48-2b186a2a318a','寄晁載之兄弟','陳師道','宋','宋诗','song-poetry','','[]','人言婚宦情欲本，我始求脫君已半。',128,'全唐诗/poet.song.62000.json','["人言婚宦情欲本，我始求脫君已半。", "孰知一世如一夢，在夢而覺寧待旦。", "寒簷凍雨作秋聲，冷屋風燈挑不明。", "樽前已作十年語，後會未期吾屢驚。", "一聞七字心已識，鈎章棘句天與力。", "念子方壯我已衰，不見參天二千尺。", "季也亦有詩百篇，叔子擬度驊騮前。", "端能過我三冬學，可復參儂一味禪。"]'),
('80ad04fd-ec7a-4858-83b9-3a7c67e5bee9','寄答王直方','陳師道','宋','宋诗','song-poetry','','[]','人情校往復，屢勉終不近。',156,'全唐诗/poet.song.62000.json','["人情校往復，屢勉終不近。", "一詩已經年，知子不我怨。", "生世餘幾何，尺箠日取寸。", "懷祿有遐心，從俗無遠韵。", "時從府中歸，數過林下飯。", "平生功名意，回作香火願。", "三年不舉觴，吻頰煙火焮。", "豈無兩蒼龍，霑我一雨潤。", "官粗詩未工，猛乞毋小靳。", "人生如此爾，文字已其閏。", "是身雖臭腐，寧作青紫楦。", "永懷忘年友，死矣餘令問。", "念子頗似之，老我何所恨。"]'),
('ce29da2b-d904-4c5c-8167-2680ec3fbd9d','送章推官','陳師道','宋','宋诗','song-poetry','','[]','從事有多譽，還家能少留。',48,'全唐诗/poet.song.62000.json','["從事有多譽，還家能少留。", "持盃猶潁尾，解纜即沙頭。", "好事今猶壯，論文老自休。", "風埃留我老，說與五湖秋。"]'),
('1d439a11-67a2-4e91-86c3-cf1b2c5393f3','送章氏兄弟兼寄金山寧禪師','陳師道','宋','宋诗','song-poetry','','[]','末塗一過馬羣空，老眼雙瞻碣石鴻。',64,'全唐诗/poet.song.62000.json','["末塗一過馬羣空，老眼雙瞻碣石鴻。", "固有江東兼渭北，其如明月與清風。", "一官羈絆吾堪老，萬里嫖姚子未窮。", "寄語此時懷馬祖，叩門何日許龐公。"]'),
('011e7f83-23a5-43f1-9b42-fdd50ab49064','寄晁以道','陳師道','宋','宋诗','song-poetry','','[]','兩官俱爲鄰，常若千里遠。',168,'全唐诗/poet.song.62000.json','["兩官俱爲鄰，常若千里遠。", "經年不通書，子孰知我懶。", "相期宇宙外，肯復校繁簡。", "我愚亦知此，子意豈不滿。", "子教東方生，自視何益損。", "人言不當價，一錢萬金産。", "須子五千卷，丹筆校黄本。", "子家太史氏，名成南北阮。", "道山鴻雁行，豈惟私門衎。", "功名須老大，四十未爲晚。", "快意會有違，急行寧小緩。", "忽有河山阻，遂恐消息斷。", "我獨不念此，人窮令智短。", "子勿效我慵，書來慰愁眼。"]'),
('25601a99-5c0d-4953-ae00-50b5b49cea97','寄侍讀蘇尚書','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六月西湖早得秋，二年歸思與遲留。',64,'全唐诗/poet.song.62000.json','["六月西湖早得秋，二年歸思與遲留。", "一時賓客餘枚叟，在處兒童說細侯。", "經國向來須老手，有懷何必到壺頭。", "遥知丹地開黄卷，解記清波沒白鷗。"]'),
('01d2beab-85d3-40ca-84cc-fde76ad40204','寄亳州林待制','陳師道','宋','宋诗','song-poetry','','[]','湖海相望闕寄聲，雲林過雨未全晴。',64,'全唐诗/poet.song.62000.json','["湖海相望闕寄聲，雲林過雨未全晴。", "青衫作吏非前日，白首論文笑後生。", "似聽兒童迎五馬，稍修書札問專城。", "一聞苦李蒙莊句，不復人間世後名。"]'),
('51ea5d42-7455-43c4-86e3-1f51c6660bbb','卧疾絕句','陳師道','宋','宋诗','song-poetry','','[]','老裏何堪病再來，愁邊不復酒相開。',32,'全唐诗/poet.song.62000.json','["老裏何堪病再來，愁邊不復酒相開。", "一生也作千年調，兩脚猶須萬里回。"]'),
('ab1226b3-2a5f-467c-a6d1-f5f659e2296a','南軒','陳師道','宋','宋诗','song-poetry','','[]','少日書林頗著勳，暮年貪佛替論文。',32,'全唐诗/poet.song.62000.json','["少日書林頗著勳，暮年貪佛替論文。", "銅鑪瓦枕芒鞋裏，此外惟須對此君。"]'),
('00fce8bd-1b37-4d23-92e3-f7936531d886','獨坐','陳師道','宋','宋诗','song-poetry','','[]','文章平日事，風竹莫年須。',72,'全唐诗/poet.song.62000.json','["文章平日事，風竹莫年須。", "衰疾懸知此，霜毛不更除。", "一丘吾欲往，百畝有如無。", "魑魅須游子，乾坤著腐儒。", "扣門聞啄木，喚酒有提壺。", "門徑無行跡，秋來不遣鋤。"]'),
('b8a942d6-8d0e-4772-b3ef-7c5987df1fdf','幼嶺','陳師道','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','外家英俊場，季氏不好弄。',48,'全唐诗/poet.song.62000.json','["外家英俊場，季氏不好弄。", "用意丘壑間，頗以石自奉。", "誰言拳握間，意作萬牛重。", "岱宗小天下，不辦一席用。"]'),
('05098268-12d3-42e0-a2e2-ce5cfdeda0ad','同道士錢泠然尋澗水源','陳師道','宋','宋诗','song-poetry','','[]','曉領黄冠子，步尋東澗源。',120,'全唐诗/poet.song.62000.json','["曉領黄冠子，步尋東澗源。", "拖筇探清淺，垂手弄潺湲。", "岸閣殘花片，槎留舊漲痕。", "鳳潛丹穴邃，龍卧古潭渾。", "脩竹青垂蔭，長蘿翠可捫。", "忽驚穿藥圃，不覺到雲根。", "嶝外看飛鳥，崖邊見飲猿。", "援琴寫山水，布席坐蘭蓀。", "白石支棋局，青沙藉酒尊。", "醉歌歸路穩，洞口月黄昏。"]'),
('8b46ac64-4cba-4512-bda8-b7f18822c410','八月十日宿百丈山慶善院明日遊松風菴謁震禪師','陳師道','宋','宋诗','song-poetry','','[]','衾裘夜宿方丈屋，風燈微茫照溪谷。',144,'全唐诗/poet.song.62000.json','["衾裘夜宿方丈屋，風燈微茫照溪谷。", "杖屨朝行百丈山，林風清泠搖佩環。", "道人八十更聰明，耳邊猶愛松風聲。", "風前飽食松下卧，夢裏光陰等閑過。", "世間貴人多白頭，未容白首送林丘。", "左足拘攣右臂緩，榮華只得傍人看。", "信知佛法有天樂，掃除疾痼何須藥。", "山林於我却有因，願言築室爲比鄰。", "不辭棄世伴幽獨，猶恐山僧嫌近俗。"]'),
('c5f4688b-8c32-46e5-a19b-e07e860eb3b4','十八日觀潮  其一','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','一年壯觀盡今朝，水伯何知故晚潮。',32,'全唐诗/poet.song.62000.json','["一年壯觀盡今朝，水伯何知故晚潮。", "海浪肯隨山俯仰，風帆長共客飄搖。"]'),
('8e7c01f9-fd9d-4796-b962-9015282d5552','十八日觀潮  其二','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','眼看白浪覆青山，誰信黄昏去復還。',32,'全唐诗/poet.song.62000.json','["眼看白浪覆青山，誰信黄昏去復還。", "縱使百年終有盡，何須豪橫詫吳蠻。"]'),
('ff854ddd-a339-4b76-85ee-5fbe56398140','十八日觀潮  其三','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','千槌擊鼓萬人呼，一抹濤頭百尺餘。',32,'全唐诗/poet.song.62000.json','["千槌擊鼓萬人呼，一抹濤頭百尺餘。", "明日潮來人不見，江邊只有候潮魚。"]'),
('e05d7f78-fdf6-48be-b066-4469303f258e','十八日觀潮  其四','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江平石出漲沙浮，船閣平洲水斷流。',32,'全唐诗/poet.song.62000.json','["江平石出漲沙浮，船閣平洲水斷流。", "朝暮去來何日了，一杯誰與弔陽侯。"]'),
('088be85f-d7d4-4566-b5b0-044e09f25037','湖上晚歸寄詩友  其一','陳師道','宋','宋诗','song-poetry','','[]','髭髮難藏老，湖山穩寄身。',48,'全唐诗/poet.song.62000.json','["髭髮難藏老，湖山穩寄身。", "却尋方外士，招作社中人。", "霜葉深於染，秋花晚自春。", "無人還有礙，詩卷莫辭頻。"]'),
('cdc14439-709d-4490-8926-21212934c372','湖上晚歸寄詩友  其二','陳師道','宋','宋诗','song-poetry','','[]','蓑笠宜多病，衣冠錯致身。',48,'全唐诗/poet.song.62000.json','["蓑笠宜多病，衣冠錯致身。", "清愁偏待客，白髮解禁人。", "江月深留雪，山梅探借春。", "興從湖上發，詩爲道人頻。"]'),
('4b42a236-7eca-4d97-b6fb-a1dfa52acd5b','湖上晚歸寄詩友  其三','陳師道','宋','宋诗','song-poetry','','[]','功名違壯志，戒律負前身。',48,'全唐诗/poet.song.62000.json','["功名違壯志，戒律負前身。", "劉德長欺客，王融却笑人。", "殘年增受歲，病眼怯逢春。", "杖屨知何向，知公未厭頻。"]'),
('da8382df-e90d-4880-8823-4caed33d48c8','湖上晚歸寄詩友  其四','陳師道','宋','宋诗','song-poetry','','[]','紅綠羞明眼，欹斜久病身。',48,'全唐诗/poet.song.62000.json','["紅綠羞明眼，欹斜久病身。", "年齡不待命，湖海却留人。", "點滴花間露，新鮮柳上春。", "情懷將底用，詩外不須頻。"]'),
('b13a349c-b1f1-448c-b2f4-df87037a642b','次韵寄答晁無咎','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖欲雨厨煙滿，風葉倒囊雲覆碗。',224,'全唐诗/poet.song.62000.json','["西湖欲雨厨煙滿，風葉倒囊雲覆碗。", "望湖樓上白頭人，獨倚欄干誰肯伴。", "獨有詩人記病身，清風千里寄行塵。", "豪華信有回天力，驚開桃李閑新春。", "往事不回如過雨，醉夢恍然忘惡語。", "人生如幻此何尤，未信黄金貴於土。", "愛子千篇頃刻成，借將胸腹詫吳人。", "吟哦怪有芳鮮氣，却被湖山識姓名。", "文章廢退知難强，身外虛華本無望。", "何曾臨水惜芒鞋，却解逢人拈拄杖。", "眼根清浄塵不留，登伽過盡不回頭。", "家在中原歸未得，江淮斷道無行舟。", "兩山相逢翻手疾，欲謀一笑寧無日。", "却慚懷朴似周人，祇可聞名不須識。"]'),
('bf9fead0-6d8e-4322-9a89-51ec243f956b','寄答顔長道  其一','陳師道','宋','宋诗','song-poetry','','[]','薄命猶多難，浮生未定居。',48,'全唐诗/poet.song.62000.json','["薄命猶多難，浮生未定居。", "故人憂已矣，千里問何如。", "白髮羞明鏡，青燈怯細書。", "不曾知史館，何用索枯魚。"]'),
('bc9f9e11-d8db-4613-87f2-8a35ae3a0b3c','寄答顔長道  其二','陳師道','宋','宋诗','song-poetry','','[]','貧病憂居士，雕蟲累壯夫。',48,'全唐诗/poet.song.62000.json','["貧病憂居士，雕蟲累壯夫。", "不能羞齒頰，幸免葬江湖。", "疲馬甘垂首，游鷹不應呼。", "爲誰歸未得，山水故鄉居。"]'),
('05c0661a-578b-4c92-82eb-54f5b1208fde','寄邢和叔','陳師道','宋','宋诗','song-poetry','','[]','昔作梁宋游，幽憂廢朝昏。',192,'全唐诗/poet.song.62000.json','["昔作梁宋游，幽憂廢朝昏。", "閉門無往還，不厭兒女喧。", "隔牆聞剝啄，暮夜誰扣門。", "知是邢夫子，低回過高軒。", "願爲布衣交，不顧年德尊。", "匆匆立談罷，又見東南奔。", "江湖多病後，僅免餉魚黿。", "久廢數行書，因人問寒暄。", "但愛孤山西，松筠數家村。", "便欲築居室，插秧仍灌園。", "生前不自愛，身後何足論。", "草玄笑揚雄，贊易悲虞翻。", "文章徒自苦，紙筆莫更存。", "却尋南郭老，隠几學忘言。", "他日宦游客，誤入桃花源。", "葦間見漁父，誰識王公孫。"]'),
('8c943990-c057-414b-83ce-db7ca33e031f','十七日觀潮三首  其一','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','潮頭初出海門山，千里平沙轉面間。',32,'全唐诗/poet.song.62000.json','["潮頭初出海門山，千里平沙轉面間。", "猶有江神憐北客，欲將奇觀破衰顔。"]'),
('230bef9c-e140-449e-a197-370df8c25229','十七日觀潮三首  其二','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江水悠悠自在流，向人無恨不應愁。',32,'全唐诗/poet.song.62000.json','["江水悠悠自在流，向人無恨不應愁。", "相逢不覺渾相似，誰使清波早白頭。"]'),
('984bfa71-ac20-432f-814b-083061109dbf','十七日觀潮三首  其三','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f", "\u5e26\u6709\u5730\u540d", "\u5199\u666f", "\u5730\u540d"]','漫漫平沙走白虹，瑶臺失手玉杯空。',32,'全唐诗/poet.song.62000.json','["漫漫平沙走白虹，瑶臺失手玉杯空。", "晴天搖動清江底，晚日浮沉急浪中。"]'),
('16431740-3776-44e4-bb9a-fd3831720bba','月下觀潮二首  其一','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','隔江燈火見西興，江水清平霧雨輕。',32,'全唐诗/poet.song.62000.json','["隔江燈火見西興，江水清平霧雨輕。", "風送潮來雲四散，水光月色鬭分明。"]'),
('63bebd61-242f-4376-8097-ba0ec7ea8ecf','月下觀潮二首  其二','陳師道','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','素練橫斜雪滿頭，銀潮吹浪玉山浮。',32,'全唐诗/poet.song.62000.json','["素練橫斜雪滿頭，銀潮吹浪玉山浮。", "猶疑海若誇河伯，豪悍須教水倒流。"]'),
('746d2767-4b8b-4db2-a73a-18ac9e892d80','宿錢塘尉廨','陳師道','宋','宋诗','song-poetry','','[]','平湖遶舍山無盜，官事長閑俸有金。',32,'全唐诗/poet.song.62000.json','["平湖遶舍山無盜，官事長閑俸有金。", "安得終身爲禦寇，不辭兒女作吳音。"]'),
('82289d1b-9cdb-4dc9-9db4-37f85a1e72bf','寄北山順法師二首  其一','陳師道','宋','宋诗','song-poetry','','[]','十年聞問不逢人，一面相逢過所聞。',32,'全唐诗/poet.song.62000.json','["十年聞問不逢人，一面相逢過所聞。", "高士不應輕俗士，欲將汙脚上垂雲。"]'),
('3742f4ae-6a8c-46b3-9e93-7d2b4898652b','寄北山順法師二首  其二','陳師道','宋','宋诗','song-poetry','','[]','山下游塵不汙人，耳邊溪水去猶聞。',32,'全唐诗/poet.song.62000.json','["山下游塵不汙人，耳邊溪水去猶聞。", "羨君身世渾無事，坐看青山過白雲。"]'),
('783c95e0-df0a-493c-b758-dd1c091b8b23','贈關彥長','陳師道','宋','宋诗','song-poetry','','[]','少年初識字，已誦子虛賦。',168,'全唐诗/poet.song.62000.json','["少年初識字，已誦子虛賦。", "嘗疑天上人，已離人間去。", "蹉跎二十年，久自歎遲暮。", "倦游梁宋間，却踏江湖路。", "此地始逢君，秋陽破朝霧。", "白首鬢毛新，青衫顔色故。", "問君胡爲然，竟坐文字誤。", "人事久難知，高才常不遇。", "論人較賢智，富貴寧在數。", "不見竹林詩，山王俱不與。", "湖塘發高興，山林有佳處。", "迨此閒暇時，觀游莫辭屢。", "功名如附贅，得失何用顧。", "但當勤秉燭，長願隨杖屨。"]'),
('6f77b5e8-c9ce-49f1-97a1-cb7b8e5518d4','送鄜州關司法','陳師道','宋','宋诗','song-poetry','','[]','早歲相知晚相識，抵掌回頭已陳迹。',64,'全唐诗/poet.song.62000.json','["早歲相知晚相識，抵掌回頭已陳迹。", "萬里從軍壯此行，一筯鱸魚留不得。", "夜靜關山秋月明，莫聽嶺頭流水聲。", "平世功名須少壯，看君一箭下遼城。"]'),
('bdfd79b2-650e-4b78-8e78-23c1a3bebfca','寄曾公權','陳師道','宋','宋诗','song-poetry','','[]','超世功名子有憑，過人才藝我何曾。',64,'全唐诗/poet.song.62000.json','["超世功名子有憑，過人才藝我何曾。", "詩書廢忘難支敵，門館光華怯再登。", "捐棄妻兒逃世累，掃除鬚髮伴禪僧。", "待君持節東南日，試問當年杜伯升。"]'),
('72eafd5d-78ea-4b62-a74e-0ba9e0eb9e38','登鳳凰山懷子瞻  其一','陳師道','宋','宋诗','song-poetry','','[]','蜿蜒曲龍腰，山間隠樓觀。',104,'全唐诗/poet.song.62000.json','["蜿蜒曲龍腰，山間隠樓觀。", "孤高伏龍角，浮圖刺雲漢。", "脩林霜雪餘，落葉青紅亂。", "想見洞中人，不知時節換。", "咳唾落江東，江東兩眼中。", "舉頭觸浮雲，失脚驚飛鴻。", "逢人自笑謀身拙，坐使紅塵生白髮。", "入山便欲棄人間，出山又與松筠別。"]'),
('10f36904-ec8e-4839-8584-0bad23b379aa','登鳳凰山懷子瞻  其二','陳師道','宋','宋诗','song-poetry','','[]','數篇曾見使君詩，前後登臨各一時。',64,'全唐诗/poet.song.62000.json','["數篇曾見使君詩，前後登臨各一時。", "妙舞新聲難得繼，清風明月却相宜。", "朱闌行遍花間路，看盡當年題壁處。", "更有何人問使君，青春欲盡花飛去。"]'),
('88c64c33-e9ce-45aa-9c77-abb1c04c06fa','平翠閣','陳師道','宋','宋诗','song-poetry','','[]','我家山水間，耳目厭華麗。',144,'全唐诗/poet.song.62000.json','["我家山水間，耳目厭華麗。", "聞道浙西山，經年通夢寐。", "從爲遠游客，忘却歸來計。", "欲買湖上田，謝絕人間世。", "湖山多變態，橫斜光景異。", "隨山轉朱閣，臨顧窮幽邃。", "惟有宣公樓，浮空堆亂翠。", "疑是水仙人，臨牆露高髻。", "道人迹愛山，朝昏閱終歲。", "最愛煙雨中，半掩青羅袂。", "我來悲歲晚，風霜掃昏翳。", "不見嶺頭雲，未盡登臨意。"]'),
('b2097fbe-483a-41c3-982f-8581d6572c6b','贈太素菴軻律師  其一','陳師道','宋','宋诗','song-poetry','','[]','林間細路暗通門，火閤深藏雪裏春。',32,'全唐诗/poet.song.62000.json','["林間細路暗通門，火閤深藏雪裏春。", "自笑世間千計錯，羨他湖上十年人。"]'),
('4de978aa-5dfa-408a-a2ec-c3a45815c0fa','贈太素菴軻律師  其二','陳師道','宋','宋诗','song-poetry','','[]','枕帳清寒夜色空，琉璃明浄晚燈紅。',32,'全唐诗/poet.song.62000.json','["枕帳清寒夜色空，琉璃明浄晚燈紅。", "定知城市無窮事，盡在山人冷眼中。"]'),
('413a5019-d10d-4df6-8193-04b4944baa38','古怨贈關彥長','陳師道','宋','宋诗','song-poetry','','[]','世態輕浮君莫道，相逢何必論才調。',64,'全唐诗/poet.song.62000.json','["世態輕浮君莫道，相逢何必論才調。", "鉛刀快利莫耶遲，果下翩翩望雲老。", "人前安得無窮好，應須富貴長年少。", "莫教白髮更棲遲，不遭毀駡逢人笑。"]'),
('895afbb7-4f18-4c02-a550-eb072b180005','次韵關子容湖上晚飲','陳師道','宋','宋诗','song-poetry','','[]','風樹吹花落四鄰，暮雲將雨作催人。',64,'全唐诗/poet.song.62000.json','["風樹吹花落四鄰，暮雲將雨作催人。", "旋傾美酒留連客，急作新詩報答春。", "試傍清湖看鬢髮，莫辭行樂費金銀。", "如今歸去還高卧，更問風光有幾旬。"]'),
('b21ccaef-6629-43ac-9a82-704c07bbeac9','春晚游寶雲寺','陳師道','宋','宋诗','song-poetry','','[]','繁杏青猶小，幽花落更香。',48,'全唐诗/poet.song.62000.json','["繁杏青猶小，幽花落更香。", "目隨雲雨斷，恨與水風長。", "蟻子何緣鬭，蜂兒有底忙。", "山人能棄世，遊子不思鄉。"]'),
('7f709bff-dcac-4e4f-afa1-db562a5a6484','夏日書事','陳師道','宋','宋诗','song-poetry','','[]','花絮隨風盡，歡娛過眼空。',48,'全唐诗/poet.song.62000.json','["花絮隨風盡，歡娛過眼空。", "窮多詩有債，愁極酒無功。", "家在斜陽下，人歸滿月中。", "肝腸渾欲破，魂夢更無窮。"]'),
('0965423d-c127-4c2a-b455-53f65b965931','贈寫真禧道人','陳師道','宋','宋诗','song-poetry','','[]','久病多愁易老身，塵容衰鬢不長新。',32,'全唐诗/poet.song.62000.json','["久病多愁易老身，塵容衰鬢不長新。", "早須置我山巖裏，不是麒麟閤上人。"]'),
('f9040b9a-bbcb-4148-9b1b-6d2dff6a72e5','晚遊九曲院','陳師道','宋','宋诗','song-poetry','','[]','冷落叢祠晚，回斜狹路賒。',48,'全唐诗/poet.song.62000.json','["冷落叢祠晚，回斜狹路賒。", "平荷留夜雨，驚鳥過鄰家。", "雲暗重重樹，風開旋旋花。", "病身無俗事，待得後歸鴉。"]'),
('6668dff7-e566-4a36-a976-2bb65f8d8fac','萱草','陳師道','宋','宋诗','song-poetry','','[]','喚作忘憂草，相看萬事休。',24,'全唐诗/poet.song.62000.json','["喚作忘憂草，相看萬事休。", "若教花有語，却解使人愁。"]'),
('3e41505c-c7a4-4845-98bf-21a2e15a2cfb','次韵順法師十三間樓避暑','陳師道','宋','宋诗','song-poetry','','[]','窗暗時時雨，門開處處山。',48,'全唐诗/poet.song.62000.json','["窗暗時時雨，門開處處山。", "心蘇解衣後，愁破立談間。", "枕簟長相待，功名久不關。", "論文非小陸，愧色滿顔間。"]'),
('12e2ff0d-b552-4bf5-ab3e-2d576d897a41','次韵性都正北山逐凉','陳師道','宋','宋诗','song-poetry','','[]','海風吹雨過梅黄，叢竹留陰借晚凉。',32,'全唐诗/poet.song.62000.json','["海風吹雨過梅黄，叢竹留陰借晚凉。", "更欲從君談妙理，鳧鷖能短鶴能長。"]'),
('235a77c4-cc10-4a59-8717-64c51dd7a5ed','賀關彥長生日  其一','陳師道','宋','宋诗','song-poetry','','[]','吉夢熊羆後，名家韋杜旁。',48,'全唐诗/poet.song.62000.json','["吉夢熊羆後，名家韋杜旁。", "風霜隨氣節，河漢借文章。", "漢相功名晚，周南德化長。", "欲伸千歲祝，願奉故人觴。"]'),
('432bdc89-7900-4584-bd5b-fbadc7cf7057','賀關彥長生日  其二','陳師道','宋','宋诗','song-poetry','','[]','經術宜傳世，清明正得秋。',48,'全唐诗/poet.song.62000.json','["經術宜傳世，清明正得秋。", "德優高士傳，名重賦家流。", "短袖妨妍舞，青衫負白頭。", "待看靈壽杖，扶出富民侯。"]'),
('d435da00-829d-4c94-93f9-2aa2159885e7','石氏畫苑','陳師道','宋','宋诗','song-poetry','','[]','卒行無好步，事忙不草書。',344,'全唐诗/poet.song.62000.json','["卒行無好步，事忙不草書。", "能事不促迫，快手多麤疏。", "君看荷葦槲葉扇，崔家仲叔三人俱。", "掃除事物費歲月，收定神氣忘形軀。", "恍然有得奪天巧，衰顔生態能相如。", "市師信手無贏餘，一日畫出東封圖。", "眼前百口怪神速，背後千指爭邪𣤔。", "君家畫苑傾東都，錦囊玉軸行盈車。", "補完破碎收亡逋，欲得不計有與無。", "問君此病何當祛，君言無事聊自娛。", "世間何事非迷途，挾策未必賢樗蒲。", "苑中最愛文與蘇，情親不獨生同閭。", "自謂知子誰如余，叔也不癡回不愚。", "憐君用意常勤劬，揮毫灑墨填空虛。", "風梢雨葉出新意，老樹僵立何年枯。", "我生百事不留意，外物不足煩敺除。", "翰墨纔能記名字，模臨寫貌無工夫。", "見溺不救危不扶，獨無一物充庖厨。", "看君髮漆顔丹朱，意氣健如生馬駒。", "逢人不信六十餘，郁然一莖無白鬚。", "呂翁落寞起釣屠，南山四老東宮須。", "人生晚達有如此，應笑虞翻早著書。"]'),
('045e8afa-8692-4e1d-81eb-2e45a70e6f19','錢塘寓居','陳師道','宋','宋诗','song-poetry','','[]','山水如相識，豪華異昔聞。',48,'全唐诗/poet.song.62000.json','["山水如相識，豪華異昔聞。", "聲言隨地改，吳越到江分。", "門閉蕭蕭雨，風催緩緩雲。", "會隨麋鹿去，長謝犬羊羣。"]'),
('925af9cc-6778-4d84-baaf-0fe2168ed999','梅花七絕  其一','陳師道','宋','宋诗','song-poetry','','[]','幽恨清愁幾萬端，故將巧笑破霜寒。',32,'全唐诗/poet.song.62000.json','["幽恨清愁幾萬端，故將巧笑破霜寒。", "落英收拾供騷客，秋菊從來不足餐。"]'),
('fcd88556-d5db-440c-bf78-70b2cd572b8c','梅花七絕  其二','陳師道','宋','宋诗','song-poetry','','[]','姑射仙姿不畏寒，謝家風格鄙鉛丹。',32,'全唐诗/poet.song.62000.json','["姑射仙姿不畏寒，謝家風格鄙鉛丹。", "誰知檀萼香鬚裏，已有調羹一點酸。"]'),
('d6c4249c-1c56-4882-af30-0082d1e2727a','梅花七絕  其三','陳師道','宋','宋诗','song-poetry','','[]','林外啼禽自往還，風前詩客倚欄干。',32,'全唐诗/poet.song.62000.json','["林外啼禽自往還，風前詩客倚欄干。", "小園門鎖黄昏月，耿耿幽姿半夜寒。"]'),
('13e5c919-2eb8-4ffa-8564-b38130571889','梅花七絕  其四','陳師道','宋','宋诗','song-poetry','','[]','清寒池館靜無塵，歲歲相逢似故人。',32,'全唐诗/poet.song.62000.json','["清寒池館靜無塵，歲歲相逢似故人。", "任遣牆頭疑似雪，欲教園主早知春。"]'),
('e479ceb0-caaa-456b-a990-eeac4c1f7cd7','梅花七絕  其五','陳師道','宋','宋诗','song-poetry','','[]','任教雪壓色終勝，却要風嚴香更聞。',32,'全唐诗/poet.song.62000.json','["任教雪壓色終勝，却要風嚴香更聞。", "江雨細時青子熟，聞名猶救渴將軍。"]'),
('728cb2b6-611e-4f67-8e1d-a0f7f786e94f','梅花七絕  其六','陳師道','宋','宋诗','song-poetry','','[]','數點深藏碧玉枝，翠峰十二擁瑶姬。',32,'全唐诗/poet.song.62000.json','["數點深藏碧玉枝，翠峰十二擁瑶姬。", "憑君說與凡桃李，徹骨清寒不解肥。"]'),
('e4c84fa9-1bd3-451b-aa15-6ea03ece6b01','梅花七絕  其七','陳師道','宋','宋诗','song-poetry','','[]','月落霜嚴自靚粧，北風工爲發清香。',32,'全唐诗/poet.song.62000.json','["月落霜嚴自靚粧，北風工爲發清香。", "晚英數點辭林去，幽獨無人爲斷腸。"]'),
('d58f781c-3a35-4df2-9b0b-cdf825742ed3','還江上','陳師道','宋','宋诗','song-poetry','','[]','夜夜滄洲夢，歸心劇旆懸。',48,'全唐诗/poet.song.62000.json','["夜夜滄洲夢，歸心劇旆懸。", "呼童買輕舸，拂榻下平川。", "遡浪潮如鬭，凌風岸若牽。", "江鄉厭回首，行及練花天。"]'),
('fbfd5ad5-88e4-4965-82d9-85ae5bdeb419','雜題  其一','陳師道','宋','宋诗','song-poetry','','[]','亂水交如線，群山翠作屏。',48,'全唐诗/poet.song.62000.json','["亂水交如線，群山翠作屏。", "寒輕春稍稍，雪盡麥青青。", "霜草猶疑滑，風林漸喜聽。", "生涯鞍馬上，歲月短長亭。"]'),
('a38afb93-90d4-4899-93e9-74afc3672003','雜題  其二','陳師道','宋','宋诗','song-poetry','','[]','泥雪纔通脚，煙雲復結陰。',48,'全唐诗/poet.song.62000.json','["泥雪纔通脚，煙雲復結陰。", "遲留隨處處，簾幕靜沉沉。", "去雁懷歸意，來禽欲好音。", "稍寬溝壑辱，不憚二毛侵。"]'),
('01bc84b5-0e76-49aa-93f4-5c4b9d19965f','奉酬應物','陳師道','宋','宋诗','song-poetry','','[]','論世闕真是，憎好成愚賢。',144,'全唐诗/poet.song.62000.json','["論世闕真是，憎好成愚賢。", "衆手挽跛牂，擬度驊騮前。", "與子早相好，於今不知年。", "似從欲著帽，憂喜同華顛。", "生世如風花，高下亦偶然。", "填溝偶不死，揮刃忽自全。", "病馬試春草，游魚縱奔川。", "稍思升斗祿，筦庫未闕員。", "一饑尚可忍，百歲當復延。", "相予乘下澤，得句要子宣。", "此生期樂死，它日須詩傳。", "縮手著袖間，彈棋一爭先。"]'),
('7c1c9c09-569b-482c-a98e-78edc56c2ef1','酬應物見戲','陳師道','宋','宋诗','song-poetry','','[]','扣門賞竹任推排，興盡歸舟挽不回。',64,'全唐诗/poet.song.62000.json','["扣門賞竹任推排，興盡歸舟挽不回。", "平世山林成偃蹇，新年詞句得參陪。", "醒心正頼揮毫疾，誤筆仍須送喜來。", "書省不應煩乳媼，一時除目盡英才。"]'),
('18654b3f-a2fd-426b-b39f-a64096808451','次韵應物有歎黄樓','陳師道','宋','宋诗','song-poetry','','[]','一代蘇長公，四海名未已。',144,'全唐诗/poet.song.62000.json','["一代蘇長公，四海名未已。", "投荒忘歲月，積毀高城壘。", "斯樓亦何與，與人壓復起。", "紛紛徒爾爲，長劍須天倚。", "循分即可久，吾行誰與止。", "邇來賢達人，五十笑百里。", "頼有寇公子，衆毀聞獨美。", "直氣懾狂童，牽聯皆可紀。", "少公作長句，班揚安得擬。", "頗有喜事人，睥睨欲搥毀。", "一朝陵谷變，天語含深旨。", "驚倒樓前人，今朝有行履。"]'),
('752fcc32-e55b-4517-ae65-1e3ed2b713f0','寄送定州蘇尚書','陳師道','宋','宋诗','song-poetry','','[]','初聞簡策侍前旒，又見衣冠送作州。',64,'全唐诗/poet.song.62000.json','["初聞簡策侍前旒，又見衣冠送作州。", "北府時清惟可飲，西山氣爽更宜秋。", "功名不朽聊通袖，海道無違具一舟。", "枉讀平生三萬卷，貂蟬當復自兜牟。"]'),
('3b3be3de-0dfe-424f-9ccc-dca87b8a89f5','寄答李方叔','陳師道','宋','宋诗','song-poetry','','[]','平生經世策，寄食不資身。',48,'全唐诗/poet.song.62000.json','["平生經世策，寄食不資身。", "孰使文章著，能辭轍跡頻。", "帝城分不入，書札詗何人。", "子未知吾懶，吾寧覺子貧。"]'),
('0bf87e94-4ec2-4558-9af9-539797d77dd0','智寶院後樓懷胡元茂','陳師道','宋','宋诗','song-poetry','','[]','晚渡呼舟疾，寒城著霧深。',48,'全唐诗/poet.song.62000.json','["晚渡呼舟疾，寒城著霧深。", "昏鷗明鳥道，風葉亂霜林。", "久客登臨目，中年懷舊心。", "猶須一長笛，領覽自霑襟。"]'),
('92c77292-d4e4-4bdc-8094-c64cfbb4870e','元日','陳師道','宋','宋诗','song-poetry','','[]','老境難爲節，寒梢未得春。',48,'全唐诗/poet.song.62000.json','["老境難爲節，寒梢未得春。", "一官兼利害，百慮孰疏親。", "積雪無歸路，扶行有醉人。", "望鄉仍受歲，回首向松筠。"]'),
('0a0a2707-efab-4468-b531-3a2bab779e9d','放懷','陳師道','宋','宋诗','song-poetry','','[]','施食烏鳶喜，持經鳥鼠聽。',48,'全唐诗/poet.song.62000.json','["施食烏鳶喜，持經鳥鼠聽。", "杖藜矜矍鑠，顧影怪伶俜。", "門靜行隨月，窗虛卧見星。", "擁衾眠未穩，艱阻飽曾經。"]'),
('cb6cbf3a-7149-45c8-aa62-2e04da4edc06','絕句','陳師道','宋','宋诗','song-poetry','','[]','此生精力盡於詩，末歲心存力已疲。',32,'全唐诗/poet.song.62000.json','["此生精力盡於詩，末歲心存力已疲。", "不共盧王爭出手，却思陶謝與同時。"]'),
('e518b6c0-6e42-4c17-b24e-19bf02ac20e8','送伯兄赴吏部改官','陳師道','宋','宋诗','song-poetry','','[]','先子初增秩，年侵鬢已皤。',48,'全唐诗/poet.song.62000.json','["先子初增秩，年侵鬢已皤。", "念兄今善繼，此別喜如何。", "親老家仍困，門衰仕未多。", "猶須教兒子，早要中文科。"]'),
('c325c38e-36d2-4565-96c5-c29fe6671dea','寄張文潛舍人','陳師道','宋','宋诗','song-poetry','','[]','今代張平子，雄深次子長。',48,'全唐诗/poet.song.62000.json','["今代張平子，雄深次子長。", "名高三俊上，官立右螭旁。", "車笠吾何恨，飛騰子莫量。", "時平身早達，未用夢凝香。"]'),
('70abcb39-8c24-4237-8e74-bf604702ea9b','後湖晚坐','陳師道','宋','宋诗','song-poetry','','[]','水浄偏明眼，城荒可當山。',48,'全唐诗/poet.song.62000.json','["水浄偏明眼，城荒可當山。", "青林無限意，白鳥有餘閑。", "身致江湖上，名成伯季間。", "目隨歸雁盡，坐待暮鴉還。"]'),
('0f5e44d3-7f34-446a-856b-c0e31250888c','春興','陳師道','宋','宋诗','song-poetry','','[]','東風作惡不成寒，野水穿沙自作灘。',32,'全唐诗/poet.song.62000.json','["東風作惡不成寒，野水穿沙自作灘。", "細草無端留客卧，繁枝有意待人看。"]'),
('8658cf25-2611-4815-873f-2b1790e756e2','次韵回山人贈沈東老二首  其一','陳師道','宋','宋诗','song-poetry','','[]','一杯領意不須沽，六字持身已有餘。',32,'全唐诗/poet.song.62000.json','["一杯領意不須沽，六字持身已有餘。", "癡子未知天上樂，先生今解世間書。"]'),
('694cbc92-afa1-44c0-bdf2-3941372790cf','次韵回山人贈沈東老二首  其二','陳師道','宋','宋诗','song-poetry','','[]','隨世功名非所望，稱家豐儉不求餘。',32,'全唐诗/poet.song.62000.json','["隨世功名非所望，稱家豐儉不求餘。", "青衫出指論奇字，白髮挑燈寫細書。"]'),
('183a65db-a6ac-4552-b26e-9aa9d9cb0439','送孝忠二首  其一','陳師道','宋','宋诗','song-poetry','','[]','老眼元多淚，春風見此行。',48,'全唐诗/poet.song.62000.json','["老眼元多淚，春風見此行。", "又爲貧賤別，更覺急難情。", "斗食吾堪老，詞場爾向榮。", "未須憐野鶩，家法付宣城。"]'),
('8c11f3c6-b101-48aa-9d1c-3a6567cce163','送孝忠二首  其二','陳師道','宋','宋诗','song-poetry','','[]','經史三年學，聰明一旦開。',48,'全唐诗/poet.song.62000.json','["經史三年學，聰明一旦開。", "把文甘潦倒，數日待歸來。", "士患聲名早，官今歲月催。", "有親須薄祿，臨路尚徘徊。"]'),
('c708edf8-04a5-4af8-87ef-a7bd5d7df23e','以拄杖供仁山主二首  其一','陳師道','宋','宋诗','song-poetry','','[]','錯節孤根勁有餘，坐牀須按起須扶。',32,'全唐诗/poet.song.62000.json','["錯節孤根勁有餘，坐牀須按起須扶。", "一生用底今相贈，更問林間有此無。"]'),
('590ddd86-8f95-4f3e-a370-a7cc7a668b38','以拄杖供仁山主二首  其二','陳師道','宋','宋诗','song-poetry','','[]','洗足投筇只坐禪，厭尋歧路費行纏。',32,'全唐诗/poet.song.62000.json','["洗足投筇只坐禪，厭尋歧路費行纏。", "老來不復人間事，不用山公更削圓。"]'),
('3074d71e-12f2-48a9-a37c-e82c60d9b492','項城道中寄劉令使修溪橋','陳師道','宋','宋诗','song-poetry','','[]','老怯危橋泥沒膝，喜聞吾黨政如春。',32,'全唐诗/poet.song.62000.json','["老怯危橋泥沒膝，喜聞吾黨政如春。", "須君不惜千金費，此後寧無我輩人。"]'),
('6781856a-2e4c-482f-86c8-61d2ba2c8614','碓磨寨','陳師道','宋','宋诗','song-poetry','','[]','以人爲食殺爲戲，自昔無聞爾所先。',32,'全唐诗/poet.song.62000.json','["以人爲食殺爲戲，自昔無聞爾所先。", "信有亡身一言盡，獨能遺臭萬人傳。"]'),
('6df30872-3652-4682-99d6-1118bbaa013a','寄張宣州','陳師道','宋','宋诗','song-poetry','','[]','與世情將盡，懷仁老未忘。',48,'全唐诗/poet.song.62000.json','["與世情將盡，懷仁老未忘。", "故人今五馬，高處謾三長。", "詩豈江山助，名成沈鮑行。", "肯爲文俗事，打鴨起鴛鴦。"]'),
('8e41290f-4a24-41ee-9891-42d8613f3065','送倫化主','陳師道','宋','宋诗','song-poetry','','[]','赤髭白足可憐生，躡蹻擔囊壯此行。',32,'全唐诗/poet.song.62000.json','["赤髭白足可憐生，躡蹻擔囊壯此行。", "要致雪峰千五百，不妨兼識謝宣城。"]'),
('b7d3fbcf-6764-4b0b-b935-f1fca1ab8088','西湖','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小徑才容足，寒花只自香。',48,'全唐诗/poet.song.62000.json','["小徑才容足，寒花只自香。", "官池下鳬雁，荒冢上牛羊。", "有子吾甘老，無家去未量。", "三年哦五字，草木借輝光。"]'),
('03ab214d-a01f-460f-9964-52d960abc4e4','別月華嚴','陳師道','宋','宋诗','song-poetry','','[]','寓世生同里，隨方去有情。',48,'全唐诗/poet.song.62000.json','["寓世生同里，隨方去有情。", "來爲百年別，不惜片時程。", "齋鉢須勤供，經鐘莫倦鳴。", "當來第三會，此界却逢迎。"]'),
('594631aa-4666-4a2d-9f42-0d4751a2f802','送吳先生謁惠州蘇副使','陳師道','宋','宋诗','song-poetry','','["\u9001\u522b", "\u6292\u6000"]','聞名欣識面，異好有同功。',48,'全唐诗/poet.song.62000.json','["聞名欣識面，異好有同功。", "我亦慚吾子，人誰恕此公。", "百年雙白鬢，萬里一秋風。", "爲說任安在，依然一禿翁。"]'),
('27dd55a1-9677-44e5-9846-f1349740b16c','別圓澄禪師','陳師道','宋','宋诗','song-poetry','','[]','法施老人卧不出，呼我取別行問疾。',128,'全唐诗/poet.song.62000.json','["法施老人卧不出，呼我取別行問疾。", "摩盤拭筯勸一飽，少待須臾莫蒼猝。", "早年著眼覷文字，萬卷初無一言契。", "多生綺語未經懺，半世虛名足爲累。", "此去它來尚有緣，頭童齒豁恐無年。", "慇懃三請久住世，弊惡可念未可捐。", "平生准擬西行計，老著人間此何意。", "他生佛會見頭陀，知是當年老居士。"]'),
('559ce2b9-ebb2-4eec-a5ef-25eef5932b0d','別觀音山主','陳師道','宋','宋诗','song-poetry','','[]','離合應生理，過逢豈近緣。',48,'全唐诗/poet.song.62000.json','["離合應生理，過逢豈近緣。", "情親見今日，語妙記當年。", "閉戶安禪主，衝風逆水船。", "不應清夜月，故作別時圓。"]'),
('6f194e46-8481-4766-955b-16646db3bec4','離潁','陳師道','宋','宋诗','song-poetry','','[]','河市千人聚，寒江百丈牽。',48,'全唐诗/poet.song.62000.json','["河市千人聚，寒江百丈牽。", "吾生能幾日，此地費三年。", "叢竹防供爨，池魚已割鮮。", "拙勤終不補，他日愧無傳。"]'),
('d1dec27c-e2d7-41af-b196-27fad9c4607f','湖上','陳師道','宋','宋诗','song-poetry','','[]','湖上難爲別，梅梢已著春。',48,'全唐诗/poet.song.62000.json','["湖上難爲別，梅梢已著春。", "林喧烏啄啄，風過水鱗鱗。", "緣有三年盡，情無一日親。", "白頭厭奔走，何地與爲鄰。"]'),
('88969803-cc8f-4224-9d03-db7d13236138','舟中二首  其一','陳師道','宋','宋诗','song-poetry','','[]','惡風橫江江卷浪，黄流湍猛風用壯。',64,'全唐诗/poet.song.62000.json','["惡風橫江江卷浪，黄流湍猛風用壯。", "疾如萬騎千里來，氣壓三江五湖上。", "岸上空荒火夜明，舟中起坐待殘更。", "少年行路今頭白，不盡還家去國情。"]'),
('b88e9a45-4eac-48fa-990d-07b175bd483e','舟中二首  其二','陳師道','宋','宋诗','song-poetry','','[]','野火燒原雉昏雊，黄塵漲天牛亂鬭。',64,'全唐诗/poet.song.62000.json','["野火燒原雉昏雊，黄塵漲天牛亂鬭。", "江間無日不風波，老去何時脫奔走。", "詩書滿腹不及口，遮日寧須釣竿手。", "愧爾茅簷炙背人，仰目青天搔白首。"]'),
('0b4f96ae-e7b0-4cfb-9074-b775884169ed','規禪停雲齋','陳師道','宋','宋诗','song-poetry','','[]','浄居衆天人，宮殿隨所適。',96,'全唐诗/poet.song.62000.json','["浄居衆天人，宮殿隨所適。", "少仕老不歸，重門閉榛棘。", "道人秀叢林，妙語出禪寂。", "是身如浮雲，隨處同建立。", "平生與二子，嗜好用一律。", "我此復助緣，語綺已多責。", "何年一把茅，據坐孤崒嵂。", "呵佛駡祖師，塗糊千五百。"]'),
('d8582159-8be0-435d-8e51-f3d9c469cf22','答晁以道','陳師道','宋','宋诗','song-poetry','','[]','轉走東南復帝城，故人相見眼偏明。',64,'全唐诗/poet.song.62000.json','["轉走東南復帝城，故人相見眼偏明。", "十年作吏仍糊口，兩地爲鄰闕寄聲。", "冷眼尚堪看細字，白頭寧復要時名。", "孰知范叔寒如此，未覺嚴公有故情。"]'),
('7bd1f46b-b7ef-4e37-9eba-64355ea31e00','病起','陳師道','宋','宋诗','song-poetry','','[]','今日秋風裏，何鄉一病翁。',48,'全唐诗/poet.song.62000.json','["今日秋風裏，何鄉一病翁。", "力微須杖起，心在與誰同。", "災疾資千悟，冤親併一空。", "百年先得老，三敗未爲窮。"]'),
('0299cac8-5a6a-4daa-ae43-76f100ae1829','九月九日魏衍見過','陳師道','宋','宋诗','song-poetry','','[]','節裏能相過，談間可解憂。',48,'全唐诗/poet.song.62000.json','["節裏能相過，談間可解憂。", "致疏君未肯，得此我何由。", "語到君房妙，詩同客子游。", "一經從白首，萬里有封侯。"]'),
('7b438f7b-e28f-4c90-8abb-33706b6c43d9','別黄徐州','陳師道','宋','宋诗','song-poetry','','[]','姓名曾落薦書中，刻畫無鹽自不工。',64,'全唐诗/poet.song.62000.json','["姓名曾落薦書中，刻畫無鹽自不工。", "一日虛聲滿天下，十年從事得途窮。", "白頭未覺功名晚，青眼常蒙今昔同。", "衰疾又爲今日別，數行老淚灑西風。"]'),
('e9f3ce3f-d421-4343-a8b1-aa045dafadab','次韵答晁無斁','陳師道','宋','宋诗','song-poetry','','[]','女生願有家，名妾以不聘。',168,'全唐诗/poet.song.62000.json','["女生願有家，名妾以不聘。", "田里亦慕君，又惡不由正。", "欲行不問塗，已破寧顧甑。", "耕蠶無一廛，庖井要三徑。", "還家憂患餘，挽鬚兒女競。", "十年寧有此，一寒可無命。", "平生晁夫子，得士公室慶。", "稍無車馬音，復作賓客請。", "論文到韓李，念舊說蘇鄭。", "長年斷消息，獨語誰和應。", "此生恩未報，他日目不瞑。", "歸卧無好懷，扣門有佳聽。", "詩來雪霜後，更覺天宇浄。", "少好老未工，持刃授子柄。"]'),
('8f77647a-ad4e-4980-a8d8-6f7f53708a44','次韵無斁偶作二首  其一','陳師道','宋','宋诗','song-poetry','','[]','肩聳三峰峻，眉厖八字橫。',48,'全唐诗/poet.song.62000.json','["肩聳三峰峻，眉厖八字橫。", "玄談人絕倒，家法句新清。", "八俊先張子，諸公少賈生。", "已傳烏鵲喜，欲聽鶺鴒聲。"]'),
('23dc1f83-b297-46aa-8d86-ccaeb109a1b7','次韵無斁偶作二首  其二','陳師道','宋','宋诗','song-poetry','','[]','此老三年別，何時萬里回。',48,'全唐诗/poet.song.62000.json','["此老三年別，何時萬里回。", "更無南去雁，猶見北枝梅。", "會有哀籠鳥，寧須溺死灰。", "聖朝無棄物，與子賦歸哉。"]'),
('ddef4ee6-7cd2-42d4-92c4-3370f0e882e8','古墨行','陳師道','宋','宋诗','song-poetry','','[]','秦郎百好俱第一，烏丸如漆姿如石。',224,'全唐诗/poet.song.62000.json','["秦郎百好俱第一，烏丸如漆姿如石。", "巧作松身與鏡面，借美於外非良質。", "潘翁拜跪摩老眼，一生再見三歎息。", "了知至鑒無遁形，王家舊物秦家得。", "君今所有亦其亞，伯仲小低猶子姪。", "黄金白璧孰不有，古錦句囊聊可敵。", "睿思殿裏春夜半，燈火闌殘歌舞散。", "自書細字答邊臣，萬里風塵入長算。", "初聞橋山送弓劍，寧知玉碗人間見。", "夜光炎炎衝斗牛，會有太史占星變。", "人生尤物不必有，時一過目驚老醜。", "念子何忍遽磨研，少待須臾圖不朽。", "明窗浄几風日暖，有愁萬斛才八斗。", "徑須脫帽管城公，小試玉堂揮翰手。"]'),
('a72ee72a-012a-402d-b64c-1edcfa7a9338','次韵晁無斁除日述懷','陳師道','宋','宋诗','song-poetry','','[]','世學違從衆，名家最近天。',48,'全唐诗/poet.song.62000.json','["世學違從衆，名家最近天。", "感時猶壯志，得句起衰年。", "袁酒無何飲，陶琴不具絃。", "平生揮翰手，幾見絕韋編。"]'),
('096d42b9-f561-4b73-abc1-109f613ef59e','次韵無斁雪後二首  其一','陳師道','宋','宋诗','song-poetry','','[]','閉閤春雲薄，開門夜雪深。',48,'全唐诗/poet.song.62000.json','["閉閤春雲薄，開門夜雪深。", "江梅猶故意，湖雁起歸心。", "草潤留餘澤，窗明度積陰。", "慇懃報春信，屋角有來禽。"]'),
('65330179-efdd-4051-8c0e-7740374019a5','次韵無斁雪後二首  其二','陳師道','宋','宋诗','song-poetry','','[]','取性無通介，隨時有異同。',48,'全唐诗/poet.song.62000.json','["取性無通介，隨時有異同。", "雪餘蓋地白，春淺著梢紅。", "寄食虛長算，論詩闕近功。", "相看不相棄，頼有古人風。"]'),
('08ca4035-80ab-432e-b918-3f1817e9f992','贈魏衍三首  其一','陳師道','宋','宋诗','song-poetry','','[]','妙年文墨秀儒林，老眼今晨得再明。',32,'全唐诗/poet.song.62000.json','["妙年文墨秀儒林，老眼今晨得再明。", "歷塊過都聊可待，未須回首一長鳴。"]'),
('df8d6e5d-4fdb-41ca-8e71-8cb15527350a','贈魏衍三首  其二','陳師道','宋','宋诗','song-poetry','','[]','崔蔡論文不足過，新詩平處到陰何。',32,'全唐诗/poet.song.62000.json','["崔蔡論文不足過，新詩平處到陰何。", "寧須萬戶權輕重，不待千篇一已多。"]'),
('bbf6a111-e589-480f-a05d-d56a635489f2','贈魏衍三首  其三','陳師道','宋','宋诗','song-poetry','','[]','敏捷爲文筆不休，何妨縮手小遲留。',32,'全唐诗/poet.song.62000.json','["敏捷爲文筆不休，何妨縮手小遲留。", "名駒已自思千里，老子終當讓一頭。"]'),
('97f0f318-86c1-4282-ae1e-2a21494dc13d','贈寇國寶三首  其一','陳師道','宋','宋诗','song-poetry','','[]','承家從昔如君少，得士於今孰我先。',32,'全唐诗/poet.song.62000.json','["承家從昔如君少，得士於今孰我先。", "口擬說詩心已解，世間快馬不須鞭。"]'),
('64fed910-4b7f-4d75-a4d2-69ba5f734918','贈寇國寶三首  其二','陳師道','宋','宋诗','song-poetry','','[]','往歲黄童今寇君，高文要學亦多聞。',32,'全唐诗/poet.song.62000.json','["往歲黄童今寇君，高文要學亦多聞。", "留年看舉天南翼，過目先空冀北羣。"]'),
('9ac0dca5-5f8b-445d-bacd-c8a8b2e986ec','贈寇國寶三首  其三','陳師道','宋','宋诗','song-poetry','','[]','虎子墮地氣食牛，雀兒浴處魚何求。',32,'全唐诗/poet.song.62000.json','["虎子墮地氣食牛，雀兒浴處魚何求。", "可奈我衰才亦盡，正須二子與同游。"]'),
('ee42a620-abc1-4aca-9b1f-611fc08f5f13','次韵春懷','陳師道','宋','宋诗','song-poetry','','[]','老形已具臂膝痛，春事無多櫻笋來。',64,'全唐诗/poet.song.62000.json','["老形已具臂膝痛，春事無多櫻笋來。", "敗絮不溫生蟣虱，大杯覆酒著塵埃。", "衰年此日仍爲客，舊國當時只廢臺。", "河嶺尚堪供極目，少年爲句未須哀。"]'),
('27a404e6-bdd3-427b-98d6-91e6a3be3be9','河上','陳師道','宋','宋诗','song-poetry','','[]','背水連漁屋，橫河架石梁。',48,'全唐诗/poet.song.62000.json','["背水連漁屋，橫河架石梁。", "窺巢烏鵲競，過雨艾蒿光。", "鳥語催春事，窗明報夕陽。", "還家慰兒女，歸路不應長。"]'),
('d389cf84-abcb-4b03-a8cc-5c0dc4beecee','題柱二首  其一','陳師道','宋','宋诗','song-poetry','','[]','桃李摧殘風雨春，天孫河鼓隔天津。',32,'全唐诗/poet.song.62000.json','["桃李摧殘風雨春，天孫河鼓隔天津。", "主恩不與妍華盡，何限人間失意人。"]'),
('30979f71-3c97-443b-a7f2-cd807147ee63','題柱二首  其二','陳師道','宋','宋诗','song-poetry','','[]','從昔嬋娟多命薄，如今歌舞更能詩。',32,'全唐诗/poet.song.62000.json','["從昔嬋娟多命薄，如今歌舞更能詩。", "孰知文雅河陽令，不削瓊奴柱下題。"]'),
('2a5ee586-8499-4500-9a77-2280bc882c31','蠅虎','陳師道','宋','宋诗','song-poetry','','[]','物微趣下世不數，隨力捕生得稱虎。',64,'全唐诗/poet.song.62000.json','["物微趣下世不數，隨力捕生得稱虎。", "匿形注目搖兩股，卒然一擊勢莫禦。", "十中失一八九取，吻間流血腹如鼓。", "却行奮臂吾甚武，明日淮南作端午。"]'),
('121f91be-3df6-4cc4-81a6-166474881e3e','陶朱公廟','陳師道','宋','宋诗','song-poetry','','[]','千篇奏牘漫多知，百戰收功未出奇。',32,'全唐诗/poet.song.62000.json','["千篇奏牘漫多知，百戰收功未出奇。", "名下難居身可辱，却將湖海換西施。"]'),
('3cc69c27-1b02-4ade-9f96-5d2ee488e6bd','次韵晁無斁夏雨','陳師道','宋','宋诗','song-poetry','','[]','咫尺隔山海，作書問如何。',180,'全唐诗/poet.song.62000.json','["咫尺隔山海，作書問如何。", "蟻垤既畜糧，蛙窟如鳴鼉。", "積暑復一雨，斧斫仍手摩。", "鈎窗欲懸麻，出門已橫河。", "人言月離畢，未必致滂沱。", "東皋繁草木，蘭艾不同科。", "驚魚畏密罟，獨鳥鳴南柯。", "稍無蟲飛喧，復覺蟬語多。", "因聲作好惡，與物殊未和。", "卧聞夜來雨，歸種故山禾。", "百年須下澤，萬里付長羅。", "先生斷百好，尚以詩作魔。", "縮子萬言手，聽渠七字哦。", "室邇人則遠，燕默勞者歌。", "思君得老瘦，觸熱生積痾。"]'),
('ea188c34-f37c-4926-8803-0ea9938f4dfd','寄無斁','陳師道','宋','宋诗','song-poetry','','[]','敬問晁夫子，官池幾許深。',48,'全唐诗/poet.song.62000.json','["敬問晁夫子，官池幾許深。", "已應飛鳥下，復作卧龍吟。", "待我中痾愈，同君把臂臨。", "泥塗無去馬，夏木有來禽。"]'),
('9f98ebae-d249-4ce3-989d-157bef224d8b','次韵別張芸叟','陳師道','宋','宋诗','song-poetry','','[]','中年爲別更堪頻，四海無家託一身。',32,'全唐诗/poet.song.62000.json','["中年爲別更堪頻，四海無家託一身。", "此別時須問生死，孰知詩力解窮人。"]'),
('ee25e35e-b2d2-4f5c-aaa4-35d12c20b239','宿深明閣二首  其一','陳師道','宋','宋诗','song-poetry','','[]','窈窕深明閣，晴寒是去年。',48,'全唐诗/poet.song.62000.json','["窈窕深明閣，晴寒是去年。", "老將災疾至，人與歲時遷。", "默坐元如在，孤燈共不眠。", "暮年身萬里，頼有故人憐。"]'),
('5e7a0e20-ef27-472c-b7f6-221800c502ad','宿深明閣二首  其二','陳師道','宋','宋诗','song-poetry','','[]','縹緲金華伯，人間第一人。',48,'全唐诗/poet.song.62000.json','["縹緲金華伯，人間第一人。", "劇談連晝夜，應俗費精神。", "時要平安報，反愁消息真。", "牆根霜下草，又作一番新。"]'),
('9679ab47-3bc7-4fdc-8610-72ef10444b1d','東山謁外大父墓','陳師道','宋','宋诗','song-poetry','','[]','土山宛轉屈蒼龍，下有槃槃蓋世翁。',64,'全唐诗/poet.song.62000.json','["土山宛轉屈蒼龍，下有槃槃蓋世翁。", "萬木刺天元自直，叢篁侵道更須東。", "百年富貴今誰見，一代功名託至公。", "少日拊頭期類我，暮年垂淚向西風。"]'),
('228e1ef6-e0a8-4798-a105-88911ace8e11','次韵晁無斁冬夜見寄','陳師道','宋','宋诗','song-poetry','','[]','寒窗冷硯欲生塵，短枕長衾却自親。',64,'全唐诗/poet.song.62000.json','["寒窗冷硯欲生塵，短枕長衾却自親。", "老子形骸從薄暮，先生意氣尚青春。", "覆杯不待回丹頰，危坐猶能作直身。", "城郭山林兩無得，暮年當復幾霑巾。"]'),
('66561c82-1fc9-404b-9e0f-ac784a108649','寒夜有懷晁無斁','陳師道','宋','宋诗','song-poetry','','[]','同好共城郭，十日不一顧。',144,'全唐诗/poet.song.62000.json','["同好共城郭，十日不一顧。", "人事雖好乖，吾生亦多忤。", "闔門對妻子，歲月不可度。", "閉目寧用遮，停杯仍下筯。", "獨無區中緣，永懷巖下趣。", "平生三徑資，安得一朝具。", "萬里初歷塊，前驅告曛暮。", "懷歸屬有思，棄世不待怒。", "老境厭逶遲，人情費將護。", "向來張長公，吾亦從茲去。", "燈花頻作喜，月色正可步。", "預恐何水曹，明朝有新句。"]'),
('898b7547-af86-42f4-9acf-dbba8fa14294','除夜','陳師道','宋','宋诗','song-poetry','','[]','七十已强半，所餘能幾何。',48,'全唐诗/poet.song.62000.json','["七十已强半，所餘能幾何。", "懸知暮景促，更覺後生多。", "遁世名爲累，留年睡作魔。", "西歸端著便，老子不婆娑。"]'),
('c3425ad9-51f9-4a77-bbba-e0c89dbea26d','寄鄧州杜侍郎','陳師道','宋','宋诗','song-poetry','','[]','南陽老幼如雲屯，連日城東候使君。',224,'全唐诗/poet.song.62000.json','["南陽老幼如雲屯，連日城東候使君。", "後者排前旁捷出，爭先見面作慇懃。", "六年重來已白髮，一日再見回青春。", "道傍過者怪相問，共言杜母真吾親。", "使君雖老心尚壯，文采風流諸謝上。", "名家從昔杜陵人，盛德于今丈人行。", "我昔卧病老彭城，畫船鳴鼓千里行。", "致書饋奠初未識，丁寧勞苦如平生。", "人言此事今未有，古人中求還得否。", "忘年屈勢不虛辱，公自爲德吾何取。", "菊潭之水甘且潔，潭上秋花照山白。", "請公酌此壽百年，奕奕長爲此邦伯。", "孰先一州後四方，重金疊蓋登廟堂。", "請從今日至雲來，月三十斛輸洛陽。"]'),
('0f6dbad4-33d1-4246-af03-7d4bac3c26f4','寄提刑李學士','陳師道','宋','宋诗','song-poetry','','[]','石渠金馬青雲上，東里西門濟水邊。',64,'全唐诗/poet.song.62000.json','["石渠金馬青雲上，東里西門濟水邊。", "上冢過家真樂事，平時持節貴當年。", "成家舊學諸儒問，脫手新詩衆口傳。", "范叔一寒今若此，相逢猶得故人憐。"]'),
('9a9a684b-27bd-4e44-9986-e2d3b12cec94','寄杜擇之','陳師道','宋','宋诗','song-poetry','','[]','詩家兩杜昔無鄰，文采傳家世有人。',64,'全唐诗/poet.song.62000.json','["詩家兩杜昔無鄰，文采傳家世有人。", "疾置送詩驚老醜，坐曹得句自清新。", "興來不假江山助，目過渾如草木春。", "農馬智專吾不讓，衡陽紙貴子能頻。"]'),
('f63707b6-433e-4d2b-b5a1-024785a5f7e5','次韵晁無斁春懷','陳師道','宋','宋诗','song-poetry','','[]','城郭朝陽散積陰，郊原注目日青深。',64,'全唐诗/poet.song.62000.json','["城郭朝陽散積陰，郊原注目日青深。", "年衰鷗鷺如今是，夢斷邯鄲何處尋。", "語鵲飛烏春稍稍，重簾深院晚沉沉。", "不辭杖屨衝泥雪，未有瓊琚報好音。"]'),
('d42b9222-5005-44d4-b2d5-4268ee5f6cea','寄晁無斁','陳師道','宋','宋诗','song-poetry','','[]','稍聽春鳥語丁寧，又見官池出斷冰。',64,'全唐诗/poet.song.62000.json','["稍聽春鳥語丁寧，又見官池出斷冰。", "雪後踏青誰與共，花邊著語老猶能。", "笑談莫倦尋常聽，山院終同一再登。", "今日已知他日恨，搶榆况得及飛騰。"]'),
('d5572abb-e5af-4938-8640-06f575b60d83','別寶講主','陳師道','宋','宋诗','song-poetry','','[]','此地相逢晚，他方有勝緣。',48,'全唐诗/poet.song.62000.json','["此地相逢晚，他方有勝緣。", "呪功先服猛，戒力得扶顛。", "暫息三支論，重參二老禪。", "夜牀鞋脚別，何日著行纏。"]'),
('a0484c4d-e604-4796-819b-0d688ae2a8d3','還里','陳師道','宋','宋诗','song-poetry','','[]','曠士愛吾廬，游子悲故鄉。',144,'全唐诗/poet.song.62000.json','["曠士愛吾廬，游子悲故鄉。", "慷慨四方志，老衰但悲傷。", "虛名自成誤，失得略相當。", "暮年還家樂，未覺道路長。", "閭里喜我來，車馬塞康莊。", "爭前借言色，草木亦晶光。", "向來千人聚，一老獨倘佯。", "手開南陽阡，松柏鬰蒼蒼。", "永願守一丘，脫身萬里航。", "平生功名念，倒海浣我腸。", "款段引下澤，斷絃更空觴。", "尚恐北山南，有文移路傍。"]'),
('91ce0eb4-e564-4a68-b8ca-9a3e49032ddc','老柏三首  其一','陳師道','宋','宋诗','song-poetry','','[]','庭柏無生意，摧殘二十秋。',48,'全唐诗/poet.song.62000.json','["庭柏無生意，摧殘二十秋。", "稍霑杯水潤，已與歲寒謀。", "黄裏青青出，愁邊稍稍瘳。", "會看笙鶴下，暮雀莫深投。"]'),
('aef4c747-b7ba-4c67-93bb-c6a8fd088495','老柏三首  其二','陳師道','宋','宋诗','song-poetry','','[]','英姿带枯槁，勁節闕和柔。',48,'全唐诗/poet.song.62000.json','["英姿带枯槁，勁節闕和柔。", "物理有興壞，人情成去留。", "稍看棲鳥集，聊待晚風秋。", "解道庭前柏，何曾識趙州。"]'),
('0936bbcd-f024-4ba4-8d28-1fb45a8da8ae','老柏三首  其三','陳師道','宋','宋诗','song-poetry','','[]','歲月那能記，風霜亦飽經。',48,'全唐诗/poet.song.62000.json','["歲月那能記，風霜亦飽經。", "槁乾仍故節，潤澤出新青。", "色與江波共，聲留靜夜聽。", "輝輝垂重露，點點綴流螢。"]'),
('c6b53a6e-4ebd-4c79-b814-3a0671c14a04','魏衍見過','陳師道','宋','宋诗','song-poetry','','[]','暑雨不作凉，爽風祇自高。',96,'全唐诗/poet.song.62000.json','["暑雨不作凉，爽風祇自高。", "我老亦衰疾，奈此正鬰陶。", "魏侯有新語，高處近風騷。", "隠几聆五字，未覺歷日勞。", "洒然墮冰井，起粟豎寒毛。", "三山已在目，萬象誰能逃。", "歷險見絕足，過口味豚膏。", "願爲夏雷鳴，莫作饑鳶號。"]'),
('7df13a3a-08d2-46d6-a412-c4e99e04bede','次韵螢火','陳師道','宋','宋诗','song-poetry','','[]','年侵觀物化，共被歲時催。',48,'全唐诗/poet.song.62000.json','["年侵觀物化，共被歲時催。", "熠熠孤光動，翩翩度水來。", "稍能穿幔入，已復受風回。", "投卷吾衰矣，微吟子壯哉。"]'),
('aa04ed35-eac5-49f5-b4e5-3f464ce207ff','次韵夏日江村','陳師道','宋','宋诗','song-poetry','','[]','漏屋簷生菌，臨江樹作門。',48,'全唐诗/poet.song.62000.json','["漏屋簷生菌，臨江樹作門。", "卷簾通燕子，織竹護雞孫。", "向夕微凉進，相逢故意存。", "何當加我歲，從子問乾坤。"]'),
('f75a3112-7ce7-4abd-a929-214d513fb04f','次韵觀月','陳師道','宋','宋诗','song-poetry','','[]','風雲隨落日，河漢欲回天。',48,'全唐诗/poet.song.62000.json','["風雲隨落日，河漢欲回天。", "隔巷如千里，還家已再圓。", "簾疏分細細，江浄共娟娟。", "他日吾何適，聽詩說去年。"]'),
('2094d5d4-8764-4236-a267-afa0175c311a','次韵夏日','陳師道','宋','宋诗','song-poetry','','[]','江上雙峰一草堂，門閑心靜自清凉。',64,'全唐诗/poet.song.62000.json','["江上雙峰一草堂，門閑心靜自清凉。", "詩書發冢功名薄，麋鹿同羣歲月長。", "句裏江山隨指顧，舌端幽眇致張皇。", "莫欺九尺鬚眉白，解醉佳人錦瑟傍。"]'),
('131e46e2-b116-4472-bebf-f059bb156a4e','夏夜有懷','陳師道','宋','宋诗','song-poetry','','[]','卧念張居士，逃名老石根。',48,'全唐诗/poet.song.62000.json','["卧念張居士，逃名老石根。", "學詩真得瘦，識字即空樽。", "鳴笛夜宜遠，燈花曉更繁。", "未須哀老子，也復守丘園。"]'),
('62e2fa17-41a7-40bc-ac1a-c322dad531a8','送林朝奉','陳師道','宋','宋诗','song-poetry','','[]','兩父論詩伯仲間，去思今識謝家安。',64,'全唐诗/poet.song.62000.json','["兩父論詩伯仲間，去思今識謝家安。", "曠懷亦苦中年別，歸翼仍愁行路難。", "四壁未堪風雨夕，百圍已試雪霜寒。", "欲逃富貴疑無地，千丈竿頭試手看。"]'),
('45e11d74-355f-49d7-a358-362dad51b788','楊夫人挽詞','陳師道','宋','宋诗','song-poetry','','[]','初說南奔道路長，湖邊丹旐已飛揚。',64,'全唐诗/poet.song.62000.json','["初說南奔道路長，湖邊丹旐已飛揚。", "百年積慶鍾連璧，十念收功到浄方。", "絳幔未經親宋母，綠衣猶記識黄裳。", "欲圖不朽須詮載，今代誰堪著石章。"]'),
('40978bf4-9780-4ff7-972b-82439f71739d','桓山','陳師道','宋','宋诗','song-poetry','','[]','平江如抱貫秦洪，雙嶺馳來欲並雄。',64,'全唐诗/poet.song.62000.json','["平江如抱貫秦洪，雙嶺馳來欲並雄。", "是物皆爲萬世計，闔棺猶有一朝窮。", "林巒特起終爲汙，美惡千年竟不空。", "尚有風流羊叔子，稍經湔洗與清風。"]'),
('56e212d1-fd75-4d00-bc10-3c64c065e071','答顔生','陳師道','宋','宋诗','song-poetry','','[]','煩君臨問我何堪，剩欲從君十日談。',64,'全唐诗/poet.song.62000.json','["煩君臨問我何堪，剩欲從君十日談。", "老退不應稱敏捷，顔蒼寧復借紅酣。", "世間公器毋多取，句裏宗風却飽參。", "陋巷遠孫還好學，未容光祿擅東南。"]'),
('df07de85-47c7-44a3-9c41-105dbae4e27e','送劉主簿','陳師道','宋','宋诗','song-poetry','','[]','平生師友豫章公，矻矻談君口不空。',64,'全唐诗/poet.song.62000.json','["平生師友豫章公，矻矻談君口不空。", "半面相看吾已了，連城增價子何窮。", "三千奏牘諸儒上，四百菴寮一歲中。", "二父風流皆可繼，謗禪排道不須同。"]'),
('6da74853-a999-4d2a-8d40-33520393507f','觸目','陳師道','宋','宋诗','song-poetry','','[]','溪響饑魚食，川明柱影斜。',48,'全唐诗/poet.song.62000.json','["溪響饑魚食，川明柱影斜。", "驚禽穿密竹，噪鵲立浮查。", "谷暗山藏雨，林喧雀啅蛇。", "鄉閭等行路，何向更爲家。"]'),
('51efb027-2788-4bac-ae68-2dc834d9019b','晚望','陳師道','宋','宋诗','song-poetry','','[]','黑雲映黄槐，更著白鳥度。',48,'全唐诗/poet.song.62000.json','["黑雲映黄槐，更著白鳥度。", "蟬鳴不餘力，蛙腹能許怒。", "稱目有佳思，側逕無好步。", "興來成獨往，意得誰與賦。"]'),
('be51d02d-dcae-4041-b236-3886d23bd894','送高推官','陳師道','宋','宋诗','song-poetry','','[]','先生鍾舊德，大府冠羣能。',48,'全唐诗/poet.song.62000.json','["先生鍾舊德，大府冠羣能。", "過手無難事，逢人有異稱。", "薦賢餘一鶚，夙記契千燈。", "看挽秦梁纜，頭頭數不勝。"]'),
('6845394e-1026-44c4-9c3c-93b99ea22020','答魏衍黄預勉余作詩','陳師道','宋','宋诗','song-poetry','','[]','我詩淺短子貢牆，衆目俯視無留藏。',192,'全唐诗/poet.song.62000.json','["我詩淺短子貢牆，衆目俯視無留藏。", "句中有眼黄別駕，洗滌煩熱生清凉。", "人言我語勝黄語，扶豎夜燎齊朝光。", "三年不見萬里外，安得奮身置汝傍。", "邇來諸子復秀發，曾未幾見加端章。", "剩欲摧藏讓頭角，豈是有意羣兒傷。", "於人無怨我何憾，愛者尚衆猶吾鄉。", "平生不自解嘲誚，禍來亦復非周防。", "我衰氣索不自振，正頼好語能恢張。", "詩家小魏新有聲，舊傳秀句西里黄。", "後生學行闕師友，臨路不進空回遑。", "看君事業青雲上，聽渠螟𧎬生膏肓。"]'),
('fe888446-7717-4cd1-89f7-338812e90564','和黄預感秋','陳師道','宋','宋诗','song-poetry','','[]','宿雲護朝霜，秋陽佐殘暑。',180,'全唐诗/poet.song.62000.json','["宿雲護朝霜，秋陽佐殘暑。", "蠅癡驅復來，汗下拭莫禦。", "庭梧自黄隕，風過成夜語。", "幸是可憐生，胡然遽如許。", "黄生多新詩，如盆繭抽緒。", "唱高難欵乃，雋永得㕮咀。", "意合無古今，投闇有迎拒。", "名成弟子韓，價重先生楮。", "向來得斯人，孰謂余齟齬。", "晚炊鄰僧米，晝拾狙公芧。", "甘酸皆適口，霜黄未登俎。", "門有曲逆車，謗甚北山女。", "寧爲溝中斷，不作太倉鼠。", "老退無好懷，續明然兩炬。", "搔首不成眠，寒蛩促機杼。"]'),
('0ad8a694-071f-46b2-be31-ada7e09f562f','和顔生同游南山','陳師道','宋','宋诗','song-poetry','','[]','竹杖芒鞋取次行，琳琅觸目路人驚。',64,'全唐诗/poet.song.62000.json','["竹杖芒鞋取次行，琳琅觸目路人驚。", "常年此日仍爲客，病目今來喜再明。", "筋力尚堪供是事，登臨那得總無情。", "已知名世徒爲爾，可復緣渠太瘦生。"]'),
('aa29abe9-cced-4e44-b9d3-63b80689a9ea','僧慧僧利同往南山','陳師道','宋','宋诗','song-poetry','','[]','驥騄同羣鴻雁行，登臨端爲作重陽。',32,'全唐诗/poet.song.62000.json','["驥騄同羣鴻雁行，登臨端爲作重陽。", "南臺二謝風流絕，準擬歸來古錦囊。"]'),
('59dad0c9-7ddb-433b-bed8-63e47e5c10a3','柏','陳師道','宋','宋诗','song-poetry','','[]','用直寧論世，名成不待官。',48,'全唐诗/poet.song.62000.json','["用直寧論世，名成不待官。", "低枝緣我有，偃蓋到誰看。", "秀色有新故，英姿無暑寒。", "要爲千歲計，豈慮萬牛難。"]'),
('9d1ab7d2-1167-40e4-b81f-8f7c1f917243','叔父惠鉢三首  其一','陳師道','宋','宋诗','song-poetry','','[]','當家父子親分付，不比黄梅萬里來。',32,'全唐诗/poet.song.62000.json','["當家父子親分付，不比黄梅萬里來。", "不解當年明上座，嶺頭言下却空回。"]'),
('32dc3706-64d0-4f34-ac78-974f163ce6ae','叔父惠鉢三首  其二','陳師道','宋','宋诗','song-poetry','','[]','蒲團未有祖師意，洗鉢何曾識趙州。',32,'全唐诗/poet.song.62000.json','["蒲團未有祖師意，洗鉢何曾識趙州。", "萬里空歸君解否，老胡端爲我能留。"]'),
('78145be1-4589-45dd-8e8f-7b003b001fb1','叔父惠鉢三首  其三','陳師道','宋','宋诗','song-poetry','','[]','聲中得句已忘言，斷酒持齋却自然。',32,'全唐诗/poet.song.62000.json','["聲中得句已忘言，斷酒持齋却自然。", "大有西來真的意，饑時著飯飽時懸。"]'),
('7f2b20e4-d7f1-40df-a713-c293587270f6','謝端硯','陳師道','宋','宋诗','song-poetry','','[]','王家舊物羣偷後，石出蠻溪百丈深。',32,'全唐诗/poet.song.62000.json','["王家舊物羣偷後，石出蠻溪百丈深。", "揮翰吾非玉堂手，斷金君有古人心。"]'),
('e25bd87c-e8bc-4053-8d09-d0ebec0d1e79','捕狼','陳師道','宋','宋诗','song-poetry','','[]','一狼將四子，二嶺走千羊。',48,'全唐诗/poet.song.62000.json','["一狼將四子，二嶺走千羊。", "意得無前敵，時乖闕後防。", "寧知射生手，已發弩機張。", "會使烏鳶飽，空令豺虎傷。"]'),
('1fdaf7dc-4e0e-47fa-9780-76f86127096f','和魏衍元夜同登黄樓','陳師道','宋','宋诗','song-poetry','','[]','車馬競清夜，人物秀三楚。',192,'全唐诗/poet.song.62000.json','["車馬競清夜，人物秀三楚。", "登臨得免俗，茲樓豈時睹。", "同來兩稚子，冠者亦四五。", "落落俱可人，頗亦厭歌鼓。", "山月出未高，潛鱗動寒浦。", "檣燈接疏星，奪目粲不數。", "魏侯轉物手，百好趨就敘。", "得句未肯吐，秀氣出眉宇。", "水浄納行影，山空答脩語。", "夜氣稍侵肌，鳥駭去其侶。", "清游豈有極，喜事戒多取。", "投靜未免喧，于今豈非古。", "永懷寂寞人，南北忘在所。", "橫嶺限魚鳥，作書欲誰與。", "情生文自哀，意動足復佇。", "憑檻共一默，望舒已侵午。"]'),
('3f88ee32-a4db-42de-bfed-a80ecc62c288','和元夜','陳師道','宋','宋诗','song-poetry','','[]','笳鼓喧燈市，車輿避火城。',48,'全唐诗/poet.song.62000.json','["笳鼓喧燈市，車輿避火城。", "彭黄爭地勝，汴泗迫人清。", "梅柳春猶淺，關山月自明。", "賦詩隨落筆，端復可憐生。"]'),
('ae255951-24f5-42fa-90a6-cc54f19cddb0','和魏衍同遊阻風','陳師道','宋','宋诗','song-poetry','','[]','舊說春風亦世情，不應作意斷人行。',64,'全唐诗/poet.song.62000.json','["舊說春風亦世情，不應作意斷人行。", "絕須一怒催新句，更可多憂促短生。", "勝日著忙端取怪，妙年得此未須驚。", "懸知出處非吾事，已復星河爛漫晴。"]'),
('5b0658e4-734e-43ca-89c7-945b778e24dd','和魏衍同登快哉亭','陳師道','宋','宋诗','song-poetry','','[]','經時不出此同臨，小徑新摧草舊侵。',64,'全唐诗/poet.song.62000.json','["經時不出此同臨，小徑新摧草舊侵。", "欲傍江山看日落，不堪花鳥已春深。", "來牛去馬中年眼，朗月清風萬里心。", "故著連峰當極目，回看幽徑遶雙林。"]'),
('401819fe-5825-4da7-a24a-e6f2a2cad739','登快哉亭','陳師道','宋','宋诗','song-poetry','','[]','城與清江曲，泉流亂石間。',48,'全唐诗/poet.song.62000.json','["城與清江曲，泉流亂石間。", "夕陽初隠地，暮靄已依山。", "度鳥欲何向，奔雲亦自閑。", "登臨興不盡，稚子故須還。"]'),
('27577fde-967a-4650-8dc5-b662f4965fad','招黄魏二生','陳師道','宋','宋诗','song-poetry','','[]','出門不雨即偶風，閉門值睡極力攻。',96,'全唐诗/poet.song.62000.json','["出門不雨即偶風，閉門值睡極力攻。", "似聞湯鼎作吟聲，已賀勝敵收全功。", "却思二子共一笑，撥棄舊語無新工。", "卒行好步不兩得，能致公等吾何窮。", "魏詩黄筆今未有，顧我獨得神所鍾。", "徑須相就踏泥潦，已辦煮餠澆油葱。"]'),
('a63757d2-c242-4eb1-b2bf-f7462d02e736','春夜','陳師道','宋','宋诗','song-poetry','','[]','宿鳥一枝足，爭林終夜鳴。',48,'全唐诗/poet.song.62000.json','["宿鳥一枝足，爭林終夜鳴。", "庭花當戶發，江月向人明。", "鳥度清溪影，風回晚市聲。", "夢中無好語，池草爲誰生。"]'),
('1d47b0ef-d1c5-48e9-90c5-12b8deec37c1','和三日','陳師道','宋','宋诗','song-poetry','','[]','苦遭年少强追陪，病眼看花更覆杯。',64,'全唐诗/poet.song.62000.json','["苦遭年少强追陪，病眼看花更覆杯。", "夾岸萬人傾國出，清江一注兩山開。", "遊人欲盡驚鷗下，晚日猶須惡雨催。", "更恐明年有離別，折花臨水共裴徊。"]'),
('82e912b0-280e-4970-99cd-b427606b03aa','登燕子樓','陳師道','宋','宋诗','song-poetry','','[]','綠暗連村柳，紅明委地花。',48,'全唐诗/poet.song.62000.json','["綠暗連村柳，紅明委地花。", "畫梁初著燕，廢沼已鳴蛙。", "鷗沒輕春水，舟橫著淺沙。", "相逢千歲語，猶說一枝花。"]'),
('b044a94b-8504-4f1a-a883-c282371bda1b','和魏衍三日二首  其一','陳師道','宋','宋诗','song-poetry','','[]','林花女頰紅，春水瓜頭綠。',48,'全唐诗/poet.song.62000.json','["林花女頰紅，春水瓜頭綠。", "步蹇我三休，來同君一足。", "苦嗟所歷小，不盡千里目。", "暮景向昏鴉，歸塗取脩竹。"]'),
('9f653338-7208-41c7-8da7-064a1ef541c8','和魏衍三日二首  其二','陳師道','宋','宋诗','song-poetry','','[]','堤沙泥盡未及塵，江波不動風生紋。',97,'全唐诗/poet.song.62000.json','["堤沙泥盡未及塵，江波不動風生紋。", "虎頭魚尾不知數，朱旗一點來奔雲。", "春容已老有餘態，祓禊雖古無前聞。", "踏青摸石修祕祝，落日带雨催行人。", "聽詩對月兩不厭，頗覺過目徒紛紛。", "君不見天寶杜陵翁，屈宋才堪作近鄰。"]'),
('1599a427-3aba-4cda-a1e5-721918b67a43','答魏衍惠朱櫻','陳師道','宋','宋诗','song-poetry','','[]','開門先得故人書，稍喜提携起覆盂。',64,'全唐诗/poet.song.62000.json','["開門先得故人書，稍喜提携起覆盂。", "得句有誰知我在，嘗新此日頼吾徒。", "傾籃的皪霑朝露，出袖熒煌得寶珠。", "會薦瑛盤驚一坐，莧腸藜口未良圖。"]'),
('6c811daf-b5d4-4d50-b7ad-dd497b29350c','和魏衍聞鶑','陳師道','宋','宋诗','song-poetry','','[]','春力著人朝睡重，葉底黄鸝鳴自送。',96,'全唐诗/poet.song.62000.json','["春力著人朝睡重，葉底黄鸝鳴自送。", "綠幕朱欄日觀明，回廊側戶風簾動。", "昨夜春回到寒谷，好鳥飛來把脩竹。", "整翰厲觜初一鳴，已落君詩專妙獨。", "退紅著綠春事殘，後時獨立知何言。", "側聽不盡已飛去，懷抱此時誰與論。"]'),
('dac24926-d444-4218-87b2-9d1300e755e8','和黄充實春盡游南山','陳師道','宋','宋诗','song-poetry','','[]','逐勝闕勇功，餞春無少色。',240,'全唐诗/poet.song.62000.json','["逐勝闕勇功，餞春無少色。", "出門欲何向，坂丸隨所擊。", "百年餘幾何，十步復一息。", "同來二三子，楚楚頗脩飾。", "行前强老夫，徑捷疲峻陟。", "山門開煙霏，禪房閉岑寂。", "口燥沾茗椀，久厄此爲德。", "逐日下西山，草路荒不識。", "回溪轉鉤曲，門徑入繩直。", "故人喜領客，內愧積腹臆。", "所來爲親舊，掃除稱寥閴。", "疾風無末勢，過雨有餘瀝。", "高花初欲然，平荷已如拭。", "因君感衰盛，醜好移頃刻。", "交新厭區區，話舊聽歷歷。", "談間十一二，四座已傾側。", "茅屋漏風霜，山田带沙礫。", "尚能哀此老，舉手觸四塞。", "君如澗底松，超拔出天壁。", "學詩有新功，黄魏共推激。"]'),
('0700a7cf-5cbe-404a-a552-acaee9d922e1','楝花','陳師道','宋','宋诗','song-poetry','','[]','密葉已成蔭，高花初著枝。',48,'全唐诗/poet.song.62000.json','["密葉已成蔭，高花初著枝。", "幽香不自好，寒艷未多知。", "會見垂金彈，聊容折紫緌。", "粉身非所恨，猶復得聞思。"]'),
('b15a05d4-685f-4834-9061-bbc7089667d3','和黄充實榴花','陳師道','宋','宋诗','song-poetry','','[]','春去花隨盡，紅榴暖欲然。',72,'全唐诗/poet.song.62000.json','["春去花隨盡，紅榴暖欲然。", "後時何所恨，處獨不祈憐。", "葉葉自相偶，重重久更鮮。", "流珠沾暑雨，改色淡朝煙。", "著子專寒酒，移根擅化權。", "愧非無價手，刻畫竟難傳。"]'),
('a60c8946-0ac6-4a81-b4ec-b4c20f355a47','和黄預病起','陳師道','宋','宋诗','song-poetry','','[]','似聞藥病已投機，牛鬭蛇妖頓覺非。',64,'全唐诗/poet.song.62000.json','["似聞藥病已投機，牛鬭蛇妖頓覺非。", "李賀固知當得疾，沈侯可更不勝衣。", "驚逢白璧山千仞，會見黄金带十圍。", "只信詩書端作祟，孰知糠籺亦能肥。"]'),
('13d6ee61-b6ab-4a36-8891-5a698c2a7c9f','和黄預久雨','陳師道','宋','宋诗','song-poetry','','[]','甲子仍逢夏，連朝雨脚垂。',120,'全唐诗/poet.song.62000.json','["甲子仍逢夏，連朝雨脚垂。", "黑雲玄甲駐，鐵騎冷官馳。", "映日還蒙霧，懸麻却散絲。", "頹牆通犬豕，破柱出蛟螭。", "野潤風光秀，凉生枕席宜。", "撥雲開日月，噀水出虹蜺。", "貧可留須睫，恩當記扊扅。", "蒼頭行冒雨，赤脚出衝泥。", "詩好聲生吻，書工手著胝。", "衰年得佳句，懷抱頓能移。"]'),
('dda53d43-c9dd-4d47-8a26-5dce88e14495','何郎中出示黄公草書四首  其一','陳師道','宋','宋诗','song-poetry','','[]','龍蛇起伏筆無前，江漢淵回語更妍。',32,'全唐诗/poet.song.62000.json','["龍蛇起伏筆無前，江漢淵回語更妍。", "好事元須一賞足，藏家不必萬人傳。"]'),
('0d8e71ed-294f-4a84-a2f6-7e0e21831192','何郎中出示黄公草書四首  其二','陳師道','宋','宋诗','song-poetry','','[]','此詩此字有誰知，畫省郎官自倔奇。',32,'全唐诗/poet.song.62000.json','["此詩此字有誰知，畫省郎官自倔奇。", "罪大從來身萬里，政成今有麥三岐。"]'),
('c667ca26-ae79-4ec3-a8a1-f199f411a229','何郎中出示黄公草書四首  其三','陳師道','宋','宋诗','song-poetry','','[]','四海聲名何水曹，新詩舊德自相高。',32,'全唐诗/poet.song.62000.json','["四海聲名何水曹，新詩舊德自相高。", "一官早要稱三字，二鬢何須著兩毛。"]'),
('ea615a4d-9bbe-4e91-86ad-63ebaefcf8a8','何郎中出示黄公草書四首  其四','陳師道','宋','宋诗','song-poetry','','[]','當年闕里與論詩，晚歲河山斷夢思。',32,'全唐诗/poet.song.62000.json','["當年闕里與論詩，晚歲河山斷夢思。", "妙手不爲平世用，高懷猶有故人知。"]'),
('9fb7ee2b-5e28-4020-975a-5445e43feeec','和黄預感懷','陳師道','宋','宋诗','song-poetry','','[]','壁立無堪佐子貧，漫修簡牒效慇懃。',64,'全唐诗/poet.song.62000.json','["壁立無堪佐子貧，漫修簡牒效慇懃。", "起臨明鏡看生意，卧向晴簷共白雲。", "逸氣不應供潦倒，劇談脫或致紛紜。", "但令蘇晉禪妨醉，不患何山病故葷。"]'),
('84ed5791-8d3c-41ec-a928-cc0bc62f6c53','陳留市隠者','陳師道','宋','宋诗','song-poetry','','[]','陳留人物後，疑有隠屠耕。',108,'全唐诗/poet.song.62000.json','["陳留人物後，疑有隠屠耕。", "斯人豈其徒，滿腹一杯羹。", "婷婷小家子，與翁同醉醒。", "薄暮行且歌，問之諱姓名。", "子豈達者與，槁竹聊一鳴。", "老生何所因，稍稍聲過情。", "閉門十日雨，吟作饑鳶聲。", "詩書工發冢，刀籋得養生。", "飛走不同穴，孔突不暇黔。"]'),
('4ed15899-c26d-484d-80b4-199d99e6a648','和休文至自新安','陳師道','宋','宋诗','song-poetry','','[]','無成底事到天涯，重見春工換柳枝。',64,'全唐诗/poet.song.62000.json','["無成底事到天涯，重見春工換柳枝。", "歷盡江山苦行役，歸來風雨過花時。", "驅馳共厭人間世，險阻時聞別後詩。", "獨有窮愁銷未盡，一番相見一伸眉。"]'),
('1f9b8204-9573-44da-a88e-874433d566a7','秋懷十首  其一','陳師道','宋','宋诗','song-poetry','','[]','昨日山中雲，今朝山下雨。',48,'全唐诗/poet.song.62000.json','["昨日山中雲，今朝山下雨。", "牛羊沒禾黍，蟋蟀促機杼。", "磨刀洗盆甕，社臘不勝數。", "豈無聚歛吏，觸手丞相怒。"]'),
('71701fe7-cd07-4cf6-8859-0d120a6f0870','秋懷十首  其二','陳師道','宋','宋诗','song-poetry','','[]','有家汴泗間，歲久榛棘荒。',48,'全唐诗/poet.song.62000.json','["有家汴泗間，歲久榛棘荒。", "稍知田家樂，感此歸意忙。", "老馬甘伏櫪，游魂還故鄉。", "四十尚無君，天下未敢忘。"]'),
('f7980bb4-b90b-49ab-8cd1-150a68172c96','秋懷十首  其三','陳師道','宋','宋诗','song-poetry','','[]','採薪墟墓間，行歌當歸耕。',48,'全唐诗/poet.song.62000.json','["採薪墟墓間，行歌當歸耕。", "向來輕薄子，懷諼以爲榮。", "喘喘轅下犢，力盡官泥深。", "壯哉八百里，一割探其心。"]'),
('caadb1f7-3c48-4b62-982d-709fdd87f6e0','秋懷十首  其四','陳師道','宋','宋诗','song-poetry','','[]','翩翩王公孫，館我翠微院。',48,'全唐诗/poet.song.62000.json','["翩翩王公孫，館我翠微院。", "粥飯隨鍾魚，朝昏度黄卷。", "中年妻子累，往世西方願。", "獨無詩書力，尼父安得怨。"]'),
('0fbe0e67-3ad8-4958-9e7b-76567e328c4c','秋懷十首  其五','陳師道','宋','宋诗','song-poetry','','[]','黄公輕千乘，尚愛五斗祿。',48,'全唐诗/poet.song.62000.json','["黄公輕千乘，尚愛五斗祿。", "風雨聽朝雞，歲月老松菊。", "平生白蓮社，不受一塵觸。", "識字即投閣，貴者須食肉。"]'),
('d9c2c4ef-5cf1-4e5e-a7ef-228a8e0ba5ed','秋懷十首  其六','陳師道','宋','宋诗','song-poetry','','[]','昔作九日期，一覽知四方。',48,'全唐诗/poet.song.62000.json','["昔作九日期，一覽知四方。", "夜雨秋水深，烈風畏褰裳。", "尊空囊亦空，花豆爲我黄。", "官奴覆青綾，破屋任飛霜。"]'),
('8dde6473-3626-4e56-8c1b-6d754e86b039','秋懷十首  其七','陳師道','宋','宋诗','song-poetry','','[]','翼翼陳州門，萬里遷人道。',48,'全唐诗/poet.song.62000.json','["翼翼陳州門，萬里遷人道。", "雨淚落成血，著木木立槁。", "今年蘇禮部，馬跡猶未掃。", "昔人死別處，一笑欲絕倒。"]'),
('ae5babd1-86ea-489c-a625-6ff2862c4ac1','秋懷十首  其八','陳師道','宋','宋诗','song-poetry','','[]','籊籊孤竹君，長我一身半。',48,'全唐诗/poet.song.62000.json','["籊籊孤竹君，長我一身半。", "凜然霜雪間，時至亦陰換。", "共與王子猷，永結忘言伴。", "可使溪壑姿，充我眼中玩。"]'),
('389364f0-139b-4c30-a484-54bf110a9bb4','秋懷十首  其九','陳師道','宋','宋诗','song-poetry','','[]','北闕書不上，南山田不歸。',48,'全唐诗/poet.song.62000.json','["北闕書不上，南山田不歸。", "朝暮陳州門，悠悠此何爲。", "我老何所爲，暖日聊差池。", "君聽城上烏，啞啞端爲誰。"]'),
('6bc4804a-bbac-4963-a2f6-8ff404321d9f','秋懷十首  其一○','陳師道','宋','宋诗','song-poetry','','[]','潭潭明光殿，稽首西方僊。',48,'全唐诗/poet.song.62000.json','["潭潭明光殿，稽首西方僊。", "平生修何行，步有黄金蓮。", "我豈昔好徑，報以履下穿。", "洗足坐道場，卒卒此何緣。"]'),
('c9757f59-709d-4b41-92d1-dedee30f86a1','寄寇荆山','陳師道','宋','宋诗','song-poetry','','[]','曠士三年別，荆山一顧中。',48,'全唐诗/poet.song.62000.json','["曠士三年別，荆山一顧中。", "百千人欲死，四六老能工。", "脫帽頭應白，求田意欲東。", "口須論世事，目已失飛鴻。"]'),
('a1176a14-8cee-40ff-adaf-067e4cc58689','次韵蘇公西湖觀月聽琴','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','公詩端正道，亭亭如紫雲。',96,'全唐诗/poet.song.62000.json','["公詩端正道，亭亭如紫雲。", "落世不敢學，謂是詩中君。", "獨有黄太史，抱杓挹其尊。", "韵出百家上，誦之心已醺。", "黄鍾毀少合，大裘擯不文。", "世事如病耳，蟻鬭作牛聞。", "苦懷太史惠，養豹煙雨昏。", "後世無高學，舉俗愛許渾。"]'),
('00c76cd6-51e6-4fd4-9dd2-088dceb0dac6','次韵德麟督叔弼季默詩及破余酒戒','陳師道','宋','宋诗','song-poetry','','[]','歲月不相貸，夜牀衾簟秋。',120,'全唐诗/poet.song.62000.json','["歲月不相貸，夜牀衾簟秋。", "朝來明鏡中，作意多少留。", "惟酒可爲娛，顧我非其流。", "丈夫意氣合，珮玦不循鈎。", "意行無人非，駿發不中休。", "相逢問何如，頗復中之不。", "清坐豈不好，致真豈糟丘。", "兩歐以詩鳴，與俗同沉浮。", "百鳥畏嘲弄，往和長鳴鷗。", "胡寧忍快便，風飄萬斛舟。"]'),
('76c52fba-229b-478c-999f-e2fcdd26936b','次韵蘇公謁告三絕  其一','陳師道','宋','宋诗','song-poetry','','[]','靜中有業官成集，醉裏無何老是鄉。',32,'全唐诗/poet.song.62000.json','["靜中有業官成集，醉裏無何老是鄉。", "丈室向來無一物，却須天女與拈香。"]'),
('f7c3b56f-4c36-4f63-aa28-302bddd16f6d','次韵蘇公謁告三絕  其二','陳師道','宋','宋诗','song-poetry','','[]','竭澤回波不作難，未應平地起風瀾。',32,'全唐诗/poet.song.62000.json','["竭澤回波不作難，未應平地起風瀾。", "是身非有從何病，試下先生一著看。"]'),
('7c938d2b-467c-48be-9dc3-977790f27ae9','次韵蘇公謁告三絕  其三','陳師道','宋','宋诗','song-poetry','','[]','紙帳薰爐作小春，青奴白牯對忘言。',32,'全唐诗/poet.song.62000.json','["紙帳薰爐作小春，青奴白牯對忘言。", "更無人問維摩詰，始是東坡不二門。"]'),
('bb7b2874-cf17-4854-8a4f-786559be496d','次韵蘇公獨酌','陳師道','宋','宋诗','song-poetry','','[]','雲月酒下明，風露衣上落。',120,'全唐诗/poet.song.62000.json','["雲月酒下明，風露衣上落。", "是中有何好，草草成獨酌。", "使君顧謂客，老子興不薄。", "飲以全吾真，醉則忘所樂。", "未解飲中趣，中之如狂藥。", "起舞屢跳踉，駡坐失酬酢。", "終然厭多事，超繁趨淡薄。", "功名無前期，山林有成約。", "身將歲華晚，意與天宇廓。", "醒醉各有適，短長聽鳬鶴。"]'),
('91a41e77-7f43-44e4-9ae7-5bfb32194a7d','城南','陳師道','宋','宋诗','song-poetry','','[]','白下官楊小弄黄，騎臺南路綠無央。',64,'全唐诗/poet.song.62000.json','["白下官楊小弄黄，騎臺南路綠無央。", "含紅破白連連好，度水吹香故故長。", "蹲滑踏青穿馬耳，轉危緣險出羊腸。", "孰知南杜風流在，預怯排門有斷章。"]'),
('70a3ef7c-ff73-485f-99f1-6845f288c715','次韵蘇公獨酌試藥玉滑盞','陳師道','宋','宋诗','song-poetry','','[]','僊人棄餘糧，玉色已可欺。',120,'全唐诗/poet.song.62000.json','["僊人棄餘糧，玉色已可欺。", "小試換骨方，價重十冰磁。", "灌以長白虹，渺若江海瀰。", "浮之端不惡，舉者亦何辭。", "但愧聞道晚，早從雁門師。", "律部無明文，可復時中之。", "汝陽佳少年，三斗出六奇。", "家有持盃手，兩好當一施。", "風吹酒面仄，月度杯心遲。", "百年容有命，一笑更須時。"]'),
('d6459f0c-abe7-443a-aba8-bee1e59519d2','次韵德麟植檜','陳師道','宋','宋诗','song-poetry','','[]','種木待成材，聊爲十年事。',132,'全唐诗/poet.song.62000.json','["種木待成材，聊爲十年事。", "日中趨百里，寧問萬牛費。", "植檜三尺强，已有凌雲氣。", "生世能幾何，擬作千歲計。", "衆人笑拍手，君子用其意。", "蕭蕭孤竹君，忘言理相契。", "名以金石交，椿楊豈奴婢。", "緬懷萬仞顛，千丈蔚蒼翠。", "蟠根泉石底，用意霜雪外。", "寧須大厦才，坐待斧斤至。", "散爲風雨聲，密作牛馬蔽。"]'),
('72e90531-4af4-497f-a149-ea2faee65abb','送叔弼寄秦張','陳師道','宋','宋诗','song-poetry','','[]','廬陵四公子，吾及識其半。',180,'全唐诗/poet.song.62000.json','["廬陵四公子，吾及識其半。", "叔也英達人，平易亦精悍。", "於時吾始壯，敗壁不塗墁。", "孤身客東都，轉食諸公館。", "時來扣君門，百過不留難。", "傾心倒囊笈，燕語徹昏旦。", "磬折晚爲親，少得而多患。", "相過汝潁上，歲月不勝難。", "君才得公餘，十日而千萬。", "舌端懸日月，筆下來江漢。", "此行不尋常，談者方一貫。", "逸足寧小試，寶刀當立斷。", "用意不崎嶇，欲得忘挾彈。", "卧念平生親，稍作春冰泮。", "因聲督張秦，書來不應緩。"]'),
('47bd983b-af57-4a3b-9a8e-6ad570fa1979','次韵德麟吳越山水','陳師道','宋','宋诗','song-poetry','','[]','吳山那可說，已覺心耳靜。',120,'全唐诗/poet.song.62000.json','["吳山那可說，已覺心耳靜。", "忍事如忍欲，可遏不可騁。", "人生如此耳，黄白滿朝鏡。", "寧懷斗升粟，不理東南艇。", "君從湖上歸，頗說寒事竟。", "沙草柔動色，溪喧魚不定。", "煩君冰玉句，緩作江湖興。", "君詩如靜女，妙絕人所敬。", "不更風雨秋，下有桃李徑。", "試寫孤竹君，名成三絕鄭。"]'),
('4fb9ce62-176d-488c-80bd-9a44b7f887be','龍潭','陳師道','宋','宋诗','song-poetry','','[]','清淵下無際，落日回風瀾。',120,'全唐诗/poet.song.62000.json','["清淵下無際，落日回風瀾。", "凜然毛髮直，敢以笑語干。", "坡陀百尺臺，葱翠萬木蟠。", "驚飈振積葉，清霜作朝寒。", "水旱或有差，精禱神其難。", "魚龍同一波，信有水府寬。", "向來三日雨，頼子一據鞍。", "何以報嘉惠，寒瓜薦金盤。", "萬口待一飽，歸卧神其安。", "猶須雪三赤，盛意莫得闌。"]'),
('3e89534b-3aa2-4b93-b63e-9b7480ebc2a6','贈魯直','陳師道','宋','宋诗','song-poetry','','[]','相逢不用蚤，論交宜晚歲。',144,'全唐诗/poet.song.62000.json','["相逢不用蚤，論交宜晚歲。", "平生易諸公，斯人真可畏。", "見之三伏中，凜凜有寒意。", "名下今有人，胸中本無事。", "神物護詩書，星斗見光氣。", "惜無千人力，負此萬乘器。", "生前一樽酒，撥棄獨何易。", "我亦奉齋戒，妻子以爲累。", "子如雙井茶，衆口願其嘗。", "顧我如麥飯，猶足填饑腸。", "陳詩傳筆意，願立弟子行。", "何以報嘉惠，江湖永相忘。"]'),
('1eff90f8-56f7-48bc-9819-e7cd06814e62','放歌行  其一','陳師道','宋','宋诗','song-poetry','','[]','春風永巷閑娉婷，長使青樓誤得名。',32,'全唐诗/poet.song.62000.json','["春風永巷閑娉婷，長使青樓誤得名。", "不惜卷簾通一顧，怕君著眼未分明。"]'),
('8f3ec290-866a-4c9d-8282-2aa172e68006','放歌行  其二','陳師道','宋','宋诗','song-poetry','','[]','當年不嫁惜娉婷，拔白施朱作後生。',32,'全唐诗/poet.song.62000.json','["當年不嫁惜娉婷，拔白施朱作後生。", "說與旁人須早計，隨宜梳洗莫傾城。"]'),
('dd027126-e722-4836-86a1-2a7ad2e2a45b','次韵蘇公竹間亭小飲','陳師道','宋','宋诗','song-poetry','','[]','自昔有遺韵，小飲不盡觴。',120,'全唐诗/poet.song.62000.json','["自昔有遺韵，小飲不盡觴。", "坐待竹間月，奈此雲影長。", "起行林下路，散策踰平崗。", "破眼一枝春，著意千葉黄。", "暄寒會有分，蜂蝶來無央。", "鳥語带餘寒，竹風回妙香。", "緬想兩公子，作惡變清凉。", "誰憐塵沙底，疲馬踏朝陽。", "斯人班馬後，如圭復如璋。", "相逢了無得，佳處每難忘。"]'),
('d3e200a4-8282-4fba-87ef-97b1f32225ca','次韵蘇公蠟梅','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','化人巧作襄樣花，何年落子空王家。',128,'全唐诗/poet.song.62000.json','["化人巧作襄樣花，何年落子空王家。", "羽衣霓袖涴香蠟，從此人間識尤物。", "青瑣諸郎却未知，天公下取仙翁詩。", "烏丸雞距寫玉葉，却怪寒花未清絕。", "北風驅雪度關山，把燭看花夜不眠。", "明朝詩成公亦去，長使梅仙誦佳句。", "湖山信美更須人，已覺西湖屬此君。", "坐想明年吳與越，行酒賦詩聽擊鉢。"]'),
('deadc27b-70bb-4c26-a30e-0b881596fda2','秋後五日應物無詩豈年志俱壯未解傷秋耶以詩挑之','陳師道','宋','宋诗','song-poetry','','[]','伏盡暑猶壯，秋生凉故遲。',48,'全唐诗/poet.song.62000.json','["伏盡暑猶壯，秋生凉故遲。", "蟬吟接遠響，螢燭度深枝。", "歲半身仍健，年侵意自悲。", "情知寇公子，不作感秋詞。"]'),
('b9d88bfb-7a9a-40a5-b5be-27eab3b27220','次韵楊內翰贈諸進士','陳師道','宋','宋诗','song-poetry','','[]','一官歸老豈嘉賓，喜見羣材入選掄。',64,'全唐诗/poet.song.62000.json','["一官歸老豈嘉賓，喜見羣材入選掄。", "學變古今人得意，化行梁楚俗還醇。", "士蒙餘勇天同力，詩度清秋物再新。", "勉作功名求善頌，徑從平地據通津。"]'),
('3ddd08fa-deeb-4508-b66a-0addb69e2fb1','送李奉議亳州判官四首  其一','陳師道','宋','宋诗','song-poetry','','[]','謝公中年後，畏與親友別。',72,'全唐诗/poet.song.62000.json','["謝公中年後，畏與親友別。", "數日懷抱惡，每笑冠纓絕。", "生有四方事，死當一語决。", "前笑今則悲，吾衰擬何說。", "著鞭何必先，倒筆不容掣。", "鞭爾轅下駒，萬里一改轍。"]'),
('573e0766-1adc-4673-952f-0d74857bd27d','送李奉議亳州判官四首  其二','陳師道','宋','宋诗','song-poetry','','[]','祁氏號外府，藏室多異書。',48,'全唐诗/poet.song.62000.json','["祁氏號外府，藏室多異書。", "自公有餘力，一覽意何如。", "爲學雖日益，受益不受誣。", "正須高著眼，濠梁有游魚。"]'),
('12a77c3b-02de-4eed-b5b8-59357bcff014','送李奉議亳州判官四首  其三','陳師道','宋','宋诗','song-poetry','','[]','吾友孫子實，愛學吾所畏。',108,'全唐诗/poet.song.62000.json','["吾友孫子實，愛學吾所畏。", "持身如處子，得句有餘味。", "交歡艱難際，凜然見名誼。", "吾病卧里中，車馬日一至。", "遣醫饋粱肉，憂憙見顔際。", "慇懃勸加餐，代我破戒罪。", "一別已三秋，君室乃其季。", "輪囷見眼中，不作千里外。", "因聲問何如，胡不枉一字。"]'),
('6f67ed66-4984-4801-9881-e8a3df239aef','送李奉議亳州判官四首  其四','陳師道','宋','宋诗','song-poetry','','[]','吾友張文潜，君行乃其里。',84,'全唐诗/poet.song.62000.json','["吾友張文潜，君行乃其里。", "當年釣游處，壯者或可指。", "聞風起遐想，意作千古士。", "不知塵土中，奴椎婢不齒。", "胸中無一塵，筆下有百紙。", "勿問見自知，未語君已憙。", "與遊今已後，行矣勿停軌。"]'),
('2778149d-3f08-4077-9a43-510d7cc784cb','寄晁說之','陳師道','宋','宋诗','song-poetry','','[]','閱世真難記，如君自不忘。',48,'全唐诗/poet.song.62000.json','["閱世真難記，如君自不忘。", "尚於書太簡，正以懶相妨。", "與有還家樂，終無却老方。", "莫須憂潦倒，未許細商量。"]'),
('56a43420-0470-45b9-9978-98fece46d0a2','再贈寇司戶','陳師道','宋','宋诗','song-poetry','','[]','仕屈諸儒底，名成一戰中。',48,'全唐诗/poet.song.62000.json','["仕屈諸儒底，名成一戰中。", "酒爲千日計，詩費幾生功。", "戲馬章臺下，呼鷹上蔡東。", "少年豪俠窟，杵臼得梁鴻。"]'),
('0b847f2f-d757-43d6-bc53-58c41d87ecca','次韵寇司戶春懷','陳師道','宋','宋诗','song-poetry','','[]','諱窮懷祿得辭勞，腰折頭低不復高。',64,'全唐诗/poet.song.62000.json','["諱窮懷祿得辭勞，腰折頭低不復高。", "夢幻更堪追鳥跡，去來何有校牛毛。", "依違玩世從君好，叱咤生風蓋代豪。", "聞說妙年心尚在，忍看花絮受風飄。"]'),
('c781bbb6-6687-4dad-9360-a805758a4b07','奉陪內翰二丈醴泉避暑','陳師道','宋','宋诗','song-poetry','','[]','疾雷倒海不成雨，黑雲銜日蠶不吐。',192,'全唐诗/poet.song.62000.json','["疾雷倒海不成雨，黑雲銜日蠶不吐。", "深院回廊晝日長，青簾朱幕風鈴語。", "神仙中人龍作馬，翠旌絳節從天下。", "竹冠芒屨紫綺裘，曳杖林間觀物化。", "清池照眼自生凉，脩竹回陰欲過廊。", "樽酒未空高興動，含毫欲下雲飛揚。", "俗聞道士業符醫，未語已作庸人樣。", "但知一扇博百金，豈識雙松到千丈。", "蠅頭小字密著行，四座歡叫醒而狂。", "忽驚天姥到庭戶，風篁露草鳴寒螿。", "回天却日有餘力，小試席間留翰墨。", "請公慎用補天手，入佐后皇和玉石。"]'),
('224d7a82-fabd-480c-a6e4-199dcd1bfeb8','秋懷','陳師道','宋','宋诗','song-poetry','','[]','稍稍昏烟集，鼕鼕一再更。',48,'全唐诗/poet.song.62000.json','["稍稍昏烟集，鼕鼕一再更。", "短檠昏細字，高枕忘平生。", "來雁妨身健，新楊喚眼明。", "已須甘酒力，不用占時名。"]'),
('91653785-0009-42fd-9ced-734ae0ae96be','戲元弼  其一','陳師道','宋','宋诗','song-poetry','','[]','濁涇清渭不同源，世好因循到子孫。',32,'全唐诗/poet.song.62000.json','["濁涇清渭不同源，世好因循到子孫。", "只待白頭能潦倒，不虞青眼已瀾翻。"]'),
('4d0c4421-4a95-4de4-97dc-b4e977b53854','戲元弼  其二','陳師道','宋','宋诗','song-poetry','','[]','山頭落日著窗明，花裏來禽起笑聲。',32,'全唐诗/poet.song.62000.json','["山頭落日著窗明，花裏來禽起笑聲。", "豈有詩成須白傅，獨於酒可置公榮。"]'),
('65973df2-a554-4993-96d0-cf421c70623d','戲元弼  其三','陳師道','宋','宋诗','song-poetry','','[]','翩翩別去七經年，特特歸來兩浩然。',32,'全唐诗/poet.song.62000.json','["翩翩別去七經年，特特歸來兩浩然。", "東道有時推謝令，後堂無地著彭宣。"]'),
('c8aa7db1-01d2-4ac1-9944-36cf6dac45fc','戲元弼  其四','陳師道','宋','宋诗','song-poetry','','[]','車馳卒奔風雨過，白髮故人餘一箇。',32,'全唐诗/poet.song.62000.json','["車馳卒奔風雨過，白髮故人餘一箇。", "幸是元無左阿君，何須不著陳驚坐。"]'),
('c03aea20-6725-4f19-abee-dca61a3427ec','陳詢秀才歸徐','陳師道','宋','宋诗','song-poetry','','[]','千里相從愧子心，未堪歸路馬駸駸。',64,'全唐诗/poet.song.62000.json','["千里相從愧子心，未堪歸路馬駸駸。", "更能作意憐衰病，肯後重來道古今。", "三歲有期看一舉，百年聊待到千尋。", "行逢浄社論餘習，爲說登臨久廢吟。"]'),
('ddbafd70-7f32-4c75-ab12-9de20a6eb4da','登彭祖樓','陳師道','宋','宋诗','song-poetry','','[]','城上危樓江上城，風流千載擅佳名。',64,'全唐诗/poet.song.62000.json','["城上危樓江上城，風流千載擅佳名。", "水兼汴泗浮天闊，山入青齊煥眼明。", "喬木下泉餘故國，黄鸝白鳥解人情。", "須知壯士多秋思，不露文章世已驚。"]'),
('27623307-c1b4-475a-ad9d-c70291193d80','送仁山主兼寄西堂園澄禪師','陳師道','宋','宋诗','song-poetry','','[]','未仕寧論馬少游，虛名非復韓潮州。',32,'全唐诗/poet.song.62000.json','["未仕寧論馬少游，虛名非復韓潮州。", "祖師若問西來信，爲說蒼頭與白頭。"]'),
('313076e7-e110-46fe-8b5f-9517ec8e775f','寄泰州曾侍郎','陳師道','宋','宋诗','song-poetry','','[]','八年門第故違離，千里河山費夢思。',64,'全唐诗/poet.song.62000.json','["八年門第故違離，千里河山費夢思。", "淮海風濤真有道，麒麟圖畫豈無時。", "今朝有客傳河尹，是處逢人說項斯。", "三徑未成心已具，世間惟有白鷗知。"]'),
('1d08cf2d-4346-48a6-ab5d-09acc26fbbef','答顔生見寄','陳師道','宋','宋诗','song-poetry','','[]','闕然車馬不聞音，行路艱危已備更。',64,'全唐诗/poet.song.62000.json','["闕然車馬不聞音，行路艱危已備更。", "求舍問田真得計，臨流據石有餘清。", "江山滿目開新卷，韋杜諸人得細評。", "閑處著身容我老，忙中見記識君情。"]'),
('c38f36bf-5c03-4343-924f-f5caccf7d7e6','和黄預七夕','陳師道','宋','宋诗','song-poetry','','[]','盈盈一水不斯須，經歲相過自作疏。',64,'全唐诗/poet.song.62000.json','["盈盈一水不斯須，經歲相過自作疏。", "坐待翔禽報佳會，徑須飛雨洗香車。", "超騰水部陳篇上，收拾愚溪作賦餘。", "信有神仙足官府，我寧辛苦守殘書。"]'),
('fbcc9d12-a93b-4461-bcf6-adaeeb72f506','贈鄭戶部','陳師道','宋','宋诗','song-poetry','','[]','千載歸來遼海東，江山如舊里閭空。',64,'全唐诗/poet.song.62000.json','["千載歸來遼海東，江山如舊里閭空。", "時平未覺身難遇，學贍依然說不窮。", "著繡晝行真細事，下車磬折得深衷。", "聖朝未有徐州相，剩作功名跨數公。"]'),
('c01f0df1-e7bb-4cc2-b5fe-7e4b32e7d7a5','九日不出魏衍見過','陳師道','宋','宋诗','song-poetry','','[]','九日登臨迫閉藏，老懷無恨自淒涼。',64,'全唐诗/poet.song.62000.json','["九日登臨迫閉藏，老懷無恨自淒涼。", "山頭落帽風流絕，壁面稱詩語笑香。", "衝雨肯來尋此老，拂牀聊待熟黄粱。", "獨無樽酒爲君壽，正使秋花未肯黄。"]'),
('45d530fe-cfab-445b-a4c6-a2d35fdccbd8','送魏衍移沛','陳師道','宋','宋诗','song-poetry','','[]','積雨斷行路，重江未安流。',144,'全唐诗/poet.song.62000.json','["積雨斷行路，重江未安流。", "胡爲冒艱險，迫此米帛謀。", "歲晏風作橫，未寬爲子憂。", "卒然託異縣，所得如所求。", "主人如古人，待士禮亦優。", "人情樂新知，豈不懷舊丘。", "我貧無四壁，愛爾胡能留。", "子也尚不容，吾代諸公羞。", "勿云百里遠，已作千山愁。", "念子捨我去，誰復從我遊。", "諸石吾未識，因子卜可不。", "能此已可尚，終焉致綢繆。"]'),
('853db6c4-13ad-48a8-b29d-da2a3f3b7f2b','送河間呂令','陳師道','宋','宋诗','song-poetry','','[]','今日中牟令，當年太守孫。',48,'全唐诗/poet.song.62000.json','["今日中牟令，當年太守孫。", "獨能憐此老，肯避席爲門。", "寒日風濤壯，邊城簿領繁。", "平生子曾子，白首得重論。"]'),
('8051650c-45dc-49a7-a17f-e0f8f764672d','次韵何子溫祈晴二首  其一','陳師道','宋','宋诗','song-poetry','','[]','夜半風回雨脚收，萬家和氣與雲浮。',64,'全唐诗/poet.song.62000.json','["夜半風回雨脚收，萬家和氣與雲浮。", "蕭條寒巷荒三徑，突兀晴空聳二樓。", "勝日登臨輕一醉，下鄉昏墊肯同憂。", "江空峽響魚龍落，盡放青青極目秋。"]'),
('f84b3dc7-bcf0-4a7b-84f8-084fabb2feb2','次韵何子溫祈晴二首  其二','陳師道','宋','宋诗','song-poetry','','[]','九虎當關信不傳，燒煙才上已回天。',64,'全唐诗/poet.song.62000.json','["九虎當關信不傳，燒煙才上已回天。", "驅除霧雨還朝日，畜縮濤波復二川。", "奪目光華開秀句，堆場藁秸驗豐年。", "從今更上中和頌，少費將軍九萬牋。"]'),
('481b5040-7013-4270-a84b-13aad7614912','寄潭州張芸叟二首  其一','陳師道','宋','宋诗','song-poetry','','[]','湖嶺一都會，西南更上游。',48,'全唐诗/poet.song.62000.json','["湖嶺一都會，西南更上游。", "秋盤堆鴨脚，春味薦貓頭。", "宣室來何暮，蒸池得借留。", "孰知爲郡樂，莫作越鄉憂。"]'),
('520ce23a-7160-4469-8d79-17f876dccd8e','寄潭州張芸叟二首  其二','陳師道','宋','宋诗','song-poetry','','[]','去國如前日，爲邦得舊游。',48,'全唐诗/poet.song.62000.json','["去國如前日，爲邦得舊游。", "霜甘先落手，春雁幾回頭。", "只道風沙惡，寧知賈宋留。", "賦詩真有助，弔古不同憂。"]'),
('b09ee9e8-8442-47b1-868e-436d24ac84b5','送曹秀才','陳師道','宋','宋诗','song-poetry','','[]','甲第衣冠後，東遷歲月侵。',48,'全唐诗/poet.song.62000.json','["甲第衣冠後，東遷歲月侵。", "情親期一諾，急病闕千金。", "孰並還家樂，毋忘在莒心。", "時能記衰疾，聲迹到雲林。"]'),
('edeb8d7f-5bf4-4320-ade7-a96229167510','送王元均貶衡州兼寄元龍二首  其一','陳師道','宋','宋诗','song-poetry','','[]','先生英氣蓋區中，命與仇謀得老窮。',64,'全唐诗/poet.song.62000.json','["先生英氣蓋區中，命與仇謀得老窮。", "又見長身有家法，可辭短簿怒吾公。", "石頭路滑行能速，宣室歸來語未終。", "宛洛風塵莫回顧，直須留眼送歸鴻。"]'),
('836644cc-2b67-4b2d-8a7f-a6469349bcb9','送王元均貶衡州兼寄元龍二首  其二','陳師道','宋','宋诗','song-poetry','','[]','先生秀句滿天東，二子緣渠再得窮。',64,'全唐诗/poet.song.62000.json','["先生秀句滿天東，二子緣渠再得窮。", "詩禮向來堪發冢，孫劉能使不爲公。", "炎方瘴癘避軒豁，故國山河開始終。", "傳語元龍要相識，江湖春動有來鴻。"]'),
('de7015c2-6c41-4371-b471-5213d8fd5c19','杜侍郎挽詞三首  其一','陳師道','宋','宋诗','song-poetry','','[]','美政真吾母，名家更杜陵。',48,'全唐诗/poet.song.62000.json','["美政真吾母，名家更杜陵。", "于張從昔少，魯衛至今稱。", "絲竹中年好，詞華夙世能。", "周南棠棣傳，平世幾人登。"]'),
('1f40e310-9510-41f6-b672-436c7bab5b11','杜侍郎挽詞三首  其二','陳師道','宋','宋诗','song-poetry','','[]','驥騄方懷遠，松筠忽有秋。',48,'全唐诗/poet.song.62000.json','["驥騄方懷遠，松筠忽有秋。", "雍容名士數，終始法家流。", "凜凜驚千載，堂堂閟一丘。", "能令羊季子，不肯過西州。"]'),
('c22dc7f9-e277-47cc-abef-e85f40e1ef87','杜侍郎挽詞三首  其三','陳師道','宋','宋诗','song-poetry','','[]','身去風流在，人難玉石分。',48,'全唐诗/poet.song.62000.json','["身去風流在，人難玉石分。", "平生才一見，治行已多聞。", "更覺知音少，還修地下文。", "他年九原淚，仍是兩馮君。"]'),
('c112c64d-55c3-456f-ab1f-7b7e6c93fdf7','黄無悔挽詞四首  其一','陳師道','宋','宋诗','song-poetry','','[]','敏慧仍江夏，風流更妙年。',48,'全唐诗/poet.song.62000.json','["敏慧仍江夏，風流更妙年。", "貧焚酒家券，病得里胥錢。", "精爽來鷹隼，清明瀉澗瀍。", "無兒傳素業，有淚徹黄泉。"]'),
('407b1901-eaa4-4aef-846c-6dade1ca0f7b','黄無悔挽詞四首  其二','陳師道','宋','宋诗','song-poetry','','[]','骨秀神仙數，詩清雅頌才。',48,'全唐诗/poet.song.62000.json','["骨秀神仙數，詩清雅頌才。", "識高懸日月，韵勝脫塵埃。", "去就堪同事，摧殘盡一哀。", "了知天上去，不似世間來。"]'),
('7bf05cc6-ab3d-404b-833a-647953c57745','黄無悔挽詞四首  其三','陳師道','宋','宋诗','song-poetry','','[]','志大期千里，身宜置一丘。',48,'全唐诗/poet.song.62000.json','["志大期千里，身宜置一丘。", "英詞真蓋世，爽氣已橫秋。", "地要黄金骨，天成白玉樓。", "平生斲泥手，斤斧恐長休。"]'),
('b9e68e8a-a689-4491-ae5c-9990f893300e','黄無悔挽詞四首  其四','陳師道','宋','宋诗','song-poetry','','[]','玉筯凝潮後，絲桐藝業餘。',48,'全唐诗/poet.song.62000.json','["玉筯凝潮後，絲桐藝業餘。", "遠塗憎早悟，曠度得中疏。", "子逝今何遽，吾生孰與居。", "豈無文士傳，未有茂陵書。"]'),
('237ef652-25ae-472f-b743-8eec8802e67e','秋懷四首  其一','陳師道','宋','宋诗','song-poetry','','[]','積雨不受暑，既晴還得秋。',48,'全唐诗/poet.song.62000.json','["積雨不受暑，既晴還得秋。", "未免困河魚，寧如喘吳牛。", "風梧有先聲，巢燕無後留。", "人生行樂爾，一經今白頭。"]'),
('59313eb1-2551-444b-92b9-76fcc20df341','秋懷四首  其二','陳師道','宋','宋诗','song-poetry','','[]','小雨斷復續，回斜落晚風。',48,'全唐诗/poet.song.62000.json','["小雨斷復續，回斜落晚風。", "寒心生蟋蟀，秋色傍梧桐。", "草與遥山碧，花欺晚照紅。", "口須談世事，目已失飛鴻。"]'),
('d2a7d315-1f11-4dd8-8f4e-1c67f25933d3','秋懷四首  其三','陳師道','宋','宋诗','song-poetry','','[]','山斷開平野，河回殺急流。',48,'全唐诗/poet.song.62000.json','["山斷開平野，河回殺急流。", "登臨須向夕，風雨更宜秋。", "急急後飛雁，翩翩不下鷗。", "晚舟猶小待，暮雀已深投。"]'),
('c324e491-2c5e-4a5e-8282-8bb107ab30fe','秋懷四首  其四','陳師道','宋','宋诗','song-poetry','','[]','梨埒當千戶，漁防擁萬頭。',48,'全唐诗/poet.song.62000.json','["梨埒當千戶，漁防擁萬頭。", "寧須一網盡，不爲百人留。", "密雨點急水，驚風擘繫舟。", "百年供轉徙，因病得夷猶。"]'),
('faa2b9ea-13a0-4d3b-af23-0d8cd083c250','送法寶禪師','陳師道','宋','宋诗','song-poetry','','[]','平生夫鐵脚，道價喧宇宙。',192,'全唐诗/poet.song.62000.json','["平生夫鐵脚，道價喧宇宙。", "望禮東南雲，吾今獨何後。", "晚始識其子，瑶林一枝秀。", "初聞飲光笑，復作空生瘦。", "今年退後禪，袖手不肯叉。", "真成菩薩魔，未免化城咎。", "白月懸清光，大鍾得辭扣。", "知止一何勇，隨緣豈無復。", "豐臺兩禪子，三請期一覯。", "翩然挈瓶盂，百里往相就。", "古寺風雨餘，觸目初邂逅。", "夙昔有靜緣，歡然宛如舊。", "教我早自異，業成誰得救。", "世故已備嘗，躊躇復何候。", "鑽火勿停手，時來自渠透。", "慇懃禮白足，吾爲太山溜。"]'),
('f7196c49-de12-45ea-897c-c717cced2d13','贈趙奉議','陳師道','宋','宋诗','song-poetry','','[]','爲惠不必廣，但問與者誰。',192,'全唐诗/poet.song.62000.json','["爲惠不必廣，但問與者誰。", "受施何用多，名義以爲資。", "平生師友間，四海參寥師。", "一窮無四壁，百代有千詩。", "再逐越淮江，三年魯中歸。", "初無贊公色，不異浄名衣。", "才如得風鷁，已復觸藩羝。", "路貧誰肯憐，語妙君所知。", "我往立談間，欻若白受緇。", "迺知仁者聽，不待辛苦詞。", "趙侯名教士，勁氣噴長蜺。", "論吐天下公，而合吾所私。", "明窗弄文墨，妍語含英姿。", "要與識者論，且避羣兒癡。", "舊好無新功，終年此交綏。", "未須堅百戰，當即建降旗。"]'),
('46cf09c0-631b-49e9-a08d-711ad87c05d3','元日雪二首  其一','陳師道','宋','宋诗','song-poetry','','[]','半夜風如許，平明雪皓然。',48,'全唐诗/poet.song.62000.json','["半夜風如許，平明雪皓然。", "簾疏穿瑣細，竹壓更嬋娟。", "窘兔走留跡，饑烏鳴乞憐。", "遥忻炎海上，還復得新年。"]'),
('15d15823-25a4-437e-baca-0fe47c17a22d','元日雪二首  其二','陳師道','宋','宋诗','song-poetry','','[]','度臘闕三白，開正還積陰。',48,'全唐诗/poet.song.62000.json','["度臘闕三白，開正還積陰。", "炊煙茅舍濕，噪雀暮枝深。", "短髮千方誤，中年萬里心。", "成書著巖穴，或有後人尋。"]'),
('d0a00c1b-180e-4dca-8c58-cf383237894c','次韵黄生','陳師道','宋','宋诗','song-poetry','','[]','入竹投窗夜有聲，似違殘臘作初正。',64,'全唐诗/poet.song.62000.json','["入竹投窗夜有聲，似違殘臘作初正。", "三更爽氣侵危坐，萬里回風逼發生。", "呵筆小吟撩我老，閉門高卧見君情。", "只今剩作驚人句，頗覺吟邊意未平。"]'),
('a66e2c61-c96d-41f2-bd7a-112facd32b21','答黄生','陳師道','宋','宋诗','song-poetry','','[]','冰泥斷道雪塞門，遠坊累日無行人。',152,'全唐诗/poet.song.62000.json','["冰泥斷道雪塞門，遠坊累日無行人。", "卧聞喧呼誰叩閽，稚子往問鹿駭奔。", "黄生學詩用力新，急手疾口如翻盆。", "衝風踏凍送七言，要令寒屋回春溫。", "是時積陰又黄昏，叫鬧索火驚四鄰。", "邇來結字穩且勻，豈不見我參寥君。", "嗟吾老矣心尚存，後來得子空馬羣。", "徑須赤手縛麒麟，四大海水一口吞。", "丈夫意氣抗浮雲，道逢其人兩手分，妬婦拊膺王右軍。"]'),
('18fe9f80-6d5c-4378-bb4a-b0b4bfe7f331','雪後','陳師道','宋','宋诗','song-poetry','','[]','送往開新雪又晴，故留臘白待春青。',64,'全唐诗/poet.song.62000.json','["送往開新雪又晴，故留臘白待春青。", "稍回杉色伸梅怨，併得朝看與夜聽。", "已覺庭泥生鳥跡，遽修田事带朝星。", "暮年功力歸持律，不是騷人故獨醒。"]'),
('cb74247b-9efc-45b6-9404-dee991e1acd3','送張蘄縣','陳師道','宋','宋诗','song-poetry','','[]','接祿才餘歲，爲邦近故園。',48,'全唐诗/poet.song.62000.json','["接祿才餘歲，爲邦近故園。", "案圖三萬戶，鎮靜五千言。", "雪盡春泥滑，風生沙水昏。", "猶須放琴客，坐席稍能溫。"]'),
('fca06316-3c50-456b-9550-a8337e3a8bc3','送何子溫移亳州三首  其一','陳師道','宋','宋诗','song-poetry','','[]','治出龍城守，名高水部郎。',48,'全唐诗/poet.song.62000.json','["治出龍城守，名高水部郎。", "清明人共識，風味獨難忘。", "骨立秦書瘦，鬚粘檜密香。", "烹鮮師老耳，曳尾肯蒙莊。"]'),
('d6e67c54-e646-4d48-bff5-6b42119bd06c','送何子溫移亳州三首  其二','陳師道','宋','宋诗','song-poetry','','[]','青衿曾誦賦，皓首始登門。',48,'全唐诗/poet.song.62000.json','["青衿曾誦賦，皓首始登門。", "意得寧論晚，心交不待言。", "向來期北上，可復改南轅。", "畫地數佳政，叢談何處村。"]'),
('f8aef797-b969-4c05-8cb0-0a6ce8d5dac8','送何子溫移亳州三首  其三','陳師道','宋','宋诗','song-poetry','','[]','復作中年別，仍懷後日憂。',48,'全唐诗/poet.song.62000.json','["復作中年別，仍懷後日憂。", "關山遮極目，汴泗只東流。", "政好遭頻借，詩清得暗投。", "會看靈壽杖，扶出富民侯。"]'),
('260126c6-496d-4add-9348-e3132aec29c5','送詹司業','陳師道','宋','宋诗','song-poetry','','[]','學舍論交二十年，白頭相對固依然。',64,'全唐诗/poet.song.62000.json','["學舍論交二十年，白頭相對固依然。", "才難孰爲吾君惜，果滿寧容我輩先。", "熟路長驅聊緩步，百全一發不虛絃。", "故懷未盡還成別，飽慣人間不更憐。"]'),
('cec7f08e-ca6d-416c-a4ed-55a4aa3051d0','西郊二首  其一','陳師道','宋','宋诗','song-poetry','','[]','紅綠相催春事闌，可能無意待人看。',32,'全唐诗/poet.song.62000.json','["紅綠相催春事闌，可能無意待人看。", "不因送客那能出，衰病經年一據鞍。"]'),
('f9325bba-4ccf-4e4e-8320-c795aeeaf2c6','西郊二首  其二','陳師道','宋','宋诗','song-poetry','','[]','攢眉斂目抵風沙，暗度城西十里花。',32,'全唐诗/poet.song.62000.json','["攢眉斂目抵風沙，暗度城西十里花。", "歷肆側聽長短句，緣溪斜著兩三家。"]'),
('3587ccdc-8304-4b77-a0f8-ad255217cf37','寄亳州何郎中二首  其一','陳師道','宋','宋诗','song-poetry','','[]','西南日下共浮雲，人事難羣喜勸分。',64,'全唐诗/poet.song.62000.json','["西南日下共浮雲，人事難羣喜勸分。", "已度城陰先得句，不應從俗未忘葷。", "松篁有節元宜晚，桃李無蹊只自薰。", "欲入帝城須帝力，且尋詩社著詩勳。"]'),
('02642269-7fb2-42eb-b708-fbb730699d90','寄亳州何郎中二首  其二','陳師道','宋','宋诗','song-poetry','','[]','西原追送未成旬，赫赫傳聲已迫人。',64,'全唐诗/poet.song.62000.json','["西原追送未成旬，赫赫傳聲已迫人。", "剩欲抄詩寄來使，尚能拂席致佳賓。", "孰知簡易歸劉向，誰使循良作寇恂。", "他日入東專一壑，少留餘地許爲鄰。"]'),
('8f417565-8e2b-408a-aefc-30c5c67ac9a9','寄答泰州曾侍郎','陳師道','宋','宋诗','song-poetry','','[]','千里馳詩慰別離，詩來吟詠轉悲思。',64,'全唐诗/poet.song.62000.json','["千里馳詩慰別離，詩來吟詠轉悲思。", "靜中取適庸非計，林下相從會有時。", "生理只今那得說，交情從昔見於斯。", "含毫欲下還休去，懷抱何由得細知。"]'),
('ed339c0d-3913-4f72-95c0-dd857deee4af','送提刑李學士移使東路','陳師道','宋','宋诗','song-poetry','','[]','襟袖從前相向開，倡酬于此未多陪。',64,'全唐诗/poet.song.62000.json','["襟袖從前相向開，倡酬于此未多陪。", "身更寵辱談彌勝，路別東西意自哀。", "隠几忘言終不近，白頭青簡兩相催。", "孰知衰老難爲別，聲問應須續續來。"]'),
('92fe75d0-0f1b-4131-a062-1a54e6a38f29','和鄭戶部寶集丈室二首  其一','陳師道','宋','宋诗','song-poetry','','[]','遠遊遊則遠，安心心已安。',48,'全唐诗/poet.song.62000.json','["遠遊遊則遠，安心心已安。", "茅茨更何事，一坐五年寬。", "客來問法要，示以無所還。", "勿云空生默，聽者不勝言。"]'),
('360aafb5-ef9e-4863-bae9-4346b2ba66be','和鄭戶部寶集丈室二首  其二','陳師道','宋','宋诗','song-poetry','','[]','貴有空王章，貧無置錐地。',48,'全唐诗/poet.song.62000.json','["貴有空王章，貧無置錐地。", "衝風窗自語，涴壁蟲成字。", "向隅有知音，闔門接彊對。", "只道庭前柏，西來本無意。"]'),
('19e49a4f-2bcf-4282-be4f-af996a538953','隠者郊居','陳師道','宋','宋诗','song-poetry','','[]','高齋繚繞度雙溝，老氣軒昂蓋九州。',64,'全唐诗/poet.song.62000.json','["高齋繚繞度雙溝，老氣軒昂蓋九州。", "不謂江山開悒怏，正緣風味得淹留。", "招携好客供談笑，拆補新詩擬獻酬。", "小摘自鋤稀菜甲，旁觀虛作不堪憂。"]'),
('4f5ce2e5-7a06-494a-9a3a-4dd3a8135f4f','覽勝亭','陳師道','宋','宋诗','song-poetry','','[]','斷岸通橫水，吹花滿繫船。',48,'全唐诗/poet.song.62000.json','["斷岸通橫水，吹花滿繫船。", "中年擅幽獨，輟食買林泉。", "草木真宜主，江山故作妍。", "升沉有流轉，且復賦歸田。"]'),
('86f3fa03-790f-4474-9954-c395237a5ea4','何太中挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','課最三川守，名成萬石君。',48,'全唐诗/poet.song.62000.json','["課最三川守，名成萬石君。", "平生欠一識，聲烈即多聞。", "兜率真歸處，琴臺只斷雲。", "傷心今夜月，忍便到初墳。"]'),
('d256998e-5530-4492-be9b-042021a4f1f0','何太中挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','哀挽諸儒競，豐碑故吏繁。',48,'全唐诗/poet.song.62000.json','["哀挽諸儒競，豐碑故吏繁。", "素車紛雨泣，丹旐與風翻。", "幾地留遺愛，他年作九原。", "涕流耆舊盡，不獨爲鄉園。"]'),
('c7e6eef9-1a1f-4fdb-8645-42dbd1b0964e','送大兄兼寄趙團練','陳師道','宋','宋诗','song-poetry','','[]','貧有分離苦，官無早晚宜。',48,'全唐诗/poet.song.62000.json','["貧有分離苦，官無早晚宜。", "又爲千里別，未覺十年遲。", "日與江山遠，風連草木悲。", "平生劉子政，見可只論詩。"]'),
('d47a1731-e411-4cc2-ac99-97e37356ac9d','寄襄州程大夫','陳師道','宋','宋诗','song-poetry','','[]','中年爲吏晚專城，不獨身榮府亦榮。',64,'全唐诗/poet.song.62000.json','["中年爲吏晚專城，不獨身榮府亦榮。", "江漢風流見羊杜，相門經術有韋平。", "十年一別音書絕，萬里相看骨肉情。", "今代龐公入城府，定將懸榻與逢迎。"]'),
('971a8d01-f202-4437-807f-a9952207910f','送檢法趙奉議','陳師道','宋','宋诗','song-poetry','','[]','三歲公門不屢過，作牋時得問如何。',64,'全唐诗/poet.song.62000.json','["三歲公門不屢過，作牋時得問如何。", "及茲去去翻爲恨，向使常常肯謂多。", "勇銳閉房猶著酒，切深疾惡反傷和。", "贈言竊取仁人號，善聽君居長者科。"]'),
('6f438488-3ac8-406f-a91a-142bb89fcd59','送建州鄭戶部','陳師道','宋','宋诗','song-poetry','','[]','清江畫舸照新晴，鐃鼓喧喧聒市鳴。',64,'全唐诗/poet.song.62000.json','["清江畫舸照新晴，鐃鼓喧喧聒市鳴。", "昔日布衣今着繡，他年鶴化只空城。", "還朝不待三年最，得郡何妨萬里行。", "歲祿二千親八十，世間誰有此時榮。"]'),
('807c63ea-5e6b-45fd-a2fe-1001d46f6d43','送張秀才','陳師道','宋','宋诗','song-poetry','','[]','學又三年積，功收一日長。',48,'全唐诗/poet.song.62000.json','["學又三年積，功收一日長。", "擅場推老手，附尾續諸郎。", "度鳥界晴碧，過雲回夕黄。", "熟知詩有驗，莫慍路無糧。"]'),
('945e0827-6807-4673-a69b-5820188c7b0f','晁無咎畫山水扇','陳師道','宋','宋诗','song-poetry','','[]','前身阮始平，今代王摩詰。',53,'全唐诗/poet.song.62000.json','["前身阮始平，今代王摩詰。", "偃屈蓋代氣，萬里入方尺。", "朽老詩作妙，險絕天與力。", "君不見杜陵老翁語，湘娥增悲真宰泣。"]'),
('562a64d3-c010-46d1-a558-58696fbc896c','奉陪趙大夫游桓山','陳師道','宋','宋诗','song-poetry','','[]','後水喧江落渾黄，晚雲障日作微凉。',64,'全唐诗/poet.song.62000.json','["後水喧江落渾黄，晚雲障日作微凉。", "笙歌聲裏旌旗動，羅綺叢中語笑香。", "勸相秋郊開稔熟，摩娑苔壁弔荒亡。", "風流一代今山簡，有底樽前著葛强。"]'),
('d5b93c59-bbee-4255-8a7e-f451e009ba67','寄曹州晁大夫','陳師道','宋','宋诗','song-poetry','','[]','東方千騎貴當年，白髮居頭也自賢。',64,'全唐诗/poet.song.62000.json','["東方千騎貴當年，白髮居頭也自賢。", "肯費精神修客主，稍回功譽入章篇。", "虛名不救空腸厄，晚歲仍遭末疾纏。", "死去不爲天下惜，鏡中當有故人憐。"]'),
('55b0f3b8-0c6f-445d-a484-f314dd812c54','送馮翊宋令','陳師道','宋','宋诗','song-poetry','','[]','三楚風流信有人，先聲今已徹咸秦。',64,'全唐诗/poet.song.62000.json','["三楚風流信有人，先聲今已徹咸秦。", "寧爲雞口官無小，欲試牛刀久要新。", "細肋卧沙勤下筯，長芒刺眼莫霑唇。", "山西豪傑知吾老，爲說猶堪舉萬鈞。"]'),
('83965071-dc5d-4b93-bb59-fa5ca2c78e8c','嗟哉行','陳師道','宋','宋诗','song-poetry','','[]','張生服石爲石奴，下潦上乾如渴烏。',80,'全唐诗/poet.song.62000.json','["張生服石爲石奴，下潦上乾如渴烏。", "一朝僨蹶須人扶，伏毒未動風出虛。", "此生所得與昔殊，韓子作志還自屠。", "自笑未竟人復吁，以身濟欲未必愚。", "欲久而速反所圖，嗟哉偉然二大夫。"]'),
('385b13ac-c13a-401a-b72f-1d6e86a3feda','夜句三首  其一','陳師道','宋','宋诗','song-poetry','','[]','過雨作秋清，歸雲放月明。',24,'全唐诗/poet.song.62000.json','["過雨作秋清，歸雲放月明。", "入簾搖竹影，塞耳落洪聲。"]'),
('528ba282-c0b3-4c1e-8b0e-6418380401fc','夜句三首  其二','陳師道','宋','宋诗','song-poetry','','[]','老樹仍孤秀，秋蟾只獨明。',24,'全唐诗/poet.song.62000.json','["老樹仍孤秀，秋蟾只獨明。", "何須夜來雨，却聽枕前聲。"]'),
('00b74622-1288-4cd3-9ac4-e7d9d58d498a','夜句三首  其三','陳師道','宋','宋诗','song-poetry','','[]','短短長長柳，三三五五星。',24,'全唐诗/poet.song.62000.json','["短短長長柳，三三五五星。", "斷雲當極目，不盡遠峰青。"]'),
('15c295d7-f8a6-4d0d-b974-83a062d4082a','送孝忠落解南歸','陳師道','宋','宋诗','song-poetry','','[]','妙年失手未須恨，白璧深藏可自妍。',64,'全唐诗/poet.song.62000.json','["妙年失手未須恨，白璧深藏可自妍。", "短髮我能今種種，曉妝他日看娟娟。", "千金市帚寧論價，萬戶分封信有年。", "清白傳家有如此，歸塗囊盡不留錢。"]'),
('f65b37b1-dd48-44a8-8b75-5137f2591c5f','寄單州張朝請','陳師道','宋','宋诗','song-poetry','','[]','平生天上張公子，尚記門間半面人。',64,'全唐诗/poet.song.62000.json','["平生天上張公子，尚記門間半面人。", "聲烈與風來不盡，音書無使去難頻。", "一言悟主心猶壯，百巧成窮髮自新。", "聞說監河收貸粟，定傾東海活窮鱗。"]'),
('84f59c76-e1c3-4a74-98ae-68085e41efc3','謝憲臺趙史惠米','陳師道','宋','宋诗','song-poetry','','[]','平生忍欲今忍貧，閉口逢人不少陳。',32,'全唐诗/poet.song.62000.json','["平生忍欲今忍貧，閉口逢人不少陳。", "俸薄身清趙都史，也能作意向詩人。"]'),
('0c1aebbe-0841-4a4b-a451-850103d7cffa','和趙大夫鹿鳴宴集','陳師道','宋','宋诗','song-poetry','','[]','趙侯詩律近風騷，雅意推賢答聖朝。',64,'全唐诗/poet.song.62000.json','["趙侯詩律近風騷，雅意推賢答聖朝。", "鴻雁著行過渭水，鳳凰覽德下虞韶。", "三千著籍今爲盛，九萬論程不作遥。", "不讀世書談世事，卧看君自致青霄。"]'),
('1930a5c8-0a54-4988-9711-0aca36956e3e','和朱智叔鹿鳴席上','陳師道','宋','宋诗','song-poetry','','[]','三楚風流秀士林，英詞從昔動脩門。',64,'全唐诗/poet.song.62000.json','["三楚風流秀士林，英詞從昔動脩門。", "充庭初識蒼龍礎，賜醴行霑白獸樽。", "已上薦書輕一鶚，更憑詩力化羣鯤。", "千年遼鶴空城郭，誰見朱公有異孫。"]'),
('891ce28b-034c-416c-aa85-147eb446e9bd','酬智叔見贈','陳師道','宋','宋诗','song-poetry','','[]','老去斯文不更論，却因夫子話師門。',64,'全唐诗/poet.song.62000.json','["老去斯文不更論，却因夫子話師門。", "清談不待傾三語，勝日何知共一樽。", "逐北我方填坎井，圖南誰得料鵬鯤。", "過逢爲說侯芭在，卧檝生衣犢有孫。"]'),
('18c6f417-f3b9-4c01-a293-a5656dc87717','再酬','陳師道','宋','宋诗','song-poetry','','[]','鄉里衣冠不絕人，近天尺五只清門。',64,'全唐诗/poet.song.62000.json','["鄉里衣冠不絕人，近天尺五只清門。", "論文正可簪雙筆，澆舌行看賜上樽。", "瓊玖每蒙先木李，蜩鳩方共笑飛鯤。", "固知賢傑當傳世，下里朱陳亦有孫。"]'),
('ea6913b1-a515-4f47-a04e-26d84172387f','敬酬智叔三賜之辱兼戲楊理曹二首  其一','陳師道','宋','宋诗','song-poetry','','[]','龍爭虎據竟成塵，只有青樓與白門。',64,'全唐诗/poet.song.62000.json','["龍爭虎據竟成塵，只有青樓與白門。", "令宰才高先得句，使君情重數開樽。", "江山故國難留鶴，科斗荒池可著鯤。", "直使頷鬚渾作白，未應投鑷愧諸孫。"]'),
('7cce6e82-12df-40eb-b552-1216faab6b83','敬酬智叔三賜之辱兼戲楊理曹二首  其二','陳師道','宋','宋诗','song-poetry','','[]','險韵廋詞費討論，真持布鼓過雷門。',64,'全唐诗/poet.song.62000.json','["險韵廋詞費討論，真持布鼓過雷門。", "更看九日臺頭句，未用三人月下樽。", "鏡裏黄花明白髮，海邊赤脚踏長鯤。", "從來相戒莫打鴨，可打鴛鴦最後孫。"]'),
('703785e6-3cad-4e84-acd3-d953abedda57','酬智叔見戲二首  其一','陳師道','宋','宋诗','song-poetry','','[]','百念皆空習尚存，稍修香火踏空門。',64,'全唐诗/poet.song.62000.json','["百念皆空習尚存，稍修香火踏空門。", "槌腰摩腹非春事，割愛投閑覆玉樽。", "白髮情多猶可染，驂鸞興盡却乘鯤。", "上界紛紛足官府，也容河鼓過天孫。"]'),
('66d00f61-24b9-419b-be0e-cc606d3b7ea0','酬智叔見戲二首  其二','陳師道','宋','宋诗','song-poetry','','[]','雨花風葉未宜春，私柳官渠白下門。',64,'全唐诗/poet.song.62000.json','["雨花風葉未宜春，私柳官渠白下門。", "每度清溪嘲短髮，時容使席近芳樽。", "雄蜂雌蝶元非偶，野馬游塵不佐鯤。", "若許成功當封賞，請看子子與孫孫。"]'),
('438f5cc5-314f-4ccf-a3d6-c303d7e97978','送智叔令咸平','陳師道','宋','宋诗','song-poetry','','[]','二謝將能事，重陽只故臺。',48,'全唐诗/poet.song.62000.json','["二謝將能事，重陽只故臺。", "固須衝節去，便恐带秋回。", "敏捷才無盡，鋪張意有開。", "猶須記衰疾，書與雁同來。"]'),
('8d7d2248-2f25-4a2a-992c-9a8c4726932f','九月八日夜雨留智叔','陳師道','宋','宋诗','song-poetry','','[]','騎臺九日登臨處，只有歸人醉扶路。',64,'全唐诗/poet.song.62000.json','["騎臺九日登臨處，只有歸人醉扶路。", "千年二謝孰可代，我每苦留君只去。", "花粗且爲前人惜，曲誤不解丞卿怒。", "只消著帽受西風，不待風流到新句。"]'),
('3805e3df-024a-407e-b1b9-ab04672600a9','九日與智叔鵰堂宴集夜歸','陳師道','宋','宋诗','song-poetry','','[]','鵰堂從昔有惡客，酒盡不去仍復索。',64,'全唐诗/poet.song.62000.json','["鵰堂從昔有惡客，酒盡不去仍復索。", "欲留歌舞盡客意，風雨和更作三厄。", "佳辰難得客更難，我窮無酒爲君歡。", "只欲泥行過白下，萬一簾疏見一斑。"]'),
('f446a847-b6ef-4bdb-91c2-6ec3dce81f23','城南夜歸寄趙大夫','陳師道','宋','宋诗','song-poetry','','[]','書生作意一斑足，杜陵據鞍兩眼寒。',32,'全唐诗/poet.song.62000.json','["書生作意一斑足，杜陵據鞍兩眼寒。", "風雨喚人歸去好，免教街吏報平安。"]'),
('dafd90df-8c76-43d5-a723-7fd785b8ef38','席上勸客酒','陳師道','宋','宋诗','song-poetry','','[]','稍開襟抱使心寬，大放酒腸須盞乾。',32,'全唐诗/poet.song.62000.json','["稍開襟抱使心寬，大放酒腸須盞乾。", "珠簾十里城南道，肯作當年小杜看。"]'),
('99ab85f1-39f9-4177-bf18-7e43136dbfe6','戲寇君二首  其一','陳師道','宋','宋诗','song-poetry','','[]','杜老秋來眼更寒，蹇馿無復逐金鞍。',32,'全唐诗/poet.song.62000.json','["杜老秋來眼更寒，蹇馿無復逐金鞍。", "南鄰却有新歌舞，借與詩人一面看。"]'),
('6869a94c-2e64-44b7-9765-9cd5b4079d1f','戲寇君二首  其二','陳師道','宋','宋诗','song-poetry','','[]','南鄰歌舞隔牆聽，想對朝窗暈倒青。',32,'全唐诗/poet.song.62000.json','["南鄰歌舞隔牆聽，想對朝窗暈倒青。", "莫望喚人看娜嫋，只憑幽夢寄丁寧。"]'),
('51a31991-7797-423b-a718-a9a814e34dff','絕句四首  其一','陳師道','宋','宋诗','song-poetry','','[]','秋牀歸卧不緣愁，病與衰謀作老仇。',32,'全唐诗/poet.song.62000.json','["秋牀歸卧不緣愁，病與衰謀作老仇。", "數樹直青能爾瘦，一軒殘照爲誰留。"]'),
('162b7f34-860c-44dd-8522-56653bf3e309','絕句四首  其二','陳師道','宋','宋诗','song-poetry','','[]','芒鞋竹杖最關身，散髮披衣不待人。',32,'全唐诗/poet.song.62000.json','["芒鞋竹杖最關身，散髮披衣不待人。", "三兩作鄰堪共活，五千插架未爲貧。"]'),
('94846b25-7c1d-4ac8-b77c-c3b565558d78','絕句四首  其三','陳師道','宋','宋诗','song-poetry','','[]','昏昏嗜睡元非病，續續題詩不耐閑。',32,'全唐诗/poet.song.62000.json','["昏昏嗜睡元非病，續續題詩不耐閑。", "作意買山還得笑，多方拔白却成斑。"]'),
('d376a198-d45e-4f74-ba1a-ded5ee377699','絕句四首  其四','陳師道','宋','宋诗','song-poetry','','["\u54f2\u7406", "\u4eba\u751f", "\u611f\u53f9"]','書當快意讀易盡，客有可人期不來。',32,'全唐诗/poet.song.62000.json','["書當快意讀易盡，客有可人期不來。", "世事相違每如此，好懷百歲幾回開。"]'),
('cbb9c559-55f1-4547-9363-1b6934fe8dd1','騎馿二首  其一','陳師道','宋','宋诗','song-poetry','','[]','復作騎馿不跨馿，此生斷酒未須扶。',32,'全唐诗/poet.song.62000.json','["復作騎馿不跨馿，此生斷酒未須扶。", "獨無錦里驚人句，也得梁園畫作圖。"]'),
('40e6e272-e43a-42a0-9344-8227488d15ff','騎馿二首  其二','陳師道','宋','宋诗','song-poetry','','[]','衝籬突市不逡巡，掠面驚風撲眼塵。',32,'全唐诗/poet.song.62000.json','["衝籬突市不逡巡，掠面驚風撲眼塵。", "出手推敲寧避尹，題門吟詠不逢人。"]'),
('73153aa9-865e-4c08-980a-6b7a60e58ece','壽安縣君挽詞','陳師道','宋','宋诗','song-poetry','','[]','兩大推平日，三從播後聲。',48,'全唐诗/poet.song.62000.json','["兩大推平日，三從播後聲。", "憂勤登上壽，簫鼓閉佳城。", "緦布千人從，松楸十里行。", "哀榮動鄰里，點筆競諸生。"]'),
('42fa9eb4-a36b-4a01-a8f5-29ed8936515f','寄曹州晁大夫','陳師道','宋','宋诗','song-poetry','','[]','墮絮隨風花作塵，黄樓桃李不成春。',32,'全唐诗/poet.song.62000.json','["墮絮隨風花作塵，黄樓桃李不成春。", "只今容有名駒子，困倚欄干一欠伸。"]'),
('6cef7fb9-2d2c-4862-90fa-6b0d63d08d36','寄題披雲樓','陳師道','宋','宋诗','song-poetry','','[]','使君高會答清秋，增飾披雲作勝游。',64,'全唐诗/poet.song.62000.json','["使君高會答清秋，增飾披雲作勝游。", "九日再逢堪一笑，終朝百過更深憂。", "落霞孤鶩知才盡，疏雨微雲怯語遒。", "賓主縱賢終少在，只今未可壓黄樓。"]'),
('bfafef03-e149-42c9-aaa7-2e29c812ab85','絕句','陳師道','宋','宋诗','song-poetry','','[]','木搖電繞雷取龍，伏蛙號蚓溝瀆空。',32,'全唐诗/poet.song.62000.json','["木搖電繞雷取龍，伏蛙號蚓溝瀆空。", "黑雲黄槐度白鳥，映日急雨回斜風。"]'),
('44f3ba00-c625-49ae-be7e-b9303838198b','寄黄充','陳師道','宋','宋诗','song-poetry','','[]','俗子推不去，可人費招呼。',96,'全唐诗/poet.song.62000.json','["俗子推不去，可人費招呼。", "世事每如此，我生亦何娛。", "黄生後來秀，純茂靜者徒。", "不見動經月，來亦不須臾。", "人事已好乖，可復自作疏。", "子雖向人懶，勝處不可孤。", "迨此田事休，仍當寒雨餘。", "深知阻泥濘，步屐意何如。"]'),
('f5103435-6f71-4498-817b-3273fd65efec','寄張大夫','陳師道','宋','宋诗','song-poetry','','[]','只應青眼老，尚記白頭翁。',48,'全唐诗/poet.song.62000.json','["只應青眼老，尚記白頭翁。", "一別今何向，三年信不通。", "不應書字倦，未有北來鴻。", "肯作彭城守，何時馬首東。"]'),
('db4d7f30-4d25-478f-bfcf-552c808bb623','懷遠','陳師道','宋','宋诗','song-poetry','','[]','海外三年謫，天南萬里行。',48,'全唐诗/poet.song.62000.json','["海外三年謫，天南萬里行。", "生前只爲累，身後更須名。", "未得平安報，空懷故舊情。", "斯人有如此，無復涕縱橫。"]'),
('abce612e-3b11-4d68-a93b-12e380fb2329','答田生','陳師道','宋','宋诗','song-poetry','','[]','酒亦有何好，人今不肯忘。',48,'全唐诗/poet.song.62000.json','["酒亦有何好，人今不肯忘。", "苟無愁可解，何必醉爲鄉。", "剩欲論奇字，終能諱祕方。", "直饒肌骨秀，正要畫眉長。"]'),
('90af6bf7-aea1-4665-aabd-b3e8f6cafd7a','早起','陳師道','宋','宋诗','song-poetry','','[]','鄰雞接響作三鳴，殘點連聲殺五更。',64,'全唐诗/poet.song.62000.json','["鄰雞接響作三鳴，殘點連聲殺五更。", "寒氣挾霜侵敗絮，賓鴻將子度微明。", "有家無食違高枕，百巧千窮只短檠。", "翰墨日疏身日遠，世間安得尚虛名。"]'),
('b113795b-bfdc-43ae-a84d-e49709f6379b','和黄充小雪','陳師道','宋','宋诗','song-poetry','','[]','度臘侵春亦未遲，紛紛款款意猶微。',64,'全唐诗/poet.song.62000.json','["度臘侵春亦未遲，紛紛款款意猶微。", "霑衣带潤元無見，著物還消不待晞。", "剩欲打窗連夜聽，未須迷雁斷行飛。", "老年才盡無新語，只欲煩君急手揮。"]'),
('a5dc6fba-60cf-4e39-9d4f-7bdd8feafcf9','寄張學士','陳師道','宋','宋诗','song-poetry','','[]','湖海三年別，譙徐一日間。',48,'全唐诗/poet.song.62000.json','["湖海三年別，譙徐一日間。", "經時猶未見，凡事信多艱。", "理極那須說，情生不自還。", "從來闕聲問，相見若爲顔。"]'),
('adce2c16-daea-4d23-9852-832a7b769534','謝趙使君','陳師道','宋','宋诗','song-poetry','','[]','欲落未落雪迫人，將盡不盡冬壓春。',96,'全唐诗/poet.song.62000.json','["欲落未落雪迫人，將盡不盡冬壓春。", "風枝冰瓦有去鳥，遠坊窮巷無來人。", "忽聞叩門聲遽速，驚雞透籬犬升屋。", "使君傳教賜薪炭，妓圍那解思寒谷。", "老身曲直不足云，冷窗凍壁作春溫。", "定知和氣家家到，不獨先生席作門。"]'),
('66aa9a2c-0961-415b-a9b8-4f3f5f92b08d','雪中寄魏衍','陳師道','宋','宋诗','song-poetry','','[]','薄薄初經眼，輝輝已映空。',48,'全唐诗/poet.song.62000.json','["薄薄初經眼，輝輝已映空。", "融泥還結凍，落木復沾叢。", "意在千山表，情生一念中。", "遥知吟榻上，不道絮因風。"]'),
('1b10b1ac-8ddc-4057-bb74-26775e097390','送澶州錄曹宋參軍','陳師道','宋','宋诗','song-poetry','','[]','宦游男子事，訪別故人情。',48,'全唐诗/poet.song.62000.json','["宦游男子事，訪別故人情。", "能吏于今少，春風及此行。", "英雄餘戰伐，犴獄寄廉平。", "未肯輕衰疾，人來闕寄聲。"]'),
('f4b4c562-58fd-47ad-b0ff-47fab332111d','和范教授同游桓山','陳師道','宋','宋诗','song-poetry','','[]','送客尋山已自仙，行談坐笑復忘年。',64,'全唐诗/poet.song.62000.json','["送客尋山已自仙，行談坐笑復忘年。", "平郊走馬斜陽裏，破屋傳杯積水邊。", "洗壁題名留歲月，登高著句記山川。", "風流幕下諸公子，縮手吟邊更覺賢。"]'),
('f1d1c9c0-1a83-45c7-afb0-ce8d6faff421','答寄魏衍','陳師道','宋','宋诗','song-poetry','','[]','往昔敦朋好，猶能作報書。',48,'全唐诗/poet.song.62000.json','["往昔敦朋好，猶能作報書。", "老衰渾得懶，疏密略相如。", "名墮網中蝶，身隨冰下魚。", "填門車馬客，左席爲君虛。"]'),
('38204e20-827a-40b1-ac0b-333503cef5cf','早春','陳師道','宋','宋诗','song-poetry','','[]','度臘不成雪，迎年遽得春。',48,'全唐诗/poet.song.62000.json','["度臘不成雪，迎年遽得春。", "冰開還舊淥，魚喜躍脩鱗。", "柳及年年發，愁隨日日新。", "老懷吾自異，不是故違人。"]'),
('bf3ea304-7b3d-4d8c-8d9d-a4332f71880f','徐僊書三首  其一','陳師道','宋','宋诗','song-poetry','','[]','蓬壺仙子補天手，筆妙詩清萬世功。',32,'全唐诗/poet.song.62000.json','["蓬壺仙子補天手，筆妙詩清萬世功。", "肯學黄家元祐脚，信知人厄匪天窮。"]'),
('331eb364-a517-4ea3-b103-e9ec3ef76b68','徐僊書三首  其二','陳師道','宋','宋诗','song-poetry','','[]','詩成已作客兒語，筆下還爲魯直書。',32,'全唐诗/poet.song.62000.json','["詩成已作客兒語，筆下還爲魯直書。", "豈是神仙未賢聖，不隨時事向人疏。"]'),
('61bd978c-36c1-4948-ba6c-50e814f8707a','徐僊書三首  其三','陳師道','宋','宋诗','song-poetry','','[]','金華牧羊小家子，西真攘桃何代兒。',32,'全唐诗/poet.song.62000.json','["金華牧羊小家子，西真攘桃何代兒。", "詩著海山書落爪，向來那免世人疑。"]'),
('418e01d4-333d-40c7-97f9-ed877843e538','寄酬咸平朱宣德','陳師道','宋','宋诗','song-poetry','','[]','冥冥超世網，蔚蔚秀儒林。',48,'全唐诗/poet.song.62000.json','["冥冥超世網，蔚蔚秀儒林。", "他日熟看面，今詩初得心。", "白頭無故意，異代有同音。", "綆短徒施巧，終然莫汲深。"]'),
('1b39a5a0-dd7f-455c-b896-da0b5a41ebb8','咸平讀書堂','陳師道','宋','宋诗','song-poetry','','[]','昔人三百篇，善世已有余。',216,'全唐诗/poet.song.62000.json','["昔人三百篇，善世已有余。", "後生守章句，不足供囁嚅。", "一登吏部選，筆硯隨掃除。", "閉閤畫眉嫵，隔屋聞歌呼。", "奉公用漢律，寧復要詩書。", "俛首出跨下，枉此七尺軀。", "今代陶朱公，不作大梁屠。", "計然特未用，意得輕全吳。", "爲邦得畿縣，政密自計疏。", "寧書下下考，不奉急急符。", "用意簿領外，築室課典謨。", "平生五千卷，還舍不問塗。", "近事更漢唐，稍以詩自娛。", "復作無事飲，醉卧擁青奴。", "桃李春事繁，軒窗晝景舒。", "鳴屋鳩渴雨，窺簾燕哺鶵。", "休吏散篇帙，風篁獻笙竽。", "听然一啟齒，斯民免爲魚。"]'),
('055abd70-ecf8-4d12-8d09-0e267a5819d1','絕句二首  其一','陳師道','宋','宋诗','song-poetry','','[]','里中餽杏得嘗新，馬上逢花始見春。',32,'全唐诗/poet.song.62000.json','["里中餽杏得嘗新，馬上逢花始見春。", "勤苦著書如作吏，世間枉是最閑人。"]'),
('37c1b53f-e86e-4527-b75b-3e2ce68d3aaa','絕句二首  其二','陳師道','宋','宋诗','song-poetry','','[]','密密丹房疊疊花，一枝臨路爲人斜。',32,'全唐诗/poet.song.62000.json','["密密丹房疊疊花，一枝臨路爲人斜。", "丁寧語鳥傳春意，白下門東第幾家。"]'),
('edc0233f-628c-4c07-a7cb-43d5dd9b3024','春懷示鄰里','陳師道','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u751f\u6d3b", "\u5b8b\u8bd7"]','斷牆著雨蝸成字，老屋無僧燕作家。',64,'全唐诗/poet.song.62000.json','["斷牆著雨蝸成字，老屋無僧燕作家。", "剩欲出門追語笑，却嫌歸鬢著塵沙。", "風翻珠網開三面，雷動蜂窠趁兩衙。", "屢失南鄰春事約，只今容有未開花。"]'),
('d525c79a-6b2a-4f3b-bc9d-d9c6a0962ed4','歸雁二首  其一','陳師道','宋','宋诗','song-poetry','','[]','弧矢千夫志，瀟湘萬里秋。',48,'全唐诗/poet.song.62000.json','["弧矢千夫志，瀟湘萬里秋。", "寧爲寶箏柱，肯作置書郵。", "遠道勤相喚，羈懷誤作愁。", "聊寬稻粱意，寧復網羅憂。"]'),
('14b90c03-44e7-4553-82fd-0ba108f270fc','歸雁二首  其二','陳師道','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','作計胸懷早，爲生去住頻。',48,'全唐诗/poet.song.62000.json','["作計胸懷早，爲生去住頻。", "固違陰嶺雪，不盡洞庭春。", "巧作斜行字，催歸去國人。", "知時如有信，决起亦相親。"]'),
('374d8f8c-cd63-4a3b-bd29-7ebeb2dc3688','和寇十一晚登白門','陳師道','宋','宋诗','song-poetry','','[]','重門傑觀屹相望，表裏河山自一方。',64,'全唐诗/poet.song.62000.json','["重門傑觀屹相望，表裏河山自一方。", "小市張燈歸意動，輕衫當戶晚風長。", "孤臣白首逢新政，遊子青春見故鄉。", "富貴本非吾輩事，江湖安得便相忘。"]'),
('8d69c369-a1ab-4643-a707-ddd0e6ae7194','謝寇十一惠端硯','陳師道','宋','宋诗','song-poetry','','[]','百工營材先利器，市道居貨如作贅。',256,'全唐诗/poet.song.62000.json','["百工營材先利器，市道居貨如作贅。", "書生活計亦酸寒，斷塼半瓦寧求備。", "端溪四山下龍淵，鬰積中州清淑氣。", "金聲玉骨石爲容，河江屈流雲作使。", "滑如女膚色馬肝，夜半神光際天地。", "諸天散花百神喜，知有聖人當出世。", "沒人投深索千丈，探頷適遭龍伯睡。", "轆轤挽出萬人賀，千歲之藏一朝致。", "琢爲時樣供翰墨，十襲包藏百金貴。", "北行萬里更衆目，寇卿好事不計費。", "南鄰居士卿之孫，豐悴相從不爲異。", "似憐陶瓦磨竈煤，輟贈不減前人志。", "人言寒士莫作事，鬼奪客偷天破碎。", "龜玉韞匵與無同，錦衾還客棄佳惠。", "衆所欲得當有緣，天獨於余可無意。", "敢書細字注魚蟲，要傳華嚴八千偈。"]'),
('5be3e1c4-5b3d-4801-9a59-5e046cbfdff9','再和寇十一二首  其一','陳師道','宋','宋诗','song-poetry','','[]','南山樓觀插穹蒼，林杪青燈出上方。',64,'全唐诗/poet.song.62000.json','["南山樓觀插穹蒼，林杪青燈出上方。", "形勝自如諸老逝，功名隨盡二流長。", "馬游從昔哀吾老，王粲當年賦異鄉。", "少日幻心今浄盡，多生綺語未全忘。"]'),
('97fbb515-a859-4bf4-a4dc-908f3e058c09','再和寇十一二首  其二','陳師道','宋','宋诗','song-poetry','','[]','與世相違孰自量，資身無策漫多方。',64,'全唐诗/poet.song.62000.json','["與世相違孰自量，資身無策漫多方。", "逢場作戲真呈拙，誤筆成蠅豈所長。", "名字不歸青史筆，形容終老白雲鄉。", "可須五斗輕千里，頼有斯人未肯忘。"]'),
('6a8a92a1-1860-42da-8553-795b2bdb88d1','與寇趙約丁塘看花寇以疾不赴有詩次其韵','陳師道','宋','宋诗','song-poetry','','[]','早年學苦斷過從，晚歲逢春意未窮。',64,'全唐诗/poet.song.62000.json','["早年學苦斷過從，晚歲逢春意未窮。", "欲共元劉爭著語，不堪姚魏已隨風。", "坐無上客席虛左，贈有英詞囊不空。", "障日長須釣竿手，歸來無計駐青驄。"]'),
('0fd62359-9e56-4a18-be82-31061f222fbf','和寇十一同游城南阻雨還登寺山','陳師道','宋','宋诗','song-poetry','','[]','雨阻游南步，泥留逐北情。',48,'全唐诗/poet.song.62000.json','["雨阻游南步，泥留逐北情。", "稍看飛霧斷，復作遠山橫。", "野潤膏新澤，樓明納晚晴。", "歸宜有佳思，紗帽壓香英。"]'),
('90c4869d-5abe-4c46-9d7a-e58f43352a8b','三月二十二日榴花盛開戲作絕句','陳師道','宋','宋诗','song-poetry','','[]','五月榴花忽見春，白頭喜遇一番新。',32,'全唐诗/poet.song.62000.json','["五月榴花忽見春，白頭喜遇一番新。", "可能略不解春意，只有尋枝摘葉人。"]'),
('7b62c209-4635-46bb-8375-759480528ca4','和寇十一雨後登樓','陳師道','宋','宋诗','song-poetry','','[]','秀嶺歸雲裏，華譙夕照中。',48,'全唐诗/poet.song.62000.json','["秀嶺歸雲裏，華譙夕照中。", "登臨終不數，吟笑近多同。", "麥秀知春力，人和驗歲豐。", "預爲逃暑約，一快楚臺風。"]'),
('e9ca5e22-f4c2-4378-8b06-4e91b157285f','答寇十一惠朱櫻','陳師道','宋','宋诗','song-poetry','','[]','故人憐一老，輟食寄三山。',48,'全唐诗/poet.song.62000.json','["故人憐一老，輟食寄三山。", "厚味非貧具，先嘗愧客閑。", "甘酸俱可口，衰白不宜顔。", "句妙那能繼，情深未覺慳。"]'),
('35a7433f-2199-4aed-8df8-c14bece6e7ba','雙櫻','陳師道','宋','宋诗','song-poetry','','[]','並蔕隨宜好，連心著意紅。',24,'全唐诗/poet.song.62000.json','["並蔕隨宜好，連心著意紅。", "只堪驚老眼，持此與誰同。"]'),
('99fb850a-4c56-4515-90b1-357f2a8ba86f','謝趙生惠芍藥三首  其一','陳師道','宋','宋诗','song-poetry','','[]','郁郁芬芬十里薰，紅紅白白數枝春。',32,'全唐诗/poet.song.62000.json','["郁郁芬芬十里薰，紅紅白白數枝春。", "要將結習惱鶖子，送與毗耶彼上人。"]'),
('a42a0d63-7182-49d0-9997-ebe9193d15aa','謝趙生惠芍藥三首  其二','陳師道','宋','宋诗','song-poetry','','[]','從微至老走風塵，喜見鄉園第四春。',32,'全唐诗/poet.song.62000.json','["從微至老走風塵，喜見鄉園第四春。", "獨舞東風醉西子，政緣無語却宜人。"]'),
('50bbd241-7ec0-4dd4-91da-107a8ea6fd1f','謝趙生惠芍藥三首  其三','陳師道','宋','宋诗','song-poetry','','[]','九十風光次第分，天憐獨得殿殘春。',32,'全唐诗/poet.song.62000.json','["九十風光次第分，天憐獨得殿殘春。", "一枝剩欲簪雙髻，未有人間第一人。"]'),
('3eb0efdc-cfaa-4cc7-a0e9-08ed4be2ecc6','寄憐','陳師道','宋','宋诗','song-poetry','','[]','借子翩翩果下駒，春原隨處小踟躕。',32,'全唐诗/poet.song.62000.json','["借子翩翩果下駒，春原隨處小踟躕。", "可能炙背春風裏，卧把青銅摘頷鬚。"]'),
('e80a6e9d-a4cb-4498-b23a-b600a60035c7','寄寇十一','陳師道','宋','宋诗','song-poetry','','[]','鄰里相望信不通，時因得句寄匆匆。',64,'全唐诗/poet.song.62000.json','["鄰里相望信不通，時因得句寄匆匆。", "畫樓著燕薰風裏，楊柳藏鴉白下東。", "度日守窗令節換，經旬無使覺門空。", "錦囊佳麗鄰徐庾，剩欲同君賦惱公。"]'),
('7c4002c8-cb0b-4c34-abda-ffe0f6be8a8c','和酬魏衍','陳師道','宋','宋诗','song-poetry','','[]','闕然聲問略相同，百里之間一水通。',64,'全唐诗/poet.song.62000.json','["闕然聲問略相同，百里之間一水通。", "春興多多高紙價，愁懷一一逐歸鴻。", "不憂寒餓成吾老，稍喜朝廷記此公。", "夢每見君心已了，不因新句覺情東。"]'),
('72a625b1-74fe-4f43-b61b-c39df9efb4df','觸目','陳師道','宋','宋诗','song-poetry','','[]','果下翩翩跨紫騮，踏花濺水見風流。',32,'全唐诗/poet.song.62000.json','["果下翩翩跨紫騮，踏花濺水見風流。", "可無雙璧千金聚，付與狂兒取次遊。"]'),
('4eaba423-e517-4a7a-a654-acbec200732d','鉅野泊觸事','陳師道','宋','宋诗','song-poetry','','[]','蒲巷牽絲直，平湖墜鏡清。',48,'全唐诗/poet.song.62000.json','["蒲巷牽絲直，平湖墜鏡清。", "順流風借便，捷路雪初晴。", "鳥度欲何向，鷗來只自驚。", "有行須快意，安得易爲情。"]'),
('08254d85-454e-40aa-973e-fa9818b9cf07','元符三年七月蒙恩復除棣學喜而成詩','陳師道','宋','宋诗','song-poetry','','[]','老作諸侯客，貧爲一飽謀。',48,'全唐诗/poet.song.62000.json','["老作諸侯客，貧爲一飽謀。", "折腰真耐辱，捧檄敢輕投。", "早作千年調，中懷萬斛愁。", "暮年隨手盡，心事許溟鷗。"]'),
('672c2530-3797-49e6-8ec3-b17c0f0223e1','送姚先生歸宜山三首  其一','陳師道','宋','宋诗','song-poetry','','[]','鄭公龍變不容親，猶有先生不絕塵。',32,'全唐诗/poet.song.62000.json','["鄭公龍變不容親，猶有先生不絕塵。", "定力不爲生死動，始知天地有閑人。"]'),
('e25ca67a-b5cf-4311-8641-4c02e945f3dd','送姚先生歸宜山三首  其二','陳師道','宋','宋诗','song-poetry','','[]','老逢熙運乞前官，病遇先生得內丹。',32,'全唐诗/poet.song.62000.json','["老逢熙運乞前官，病遇先生得內丹。", "一飽有期吾事了，千年不死後人看。"]'),
('699eb7da-3610-45b0-be78-35c3e1fa98e2','送姚先生歸宜山三首  其三','陳師道','宋','宋诗','song-poetry','','[]','宇定心清面發丹，下牀投杖覺輕安。',32,'全唐诗/poet.song.62000.json','["宇定心清面發丹，下牀投杖覺輕安。", "此身已許壺丘子，他日爭尋靖長官。"]'),
('286f852f-af9b-4ede-9b1c-d534b603deb6','上趙使君','陳師道','宋','宋诗','song-poetry','','[]','老氣崢嶸蓋九州，治聲騰湧逐雙流。',64,'全唐诗/poet.song.62000.json','["老氣崢嶸蓋九州，治聲騰湧逐雙流。", "向來置醴蒙殊遇，此日彈冠愧少留。", "千里山連環故國，中秋月好傍黄樓。", "不應爲米輕鄉里，定復還從馬少游。"]'),
('2de9dde9-4539-44ad-896c-d4ad24edc2eb','送鄭祠部','陳師道','宋','宋诗','song-poetry','','[]','持節還家未白頭，有親八十更何求。',64,'全唐诗/poet.song.62000.json','["持節還家未白頭，有親八十更何求。", "又須急詔登天去，不爲寒鄉盡歲留。", "四著儒冠甘送老，數經奇運得銷憂。", "擬登碣石臨朝日，浩蕩滄溟沒白鷗。"]'),
('232006c9-a673-4df8-b7db-4bfadb4b80c9','和寇十一同登寺山','陳師道','宋','宋诗','song-poetry','','[]','度暑無好懷，憑危略幽致。',144,'全唐诗/poet.song.62000.json','["度暑無好懷，憑危略幽致。", "衣冠蔚如林，從我才一二。", "茲山昔深登，歲月誰得記。", "尚有名勝流，不與金石悴。", "孰知千載後，我與子復至。", "煙昏倏見燈，洪發恐無地。", "領略章句手，割據英雄志。", "興壞容一瞬，今昔當幾喟。", "圍山缺西北，放目不可制。", "歸懷納清境，夜榻成良寐。", "零落壁間詩，豈特彼所愧。", "會逢南過適，不問西來意。"]'),
('86f00d34-e1c5-454e-ba4e-983081b64792','謝孫奉職惠胡德墨','陳師道','宋','宋诗','song-poetry','','[]','奚李風流盡，法傳外諸孫。',120,'全唐诗/poet.song.62000.json','["奚李風流盡，法傳外諸孫。", "常山陳贍子，懷抱自高攑。", "孰云勝潘翁，惟眉山公言。", "四海未盡試，一變歸九原。", "胡郎少年子，外家典刑存。", "一點落髹漆，重價壓璵璠。", "孫侯磊落人，情義久益惇。", "解囊贈玄圭，孰知師白猿。", "我資不解書，下筆輒自喛。", "良寶不受辱，默默面稱冤。"]'),
('3789314c-ca72-4fd3-bf85-d81c02d18891','登寺山','陳師道','宋','宋诗','song-poetry','','[]','晴山堪著眼，別意不勝秋。',48,'全唐诗/poet.song.62000.json','["晴山堪著眼，別意不勝秋。", "小作三年別，聊爲五斗謀。", "要須乘下澤，不待到壺頭。", "預恐登臨處，長思馬少游。"]'),
('898d282a-d03d-4dee-b433-c100778611bb','拱翠亭','陳師道','宋','宋诗','song-poetry','','[]','千年茅竹蔽幽奇，一日堂成四海知。',64,'全唐诗/poet.song.62000.json','["千年茅竹蔽幽奇，一日堂成四海知。", "便有文公來作記，尚須吾輩與題詩。", "至人但有經行處，寶蓋仍存朽老枝。", "能事向來非促迫，經年安得便嫌遲。"]'),
('48711a30-af9e-4f7d-888c-7c78eb4ef3a1','贈田從先','陳師道','宋','宋诗','song-poetry','','[]','衣冠魯國動成羣，憂患相從只有君。',64,'全唐诗/poet.song.62000.json','["衣冠魯國動成羣，憂患相從只有君。", "落筆如流寧蹈襲，行前應敵却紛紜。", "愧非伏老成和伯，喜有侯芭守子雲。", "意氣有餘功用少，相望千里定能勤。"]'),
('9119d587-e22a-4b52-a58f-6e0d7b513c93','別鄉舊','陳師道','宋','宋诗','song-poetry','','[]','數有中年別，寬爲滿歲期。',48,'全唐诗/poet.song.62000.json','["數有中年別，寬爲滿歲期。", "得無魚口厄，聊復雁門踦。", "齒脫心猶壯，秋清意自悲。", "平時郡文學，鄧禹得三爲。"]'),
('724ae8bf-768a-4a34-901a-9389b5895417','和李使君九日登戲馬臺','陳師道','宋','宋诗','song-poetry','','[]','登高能賦屬吾儕，不用傳杯擊鉢催。',64,'全唐诗/poet.song.62000.json','["登高能賦屬吾儕，不用傳杯擊鉢催。", "九日風光堪落帽，中年懷抱更登臺。", "江山信美因人勝，萸菊逢辰滿意開。", "二謝風流今復見，千年留句待公來。"]'),
('0d56c537-81e4-46f1-8c48-b338ff200c42','與魏衍寇國寶田從先二姪分韵得坐字','陳師道','宋','宋诗','song-poetry','','[]','將老蒙誤恩，受弔不受賀。',144,'全唐诗/poet.song.62000.json','["將老蒙誤恩，受弔不受賀。", "欲起尚遲回，積閑習成惰。", "向來二三子，相與守寒餓。", "一日不可無，三歲安得過。", "是時秋益高，夜永月初破。", "漏鼓已再更，坐者餘幾箇。", "酒薄多可强，談勝堅莫破。", "簷昏讀字細，林缺瞻星大。", "吳吟未至慢，楚語不假些。", "懷遠已屢歎，論昔先急唾。", "身世喜相違，真成螘旋磨。", "平生陳孟公，歲晚不驚坐。"]'),
('bf9f0e95-6322-4b41-b011-2481e14c3d41','和黄充出游三首  其一','陳師道','宋','宋诗','song-poetry','','[]','右坊左里遠相求，東度南登稱意游。',32,'全唐诗/poet.song.62000.json','["右坊左里遠相求，東度南登稱意游。", "已著連峰妨目極，不應疾雨使心休。"]'),
('af7c34a6-b577-432f-806a-e4648c5dcc28','和黄充出游三首  其二','陳師道','宋','宋诗','song-poetry','','[]','諸郎聯璧萬人看，新有詩聲伯仲間。',32,'全唐诗/poet.song.62000.json','["諸郎聯璧萬人看，新有詩聲伯仲間。", "作意登臨還得句，此生寧復要長閑。"]'),
('c89dce43-5cc8-405e-abd8-582867132332','和黄充出游三首  其三','陳師道','宋','宋诗','song-poetry','','[]','剩欲登臨强作歡，衣冠未動意先闌。',32,'全唐诗/poet.song.62000.json','["剩欲登臨强作歡，衣冠未動意先闌。", "從今泉石非吾事，只借君詩細細看。"]'),
('1ff1b9b9-6cbf-4c41-a910-c953eb567a85','盤馬山','陳師道','宋','宋诗','song-poetry','','[]','耕桑戰伐飽曾經，廟毀村荒不乞靈。',32,'全唐诗/poet.song.62000.json','["耕桑戰伐飽曾經，廟毀村荒不乞靈。", "尚有君王盤馬跡，至今草木不能青。"]'),
('f986ac5b-f773-43c7-a04c-277b0e7af580','爛石村','陳師道','宋','宋诗','song-poetry','','[]','亂石何年爛，千林昨夜黄。',48,'全唐诗/poet.song.62000.json','["亂石何年爛，千林昨夜黄。", "曉耕來鳥雀，麥壠縱牛羊。", "投老須微祿，持身闕寸長。", "洗心聞吉語，時事信難量。"]'),
('5b988a82-5bcb-4610-b4e7-629c43840bc0','別叔父崑山丞','陳師道','宋','宋诗','song-poetry','','[]','父子兼知己，扶携共白頭。',48,'全唐诗/poet.song.62000.json','["父子兼知己，扶携共白頭。", "又爲千里別，未使寸心休。", "鳥雀空庭曉，風霜落木秋。", "近親零落盡，更覺別離愁。"]'),
('d9e89ad0-9574-403a-aaa8-521e85c972de','從寇生求茶庫紙','陳師道','宋','宋诗','song-poetry','','[]','南朝官紙女兒膚，玉版雲英比不如。',32,'全唐诗/poet.song.62000.json','["南朝官紙女兒膚，玉版雲英比不如。", "乞與此翁元不稱，他年留待大蘇書。"]'),
('b31395e2-49e8-4479-9a03-86c2b895dda2','黄樓','陳師道','宋','宋诗','song-poetry','','[]','樓上當當徹夜聲，與人何事有枯榮。',32,'全唐诗/poet.song.62000.json','["樓上當當徹夜聲，與人何事有枯榮。", "已傳紙貴咸陽市，更恐書留後世名。"]'),
('44e398a6-eb19-4b89-9c7d-8850828a8489','酬顔生惠茶庫紙','陳師道','宋','宋诗','song-poetry','','[]','破卵剝膜肌理滑，削玉作版光氣熏。',32,'全唐诗/poet.song.62000.json','["破卵剝膜肌理滑，削玉作版光氣熏。", "老子尚堪哦七字，阿買頗能書八分。"]'),
('b47b618f-4a32-4e88-81bb-d0dccb026b4d','黄樓','陳師道','宋','宋诗','song-poetry','','[]','樓以風流勝，情緣貴賤移。',48,'全唐诗/poet.song.62000.json','["樓以風流勝，情緣貴賤移。", "屏亡老畢篆，市發大蘇碑。", "更覺江山好，難忘父老思。", "只應千載後，覽古勝當時。"]'),
('ffaba545-46d3-41a3-9fae-bceac2d68384','答黄充','陳師道','宋','宋诗','song-poetry','','[]','我無置錐君立壁，舂黍作麋甘勝蜜。',64,'全唐诗/poet.song.62000.json','["我無置錐君立壁，舂黍作麋甘勝蜜。", "綈袍不受故人意，藥餌肯爲兒輩屈。", "割白鷺股何足難，食盧鷀肉未爲失。", "暮年五斗得千里，有愧寒簷背朝日。"]'),
('67caae7f-6e1e-4a3e-9389-928e91c05c9f','寒夜','陳師道','宋','宋诗','song-poetry','','[]','閉戶風將雨，通宵浪打頭。',48,'全唐诗/poet.song.62000.json','["閉戶風將雨，通宵浪打頭。", "若爲中夕聽，復作別時愁。", "宿雁鳴漁火，村舂急暗投。", "不應田二頃，能使寸心休。"]'),
('16c5308c-2db2-41ee-85e8-592680872c46','贈周秀才二首  其一','陳師道','宋','宋诗','song-poetry','','[]','與君世好自比鄰，豐悴相從久更親。',32,'全唐诗/poet.song.62000.json','["與君世好自比鄰，豐悴相從久更親。", "急棹小舟來取別，固知風味似前人。"]'),
('f3bc7849-21da-4efe-8dd2-b695fdd038b2','贈周秀才二首  其二','陳師道','宋','宋诗','song-poetry','','[]','早逢異人得異術，究考咎休出頃刻。',32,'全唐诗/poet.song.62000.json','["早逢異人得異術，究考咎休出頃刻。", "相逢拍手問由來，怪我今年有陰德。"]'),
('bcc8b821-48b6-4d5b-bbf9-3c650f028642','五子相送至湖陵','陳師道','宋','宋诗','song-poetry','','[]','中年患別多作別，早日諱窮常得窮。',128,'全唐诗/poet.song.62000.json','["中年患別多作別，早日諱窮常得窮。", "勿云一水四十里，衣冠塞郭何人同。", "周生子病輟身出，劉子遠來今幾日。", "石家仲叔好少年，頗能厭俗從吾律。", "魏君不獨相從早，自君之來吾却掃。", "歲月磨人孰能久，反覆看渠難得好。", "湖陵古城風日寒，情義乃知生別難。", "高懷已爲故人盡，交道應留後代看。"]'),
('4832899a-19a5-411b-90a9-22f3bbc22541','湖陵與劉生別','陳師道','宋','宋诗','song-poetry','','[]','觸寒歷險來特特，愧無以當欣有得。',64,'全唐诗/poet.song.62000.json','["觸寒歷險來特特，愧無以當欣有得。", "向來憂患不相捨，知子用心堅鐵石。", "人畏有心事無難，此語雖鄙理則然。", "君今意在翰墨間，他日人爭讓一先。"]'),
('9b771813-7890-47d3-b2ca-b2d69145d749','寄滕縣李奉議','陳師道','宋','宋诗','song-poetry','','[]','滕大夫伯陽父孫，烹小鮮治大國原。',136,'全唐诗/poet.song.62000.json','["滕大夫伯陽父孫，烹小鮮治大國原。", "一得何用五千言，弛災决獄人不冤。", "盛氣走訟畏討論，終歲斂吏不到門。", "子弟無頼皆西奔，外吏畏懼過乃尊。", "踵門父老如雲屯，拊髀跳踉走兒孫。", "絳幡翠節歌唄喧，畫盆戴頂煙如焚。", "繡褾綵軸箱帕繁，曲躬叉手前致言。", "畜眼未見耳不聞，暮年何以答此恩，請誦華嚴壽我君。"]'),
('ed197934-7c53-4401-9b47-806494d64972','住雁','陳師道','宋','宋诗','song-poetry','','[]','斷岸通橫水，枯荷著早霜。',48,'全唐诗/poet.song.62000.json','["斷岸通橫水，枯荷著早霜。", "一陂堪度歲，數雁不成行。", "市遠無繒繳，年豐足稻粱。", "中原有佳氣，不必到衡陽。"]'),
('2c16452f-15f8-4ef8-9857-6d5f463a7d48','寓目','陳師道','宋','宋诗','song-poetry','','[]','曲曲河回復，青青草接連。',48,'全唐诗/poet.song.62000.json','["曲曲河回復，青青草接連。", "去帆風力滿，來雁一聲先。", "野曠低歸鳥，江平進晚牽。", "望鄉從此始，留眼未須穿。"]'),
('8bdcde0e-43c8-403f-a43b-1aefd1b176e6','野望','陳師道','宋','宋诗','song-poetry','','[]','霜葉紅於染，吹花落更馨。',48,'全唐诗/poet.song.62000.json','["霜葉紅於染，吹花落更馨。", "平江行詰曲，小徑夾葱青。", "度鳥開愁眼，遥山入畫屏。", "畏人惟可飲，從俗却須醒。"]'),
('4f040f55-6df4-4907-b105-59ba556e38a4','寄單州呂侍講','陳師道','宋','宋诗','song-poetry','','[]','往時三呂共脩途，擬上青雲近玉除。',64,'全唐诗/poet.song.62000.json','["往時三呂共脩途，擬上青雲近玉除。", "中道勒回奔電足，今年還直邇英廬。", "縱談尚記華嚴夜，枉道難隨刺史車。", "遣興寬爲七字語，尋人聊代一行書。"]'),
('c5e9f409-09fe-466a-9b45-aee956ad72c8','寄沛縣姜承議','陳師道','宋','宋诗','song-poetry','','[]','平生魯國老先生，晚見諸郎識老成。',64,'全唐诗/poet.song.62000.json','["平生魯國老先生，晚見諸郎識老成。", "怪有武功蒙寵錫，果緣陰德貫神明。", "金池已作歸田計，玉版方書濟物情。", "百里饑寒獨顔闔，忍令一物不敷榮。"]'),
('52412f5b-53ff-4a29-bf38-9171976f92a2','寄兖州張龍圖文潛二首  其一','陳師道','宋','宋诗','song-poetry','','[]','去國遭前政，還家未白頭。',48,'全唐诗/poet.song.62000.json','["去國遭前政，還家未白頭。", "百年當晚遇，一辱獨先收。", "齒脫空餘舌，顔衰早著秋。", "三爲郡文學，大勝鄧元侯。"]'),
('f8f769e4-2c73-4c0e-a972-1bb6a4d3faca','寄兖州張龍圖文潛二首  其二','陳師道','宋','宋诗','song-poetry','','[]','剩喜開三面，旋聞乞一州。',48,'全唐诗/poet.song.62000.json','["剩喜開三面，旋聞乞一州。", "力難隨鳥翼，行復立螭頭。", "今日騏驎閣，當年鸚鵡洲。", "寄書愁不達，書達得無愁。"]'),
('4ed86e8c-65d9-4d4a-9a3c-1cb40074f230','晚立','陳師道','宋','宋诗','song-poetry','','[]','遶舍苔衣積，倚牆梨頰紅。',48,'全唐诗/poet.song.62000.json','["遶舍苔衣積，倚牆梨頰紅。", "地平宜落日，野曠自多風。", "禹跡千年後，家山一顧中。", "未休嗤土偶，已復逐飄蓬。"]'),
('9a9477d5-a8d7-4fae-a893-069effbce33b','寒夜','陳師道','宋','宋诗','song-poetry','','[]','一夜風澎浪，中宵月脫雲。',48,'全唐诗/poet.song.62000.json','["一夜風澎浪，中宵月脫雲。", "到窗資少睡，遠響倦多聞。", "星火遠相亂，江山氣不分。", "早雞先得便，斷雁屢鳴羣。"]'),
('08bbca23-c069-4cc4-a495-99328980aa02','雁二首  其一','陳師道','宋','宋诗','song-poetry','','[]','來往違寒暑，飛鳴在稻粱。',24,'全唐诗/poet.song.62000.json','["來往違寒暑，飛鳴在稻粱。", "未知溟海大，不肯過衡陽。"]'),
('78e3ac71-0da9-4d2d-8a81-520423edc0b6','雁二首  其二','陳師道','宋','宋诗','song-poetry','','[]','截水無留影，哀空有斷羣。',24,'全唐诗/poet.song.62000.json','["截水無留影，哀空有斷羣。", "翅開先作字，行斷不成文。"]'),
('65b6ba8e-bed5-4baf-92a9-1ca23a247760','山口','陳師道','宋','宋诗','song-poetry','','[]','重霧真成雨，疏簾不隔風。',48,'全唐诗/poet.song.62000.json','["重霧真成雨，疏簾不隔風。", "青林擁紅樹，家鶩雜賓鴻。", "漁屋渾環水，晴湖半落東。", "往來成一老，猶在半塗中。"]'),
('3bbbaa0c-06f3-4ab7-a245-c5f14da58a7a','晚泊','陳師道','宋','宋诗','song-poetry','','[]','清切臨風笛，深明隔水燈。',48,'全唐诗/poet.song.62000.json','["清切臨風笛，深明隔水燈。", "堆場穿鳥雀，暗溜入溝塍。", "年使扶行老，船催趁渡僧。", "茲遊恐未已，著句續先曾。"]'),
('fad582ba-8f20-4e1c-be3a-1fe683ef569c','夜雨','陳師道','宋','宋诗','song-poetry','','[]','十月天猶雨，三更月失明。',48,'全唐诗/poet.song.62000.json','["十月天猶雨，三更月失明。", "溟濛才灑潤，點滴不成聲。", "闢戶風煙入，投林鳥雀輕。", "旅懷終易感，倏起別離情。"]'),
('a32b751b-c6cd-4499-9fab-a1f43f362875','宿合清口','陳師道','宋','宋诗','song-poetry','','[]','風葉初疑雨，晴窗誤作明。',48,'全唐诗/poet.song.62000.json','["風葉初疑雨，晴窗誤作明。", "穿林出去鳥，舉棹有來聲。", "深渚魚猶得，寒沙雁自驚。", "卧家還就道，自計豈蒼生。"]'),
('eeab23a7-b753-431b-801d-b669fc226304','宿泊口','陳師道','宋','宋诗','song-poetry','','[]','弱柳經寒色，懸流盡夜聲。',48,'全唐诗/poet.song.62000.json','["弱柳經寒色，懸流盡夜聲。", "更長疑睡少，霜落怯寒生。", "急急占星度，搖搖苦舫傾。", "風濤兼盜賊，恩重覺身輕。"]'),
('91a0673d-7ee4-48d4-a44f-fc279da39dbc','野望','陳師道','宋','宋诗','song-poetry','','[]','山開兩岸柳，水遶數家村。',48,'全唐诗/poet.song.62000.json','["山開兩岸柳，水遶數家村。", "地勢傾崖口，風濤嚙石根。", "平林霜著色，沙岸水留痕。", "剩寄還鄉泣，難招去國魂。"]'),
('6bba23aa-15a0-48e8-8e96-ce09cbe216ab','宿柴城','陳師道','宋','宋诗','song-poetry','','[]','卧埋塵葉走風煙，齒豁頭童不記年。',64,'全唐诗/poet.song.62000.json','["卧埋塵葉走風煙，齒豁頭童不記年。", "起倒不供聊應俗，高低莫可只隨緣。", "鼕鼕遠鼓三行夜，隠隠平湖四接天。", "枕底濤波蓬上雨，故將羈老到愁邊。"]'),
('ce713274-d546-4029-8baa-61e28f614717','顔市阻風二首  其一','陳師道','宋','宋诗','song-poetry','','[]','水到西流闊，風從北極來。',48,'全唐诗/poet.song.62000.json','["水到西流闊，風從北極來。", "聲驅峽口坼，力拔嶺根摧。", "突兀重重浪，轟豗處處雷。", "順流看過舫，更著快帆催。"]'),
('deb9b545-faf9-44fc-8b05-682036dbe617','顔市阻風二首  其二','陳師道','宋','宋诗','song-poetry','','[]','萬古梁山泊，今年未掾船。',48,'全唐诗/poet.song.62000.json','["萬古梁山泊，今年未掾船。", "阻風兼著雪，費日亦忘年。", "世事元相忤，衰懷忍自煎。", "晚來聲更惡，始覺畏途邊。"]'),
('6917f627-60e0-4b3c-b2c4-b54a47f0ab67','晚坐','陳師道','宋','宋诗','song-poetry','','[]','柳弱留春色，梅寒讓雪花。',48,'全唐诗/poet.song.62000.json','["柳弱留春色，梅寒讓雪花。", "溪明數積石，月過戀平沙。", "病減還憎藥，年侵却累家。", "後歸棲未定，不但只昏鴉。"]'),
('49051ec9-bbbb-44be-8123-fd448780ffe8','寒夜','陳師道','宋','宋诗','song-poetry','','[]','留滯常思動，艱虞却悔來。',48,'全唐诗/poet.song.62000.json','["留滯常思動，艱虞却悔來。", "寒燈挑不燄，殘火撥成灰。", "凍水滴還歇，風簾掩復開。", "孰知文有忌，情至自生哀。"]'),
('567467b7-f3e8-4283-b9f8-c4087864b205','絕句','陳師道','宋','宋诗','song-poetry','','[]','雲海冥冥日向西，春風欲動意猶微。',32,'全唐诗/poet.song.62000.json','["雲海冥冥日向西，春風欲動意猶微。", "無端一棹歸舟疾，驚起鴛鴦相背飛。"]'),
('9d9769d9-c7c0-4e8e-a4f0-cf9f6f5513b6','禮武臺坐化僧','陳師道','宋','宋诗','song-poetry','','[]','至人本無心，起滅因衆緣。',264,'全唐诗/poet.song.62000.json','["至人本無心，起滅因衆緣。", "化盡悲願在，留形此臺顛。", "聞名與致敬，獲福皆無前。", "千年一鉢水，宿疾幾人痊。", "驍雄兖州軍，馬步餘數千。", "一呼可摧山，四合如垂天。", "老幼十八村，頃刻理無全。", "哀鳴寄香火，毀塔投其塼。", "盛怒忽驚奔，如有所見然。", "等觀同一子，豈特此所憐。", "我來已再見，童稚亦虔虔。", "發火觸暗室，青燈已娟妍。", "始讀壁間碑，妙力隠不傳。", "頗恨語未工，安得筆如椽。", "歸路雲月黑，濤波隔長川。", "溪翁停舟待，相喚聲相連。", "解纜風泊岸，中流水入船。", "欹側脚不停，竟脫蛟魚涎。", "興壞如有待，適當使君賢。", "定能選妙士，拂塵起熏煙。", "昔承靈山囑，早契少林禪。", "丐我一片石，併刻維摩篇。"]'),
('89108859-ace3-49d6-914f-2ca7fa9aa0e7','晚興','陳師道','宋','宋诗','song-poetry','','[]','去國猶能別，逢人始欲愁。',48,'全唐诗/poet.song.62000.json','["去國猶能別，逢人始欲愁。", "不干遮極目，自是怯回頭。", "布網收漁槮，連筒下釣鈎。", "誰初教鮮食，澤竭未能休。"]'),
('169b25f4-ee28-4b62-8e37-97e3a9af5cbd','宿齊河','陳師道','宋','宋诗','song-poetry','','[]','燭暗人初寂，寒生夜向深。',48,'全唐诗/poet.song.62000.json','["燭暗人初寂，寒生夜向深。", "潛魚聚沙窟，墜鳥滑霜林。", "稍作他方計，初回萬里心。", "還家只有夢，更著曉寒侵。"]'),
('070ef0e2-2026-4816-80cb-70d6fd4f2076','別劉郎','陳師道','宋','宋诗','song-poetry','','[]','一別已六載，相逢有餘哀。',48,'全唐诗/poet.song.62000.json','["一別已六載，相逢有餘哀。", "公私兩多事，災病百相催。", "無酒與君別，有懷向誰開。", "深知百里遠，肯爲老夫來。"]'),
('0c9145fd-3df4-451e-a5ee-844554354492','趙巖','陳師道','宋','宋诗','song-poetry','','[]','一市萬人聚，四衝千里遥。',48,'全唐诗/poet.song.62000.json','["一市萬人聚，四衝千里遥。", "胡然不作邑，兼自可成橋。", "羣盜去無跡，諸家壓不驕。", "由來天下事，浮議易傾搖。"]'),
('8117c2c7-1794-4502-9f37-a2f5fb79be79','雞籠鎮','陳師道','宋','宋诗','song-poetry','','[]','河市新經集，雞籠舊得名。',48,'全唐诗/poet.song.62000.json','["河市新經集，雞籠舊得名。", "初聞北人語，意作故鄉聲。", "客久艱難極，情忘去就輕。", "空虛仍廢忘，何以慰諸生。"]'),
('36920040-e4ab-478c-b4be-ae435f0b6b17','東阿','陳師道','宋','宋诗','song-poetry','','[]','慟哭東阿縣，傷心莫與論。',48,'全唐诗/poet.song.62000.json','["慟哭東阿縣，傷心莫與論。", "却思當痛日，敢望此身存。", "舉目人將母，回頭影弔魂。", "更堪悲手足，孤稚滿船門。"]'),
('ff79d5a2-91a0-4fc1-aa0d-a49db86c1bdc','甲亭','陳師道','宋','宋诗','song-poetry','','[]','峻壁亭臨水，橫陂樹徹山。',48,'全唐诗/poet.song.62000.json','["峻壁亭臨水，橫陂樹徹山。", "兩河惟甲氏，數柏共蒼顔。", "隨意游成適，回舟月與還。", "早知乘下澤，不再結青綸。"]'),
('1f62fa9e-a7da-4173-8cc3-30ff404ee931','游鵲山院','陳師道','宋','宋诗','song-poetry','','[]','積石橫成嶺，行楊密映門。',48,'全唐诗/poet.song.62000.json','["積石橫成嶺，行楊密映門。", "人聲隠林杪，僧舍遶雲根。", "頓攝塵緣盡，方知象教尊。", "只應羊叔子，名字與山存。"]'),
('40e95ede-6606-4501-a9ab-b13034dfad17','登鵲山','陳師道','宋','宋诗','song-poetry','','[]','小試登山脚，今年不用扶。',48,'全唐诗/poet.song.62000.json','["小試登山脚，今年不用扶。", "微微交濟濼，歷歷數青徐。", "朴俗猶虞力，安流尚禹謨。", "終年聊一快，吾病失醫盧。"]'),
('a59f8e47-502d-4f0a-a812-4cf49af299a5','梁山泊','陳師道','宋','宋诗','song-poetry','','[]','積陰風易作，隆寒聲益急。',168,'全唐诗/poet.song.62000.json','["積陰風易作，隆寒聲益急。", "百爲定有數，一動必三日。", "奔隤水勢壯，犦胅波頭立。", "前行後浪促，突起旁抶射。", "奔騰萬騎來，倏忽一箭疾。", "摧殘蒲葦盡，簸蕩魚龍泣。", "私憂地軸脫，已分梁山沒。", "向來萬斛重，不作一葉直。", "舟行兩水間，觸奪聲蟋蟀。", "路轉帆舉落，舟排冰疊積。", "經事長一智，中人所知識。", "千金不垂堂，豈復待一失。", "窮途得偉觀，老氣猶少色。", "事定未得忘，嗟來庶可及。"]'),
('9ad10abf-b230-4812-a4ca-0f7a1f095372','除官','陳師道','宋','宋诗','song-poetry','','[]','扶老趨嚴召，徐行及聖時。',48,'全唐诗/poet.song.62000.json','["扶老趨嚴召，徐行及聖時。", "端能幾字正，敢恨十年遲。", "肯著金根謬，寧辭乳媼譏。", "向來憂畏斷，不盡鹿門期。"]'),
('6ebc96b0-37fe-49c3-b8e4-1e8440977354','酬王立之二首  其一','陳師道','宋','宋诗','song-poetry','','[]','頓有亭前玉色梅，情知不肯破寒開。',32,'全唐诗/poet.song.62000.json','["頓有亭前玉色梅，情知不肯破寒開。", "似憐憔悴兩公客，獨倚東風遣信來。"]'),
('54d07c93-abe8-4f13-a3a5-7d263c828c47','酬王立之二首  其二','陳師道','宋','宋诗','song-poetry','','[]','重梅雙杏巧相將，不爲遊人只自芳。',32,'全唐诗/poet.song.62000.json','["重梅雙杏巧相將，不爲遊人只自芳。", "應怪詩翁非老手，相逢不作舊時香。"]'),
('cbf5eb92-0dac-4b18-b855-a407633e21ea','欽聖憲肅皇后挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','二妃端協帝，三后共興周。',48,'全唐诗/poet.song.62000.json','["二妃端協帝，三后共興周。", "决策天同力，收功語不流。", "權宜從殺禮，末命尚深憂。", "鬰鬰佳城閉，終天配壽丘。"]'),
('31e358f0-34d9-42ad-83e1-cb4472f31e2d','欽聖憲肅皇后挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','復辟先元約，長年損積憂。',48,'全唐诗/poet.song.62000.json','["復辟先元約，長年損積憂。", "春移柏城仗，仙去帝鄉游。", "德並塗莘敏，功臨馬鄧優。", "千秋修故事，車馬戒如流。"]'),
('1eac50d5-e66c-4d95-a428-7ce7293395aa','欽慈皇后挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','二祧從孝祀，五典載虞嬪。',48,'全唐诗/poet.song.62000.json','["二祧從孝祀，五典載虞嬪。", "顯號追先志，陰功見後人。", "承顔親不待，罔極痛如新。", "未有如椽筆，光容可得陳。"]'),
('05e155cc-9753-46a0-bedd-58ebe8c5235f','欽慈皇后挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','靈岳占佳氣，琳宮閟寶衣。',48,'全唐诗/poet.song.62000.json','["靈岳占佳氣，琳宮閟寶衣。", "應祈符聖曆，錫號煥皇扉。", "日月堯同數，謳歌啟與歸。", "傷心五雲去，不見六龍飛。"]'),
('c37e3455-72f4-4fac-8e1d-dea7d7f21311','大行皇太后挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','德名三后並，母道兩朝尊。',48,'全唐诗/poet.song.62000.json','["德名三后並，母道兩朝尊。", "勇决高千古，危疑定一言。", "先期還政事，隆禮改山園。", "哀挽西郊道，雲愁晝亦昏。"]'),
('d922d613-94aa-4f18-a0ac-7d1e551d8894','大行皇太后挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','扶日行黄道，乘雲上紫微。',48,'全唐诗/poet.song.62000.json','["扶日行黄道，乘雲上紫微。", "憂勞形末命，恭儉見陳衣。", "布德刑開網，和戎戢武威。", "要知懷惠處，行路涕交揮。"]'),
('51e82ea5-8832-4d3a-b946-e5f64a8653e8','追尊皇太后挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','彤管書陰教，黄圖載德容。',48,'全唐诗/poet.song.62000.json','["彤管書陰教，黄圖載德容。", "漢宮元夢日，代邸近乘龍。", "喬岳已遺服，青門啟故封。", "從今祠百世，清廟配商宗。"]'),
('f9037886-40bd-4769-bf57-cc7589bf333c','追尊皇太后挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','典冊尊徽號，欽崇煥德名。',48,'全唐诗/poet.song.62000.json','["典冊尊徽號，欽崇煥德名。", "終身聞舜慕，歷月見堯生。", "兵衛嚴天仗，車輿轉帝城。", "故奩脂澤在，哀感倍皇情。"]'),
('97accae9-cb73-4abb-8a16-f39fc76031cd','王察院挽詞二首  其一','陳師道','宋','宋诗','song-poetry','','[]','施報終何在，窮通共一空。',48,'全唐诗/poet.song.62000.json','["施報終何在，窮通共一空。", "兩言成益友，百代仰高風。", "終始無遺恨，恩榮託至公。", "不應埋直氣，會見吐長虹。"]'),
('01ccf6fe-63f5-4296-8750-136f48967cdc','王察院挽詞二首  其二','陳師道','宋','宋诗','song-poetry','','[]','良貴官何與，長年死不亡。',48,'全唐诗/poet.song.62000.json','["良貴官何與，長年死不亡。", "身須禦魑魅，氣已懾豺狼。", "不盡胸中藴，猶堪地下郎。", "豈惟吾道慶，編簡亦輝光。"]'),
('2d640e1c-5daa-4c6c-a238-83fa690813c9','和吳子副知海齋','陳師道','宋','宋诗','song-poetry','','[]','法筵應供頼三車，堆案抽身輟算沙。',64,'全唐诗/poet.song.62000.json','["法筵應供頼三車，堆案抽身輟算沙。", "破暑好風開樂國，脫塵新句散餘霞。", "僧奩手汗空留迹，佛几堆紅拂委花。", "客舍黄粱未應熟，且容秋蝶夢南華。"]'),
('c7503f65-796b-4a79-a61c-c5db209d7f0c','舅氏新齋','陳師道','宋','宋诗','song-poetry','','[]','堂因竹柏有，花與歲時闌。',48,'全唐诗/poet.song.62000.json','["堂因竹柏有，花與歲時闌。", "欲作終年計，長留別眼看。", "色侵杯酒重，子孰落聲乾。", "只有林園主，相期耐歲寒。"]'),
('b1895793-5944-4617-af42-1bb5f5e57bca','答王立之','陳師道','宋','宋诗','song-poetry','','[]','每逢無可語，暫阻即相求。',48,'全唐诗/poet.song.62000.json','["每逢無可語，暫阻即相求。", "解卷初增氣，開懷得寫憂。", "昏煙宜带雨，風樹更添秋。", "絕唱猶多和，先衰怯後酬。"]'),
('5bda8a3e-c55d-4103-a51d-ba06291f7abf','送歐陽叔弼知蔡州','陳師道','宋','宋诗','song-poetry','','[]','潁陰爲別悔匆匆，十載相望信不通。',64,'全唐诗/poet.song.62000.json','["潁陰爲別悔匆匆，十載相望信不通。", "晚遇聖朝收放逸，旋遭官禁限西東。", "又爲太守專淮石，剩喜郎君類若翁。", "梅柳作新詩興動，可令千里不同風。"]'),
('3700186b-393d-4ac1-93f1-32c36abfe970','送晁堯民守徐','陳師道','宋','宋诗','song-poetry','','[]','中年爲別不堪憂，束髮登門到白頭。',64,'全唐诗/poet.song.62000.json','["中年爲別不堪憂，束髮登門到白頭。", "南省望郎仍國士，東方千騎更吾州。", "彭翁老壽終遺骨，燕子飛來只故樓。", "知己難逢身易老，煩公置醴我歸休。"]'),
('baf8c291-e5f0-480d-9078-afa724a8468c','贈吳氏兄弟三首  其一','陳師道','宋','宋诗','song-poetry','','[]','一長未可衆人師，萬里元隨八馬蹄。',32,'全唐诗/poet.song.62000.json','["一長未可衆人師，萬里元隨八馬蹄。", "不解征西說子弟，却憐野鶩厭家雞。"]'),
('b5e9a345-1d54-4190-9546-fce7ce8a2b97','贈吳氏兄弟三首  其二','陳師道','宋','宋诗','song-poetry','','[]','才隨年盡不重奇，每愧諸郎索近詩。',32,'全唐诗/poet.song.62000.json','["才隨年盡不重奇，每愧諸郎索近詩。", "旋作七言供一笑，自癡那得使人癡。"]'),
('8678541b-9730-4272-aade-aca5c62408f7','贈吳氏兄弟三首  其三','陳師道','宋','宋诗','song-poetry','','[]','得失媸妍只自知，略容千載有心期。',32,'全唐诗/poet.song.62000.json','["得失媸妍只自知，略容千載有心期。", "恨君不識金華伯，何處如今更有詩。"]'),
('730c839b-4619-451d-91cf-cb1308271612','上晁主客','陳師道','宋','宋诗','song-poetry','','[]','兩疏父子共含香，不獨家榮國有光。',64,'全唐诗/poet.song.62000.json','["兩疏父子共含香，不獨家榮國有光。", "剩欲展懷因問疾，孰知相對只銜觴。", "年侵身要兼人健，節近花須滿意黄。", "從此竹林須小阮，只今未可棄山王。"]'),
('7623c56c-0270-4dee-898a-c7787f427603','和鮮于大受崇先觀餞別曾元中','陳師道','宋','宋诗','song-poetry','','[]','此別未爲遠，兩都東西州。',120,'全唐诗/poet.song.62000.json','["此別未爲遠，兩都東西州。", "情親有乖隔，江湖成阻脩。", "脫塵度翠密，徐行當尋幽。", "各有惜別懷，共此一日留。", "意合豈待約，酒盡不更求。", "闕詞固未可，忍手亦何猶。", "坐有黄冠師，未解逍遥遊。", "興來我與共，醉罷君當休。", "僧房火可親，此樂行且謀。", "萬事自糾紛，高懷元一丘。"]'),
('5b92f252-4fb8-414e-86f3-6f8d643d04a3','和過田承君','陳師道','宋','宋诗','song-poetry','','[]','寺古專宜僻，居深自作幽。',48,'全唐诗/poet.song.62000.json','["寺古專宜僻，居深自作幽。", "興來寧憚遠，句苦不緣愁。", "逸氣無前足，虛懷不繫舟。", "逢人難晤語，冒雨亦相求。"]'),
('5c003df5-a82a-4d63-a096-a1f08db2bbc5','贈石先生','陳師道','宋','宋诗','song-poetry','','[]','多方作計老如期，百疾交攻遽得衰。',64,'全唐诗/poet.song.62000.json','["多方作計老如期，百疾交攻遽得衰。", "晚有勝緣逢異士，生須快意闕前知。", "迫人鬢頷紛紛白，臨事回迂種種遲。", "分我刀圭容不死，他年鶴馭得追隨。"]'),
('27f07fdf-8dd6-4825-8d2b-5c990f71b27b','送晁無咎出守蒲中','陳師道','宋','宋诗','song-poetry','','[]','一麾出守自多奇，四十專城古亦稀。',64,'全唐诗/poet.song.62000.json','["一麾出守自多奇，四十專城古亦稀。", "解榻坐談無我輩，鋪筵踏舞欠崔徽。", "的桃作劇聊同俗，遇事當前莫後幾。", "聖世急才常患少，棧羊釃酒待公歸。"]'),
('25eb22b1-67b0-4aed-bdd1-f22f4e84f40c','送王定國通判河南','陳師道','宋','宋诗','song-poetry','','[]','孤身十載客都城，白社雙林諱姓名。',64,'全唐诗/poet.song.62000.json','["孤身十載客都城，白社雙林諱姓名。", "授館不爲他日計，解衣真出故人情。", "翹材必定延枚叟，宣室終須記賈生。", "萬里歸來髮如漆，了知句畫更新清。"]'),
('f6f98eb5-eadd-428a-9613-ba519f9748e9','寄子開','陳師道','宋','宋诗','song-poetry','','[]','致君意氣日方中，許國精誠月貫虹。',64,'全唐诗/poet.song.62000.json','["致君意氣日方中，許國精誠月貫虹。", "一代英豪出門第，當時毀譽豈窮通。", "風流身致羲黄上，日夜心隨汴洛東。", "從使少年輕我輩，只留顔面對吾公。"]'),
('a7878860-e29d-487f-833b-512f59c4ab8b','題王平甫帖','陳師道','宋','宋诗','song-poetry','','[]','早聞英氣擅家聲，晚得諸郎識老成。',64,'全唐诗/poet.song.62000.json','["早聞英氣擅家聲，晚得諸郎識老成。", "可恨治朝無此老，却嫌晚進不同生。", "足知落筆千言疾，尚想揮毫一坐傾。", "未信哲人窮五字，二難還復以詩鳴。"]'),
('87a8b739-7231-4993-9587-064ab3e2e29c','和李文叔退朝','陳師道','宋','宋诗','song-poetry','','[]','朝流駭汗蒸雙猊，風卷屯雲散萬蹄。',32,'全唐诗/poet.song.62000.json','["朝流駭汗蒸雙猊，風卷屯雲散萬蹄。", "任使輕衫汙嬌色，可令纖手洗春泥。"]'),
('c67b502d-0501-4b33-9519-68a2d02c6778','和謝公定雨行逢賣花','陳師道','宋','宋诗','song-poetry','','[]','逢花駐馬尚多情，天不違人旋作晴。',32,'全唐诗/poet.song.62000.json','["逢花駐馬尚多情，天不違人旋作晴。", "不使近詩增紙價，得知春入鳳凰城。"]'),
('fa98f13f-d766-4721-84ed-8f99d9aa2e48','謝王立之送花','陳師道','宋','宋诗','song-poetry','','[]','過雨生泥風作塵，馬蹄聲裏度芳辰。',32,'全唐诗/poet.song.62000.json','["過雨生泥風作塵，馬蹄聲裏度芳辰。", "城南居士風流在，時送名花與報春。"]'),
('3a0523b9-10b4-41af-ab33-25adbb08125f','和參寥明發見鄰家花二首  其一','陳師道','宋','宋诗','song-poetry','','[]','短牆春色過鄰家，行不逢人只見花。',32,'全唐诗/poet.song.62000.json','["短牆春色過鄰家，行不逢人只見花。", "新綠葱葱紅蔌蔌，却成粧面映青紗。"]'),
('4a0ea166-3b38-4c00-96d0-e207bcc36ae1','和參寥明發見鄰家花二首  其二','陳師道','宋','宋诗','song-poetry','','[]','滿城桃李一番新，深院繁枝別得春。',32,'全唐诗/poet.song.62000.json','["滿城桃李一番新，深院繁枝別得春。", "從此詩翁有新語，不須紅濕少城闉。"]'),
('acbbf1c4-46c0-48ee-8188-17b708a67728','和張奉議贈舅氏龐大夫','陳師道','宋','宋诗','song-poetry','','[]','朝下公門不曳裾，身寬心遠等林居。',64,'全唐诗/poet.song.62000.json','["朝下公門不曳裾，身寬心遠等林居。", "傳家聲烈三公後，貯腹平生萬卷餘。", "藤架倚春聽語鳥，石池迎日數游魚。", "人言酷似牢之舅，未有新詩錦不如。"]'),
('3dde87a6-565f-435c-8fc5-5e4622b92285','和舅氏公退言懷','陳師道','宋','宋诗','song-poetry','','[]','追陪强韵愧難過，應接前聞覺未多。',64,'全唐诗/poet.song.62000.json','["追陪强韵愧難過，應接前聞覺未多。", "盛禮每虛摩詰席，舊詞猶可雪兒歌。", "手開新徑延徐步，眼趁高梧上碧蘿。", "風雨入懷泥滿眼，時須好語滌煩痾。"]'),
('32d1dc9f-0859-4c26-b06c-f88e570e9cab','和謝公定觀秘閣文與可枯木','陳師道','宋','宋诗','song-poetry','','[]','斯人不復有，累世或可期。',156,'全唐诗/poet.song.62000.json','["斯人不復有，累世或可期。", "每於丹青裏，一見如平時。", "壞障塵得入，慘澹令人悲。", "墨色落欲盡，嚴顔終不移。", "朽老莫使年，石心烏銅皮。", "念此猶少作，未盡冰霰姿。", "北枝把異鵲，意定了不疑。", "惜哉不得語，胸次幾興衰。", "一爲要貴役，可復辭畫師。", "隠奧雖可惜，塗抹復見遺。", "謝侯名家子，感慨形苦詞。", "豈惟語畫工，勁特頗似之。", "何當補諫列，一吐胸中奇。"]'),
('cc5344e5-88bf-445e-b7e0-4adcfd991d27','題畫李白真','陳師道','宋','宋诗','song-poetry','','[]','君不見浣花老翁醉騎馿，熊兒捉轡驥子扶。',227,'全唐诗/poet.song.62000.json','["君不見浣花老翁醉騎馿，熊兒捉轡驥子扶。", "金華仙伯哦七字，好事不復千金模。", "青蓮居士亦其亞，斗酒百篇天所借。", "英姿秀骨尚可似，逸氣高懷那得畫。", "周郎韵勝筆有神，解衣磅礴未必真。", "一朝寫此英妙質，似悔只識如花人。", "醉色欲盡玉色起，分明尚带金井水。", "烏紗白紵真天人，不用更著山巖裏。", "平生潦倒飽丘園，禁省不識將軍尊。", "袖手猶懷脫靴氣，豈是從來骨相屯。", "仰視雲空鴻鵠舉，眼前紛紛那得顧。", "是非榮辱不到處，只恐朝來有新句。", "勿言身後不要名，尚得吳侯費百金。", "江西勝士與長吟，後來不憂身陸沉。"]'),
('17474ac3-8138-47e0-bc3a-0ed0ceeb3dd7','題明發高軒過圖','陳師道','宋','宋诗','song-poetry','','[]','滕王蛺蝶江都馬，一紙千金不當價。',224,'全唐诗/poet.song.62000.json','["滕王蛺蝶江都馬，一紙千金不當價。", "異才天縱非力能，畫工不是甘爲下。", "今代風流數大年，含毫落筆開山川。", "忽忘朽老壓塵底，却怪鳬鴻墮目前。", "爾來八二復秀出，萬里河山才咫尺。", "眼邊安得有突兀，復似天地初開闢。", "明窗寫出高軒過，便逐愈湜聞吟哦。", "晚知書畫真有益，却悔歲月來無多。", "官禁修嚴斷過訪，時於僻寺逢稅鞅。", "秀潤如行琮璧間，清明似引星辰上。", "憂悲愉怢百不平，河擘太華東南傾。", "平生秀句寰區滿，拾掇餘棄成丹青。", "平湖遠嶺開精神，斗覺文字生清新。", "未許二豪今角立，要知旁有衛夫人。"]'),
('f44eedf2-e239-4b0b-9a2b-3ec613127b7c','寄徐吉父學士','陳師道','宋','宋诗','song-poetry','','[]','卧龍山上摘黄花，曾共西風醉帽斜。',64,'全唐诗/poet.song.62000.json','["卧龍山上摘黄花，曾共西風醉帽斜。", "當日已應天下樂，無人傳入畫圖誇。", "低頭强笑今何似，多病難堪懶自嗟。", "聞道承明方厭直，幾時來伴訪山家。"]'),
('3f368dba-f1aa-4092-87e3-08c28ec87c5a','和南豐先生西游之作','陳師道','宋','宋诗','song-poetry','','[]','孤雲秀壁共崔嵬，倚壁看雲足懶回。',64,'全唐诗/poet.song.62000.json','["孤雲秀壁共崔嵬，倚壁看雲足懶回。", "睡眼剩潮寒綠洗，醉頭强爲好峰擡。", "山僧煮茗留寬坐，寺板題名卜再來。", "有愧野人能自在，塵樊束縛久低徊。"]'),
('2333c61a-6c56-4b77-920b-1925552f51c1','和南豐先生出山之作','陳師道','宋','宋诗','song-poetry','','[]','側徑籃舁兩眼明，出山猶带骨毛清。',64,'全唐诗/poet.song.62000.json','["側徑籃舁兩眼明，出山猶带骨毛清。", "白雲笑我還多事，流水隨人合有情。", "不及鳥飛渾自在，羨他僧住便平生。", "未能與世全無意，起爲蒼生試一鳴。"]'),
('1f65f502-dd7b-4403-9fd8-30e3a13afef8','和張次道再游翠巖之作','陳師道','宋','宋诗','song-poetry','','[]','去歲尋山有舊題，重來似與故人期。',64,'全唐诗/poet.song.62000.json','["去歲尋山有舊題，重來似與故人期。", "回巒俯仰如迎客，流水喧鳴擬索詩。", "嶺路依危通鳥過，吾身趁健白雲隨。", "自憐久快屠門嚼，欲往安能久茹芝。"]'),
('fbcad1dc-2623-46ce-adf9-bbfd5a2f97ae','初到錦城','陳師道','宋','宋诗','song-poetry','','[]','溪遶層巒路遶溪，飛梁相接掛晴霓。',64,'全唐诗/poet.song.62000.json','["溪遶層巒路遶溪，飛梁相接掛晴霓。", "山川王氣今何有，巖谷靈蹤昔未躋。", "十里松篁參羽仗，半天樓閣倚雲梯。", "勝遊欲盡無窮目，未到桃源客已迷。"]'),
('d6a4a0b3-6abc-4188-a580-90c7cceeb7ac','何復教授以事待理','陳師道','宋','宋诗','song-poetry','','[]','負俗寧能累哲人，昔賢由此致功名。',64,'全唐诗/poet.song.62000.json','["負俗寧能累哲人，昔賢由此致功名。", "驥收鹽坂車前足，琴得焦桐爨下聲。", "三獻荆山時未識，一鳴齊鳥衆方驚。", "傳聞下詔搜遺逸，勸講方思用老成。"]'),
('a15f36d1-0ddd-47b6-bbf0-a92eb32b3d45','和富中容朝散雨中感懷','陳師道','宋','宋诗','song-poetry','','[]','節物驚心懶復嗟，罇中酒盡復誰賒。',64,'全唐诗/poet.song.62000.json','["節物驚心懶復嗟，罇中酒盡復誰賒。", "風撩雨脚俄成陣，雪閣雲頭欲結花。", "萬里可堪長作客，一年將盡未還家。", "自憐落落終難合，白首詩書謾五車。"]'),
('f40e0b4e-6191-4687-b2fe-ac0361e39510','謝贇闍梨見訪','陳師道','宋','宋诗','song-poetry','','[]','好在談經老上人，衝風踏雪到江濱。',64,'全唐诗/poet.song.62000.json','["好在談經老上人，衝風踏雪到江濱。", "百篇出篋自新得，一鉢隨身依舊貧。", "終歲杜門逃俗士，爲師設榻對脩筠。", "蒲團藜杖焚香坐，此意此時無點塵。"]'),
('6c43d0ca-2dac-4fe5-941d-ae7605a8dd00','和蒲左丞有美座上觀雪二首  其一','陳師道','宋','宋诗','song-poetry','','[]','高牙大纛曉登山，卷帳飛觴不避寒。',64,'全唐诗/poet.song.62000.json','["高牙大纛曉登山，卷帳飛觴不避寒。", "十二玉樓橫閤道，三千銀甲壯師干。", "封條已驗遺蝗化，平隴寧虞宿麥乾。", "預喜豐年惟太守，旋追賓從促盃盤。"]'),
('0281eba8-ac8b-4395-9b4c-f6ce916de9d4','和蒲左丞有美座上觀雪二首  其二','陳師道','宋','宋诗','song-poetry','','[]','破曉初驚失舊山，瑶臺化出坐中寒。',64,'全唐诗/poet.song.62000.json','["破曉初驚失舊山，瑶臺化出坐中寒。", "江心凍合愁蛟蜃，匣裏冰生吼鏌干。", "門閉洛陽人跡絕，指穿東郭履痕乾。", "鳳池不比梁園客，咳唾珠璣落玉盤。"]'),
('67d11d14-6630-48ff-bc43-2c44d047a440','和秦太虛湖上野步','陳師道','宋','宋诗','song-poetry','','[]','曉風疏日乍相親，黯黯輕寒拂拂春。',64,'全唐诗/poet.song.62000.json','["曉風疏日乍相親，黯黯輕寒拂拂春。", "觸目漸隨紅蕊亂，經年不見綠條新。", "寧論白黑人間世，懶復雌黄紙上塵。", "十里松陰窮野步，暫時留得自由身。"]'),
('41f94199-6b08-4ea3-a379-ae2d0255d886','和沈世卿推官見寄','陳師道','宋','宋诗','song-poetry','','[]','倦看世態久低徊，且置窮通近酒杯。',64,'全唐诗/poet.song.62000.json','["倦看世態久低徊，且置窮通近酒杯。", "未忍一身閑處著，暫容雙眼醉時開。", "爲呼阿武扶頭起，擬與山翁倒載回。", "好在東籬舊時菊，無心準擬白衣來。"]'),
('242d8d60-b87c-4724-83f2-fdd45224e216','和劉元樂月夜寄賈耘老','陳師道','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','胡牀欲上庾公樓，那復周南歎滯留。',64,'全唐诗/poet.song.62000.json','["胡牀欲上庾公樓，那復周南歎滯留。", "皓魄光連鮫室午，疏星冷浸洞庭秋。", "錦袍有興思姑熟，桃楫無心問莫愁。", "喚取長江來入社，不勞牛渚問行舟。"]'),
('eab4ab54-a814-452b-9fdc-48606c5cdb1f','酬呂明父學士','陳師道','宋','宋诗','song-poetry','','[]','當日功名指顧收，一言悟主過千秋。',64,'全唐诗/poet.song.62000.json','["當日功名指顧收，一言悟主過千秋。", "去登霄漢如平地，歸到雲山尚黑頭。", "解組行參蓮社客，揮金坐揖醉鄉侯。", "謝公不爲蒼生起，擁鼻重來可自由。"]'),
('63bf7a58-f23d-4fce-8641-fe344a8103dc','送傅子正宣義','陳師道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漸漸烏竿五兩輕，一帆秋色下江濱。',64,'全唐诗/poet.song.62000.json','["漸漸烏竿五兩輕，一帆秋色下江濱。", "請纓北闕非無意，捧檄南州且爲親。", "神驥解韁天上足，風鵬搖翮日邊身。", "歸途瞇眼塵沙惡，想夢西湖十里春。"]'),
('985dd856-7718-4940-9e76-9fb62d9a7b93','和元樂銷暑樓曉望','陳師道','宋','宋诗','song-poetry','','[]','遶郭溪山接四鄰，身輕步躡一梯雲。',64,'全唐诗/poet.song.62000.json','["遶郭溪山接四鄰，身輕步躡一梯雲。", "圖南羽翮摶空見，倚北光芒入夜分。", "蕪沒池臺餘故事，風流人物想前聞。", "翛然便欲移招隠，猿鶴還應怨舊羣。"]'),
('fe8e792f-a518-48e0-b4ba-a8f1cd8f06a2','和寄朱文中','陳師道','宋','宋诗','song-poetry','','[]','仰高當日誦成規，想見風流盛一時。',64,'全唐诗/poet.song.62000.json','["仰高當日誦成規，想見風流盛一時。", "魯國故知臧有後，孔庭早見鯉能詩。", "侵尋末路同傾蓋，邂逅清談爲解頤。", "願借湖山容膝地，爲令松菊寄吾衰。"]'),
('dd8878d9-863e-4f97-9c19-c96765f3bf96','和王明之見寄','陳師道','宋','宋诗','song-poetry','','[]','末路相逢首重回，紫芝眉宇向人開。',64,'全唐诗/poet.song.62000.json','["末路相逢首重回，紫芝眉宇向人開。", "老來惟有風情在，事去空憐歲月催。", "憔悴不堪臨楚澤，棲遲無路上燕臺。", "少陵肺病疏杯斝，想負花前載酒來。"]'),
('93da24af-fff7-4cae-874d-fd98494359ed','和酬施和叟宣德','陳師道','宋','宋诗','song-poetry','','[]','山陰傾蓋兩綢繆，十載重來鬢已秋。',64,'全唐诗/poet.song.62000.json','["山陰傾蓋兩綢繆，十載重來鬢已秋。", "往事侵尋如昨日，故人牢落半滄洲。", "流離道路生涯拙，蕪沒田園歲計休。", "久要尚憐君子在，爲言雞黍亦遲留。"]'),
('18d23af4-c71f-4c2f-9fb6-517a5f945da6','呂吉父使君生日','陳師道','宋','宋诗','song-poetry','','[]','司漏凌晨報曉籤，曈曈赫日上重簷。',64,'全唐诗/poet.song.62000.json','["司漏凌晨報曉籤，曈曈赫日上重簷。", "良辰也應純乾策，吉夢先符太卜占。", "棣萼同時升紫禁，棠陰由此駐彤襜。", "一杯欲助邦人禱，願借黄堂壽斝添。"]'),
('648b7bf8-dcbf-4549-a0bc-2a8d0b981e80','送澤之過維揚','陳師道','宋','宋诗','song-poetry','','[]','夢裏揚州十載間，青樓陳迹故依然。',64,'全唐诗/poet.song.62000.json','["夢裏揚州十載間，青樓陳迹故依然。", "袍爭爛錦催詩筆，雨濺明珠落酒船。", "顧我老無騎鶴興，羨君行及看花天。", "囊中繡句歸應滿，不負韋郎五色牋。"]'),
('90a5ffc7-ce87-4cc7-a382-e031cd7bf628','和和叟第課還自都下','陳師道','宋','宋诗','song-poetry','','[]','青雲直上馬如龍，來往泠然若御風。',64,'全唐诗/poet.song.62000.json','["青雲直上馬如龍，來往泠然若御風。", "高步只應天咫尺，舊游寧寄浙西東。", "升沉道路從今異，邂逅比鄰此日同。", "相見可堪懷抱冷，需君健語破樊籠。"]'),
('c2abf99c-af9e-4e44-b1b4-8b4c7a615229','和和叟梅花','陳師道','宋','宋诗','song-poetry','','[]','百卉前頭第一芳，低臨粉水浸寒光。',64,'全唐诗/poet.song.62000.json','["百卉前頭第一芳，低臨粉水浸寒光。", "卷簾初認雲猶凍，逆鼻渾疑雪亦香。", "鼎實自應終有待，天真不假更勻粧。", "江南望斷無來使，且伴詩翁入醉鄉。"]'),
('d78ede13-11f9-47e9-9dbb-07d272cd9959','再到錢塘呈會宗伯益','陳師道','宋','宋诗','song-poetry','','[]','負笈重來感舊游，流年衰鬢兩經秋。',64,'全唐诗/poet.song.62000.json','["負笈重來感舊游，流年衰鬢兩經秋。", "湖山依舊渾相識，風月愁人不自由。", "尚有故交重冷榻，可堪歸夢到滄洲。", "誰憐壯志空凋落，百鍊金爲繞指柔。"]'),
('ce15559d-7911-4404-80be-510fe12c8b26','簡楊安國','陳師道','宋','宋诗','song-poetry','','[]','侯門誰預識馮諼，歲晚寧知范叔寒。',64,'全唐诗/poet.song.62000.json','["侯門誰預識馮諼，歲晚寧知范叔寒。", "傾蓋尚憐吾道在，立談相信古人難。", "開懷磊落無城府，握手侵尋出肺肝。", "共許異時終此去，滿冠塵土待君彈。"]'),
('26228579-d581-4070-b65e-f9e43cd28969','簡李伯益','陳師道','宋','宋诗','song-poetry','','[]','虀鹽度歲每無餘，垂橐東歸口未糊。',64,'全唐诗/poet.song.62000.json','["虀鹽度歲每無餘，垂橐東歸口未糊。", "貧裏交遊新斷絕，老來光景半消除。", "時情視我門前雀，人好看君屋上烏。", "尚喜弊廬連蔣徑，願求佳句遞髯奴。"]'),
('5c814637-1e08-4765-99c6-2eddbc1db30a','九日無酒書呈漕使韓伯修大夫','陳師道','宋','宋诗','song-poetry','','[]','老大悲傷節物催，酒腸枯涸壯心灰。',64,'全唐诗/poet.song.62000.json','["老大悲傷節物催，酒腸枯涸壯心灰。", "慚無白水真人分，難置青州從事來。", "倦筆懶從都市出，醉眸剛爲麴車回。", "黄花也似相欺得，坐對空樽不肯開。"]'),
('0ba0b895-2cab-4997-8fb4-3efc0a631f62','過杭留別曹無逸朝奉','陳師道','宋','宋诗','song-poetry','','[]','陳蕃解榻爲留連，俯仰徒驚歲月遷。',64,'全唐诗/poet.song.62000.json','["陳蕃解榻爲留連，俯仰徒驚歲月遷。", "故意斯人奈風雨，多情於我獨山川。", "可憐顔貌非前日，依舊窮愁似去年。", "後夜相思隔煙水，夢魂空寄過江船。"]'),
('7f05f18a-81e6-45ee-b13a-cadc0f632db1','五言賀雨出','陳師道','宋','宋诗','song-poetry','','[]','六月鄞江旱，焦勞刺史憂。',120,'全唐诗/poet.song.62000.json','["六月鄞江旱，焦勞刺史憂。", "戴星趨洞府，踏月叩龍湫。", "引咎青章設，爲壇古法修。", "山川將爾徧，牲幣豈吾留。", "帝意茲回眷，神聰俯應求。", "油雲潜感召，靈雨忽滂流。", "急勢朝翻幕，寒聲暮咽溝。", "餘波平浦嶼，翠色蔽田疇。", "池閣消殘暑，閭閻慶有秋。", "邦民無以謝，惟起載途謳。"]'),
('48d4ca30-1320-44c3-9be7-d4eceff12d74','別威德寺','陳師道','宋','宋诗','song-poetry','','[]','三宿城隈寺，輕齎類老禪。',48,'全唐诗/poet.song.62000.json','["三宿城隈寺，輕齎類老禪。", "暫來真偶爾，適去更翛然。", "笑別留春塢，行尋下瀨船。", "此身猶斷梗，飄泊且隨緣。"]'),
('cc7c8bad-bdcf-4cd6-a063-80bb838c21b2','雜題','陳師道','宋','宋诗','song-poetry','','[]','春水漲湖田，先尋滬瀆船。',48,'全唐诗/poet.song.62000.json','["春水漲湖田，先尋滬瀆船。", "隔江爭問主，入市不論錢。", "味得蓴尤滑，香因豉更便。", "它年楝花落，追憶漫流涎。"]'),
('5ddeb1ab-694e-41a4-a07a-6931c85931d2','和董判官寺居作','陳師道','宋','宋诗','song-poetry','','[]','共作東州客，同棲古寺深。',48,'全唐诗/poet.song.62000.json','["共作東州客，同棲古寺深。", "論交非有舊，不見解相尋。", "冷過清明節，悲生故國心。", "此身隨所寄，未足問升沉。"]'),
('1c1ad0fb-e396-4fde-8640-1ee078326ce1','贈白闍梨','陳師道','宋','宋诗','song-poetry','','[]','瓶錫倦西東，歸來一榻空。',48,'全唐诗/poet.song.62000.json','["瓶錫倦西東，歸來一榻空。", "宗乘能自判，文學更兼通。", "講徹夜堂月，定回枯樹風。", "無從參浄社，回首倦飛蓬。"]'),
('b7cd6cc3-b66d-429b-afec-9b2eac4efa19','舒御史太夫人挽辭','陳師道','宋','宋诗','song-poetry','','[]','回合江山秀，佳城去域中。',48,'全唐诗/poet.song.62000.json','["回合江山秀，佳城去域中。", "珮環無曉日，蘋藻自春風。", "斷髮人何在，捐金事已空。", "遂移男子孝，更作直臣忠。"]'),
('b351ed44-7868-43f3-8738-eee6dc8f3054','和賈明叔秋晚見懷','陳師道','宋','宋诗','song-poetry','','[]','陋巷少行跡，故人車馬稀。',48,'全唐诗/poet.song.62000.json','["陋巷少行跡，故人車馬稀。", "世情方汩沒，吾道肯依違。", "萬葉迎風脫，孤雲带月歸。", "獨憐高義在，猶肯問柴扉。"]'),
('4885ec0a-589c-48c9-880d-239be5d24f36','望夫石','陳師道','宋','宋诗','song-poetry','','[]','磧戍人何在，秋霜志不移。',48,'全唐诗/poet.song.62000.json','["磧戍人何在，秋霜志不移。", "無言息媯怨，有淚舜娥悲。", "山靜雲盤髻，江空月印眉。", "誰將望遠意，歌作送征詩。"]'),
('bc060c63-8e42-4653-b7d5-b623e973033e','夏杪','陳師道','宋','宋诗','song-poetry','','[]','一室青蕪長，終朝靜不譁。',48,'全唐诗/poet.song.62000.json','["一室青蕪長，終朝靜不譁。", "聖賢開美酒，子母破新瓜。", "綠篠初翻籜，紅蕖稍薦花。", "咄嗟功業晚，覽照鬢初華。"]'),
('2c3ff817-e853-46e2-8b59-dc335b018e19','虞美人草','陳師道','宋','宋诗','song-poetry','','[]','幽草默通神，舊題虞美人。',48,'全唐诗/poet.song.62000.json','["幽草默通神，舊題虞美人。", "長言方度曲，應節若翻身。", "律呂聲相召，雲龍氣自親。", "無情猶感會，不獨在君臣。"]'),
('7905277e-ee5d-4713-8ea4-2e632d1b5466','沈道院有水墨壁畫奇筆也惜其窮年無賞之者賈明叔請余同賦','陳師道','宋','宋诗','song-poetry','','[]','壁間水墨畫，爲爾拂塵埃。',48,'全唐诗/poet.song.62000.json','["壁間水墨畫，爲爾拂塵埃。", "草樹精神出，溪山氣勢回。", "路從沙觜斷，人自渡頭來。", "莫怪知音少，牙絃匣不開。"]'),
('08cb42f7-9e8d-41c2-a260-bd1e7bc3cf28','同蘇不疑避暑法惠寺','陳師道','宋','宋诗','song-poetry','','[]','酷暑不可處，相將尋晝凉。',48,'全唐诗/poet.song.62000.json','["酷暑不可處，相將尋晝凉。", "清談廕廣厦，甘寢就匡牀。", "蓮剝明珠滑，瓜浮紺玉香。", "因知北窗卧，自信出羲皇。"]'),
('d445053d-a8b2-4019-840b-40dcaad62d05','和彥詹題遠軒','陳師道','宋','宋诗','song-poetry','','[]','開窗得遠意，興出杳冥間。',48,'全唐诗/poet.song.62000.json','["開窗得遠意，興出杳冥間。", "芳草日邊路，片雲天外山。", "好花和露斸，脩竹夾藤刪。", "每許南鄰伴，時來一寄閑。"]'),
('d81c07d1-27e1-4c10-8333-2b78729c35a1','讀白樂天臨水坐詩','陳師道','宋','宋诗','song-poetry','','[]','西方社裏收身早，白髮人中得計長。',32,'全唐诗/poet.song.62000.json','["西方社裏收身早，白髮人中得計長。", "不作北門東掖客，更無閑事可思量。"]'),
('e19f8d9b-4cff-4e5e-b408-026ed373bd9c','寄君玉','陳師道','宋','宋诗','song-poetry','','[]','不見紫霄翁，侵尋鬢已蓬。',48,'全唐诗/poet.song.62000.json','["不見紫霄翁，侵尋鬢已蓬。", "倦游鄉域異，歸夢夙宵同。", "愛酒貧應甚，吟詩老更工。", "清時公道在，未足歎途窮。"]'),
('2b46c779-aae0-49f4-be36-284756cfc8f0','簡令由司理','陳師道','宋','宋诗','song-poetry','','[]','居連里巷室連甍，多謝能空鑿壁生。',64,'全唐诗/poet.song.62000.json','["居連里巷室連甍，多謝能空鑿壁生。", "幸有餘光子何損，豈無鄰好我先傾。", "已知涉世蘧蘧夢，但欲求田俋俋耕。", "貧病久甘從棄置，寧堪更類汝南評。"]'),
('9b55214c-48a7-4535-bdbf-2e689ac3cc41','立春致語口號','陳師道','宋','宋诗','song-poetry','','[]','霏微臘雪不霑塵，收拾陽和作早春。',64,'全唐诗/poet.song.62000.json','["霏微臘雪不霑塵，收拾陽和作早春。", "一坐盡傾歸盛德，四時難得是佳辰。", "鬢邊綵勝年年好，樽下歌聲日日新。", "一笑難逢時易失，杯行到手莫辭頻。"]'),
('3ba46e5d-8001-4ba1-aab7-239f45d6318f','上元致語口號','陳師道','宋','宋诗','song-poetry','','[]','歡聲喜氣塞康莊，妙舞清歌樂未央。',64,'全唐诗/poet.song.62000.json','["歡聲喜氣塞康莊，妙舞清歌樂未央。", "此節定知隨意好，今宵端復爲人長。", "粧成粉白生春色，酒瀉鵝黄射燭光。", "報答風光須一醉，從來千騎貴東方。"]'),
('cb4d3753-7a80-4105-8182-18c6665fc06c','宴黄提刑致語口號','陳師道','宋','宋诗','song-poetry','','[]','當年天下無雙譽，此日朝中第一人。',64,'全唐诗/poet.song.62000.json','["當年天下無雙譽，此日朝中第一人。", "坐使黄流隨指顧，即看丹閣畫精神。", "天威行復朝三接，和氣今如物再春。", "肯駐行軒慰離索，聽歌舉白莫辭頻。"]'),
('d8342b17-e66b-4865-b629-e58a6fd4f8c5','興龍節致語口號','陳師道','宋','宋诗','song-poetry','','[]','劍珮聲來合玉除，騏驎煙上暗金鋪。',64,'全唐诗/poet.song.62000.json','["劍珮聲來合玉除，騏驎煙上暗金鋪。", "近臣先識天顔喜，九奏初知晝景舒。", "東海爲田將幾見，南山稱壽已三呼。", "欲知帝力今多少，醉舞行歌塞道塗。"]'),
('c234056c-e18b-4f15-a3ba-fe84987f2a02','對廳口號','陳師道','宋','宋诗','song-poetry','','[]','黄堂窈窕慶佳辰，密坐雍容合搢紳。',64,'全唐诗/poet.song.62000.json','["黄堂窈窕慶佳辰，密坐雍容合搢紳。", "廣樂充庭如在夢，歡聲著物似逢春。", "瞻天已祝無窮壽，盡醉爲期莫計巡。", "平世難逢身易老，嶺梅初破酒方醇。"]'),
('9bf0840a-26ad-4450-bb51-85ec363ab974','送張秀才兼簡德麟','陳師道','宋','宋诗','song-poetry','','[]','長安千門憎熱客，我獨憐君來解熱。',64,'全唐诗/poet.song.62000.json','["長安千門憎熱客，我獨憐君來解熱。", "呼兒具飯懶出口，藜羹不糝甘一啜。", "北州別駕玉刻麟，索書往見良可人。", "驛使別來無一字，知有此情誰與親。"]'),
('a7887859-e8be-4292-89a6-15381934c279','寄子閔','陳師道','宋','宋诗','song-poetry','','[]','煙昏晚寒風發屋，行者抽篷離者哭。',64,'全唐诗/poet.song.62000.json','["煙昏晚寒風發屋，行者抽篷離者哭。", "青衫白髮兩相鮮，積雪朝陽眩雙目。", "猛虎食子有分羹，潔鷺割股謀補肉。", "妻孥不用哭窮途，前府故人風義篤。"]'),
('31f5aff8-8906-4608-a46a-2583d06dd325','贈黄氏子小德','陳師道','宋','宋诗','song-poetry','','[]','黄童三尺世無雙，筆頭滾滾懸秋江。',128,'全唐诗/poet.song.62000.json','["黄童三尺世無雙，筆頭滾滾懸秋江。", "不憂老子難爲父，平生崛强今心降。", "我來喜共阿戎語，應敵縱橫如急雨。", "生子還如孫仲謀，豚犬漫多何足數。", "黄家小兒名小德，眉如長林目如漆。", "只今數歲已動人，老人留眼看他日。", "笑君老蚌生明珠，自笑此物吾家無。", "君當置酒吾當賀，有兒傳業更何須。"]'),
('d0de2cbd-f302-49e6-b5f5-e0dd572f428c','次韵游花洞','陳師道','宋','宋诗','song-poetry','','[]','遠洞容徐步，繁英故壓枝。',48,'全唐诗/poet.song.62000.json','["遠洞容徐步，繁英故壓枝。", "錦衾堆襞積，春事向離披。", "作意真成誤，尋芳似較遲。", "預爲來歲約，及早共瑶巵。"]'),
('771e94ee-e06c-4d8c-8289-bfcd99940f9f','送張芝卿','陳師道','宋','宋诗','song-poetry','','[]','相逢已偶爾，告別更蒼然。',48,'全唐诗/poet.song.62000.json','["相逢已偶爾，告別更蒼然。", "離合驚時換，行藏乃世緣。", "君無學干祿，我亦賦歸田。", "泗水秋山外，長安夕照邊。"]'),
('d1a96725-8357-4e97-afa8-a018d6ee2e8d','行次舊縣寄立之','陳師道','宋','宋诗','song-poetry','','[]','歲晚方奔命，春期作過賓。',48,'全唐诗/poet.song.62000.json','["歲晚方奔命，春期作過賓。", "逢君爲地主，顧我拙謀身。", "官是三年客，情緣一日親。", "將身隨斗食，應作未歸人。"]'),
('cce45a78-2007-4423-84dd-85ab9573e990','送晁奉議高郵判官','陳師道','宋','宋诗','song-poetry','','[]','公族仍前輩，都城早與遊。',48,'全唐诗/poet.song.62000.json','["公族仍前輩，都城早與遊。", "士窮須祿食，才大豈身謀。", "雪嶺無歸鳥，冰河有去舟。", "平生湖海意，不爲有魚留。"]'),
('0751b56a-d82a-4045-bc28-1d7847c9a65b','張謀父乞花','陳師道','宋','宋诗','song-poetry','','[]','二頃田園汴泗東，春來心事幾人同。',64,'全唐诗/poet.song.62000.json','["二頃田園汴泗東，春來心事幾人同。", "固知短綆無深汲，又見新花發舊叢。", "花氣著人渾欲醉，妍華過眼旋成空。", "冷官門外無消息，與報江南春信通。"]'),
('bdfe1f9c-1c55-4cc4-8837-0af62e5d58c8','寄子開','陳師道','宋','宋诗','song-poetry','','[]','道山清絕况真仙，杜曲風流最近天。',64,'全唐诗/poet.song.62000.json','["道山清絕况真仙，杜曲風流最近天。", "曹濮於今真樂國，股肱從昔著時賢。", "今回不辨終朝語，此去無端久疾痊。", "可念卧時遭末劫，新陳埋沒不知年。"]'),
('496d17a7-c225-493a-bc16-70b33087243e','次韵黄無悔惜梅','陳師道','宋','宋诗','song-poetry','','[]','雪擁寒門鵲不來，江南春信小遲回。',32,'全唐诗/poet.song.62000.json','["雪擁寒門鵲不來，江南春信小遲回。", "遥知詩力生春早，一抹江梅趁眼開。"]'),
('f7a73048-1d75-438e-b174-3fd9aef2ea91','酒戶獻花以奉先聖戲作','陳師道','宋','宋诗','song-poetry','','[]','蕭蕭竹雨亂鳴鴉，嫋嫋風窗暗碧紗。',32,'全唐诗/poet.song.62000.json','["蕭蕭竹雨亂鳴鴉，嫋嫋風窗暗碧紗。", "玉座塵埃香火冷，酒家來獻一枝花。"]'),
('57bc5d07-3193-4c7f-9f00-9f132b2439b1','謝田氏','陳師道','宋','宋诗','song-poetry','','[]','登門執別有不答，慚愧公家父子孫。',32,'全唐诗/poet.song.62000.json','["登門執別有不答，慚愧公家父子孫。", "顧我何堪能至此，正緣同德又同門。"]'),
('a5bbfdef-f982-4e7e-815a-895c7a921fff','南臺','陳師道','宋','宋诗','song-poetry','','[]','城郭收燈興未休，却回春信到臺頭。',32,'全唐诗/poet.song.62000.json','["城郭收燈興未休，却回春信到臺頭。", "東風未借登臨便，柳色遥看特地愁。"]'),
('d696d5ba-a217-48de-8b23-ed1711c19bbb','馬上口占呈立之','陳師道','宋','宋诗','song-poetry','','[]','廉纖小雨濕黄昏，十里塵泥不受辛。',32,'全唐诗/poet.song.62000.json','["廉纖小雨濕黄昏，十里塵泥不受辛。", "轉就鄰家借油蓋，始知公是最閑人。"]'),
('2cd3eee9-da44-4b1c-a164-30427fc69a4d','鷙鵲詩','陳師道','宋','宋诗','song-poetry','','[]','若奚不鸇，吾知避而遷。',62,'全唐诗/poet.song.62000.json','["若奚不鸇，吾知避而遷。", "汝胡不貍，吾知遠而馳。", "宵邇吾巢，晨並吾枝。", "懷毒妊凶，初不汝期。", "莽莽拳拳，甫笑嬉嬉。", "情貌深厚，孰從而追。"]'),
('3bb15e76-2011-4988-9895-137d55ea4db9','病中六首  其一','陳師道','宋','宋诗','song-poetry','','[]','舊歲連新歲，凉牀又暖牀。',48,'全唐诗/poet.song.62000.json','["舊歲連新歲，凉牀又暖牀。", "山川屏裏畫，時刻篆中香。", "畏壘安吾土，支離飽太倉。", "若教身再健，鶴背入維揚。"]'),
('729db430-7f63-4379-9dd5-6f04a657f5c2','病中六首  其二','陳師道','宋','宋诗','song-poetry','','[]','日暖衣猶襲，宵長被有稜。',48,'全唐诗/poet.song.62000.json','["日暖衣猶襲，宵長被有稜。", "朝晡三楪飯，昏曉一缸燈。", "伴坐跧如几，扶行瘦比藤。", "生緣堪入畫，寂寞憩松僧。"]'),
('4997b070-98c5-430e-b8b2-e96442776172','病中六首  其三','陳師道','宋','宋诗','song-poetry','','[]','軟熟羞盤饌，芳辛實枕幃。',48,'全唐诗/poet.song.63000.json','["軟熟羞盤饌，芳辛實枕幃。", "候晴先晒席，占濕預烘衣。", "易粟雞皮皺，難培鶴骨肥。", "頭顱雖若此，虛白日生輝。"]'),
('d7317f98-1a9f-4812-bd99-7c726e5da67f','病中六首  其四','陳師道','宋','宋诗','song-poetry','','[]','歎息憎晨凊，伸眉愜晚晴。',48,'全唐诗/poet.song.63000.json','["歎息憎晨凊，伸眉愜晚晴。", "隙虛浮日影，窗穴嘯風聲。", "捫蝨天機動，驅蚊我相生。", "偶然成一笑，栩栩暫身輕。"]'),
('885b7dd3-f8e0-4af1-a570-a92e11232e9f','病中六首  其五','陳師道','宋','宋诗','song-poetry','','[]','日眚浮珠珮，聲塵籟玉簫。',48,'全唐诗/poet.song.63000.json','["日眚浮珠珮，聲塵籟玉簫。", "晚秋潘鬢禿，午夢楚魂消。", "注水瓶花醒，吹薪藥鼎潮。", "南柯何處是，斜日上廊腰。"]'),
('34fc84c9-9118-4fce-8918-ac7e995cd6fe','病中六首  其六','陳師道','宋','宋诗','song-poetry','','[]','靜裏秋光到，閒中晝自長。',48,'全唐诗/poet.song.63000.json','["靜裏秋光到，閒中晝自長。", "閉門宜泄柳，尸祝謾庚桑。", "腹已枵經笥，身猶試藥方。", "强名今日愈，勃窣負東牆。"]'),
('183b67d1-5fa0-4c85-9b0e-24c9e74ca936','詩一首','陳師道','宋','宋诗','song-poetry','','[]','松樹倒影半溪寒，數個沙鷗似水安。',32,'全唐诗/poet.song.63000.json','["松樹倒影半溪寒，數個沙鷗似水安。", "曾買江南千本畫，歸來一筆不中看。"]'),
('af87901e-3f4b-40cc-847e-5279358f8f07','詩一首','陳師道','宋','宋诗','song-poetry','','[]','南朝官紙兒女膚，玉版雲英比不如。',32,'全唐诗/poet.song.63000.json','["南朝官紙兒女膚，玉版雲英比不如。", "乞與此公原不稱，他年留與大蘇書。"]'),
('bb5d788f-92d1-451d-87da-a2d7a21b6151','句  其一','陳師道','宋','宋诗','song-poetry','','[]','聞道新文能入樣，相州紅纈鄂州花。',16,'全唐诗/poet.song.63000.json','["聞道新文能入樣，相州紅纈鄂州花。"]'),
('10091da2-543a-433d-bd70-39648781123a','句  其二','陳師道','宋','宋诗','song-poetry','','[]','磊落金盤薦糟蟹，纖柔玉指破霜柑。',16,'全唐诗/poet.song.63000.json','["磊落金盤薦糟蟹，纖柔玉指破霜柑。"]'),
('d145e72d-b208-4fd1-b032-97abfb8f837c','句  其三','陳師道','宋','宋诗','song-poetry','','[]','牆頭霜下草，又作一番新。',12,'全唐诗/poet.song.63000.json','["牆頭霜下草，又作一番新。"]'),
('c7c2681c-333a-48c3-85e3-e6257672af9e','句  其四','陳師道','宋','宋诗','song-poetry','','[]','白鳥過林分外明。',8,'全唐诗/poet.song.63000.json','["白鳥過林分外明。"]'),
('5a7e9627-f82c-4fc5-80d8-dc7536156380','句  其五','陳師道','宋','宋诗','song-poetry','','[]','早晚望夫能化石，盡分人世作支機。',16,'全唐诗/poet.song.63000.json','["早晚望夫能化石，盡分人世作支機。"]'),
('039549de-8080-4fc0-a528-c66c04eeefaa','句  其六','陳師道','宋','宋诗','song-poetry','','[]','日來霜露後，更覺天宇浄。',12,'全唐诗/poet.song.63000.json','["日來霜露後，更覺天宇浄。"]'),
('1343af87-6d4c-4341-9694-8704ecf7b3f9','句  其七','陳師道','宋','宋诗','song-poetry','','[]','熊兒投□驥子扶。',8,'全唐诗/poet.song.63000.json','["熊兒投□驥子扶。"]'),
('20230780-f9e7-4e88-a364-459681c63b91','句  其八','陳師道','宋','宋诗','song-poetry','','[]','江清風偃木，霜落雁橫空。',12,'全唐诗/poet.song.63000.json','["江清風偃木，霜落雁橫空。"]'),
('eddc8de6-e9dc-4bda-8bfc-03c5c5615687','句  其九','陳師道','宋','宋诗','song-poetry','','[]','勢不可使盡，福不可享盡。',36,'全唐诗/poet.song.63000.json','["勢不可使盡，福不可享盡。", "事不可做盡，話不可說盡。", "人生如此耳，文字已其閏。"]'),
('0f3462bc-7770-422e-86ba-503f3c8d0bc0','句  其一○','陳師道','宋','宋诗','song-poetry','','[]','吳音未至慢，楚語不假些。',12,'全唐诗/poet.song.63000.json','["吳音未至慢，楚語不假些。"]'),
('4faaf855-2382-4002-ba51-bea10d5ab5c8','望渦流辭','晁補之','宋','宋诗','song-poetry','','[]','望渦流兮浼浼，勢南折兮東還。',256,'全唐诗/poet.song.63000.json','["望渦流兮浼浼，勢南折兮東還。", "水衝隈兮岸圮，嗟龍去兮幾年。", "俛余進兮藂祠，儼帝服兮神冠。", "牆壁繢兮怪奇，泯蛇穴兮蝸盤。", "列缺鞭兮雷輈，衛兩鰻兮驂鱣。", "老龜起兮霧游，跂瑇瑁兮鼈黿。", "或若馬兮非人，紛陪後兮導前。", "木陰陰兮藻長，科斗舞兮下顛。", "鯈羣出兮旅嬉，忽俱去兮不還。", "意土國兮無龍，恐逃桷兮藏{木邊}。", "帝有命兮時乘，亦隠隠兮填填。", "世鑠石兮流金，將誰職兮此愆。", "包之水可揭也，渙之水可厲也。", "前汝足其暨也，後汝跗其躓也。", "江有鯢兮橫淵，海有鯤兮翔天。", "汝隘此兮往爭，滔淫水兮八埏。", "重曰：望其厓若有宅於隈。", "不汝爭於厓，汝安其隈，澤不必施也。"]'),
('d2088169-2eff-4f2b-a2a4-3eda47c86c4b','追和陶淵明歸去來辭','晁補之','宋','宋诗','song-poetry','','[]','歸去來兮，吾無以歸奚以歸。',321,'全唐诗/poet.song.63000.json','["歸去來兮，吾無以歸奚以歸。", "既身不足以任責，畏首尾而心悲。", "慕往昔之經世，嗟吾力之莫追。", "彼辭位而灌園，豈吾今之獨非。", "雨冥冥而荷笠，榛莽莽而褰衣。", "我行野而視天，覺宇大而身微。", "乃矜虻蚷，止驅息奔。", "背隍築室，面坂植門。", "三綬從褫，圖書尚存。", "忘瓠落之可憂，比浮海之爲樽。", "躒太初而游意，弊無極而彫顔。", "反國蝸而自足，俯巢幕而亦安。", "解予轡之沃濡兮，脫予舝之間關。", "識鳥鳴而物華，陶陽氣以流觀。", "悟息淵而消枝，亦墐戶而俱還。", "惟文字之幼工，則雖老而桓桓。", "歸去來兮，彼河濱之善游。", "或往學而喪生，復裹糧其安求。", "善陶生之達情，不與世兮同憂。", "實迷途其已遠，懼斯人之莫疇。", "或待兔守株，或遺劍刻舟。", "雖成事之不說，聚悔踰於山丘。", "庶西方之至言，聊反聞而逆流。", "守一靜而爲君，亦何往而不休。"]'),
('244c068f-07a4-468a-80a5-bcfe64b17c8d','返迷辭','晁補之','宋','宋诗','song-poetry','','[]','五達跂，行者迷。',156,'全唐诗/poet.song.63000.json','["五達跂，行者迷。", "茨菉蹊，蚖蜴嬉。", "杳淒淒，莽離離。", "赫隆曦，可還時。", "日黯西，與誰期。", "往不思，逢詭期。", "死𤟹貔，安可知，亟反之。", "大道夷，都邑差。", "車馬馳，冠劍祇。", "志可持，能足施。", "貴名垂，好爵靡。", "儼罇巵，饜粱肥。", "窈室帷，安厥妃。", "觀盈虧，浩浩移。", "逝不遲，咸若斯。", "何綏綏，不返爲。", "從魈夔，神索衰。", "今狐疑，後當悲。", "我此詞，如泰龜。"]'),
('2afb0e47-adab-4e28-a885-3e3530d2e6a6','冰玉堂辭','晁補之','宋','宋诗','song-poetry','','[]','論世以觀士兮，集義以爲詞。',211,'全唐诗/poet.song.63000.json','["論世以觀士兮，集義以爲詞。", "所非正而敢從兮，日可罣而東之。", "嗟若士之弗獲兮，羌何忿而負石。", "繄聖賢之出處兮，惟遵道而守德。", "鳳覽輝而乃下兮，雛猶恥乎腐嚇。", "非九方之爲使兮，夫何足以得馬。", "廬岑岑以鎮楚兮，洶大江之東涹。", "分陰陽之晦明兮，鍾斯人以正直。", "惟天道與地寶兮，非所求其猶愛。", "與之全而不用兮，懷斯美以固在。", "大固不可以適兮，方固不可以圓。", "試回功謝於土穀兮，夫乃同道於禹稷。", "譬人生猶吹吷兮，無得喪之可齊。", "紛吾何指以爲正兮，服吾初其庶幾。"]'),
('97aec35d-3aa1-44a3-a2a0-39726de41ad3','漫浪閣辭','晁補之','宋','宋诗','song-poetry','','[]','沛高皇之受嬴兮，劉別子曰楚元。',361,'全唐诗/poet.song.63000.json','["沛高皇之受嬴兮，劉別子曰楚元。", "羌好詩而說義兮，敬設醴於穆生。", "戊始怠而穆去兮，申白笑而鉗市。", "富傳孫而失國兮，派辟彊之支子。", "爰清浄而少欲兮，以身悟乎霍光。", "蹇孫向之洽聞兮，至耆老而彌良。", "曰衆賢和於朝兮，萬物和於野。", "粵百世而能調兮，民胥來而鳳下。", "惟劉有後於楚兮，千歲發夫道原。", "流其芳以益遠兮，偉壯輿之不愆。", "原惟博而好直兮，向異世而復起。", "輿惟進而未已兮，載向學亦不墜。", "彼元結之信修兮，羌何爲此漫浪也。", "將履中而晦外兮，其德固天之放也。", "惟漫浪之爲言兮，匪正則之嘉名。", "豈其懲屈之死忠兮，欲猗移以保生。", "結當易之一爻兮，幽人履而正吉。", "輿方壯而惡畫兮，棄爾輔欲誰頼。", "吾語子漫浪之可兮，遺物往其庶幾。", "苟畏人而羣於人兮，拭唾面其猶殆。", "朝騁望乎紫霄兮，夕歸次乎左蠡。", "五老兮在上，星子兮在下。", "垂瀑介於高丘兮，洞深林而北靡。", "飛梁亙於三峽兮，倏異景而殊世。"]'),
('4b9e9906-878c-40e9-a700-761436200d75','遐觀樓辭','晁補之','宋','宋诗','song-poetry','','[]','窘牆堵之伏潛兮，登斯樓以遐觀。',357,'全唐诗/poet.song.63000.json','["窘牆堵之伏潛兮，登斯樓以遐觀。", "匪吾居之爲隘兮，乾坤曶其盂盤。", "仰攀甍而拊楯兮，宇曠曠而益寬。", "彼何大而能舒兮，吾何眇而莫閑。", "霜肅壟而木枯兮，潦收竇而澤乾。", "蓬鳴野而相追兮，知海冰而天寒。", "左睇兮城闉，右盼兮林坰。", "商賈紛其晝合兮，陶冶蓊其煙興。", "之罘杳以在東，雙柏近而青青。", "物暇遽之不同兮，余亦不知其何情。", "聊浮遊以相羊兮，初怫鬰而中清。", "彼坱圠之無垠兮，人駒隙之暫更。", "道本夷而世險兮，夸奪饜而卒平。", "周垣兀其跨衍兮，逝千古於樵耕。", "春與秋之不淹兮，歲忽忽其崢嶸。", "招搖指於北陸兮，澹黄宮之陽生。", "固天道之反覆兮，氣默會而孤萌。", "朝卷箔而極望兮，稍霧廓而日晶。", "及暘景之方中兮，晞余髮乎南榮。", "浮雲起而景翳兮，四暝合而覩星。", "風摵摵而感軒兮，雀啾啾而赴楹。", "收百爲以清慮兮，施余裯而榻橫。", "漠洶洶而非聲兮，邈冉冉而非征。", "形欺魄而若存兮，神無虧而靡成。"]'),
('0d21bad3-1116-4ba9-9fcf-f5d2d9991624','樂哉侯之邦兮樂哉侯之堂兮  其一','晁補之','宋','宋诗','song-poetry','','[]','樂哉侯之邦兮，封楚宮與復關。',176,'全唐诗/poet.song.63000.json','["樂哉侯之邦兮，封楚宮與復關。", "美哉洋洋水兮，崑崙始乎并川。", "桐離夫其實兮，綠竹兌於丘園。", "三年庶夫有成兮，蹇吾師其永歎。", "營室壁而建墉兮，參國一其可觀。", "塗椒丘吾駕車兮，攬予騑之嘽嘽。", "襲予旆之悠悠兮，侯降觀其于田。", "春陽滿其親天兮，乃物作而芄蘭。", "來吾省夫在疇兮，介黍稷之有年。", "侯寧般于遊兮，無非事而不煩。", "羌信修而好我兮，曷懷歸而翩翩。", "信侯邦之可樂兮，蹇携手其同行。"]'),
('3b6d0538-1173-43db-bae8-f951c24c5b80','樂哉侯之邦兮樂哉侯之堂兮  其二','晁補之','宋','宋诗','song-poetry','','[]','樂哉侯之堂兮，高門桀兮蘭錡。',164,'全唐诗/poet.song.63000.json','["樂哉侯之堂兮，高門桀兮蘭錡。", "切雲冠之峨峨兮，四牡矯兮戾止。", "夜悠悠其未晨兮，紛侯庭之徙履。", "雲容容而承楣兮，日澹澹兮階戺。", "雨雪晛其將流兮，黄宮動乎子美。", "爰俶生之煌煌兮，又尚茲夫介祉。", "嚴若植其姣服兮，侯何須兮堂際。", "進蕙幬予稱觥兮，芬予席之蘭茝。", "朱顔忽其滿堂兮，五音昌兮來會。", "藐姑射之綽約兮，愿慤保而爲使。", "洵侯堂之可樂兮，與日月其無圮。"]'),
('86be5ae6-eb26-4267-844c-0979265d8a4c','維夫君兮桂舟一首送梁正受歸汶陽','晁補之','宋','宋诗','song-poetry','','[]','維夫君兮桂舟，酌余酒兮攬君留。',275,'全唐诗/poet.song.63000.json','["維夫君兮桂舟，酌余酒兮攬君留。", "君何爲兮此野，菊菲菲兮蜨下。", "韡韡兮煌煌，爛金敷兮襲余堂。", "茱萸兮芙蓉，衆芳越兮亂五風。", "饑咀兮靈芝，君歌樂兮余和之。", "日下兮野陰，澹忘歸兮中林。", "橘棟兮梅宇，紛瓊茅兮被南榮。", "白羽兮黑翮，邀仙人兮語此文。", "余高馳兮世之外，君猋舉兮先余至。", "襟带兮東方旦，爭門兮汶之陽。", "大野兮始波，翔鶬鸛兮嘷鴐鵝。", "羣宿兮迷阯，旅食兮殫穗。", "霜肅肅兮葉方下，君欲濟兮淹回。", "水通道兮躞蹀，冠如箕兮带長鋏。", "里千室兮士一喙，余不善兮紛余誶。", "世謂折揚好兮，余白雪而莫知棄。", "火布而以爲垢兮，胡不浣炎而振之。", "彼鏌邪而能言兮，工謂余以不祥。", "聊逍遥而挫銳兮，蒙黯黮而益光。"]'),
('e6bffe6d-b4a2-4801-a21d-284afa522101','山坡陀辭','晁補之','宋','宋诗','song-poetry','','[]','山坡陀兮下屬江，勢崖絕兮濤波所盪如頹牆。',319,'全唐诗/poet.song.63000.json','["山坡陀兮下屬江，勢崖絕兮濤波所盪如頹牆。", "松鬰律兮其高百尺，旁枝虬騖葛虆之。", "仰不見日兮下可依，吾曳杖兮吾僮以吾之書隨。", "邈余望兮水中汦，頎然而長者黄冠兮羽衣。", "軒頤坦腹濤石箕坐兮，石亦有趾安不危，四無人兮可忘饑。", "仙人偓佺兮自言其居瑶之圃，一日一夕兮飛相往來不可數。", "使其開口而言兮，豈惟河漢無極驚余心。", "默不言兮，蹇昭氏之不鼓琴。", "憺將翔兮山海，與日月兮常在。", "若有聞兮夢中仇池我歸路，此非小有兮噫乎何以樂此而不去。", "昔余遊於葛天氏兮，身非陶氏猶與偕乘。", "渺莽良未可兮，僕夫悲余馬懷。", "聊逍遥兮容與，晞余髮兮蘭之陼。", "余論世兮千載一人猶並時，歧又有歧兮余行詰曲欲知余者希。", "峨峨洋洋余方樂兮，譬余擊舟於水。", "魚沉鳥揚亦不知，何必每念輒得應余若響，坐有如此兮人子期。"]'),
('8faee51d-3784-46c4-af02-eff396874a91','白紵辭上蘇翰林二首  其一','晁補之','宋','宋诗','song-poetry','','[]','白紵棼莫緝，紉蘭作衣袪。',48,'全唐诗/poet.song.63000.json','["白紵棼莫緝，紉蘭作衣袪。", "朝兮日所暴，暮兮雨所濡。", "木瓜諒微物，期報乃瓊琚。", "芳華辭甚妙，贈我不如無。"]'),
('07e6691c-4ac5-4798-8464-852913c7ae59','白紵辭上蘇翰林二首  其二','晁補之','宋','宋诗','song-poetry','','[]','上山割白紵，山高葉摵摵。',48,'全唐诗/poet.song.63000.json','["上山割白紵，山高葉摵摵。", "持歸當戶績，爲君爲絺綌。", "不惜潔如霜，畏君莫我即。", "誰言菖蒲花，可聞不可識。"]'),
('b8ecbe43-2f90-45ef-b30d-a8ee49fc6be1','江頭秋風辭','晁補之','宋','宋诗','song-poetry','','[]','雒陽客，後車結駟傳燭食，人生富貴不易得。',68,'全唐诗/poet.song.63000.json','["雒陽客，後車結駟傳燭食，人生富貴不易得。", "江頭秋風旦夕起，胡爲翩翩雒陽陌。", "雒陽陌，吹塵埃。", "江頭樹，安在哉。", "秋風起，菱花開。", "鱸魚肥，歸去來。"]'),
('2328f28b-327a-4abb-97ce-56ea9dac5c31','琴中宮調辭','晁補之','宋','宋诗','song-poetry','','[]','神仙神仙何處，青山裏，白雲際，不似人間世。',48,'全唐诗/poet.song.63000.json','["神仙神仙何處，青山裏，白雲際，不似人間世。", "源上正碧桃春，清溪乍逢人。", "住無因，憶紅塵，出洞花紛紛。"]'),
('e3ff8ff7-ae7b-4c6a-92cc-d2ca76cfad3d','擬古六首上鮮于大夫子駿 西北有高樓','晁補之','宋','宋诗','song-poetry','','[]','西北有高樓，縹緲齊紫清。',96,'全唐诗/poet.song.63000.json','["西北有高樓，縹緲齊紫清。", "周欄十二折，飛鸞結丹楹。", "上有絃歌女，充耳以黄瑛。", "當窗弄白日，顔若苕之榮。", "陽阿奮哀響，梁欐有遺聲。", "不惜厲清商，零霜飛園英。", "誰爲聽之者，皎皎自知明。", "幸承遺褋眷，同車以遐征。"]'),
('cc3fb1b0-969d-4152-be7a-d42492bc89f8','擬古六首上鮮于大夫子駿 東城高且長','晁補之','宋','宋诗','song-poetry','','[]','東城高且長，下瞰阡與陌。',144,'全唐诗/poet.song.63000.json','["東城高且長，下瞰阡與陌。", "谷風麗百草，春華紛已白。", "良時忽如此，馳景一何逼。", "喟彼飯牛詩，終年守寒阨。", "恭儉夙所敦，葛屨傷褊窄。", "身爲物逆旅，生乃遠行客。", "豈無百日蜡，樂此一日澤。", "美人顔煌煌，奇服爛五色。", "彈箏奮新響，盃酒縱相索。", "鬭雞逐狐兔，六博呼一擲。", "貧士悲失職，坎壈何所迫。", "安知黄鵠舉，隨時振六翮。"]'),
('7323af1d-a5fc-4100-be4a-176614e7e1e0','擬古六首上鮮于大夫子駿 庭前有奇樹','晁補之','宋','宋诗','song-poetry','','[]','庭前有奇樹，好鳥鳴喈喈。',48,'全唐诗/poet.song.63000.json','["庭前有奇樹，好鳥鳴喈喈。", "朱榮被紫萼，采掇以忘懷。", "棄置而不省，秋風淒以摧。", "不惜朝華暮，君行殊未來。"]'),
('6e26a4b6-7df2-4d70-baaa-56c1d3bfa407','擬古六首上鮮于大夫子駿 冉冉孤生竹','晁補之','宋','宋诗','song-poetry','','[]','冉冉孤生竹，託根中谷卑。',84,'全唐诗/poet.song.63000.json','["冉冉孤生竹，託根中谷卑。", "結髮事君子，江蘺近華池。", "江蘺榮有時，迨此春冰期。", "玉盤有嘉餐，思君以忘饑。", "棗下何纂纂，朱實亦離離。", "秋風一披拂，菀其爲枯枝。", "願垂太陽惠，照妾葵藿微。"]'),
('33484356-9a6e-4359-ae94-0644235a60f3','擬古六首上鮮于大夫子駿 涉江采芙蓉','晁補之','宋','宋诗','song-poetry','','[]','涉江采芙蓉，江上零露滋。',48,'全唐诗/poet.song.63000.json','["涉江采芙蓉，江上零露滋。", "方舟不能度，日暮白蘋悲。", "清波有鳴鴻，蕩漾安可期。", "幸因南風逝，寄言欽所思。"]'),
('20f91bb1-f0cc-4935-836d-380d703dde69','擬古六首上鮮于大夫子駿 生年不滿百','晁補之','宋','宋诗','song-poetry','','[]','生年不滿百，一日何三秋。',60,'全唐诗/poet.song.63000.json','["生年不滿百，一日何三秋。", "花開苦多雨，何不張幕游。", "行樂時不再，春榮豈長在。", "古人輕尺璧，愚者昧所戒。", "君看龍與虎，飄忽不相待。"]'),
('25b2f4c3-1d49-4303-811b-3d0460813bf3','建除體二首答黄魯直教授  其一','晁補之','宋','宋诗','song-poetry','','[]','建策移漢都，奉春緣衣布。',144,'全唐诗/poet.song.63000.json','["建策移漢都，奉春緣衣布。", "除地願見公，及以舍人故。", "滿船載明月，且復酌清酤。", "平旦襏襫出，牛羊下來暮。", "定境要兩言，出處非並趣。", "執臂欣逢迎，秋蘭在堂下。", "破甑雨生衣，蹇不改茲度。", "危莫如人心，難莫如行路。", "成事安得悔，來者其可悟。", "收拾不須陳，千言一棄屨。", "開門見井市，終歲紛遑遽。", "閉門面牆壁，少日豐暇豫。"]'),
('a2ea18ab-2328-44da-90d7-898080d38dfa','建除體二首答黄魯直教授  其二','晁補之','宋','宋诗','song-poetry','','[]','建鼓求亡子，初昧學所之。',144,'全唐诗/poet.song.63000.json','["建鼓求亡子，初昧學所之。", "除去日月多，及此歲未遲。", "滿國和巴人，若士誰與知。", "平陸不推舟，客行當來茲。", "定居厭屋廬，風雨勞所思。", "執鞭慕昔人，孰與並此時。", "破裘不御冬，要假完腋裨。", "危言則來詬，慎密又逢譏。", "成德尚如是，薄志安能期。", "收聲復藏熱，雷火忽然微。", "開口且復歡，是事置勿推。", "閉眼可內視，獨復不自爲。"]'),
('9832ef46-a8ba-459f-b950-a7d2d379a2a0','八音歌二首答黄魯直  其一','晁補之','宋','宋诗','song-poetry','','[]','金蘭况同心，莫樂心相知。',96,'全唐诗/poet.song.63000.json','["金蘭况同心，莫樂心相知。", "石田罹清霜，念此百草腓。", "絲看煮繭吐，士聽憤悱語。", "竹馬非妙齡，美人恐遲暮。", "匏繫魯東家，今君尚天涯。", "土膏待陽癉，氣至如咄嗟。", "革薄不可廓，士迫下流惡。", "木無松柏心，蝎處螻蟻託。"]'),
('91da2fe7-a9e1-4253-9447-726a14e99c20','八音歌二首答黄魯直  其二','晁補之','宋','宋诗','song-poetry','','[]','金丹妙通靈，子有遺世術。',96,'全唐诗/poet.song.63000.json','["金丹妙通靈，子有遺世術。", "石髓不成餐，閔予多滯骨。", "絲聲紡事暮，搗聲寒事來。", "竹葉將菊花，及時同一盃。", "匏器祀天地，貴質不貴華。", "土緣井渠繁，生氣泄大和。", "革面固非性，小人變丹青。", "木雞本無心，風雨安所能。"]'),
('ba0389c4-cf71-4077-b793-d983da3d131b','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其一','晁補之','宋','宋诗','song-poetry','','[]','鳲鳩興獨居，百兩誰與將。',48,'全唐诗/poet.song.63000.json','["鳲鳩興獨居，百兩誰與將。", "未見憂忡忡，既覯爲龍光。", "吹竽沸齊市，零雨暗空桑。", "寒歌牛軛底，激烈氣彌剛。"]'),
('cce5f881-09eb-4abc-becf-c8608ed31b0c','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其二','晁補之','宋','宋诗','song-poetry','','[]','雁以無能亨，鼠以有技窮。',48,'全唐诗/poet.song.63000.json','["雁以無能亨，鼠以有技窮。", "古來達生者，神不馳其胸。", "物或似而非，藁本奪芎藭。", "臧否何間然，吾師阮生風。"]'),
('f586d559-7dea-4bb8-ae58-712d0e8fb350','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其三','晁補之','宋','宋诗','song-poetry','','[]','倉鶊知陽春，喬木聲關關。',48,'全唐诗/poet.song.63000.json','["倉鶊知陽春，喬木聲關關。", "白駒不食苗，奈此空谷寒。", "昔有丹徒士，檳榔貯金槃。", "富貴懷隠憂，無寧歸故山。"]'),
('8502dc30-4c4f-4d94-a5a9-a5cb4c0a2fa7','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其四','晁補之','宋','宋诗','song-poetry','','[]','吾期瑶之圃，玉英良可采。',48,'全唐诗/poet.song.63000.json','["吾期瑶之圃，玉英良可采。", "崑崙在萬里，積石更磊磈。", "學經儻無用，詩禮發含琲。", "叢臺尚何爲，袨服若煙海。"]'),
('292cd4bf-6f36-410e-8250-c54d7b1400db','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其五','晁補之','宋','宋诗','song-poetry','','[]','鼓吹出西羌，光華動眉額。',48,'全唐诗/poet.song.63000.json','["鼓吹出西羌，光華動眉額。", "鞬櫜望酒泉，面有可憐色。", "念身匪兕虎，少日四方迹。", "百計等畫蛇，老大悲故國。"]'),
('13c696e6-d984-4dd3-8b43-9fac2b8102fc','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其六','晁補之','宋','宋诗','song-poetry','','[]','謝公文章餘，幽事課伐嶺。',48,'全唐诗/poet.song.63000.json','["謝公文章餘，幽事課伐嶺。", "清詩如玄酒，胡乃淡而永。", "得無西堂夢，春草句彌勝。", "但使田野傳，何須論銘鼎。"]'),
('c0307664-7361-4daa-839b-8d318b6cabbd','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其七','晁補之','宋','宋诗','song-poetry','','[]','江南盛鬰蒸，代北紛霰雪。',48,'全唐诗/poet.song.63000.json','["江南盛鬰蒸，代北紛霰雪。", "卞生無出游，何以得此刖。", "一朝有天運，春華未萎絕。", "吾猶託雄鳩，而彼固不拙。"]'),
('a2e6172a-3d98-49a1-aca5-5b022602d936','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其八','晁補之','宋','宋诗','song-poetry','','[]','平生莫逆交，弦斷寄心賞。',48,'全唐诗/poet.song.63000.json','["平生莫逆交，弦斷寄心賞。", "相思望青楓，目極江水上。", "念當及時節，農事動春壤。", "來者不有年，何能咎吾往。"]'),
('158387e9-8688-45f4-8482-21b46dc21201','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其九','晁補之','宋','宋诗','song-poetry','','[]','楚有吹竹者，工作百獸音。',48,'全唐诗/poet.song.63000.json','["楚有吹竹者，工作百獸音。", "削格爲爾多，滔滔寧適今。", "嘗俾範馳驅，終日無一禽。", "復之儻或可，詭遇亦何心。"]'),
('f8ec5b59-7c0f-483e-bd25-ce64024bf37b','感寓十首次韵和黄著作魯直以將窮山海迹勝絕賞心晤爲韵  其一○','晁補之','宋','宋诗','song-poetry','','[]','葉公好畫龍，龍固不可晤。',48,'全唐诗/poet.song.63000.json','["葉公好畫龍，龍固不可晤。", "安知下其室，驚駭暗楹霧。", "昭王亦貿骨，冀以得馬故。", "相者競舉肥，終然駒遠去。"]'),
('07f48c6b-9588-4c73-a84b-a885b9da6cd9','西歸七首次韵和泗州十五叔父  其一','晁補之','宋','宋诗','song-poetry','','[]','潔腹不受污，昔人因食薇。',48,'全唐诗/poet.song.63000.json','["潔腹不受污，昔人因食薇。", "薇亦周土生，悲哉懷永饑。", "武王與周公，聖德天動威。", "奈此二子何，猶歎安適歸。"]'),
('9cd1e7ed-001a-49ce-a84b-087eb8b873ef','西歸七首次韵和泗州十五叔父  其二','晁補之','宋','宋诗','song-poetry','','[]','霏雨晚霑裳，零霜曉被路。',48,'全唐诗/poet.song.63000.json','["霏雨晚霑裳，零霜曉被路。", "驅車歎時邁，所遇一無故。", "悠悠天地宇，萬物各有聚。", "閟我冰雪姿，幽居從可住。"]'),
('14e6fa42-bbcc-4dea-a993-be085d498754','西歸七首次韵和泗州十五叔父  其三','晁補之','宋','宋诗','song-poetry','','[]','暮投古店宿，夜聞狐狸嘷。',48,'全唐诗/poet.song.63000.json','["暮投古店宿，夜聞狐狸嘷。", "僕夫告行邁，起視月尚高。", "清霜來何許，不覺滿我袍。", "逆舍良非時，求前茲已勞。"]'),
('fd07d96c-37e9-4408-9372-56356823f5fe','西歸七首次韵和泗州十五叔父  其四','晁補之','宋','宋诗','song-poetry','','[]','浮雲如游塵，倏忽蔽白日。',48,'全唐诗/poet.song.63000.json','["浮雲如游塵，倏忽蔽白日。", "登高念搖落，歲暮一何疾。", "東陵種瓜事，富貴寧可必。", "人生無南北，行樂時易失。"]'),
('2cb4f3d1-7c5b-4b1e-ad8b-b985e3c435ce','西歸七首次韵和泗州十五叔父  其五','晁補之','宋','宋诗','song-poetry','','[]','驅馬馬走山，回車車漸水。',48,'全唐诗/poet.song.63000.json','["驅馬馬走山，回車車漸水。", "塗窮我何適，慟哭盈襟淚。", "巢居識風聲，穴藏知雨意。", "救鬭曾得傷，纓冠亦可已。"]'),
('bbc5f041-41c0-49ad-9377-955c3c868c68','西歸七首次韵和泗州十五叔父  其六','晁補之','宋','宋诗','song-poetry','','[]','贈君彼風蘭，佩之可爲璫。',48,'全唐诗/poet.song.63000.json','["贈君彼風蘭，佩之可爲璫。", "贈君彼露荷，製之可爲裳。", "薄言茲擷掇，道遠莫置傍。", "崢嶸又歲暮，與君同所望。"]'),
('795003cf-c636-4614-a9d7-2e7d2c762ce5','西歸七首次韵和泗州十五叔父  其七','晁補之','宋','宋诗','song-poetry','','[]','古人重生男，豚酒慶親戚。',48,'全唐诗/poet.song.63000.json','["古人重生男，豚酒慶親戚。", "桑弧射四方，言有四方役。", "奉璋比德性，墮地要膂力。", "如何晉公子，安樂忘所適。"]'),
('43ba0696-8e23-4476-b548-3ff5e0473c37','感興五首次韵和李希孝  其一','晁補之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','海鳥御羊角，飄然凌紫清。',48,'全唐诗/poet.song.63000.json','["海鳥御羊角，飄然凌紫清。", "有背如泰山，未覺毛羽輕。", "鹽陽亦羣飛，日景爲不明。", "空倉自苦饑，安得有此名。"]'),
('7b875046-9574-497b-8574-e872ca506a90','感興五首次韵和李希孝  其二','晁補之','宋','宋诗','song-poetry','','[]','人生須富貴，如俟河之清。',48,'全唐诗/poet.song.63000.json','["人生須富貴，如俟河之清。", "草木競榮華，春服亦已輕。", "桑田自足樂，未可居高明。", "君子順天道，小人眷時名。"]'),
('73645b66-346f-4b1e-870d-cb3931d8befc','感興五首次韵和李希孝  其三','晁補之','宋','宋诗','song-poetry','','[]','長歌遺世情，滄浪之水清。',48,'全唐诗/poet.song.63000.json','["長歌遺世情，滄浪之水清。", "鑠金在衆口，折軸由羣輕。", "君子貴同塵，安事皎皎明。", "儻在子所呼，牛馬亦我名。"]'),
('7d9a3abe-0867-4fa2-b6c6-820981b947d7','感興五首次韵和李希孝  其四','晁補之','宋','宋诗','song-poetry','','[]','不肯埽一室，顧欲天下清。',48,'全唐诗/poet.song.63000.json','["不肯埽一室，顧欲天下清。", "少日又不羈，頗復鄉黨輕。", "長年始羞悔，耳目尚聰明。", "何須更市藥，小女故知名。"]'),
('b1a66762-db1b-4226-a63d-fc5d688c2a7a','感興五首次韵和李希孝  其五','晁補之','宋','宋诗','song-poetry','','[]','春半寒未已，今晨天氣清。',48,'全唐诗/poet.song.63000.json','["春半寒未已，今晨天氣清。", "彈冠適新沐，搔髮亦良輕。", "但愛百鳥樂，復憐一窗明。", "干世寧可期，歸耕良近名。"]'),
('abd08c66-fe1d-45be-ae19-76055b30f29c','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一','晁補之','宋','宋诗','song-poetry','','[]','少賤足可喜，險阻更嘗之。',60,'全唐诗/poet.song.63000.json','["少賤足可喜，險阻更嘗之。", "爲親謀斗粟，無意出競時。", "緬焉效一官，報國方在茲。", "寧當不卹緯，對酒懷憂疑。", "學道恨力淺，中遭世網持。"]'),
('3a68c8a0-a0e4-47ac-92de-3fdb8cc427a1','飲酒二十首同蘇翰林先生次韵追和陶淵明  其二','晁補之','宋','宋诗','song-poetry','','[]','沉飲非荒宴，凜然忽頹山。',48,'全唐诗/poet.song.63000.json','["沉飲非荒宴，凜然忽頹山。", "或人欲問事，已醉不能言。", "古來亦如此，名字垂千年。", "但問酒中適，豈計飲者傳。"]'),
('7783907d-e1af-4049-b8ec-753b02201fe9','飲酒二十首同蘇翰林先生次韵追和陶淵明  其三','晁補之','宋','宋诗','song-poetry','','[]','陶公羣於人，而無人之情。',60,'全唐诗/poet.song.63000.json','["陶公羣於人，而無人之情。", "詩豈世外語，世語不可名。", "東坡憐此翁，同調但隔生。", "形光來戶屨，真處人不驚。", "得酒自醒醉，放意無虧成。"]'),
('3971a7a7-c7a5-4090-9737-982b76d7d132','飲酒二十首同蘇翰林先生次韵追和陶淵明  其四','晁補之','宋','宋诗','song-poetry','','[]','園林日夕好，花繁時鳥飛。',72,'全唐诗/poet.song.63000.json','["園林日夕好，花繁時鳥飛。", "少年玩芳物，不飲成坐悲。", "只今未白髮，念昔已依依。", "紛華戰吾道，决勝當有歸。", "挫銳培其根，外槁中匪衰。", "念方終日行，輜重安得違。"]'),
('4c306319-9f36-4c85-bbc8-90f5f037e010','飲酒二十首同蘇翰林先生次韵追和陶淵明  其五','晁補之','宋','宋诗','song-poetry','','[]','一眼異青白，口語來啾喧。',60,'全唐诗/poet.song.63000.json','["一眼異青白，口語來啾喧。", "酌一不酌一，用意何其偏。", "誰似子孫子，高栖蘇門山。", "時隨嶺雲出，又與林鳥還。", "平生但長嘯，獨爲嵇生言。"]'),
('a93d6363-7805-4671-a4c6-6f2604844775','飲酒二十首同蘇翰林先生次韵追和陶淵明  其六','晁補之','宋','宋诗','song-poetry','','[]','高賢衆所懷，衆理應取是。',48,'全唐诗/poet.song.63000.json','["高賢衆所懷，衆理應取是。", "如何濟衆事，難成復易毀。", "功成身無與，天運亦復爾。", "軒裳役羣愚，兒曹眩文綺。"]'),
('c4244a08-b3dc-461a-87f7-21575d95aa2e','飲酒二十首同蘇翰林先生次韵追和陶淵明  其七','晁補之','宋','宋诗','song-poetry','','[]','庭前兩古柏，凌霄燦其英。',60,'全唐诗/poet.song.63000.json','["庭前兩古柏，凌霄燦其英。", "問此誰榮枯，雪霜見其情。", "榮枯何足計，有酒還自傾。", "熟寐暫展轉，覺來一蟬鳴。", "歸休但如此，便足了平生。"]'),
('93351fa7-631d-484f-b726-5f27089b8fba','飲酒二十首同蘇翰林先生次韵追和陶淵明  其八','晁補之','宋','宋诗','song-poetry','','[]','功名有天命，美好無定姿。',60,'全唐诗/poet.song.63000.json','["功名有天命，美好無定姿。", "雲夢未足吞，聊可巢一枝。", "同時金門士，文學多瑰奇。", "幞被向淮海，酣放遽爾爲。", "車蓋豈不榮，野馬不受羈。"]'),
('550a7d79-e727-4382-9d46-fd8c72c7b817','飲酒二十首同蘇翰林先生次韵追和陶淵明  其九','晁補之','宋','宋诗','song-poetry','','[]','城東故鹽渠，自昔誰所開。',96,'全唐诗/poet.song.63000.json','["城東故鹽渠，自昔誰所開。", "似說全盛時，邈焉一長懷。", "穿渠引江水，此計未爲乖。", "千帆競暮入，集浦如烏棲。", "萬疇分白浪，嘉稻擢新泥。", "恐此太多事，且當寄嬉諧。", "疏通養魚鳥，花柳共低迷。", "時時載酒往，江上亦忘回。"]'),
('7f5c39fe-f84b-44f9-b960-3bfe86d12ac7','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一○','晁補之','宋','宋诗','song-poetry','','[]','大明唐來寺，廢苑西南隅。',60,'全唐诗/poet.song.63000.json','["大明唐來寺，廢苑西南隅。", "青松拱高阜，崎嶇有微途。", "肩輿病我早，一馬良可驅。", "衆木媚深壑，氣熏時雨餘。", "此焉可數醉，何用葺吾居。"]'),
('f21da29c-6681-484e-b113-8c80117cc192','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一一','晁補之','宋','宋诗','song-poetry','','[]','蘇公士冠冕，復似郭有道。',72,'全唐诗/poet.song.63000.json','["蘇公士冠冕，復似郭有道。", "知士未達間，趣操保耆老。", "精鋼試九火，勞倦容不槁。", "爲州第飲酒，况此年歲好。", "藏鋒避世故，輕敵喪吾寶。", "時來用毫末，勳業自世表。"]'),
('bf2bc5aa-67cd-46cb-ba19-fac5c15979ab','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一二','晁補之','宋','宋诗','song-poetry','','[]','東漢有兩士，才智炫一時。',72,'全唐诗/poet.song.63000.json','["東漢有兩士，才智炫一時。", "三公往訪事，卧痾亦見辭。", "偉明獨不然，小道安取茲。", "斯人似水鏡，與世破昏疑。", "憂國不爲身，百世那可欺。", "舉盃相歡屬，是事亦置之。"]'),
('e0628a1f-cbbe-4bf8-8abd-5138e76add1c','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一三','晁補之','宋','宋诗','song-poetry','','[]','齋居忽若遺，不識身與境。',60,'全唐诗/poet.song.63000.json','["齋居忽若遺，不識身與境。", "頗疑酣中似，奈爾輒復醒。", "東坡自云然，挈世一裘領。", "是事吾有師，安敢囊出穎。", "指窮火已傳，豈待得薪炳。"]'),
('83f646b1-08c4-4e54-b4a1-291cf0403a43','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一四','晁補之','宋','宋诗','song-poetry','','[]','安昌漢耆儒，樂飲侈亦至。',60,'全唐诗/poet.song.63000.json','["安昌漢耆儒，樂飲侈亦至。", "東坡儉不固，少飲得徑醉。", "愚敢效戴崇，正復思其次。", "旁通獲親愛，公亦安所貴。", "便坐時一巵，彭宣寧寡味。"]'),
('635ed79d-d17f-45ab-95b7-f9d1c012a74c','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一五','晁補之','宋','宋诗','song-poetry','','[]','幼聞錦江春，欲訪子雲宅。',60,'全唐诗/poet.song.63000.json','["幼聞錦江春，欲訪子雲宅。", "叩門問奇字，便埽四方跡。", "青雲看一鶚，凡毛愧累百。", "勞公諭伯業，齒堅頭未白。", "何當擺俗累，歲月可惋惜。"]'),
('52a68656-4d55-4ba7-a0ba-9049aa01c663','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一六','晁補之','宋','宋诗','song-poetry','','[]','王道無偏黨，此語聞諸經。',72,'全唐诗/poet.song.63000.json','["王道無偏黨，此語聞諸經。", "高賢如大海，亦以衆流成。", "文饒歎維州，刀鋸人所更。", "相如後私怨，此語驚秦庭。", "小人慮事疏，妄意鹽車鳴。", "安得如江酒，洗我塵垢情。"]'),
('2327d0a0-f228-4f08-8b13-381eb79c3b93','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一七','晁補之','宋','宋诗','song-poetry','','[]','淮南夏早收，晚秧亦含風。',48,'全唐诗/poet.song.63000.json','["淮南夏早收，晚秧亦含風。", "連艫似雍絳，千斛輸吳中。", "使君飲酒樂，歲美關梁通。", "安得天下人，俱忘楚人弓。"]'),
('760799d2-f94e-4a77-a6d8-92d43613d924','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一八','晁補之','宋','宋诗','song-poetry','','[]','十年一麥禾，此歲亦難得。',60,'全唐诗/poet.song.63000.json','["十年一麥禾，此歲亦難得。", "寄語吾州人，不飲良大惑。", "經時無死市，吏責亦可塞。", "先生門弟子，佐守同一國。", "舉杯日相屬，有句安得默。"]'),
('e2cdb639-7570-476d-8d8b-73c5767215ba','飲酒二十首同蘇翰林先生次韵追和陶淵明  其一九','晁補之','宋','宋诗','song-poetry','','[]','堂堂門下公，英發自初仕。',84,'全唐诗/poet.song.63000.json','["堂堂門下公，英發自初仕。", "卷舒固以時，出處不爲己。", "朝廷登儒輔，德禮民有恥。", "岷峨更崢嶸，清風在閭里。", "獨醒固不惡，既醉又可紀。", "成王訪落時，百室賦盈止。", "吾儕爲國謀，私愛不足恃。"]'),
('4b8364fc-5452-45fc-b904-4037ea6a0805','飲酒二十首同蘇翰林先生次韵追和陶淵明  其二○','晁補之','宋','宋诗','song-poetry','','[]','黄子似淵明，城市亦復真。',120,'全唐诗/poet.song.63000.json','["黄子似淵明，城市亦復真。", "陳君有道舉，化行閭井淳。", "張侯公瑾流，英思春泉新。", "高才更難及，淮海一髯秦。", "嗟予競何爲，十駕晞後塵。", "文章不急事，用意斯已勤。", "平生不共飲，歎息無與親。", "問道伯昏室，何人獨知津。", "各在天一方，淚落衣上巾。", "歸休可共隠，山中復何人。"]'),
('6c3964c2-5683-440f-80f3-339e349e4557','視田五首贈八弟無斁  其一','晁補之','宋','宋诗','song-poetry','','[]','河流之所濡，一斛泥數斗。',48,'全唐诗/poet.song.63000.json','["河流之所濡，一斛泥數斗。", "我莊當水窮，乃比石田瘦。", "尚無東陵瓜，況有南山豆。", "天雨不可期，且復鞭牛後。"]'),
('10de7805-b4d5-4381-a080-e744339051eb','視田五首贈八弟無斁  其二','晁補之','宋','宋诗','song-poetry','','[]','蘇秦不願印，迺在二頃田。',48,'全唐诗/poet.song.63000.json','["蘇秦不願印，迺在二頃田。", "東皋五十畝，力薄荆杞填。", "擇高種苜蓿，不溼牛口涎。", "拙計安足爲，朝往而暮旋。"]'),
('f0ab3d9b-cf60-4603-b3ec-434ca0916776','視田五首贈八弟無斁  其三','晁補之','宋','宋诗','song-poetry','','[]','薄遊廢家務，待子營糗糧。',48,'全唐诗/poet.song.63000.json','["薄遊廢家務，待子營糗糧。", "莊奴不入租，報我田久荒。", "凌矜馬到門，硉兀牛卧場。", "立苗蒼耳根，此策殊未長。"]'),
('9cc64ee7-856a-481e-aad7-866e5605fd0e','視田五首贈八弟無斁  其四','晁補之','宋','宋诗','song-poetry','','[]','家世不爲農，長安有大第。',48,'全唐诗/poet.song.63000.json','["家世不爲農，長安有大第。", "官糧弗充口，萬里聊自庇。", "一從學聱牙，世事百色廢。", "賣牛姑補屋，歲晚霜雪至。"]'),
('a9aef4ae-f729-4617-b6ae-1ced259ea0dc','視田五首贈八弟無斁  其五','晁補之','宋','宋诗','song-poetry','','[]','居貧廢文字，銚鎒學苦耕。',48,'全唐诗/poet.song.63000.json','["居貧廢文字，銚鎒學苦耕。", "怪子獨伶俜，久與地力爭。", "苦耕又不時，狐虺日縱橫。", "高原一釋耒，歎息心怦怦。"]'),
('8dd4aa07-af8b-4f8f-bac6-f435d5eb55fb','即事一首次韵祝朝奉十一丈','晁補之','宋','宋诗','song-poetry','','[]','平生交游情，獨處不可乍。',288,'全唐诗/poet.song.63000.json','["平生交游情，獨處不可乍。", "那爲一馬飲，濁水噴百馬。", "弦歌高樓上，但恨知者寡。", "丈人遺世心，口語儻能借。", "不然抱幽璞，終歲裹幞帊。", "坐令青蠅繁，暫出刑兩踝。", "儒冠成自誤，歸去無屋瓦。", "頼逢里中賢，築室各萧洒。", "及時秫麥賤，樽酒得同把。", "安能效乾沒，肩與市人亞。", "居然邑里號，曾墨爲還駕。", "况在竈奧間，欲恥王孫賈。", "東方錢二百，得米稚啼嗄。", "嘲笑坐窮辰，無肉飽伏假。", "尚聞剝啄聲，聊復屣屐迓。", "子常妙工詩，蘇李掩曹謝。", "有時醉酕醄，大笑翻盞斝。", "倒床鼻息惡，喚起對殘灺。", "復古志尚奇，衆競方獨暇。", "捫蝨與人言，豈不逢譴訝。", "崇朝潔腹坐，往往食旁舍。", "子固業少成，議論媲風雅。", "嘗聞莊生說，乃慕巨魚化。", "平居似晏子，志念能自下。"]'),
('d0b5b085-e513-4e75-9de0-64aeabf36249','謁岱祠即事','晁補之','宋','宋诗','song-poetry','','[]','澤南三百里，極望橫天雲。',288,'全唐诗/poet.song.63000.json','["澤南三百里，極望橫天雲。", "雲端色凝黛，諦視初可分。", "崢嶸介丘像，澒洞元氣屯。", "頃刻有變化，慘澹殊明昏。", "天行帝出震，其位生物元。", "不周僨西北，川乃東南奔。", "寧知六鼇死，竟使二山淪。", "不有是難傾，孰維大塊根。", "嘗聞周官說，實惟天帝孫。", "神靈所鎮守，民物斯芘存。", "幽明脗一理，有道惟常尊。", "不覺下馬拜，僮奴亦蹲循。", "迺知正直理，足使冥頑敦。", "三王有損益，商人所尊神。", "明法或不懼，夜行安得逡。", "以此輔世教，庶幾驅驁民。", "暮宿太平驛，不眠慮絲棼。", "明朝好天色，萬象開胚渾。", "勢橫恒碣盡，支壓齊魯蹲。", "五色冒日觀，一握通帝閽。", "恢拓下嶊嶉，青蒼上氤氳。", "泉石競沮洳，煙嵐互紛綸。", "高舉躐風海，深蹯跆火輪。", "濤波卷堆阜，一一溟渤吞。"]'),
('f90d160a-51a6-4224-b1c4-105f712585e4','遊信州南巖','晁補之','宋','宋诗','song-poetry','','[]','南巖夫何爲，山作天倚蓋。',288,'全唐诗/poet.song.63000.json','["南巖夫何爲，山作天倚蓋。", "山南豁山腹，飛頂覆其外。", "初如鵬將翔，膺擊羣麓背。", "乍似海大魚，呀口噞而嘬。", "當空橫廣額，架屋喉舌內。", "仰窺駭憑凌，俯進愁壓墜。", "嘗聆釋氏說，仰覆各世界。", "千間未可著，五畝良不隘。", "清泠氣射人，熱惱從此潰。", "崖奔木疏瘦，谷遠鳥幽怪。", "問僧何年居，投老四五輩。", "問客何人來，官滿或一再。", "而予與二子，高興偶相戒。", "松舟下清江，毛髮數蝦蟹。", "籃輿上峻嶺，幢節望杉檜。", "李侯勛門胄，文采山作繪。", "趙君儒林孫，嫮美蘭結珮。", "不爲城郭遊，繼月此于邁。", "寧知老逾拙，意在精賞退。", "得居溪南山，食飲與山對。", "夔魈入奧穾，雲雨出巾襘。", "古人戒賤目，慣睹誰復貴。", "顧此誠未逢，欣然與心會。", "彭湖兩崖蹙，泉作一線霈。"]'),
('a4fbc31b-554a-49c4-b941-a3396df6cd46','北京水後往棣州試進士','晁補之','宋','宋诗','song-poetry','','[]','晡時北京城，行李上客槎。',204,'全唐诗/poet.song.63000.json','["晡時北京城，行李上客槎。", "二更無人聲，騎馬黄河沙。", "誤緣柳灘中，尋炬知田家。", "道有轉徙人，襁負依丘麻。", "雞鳴不安枕，彷彿墟里斜。", "秋瓜抱子母，蕎麥亦已華。", "頼茲野物登，爾輩生有涯。", "夜宿冠氏驛，旅衾魂夢嘉。", "明發縈長坂，晚開堂邑衙。", "秋陽此方熾，流汗霑巾紗。", "處陰甘吾願，聊逸豈在多。", "有風東北來，慘慘飛雨加。", "頃時異晦明，稍矚天表霞。", "僕夫爲我言，塗梗絕行車。", "且還解吾褚，中林侶群鴉。", "詩書維永夕，蚤作從復賒。", "豈不有王事，奈此僕夫何。"]'),
('9cd79e2f-761c-41c5-a9e9-6dedd3474ae6','次韵王宗正定國與蘇翰林先生黄校書魯直唱和','晁補之','宋','宋诗','song-poetry','','[]','東國寬市征，西山休騎屯。',120,'全唐诗/poet.song.63000.json','["東國寬市征，西山休騎屯。", "時清詩人喜，洗濯出佳言。", "淵源蘇夫子，河入莆菖翻。", "軌轍校書君，駕驂盜驪奔。", "後來得濬沖，它人孰窺藩。", "譬余學禮素，婦祭盛於盆。", "不應麾門牆，尚許酌衢樽。", "夢天九門開，燦然列星繁。", "群公顧我喜，顔若白璧溫。", "赤城何足躡，愁絕永嘉孫。"]'),
('483e169e-9cf5-4b9a-bf56-7e8301328f39','次韵孔著作常父館中喜雪','晁補之','宋','宋诗','song-poetry','','[]','冬旱及茲雪，都人銷百憂。',168,'全唐诗/poet.song.63000.json','["冬旱及茲雪，都人銷百憂。", "牆根有宿草，餘綠尚去秋。", "新陽解薄冰，大潤升介丘。", "夜聞窗響紗，高雲正綢繆。", "明旦天津望，寒花翳川流。", "宮中聖人喜，癘氣一夕收。", "史占上日祥，知欲遍九州。", "敢任肉食謀，官閑欣歲休。", "雖無山陰船，窮巷窘若囚。", "却幸葛翁來，湯餠有麥牟。", "孔侯金閨彥，平昔慕追遊。", "延閣排霄起，登臨忘我愁。", "何當聯轡鐶，城苑佳氣浮。", "春郊日可望，桑野聽行謳。"]'),
('fe475557-82f4-4b3d-8168-da62b818ff5c','次韵張著作文潛休日不出二首  其一','晁補之','宋','宋诗','song-poetry','','[]','張侯經濟術，見遇未容心。',48,'全唐诗/poet.song.63000.json','["張侯經濟術，見遇未容心。", "揚子執戟老，蔣生開徑深。", "予亦拙造請，素懷愛園林。", "閉門鳥雀喜，朝日上駸駸。"]'),
('169a3973-e169-442a-846f-68c565f73498','次韵張著作文潛休日不出二首  其二','晁補之','宋','宋诗','song-poetry','','[]','文史平昔契，淮山別離心。',48,'全唐诗/poet.song.63000.json','["文史平昔契，淮山別離心。", "省中並日直，天上青春深。", "買屋近城塢，往來成竹林。", "詩模黄著作，吾亦意駸駸。"]'),
('b4352e63-6350-4dbd-a6d3-effa1840b439','次韵文潛病中作時方求補外','晁補之','宋','宋诗','song-poetry','','[]','貧爐初著灰，濁酒寒不溫。',168,'全唐诗/poet.song.63000.json','["貧爐初著灰，濁酒寒不溫。", "鄰張病未來，獨負南窗暄。", "昨日往過之，歡喜能兩餐。", "酲醲淟然解，愧無枚乘言。", "祝君抱虛一，邪氣襲無門。", "今晨有起色，迎笑眉宇軒。", "扶掖兩男兒，總丱佳弟昆。", "遣誦寄我詩，妙可白玉刊。", "平生俱豪氣，見酒渴驥奔。", "賜休常苦稀，晨謁良不閑。", "約君向南邦，勿厭敲扑諠。", "公餘未忘飲，何必釂十分。", "時平但行樂，卧治安足論。", "琵琶五十面，雷雨出鵾絃。"]'),
('44f2dd75-6a33-408a-b784-fc03b8cfc0fc','再次韵文潛病起','晁補之','宋','宋诗','song-poetry','','[]','淮浦見之子，春風初策名。',252,'全唐诗/poet.song.63000.json','["淮浦見之子，春風初策名。", "頗訝謫仙人，有籍白玉京。", "晚遇廣文直，老交心愈傾。", "同升芸香府，偶坐華髮生。", "斯人自龍性，意變難章程。", "耆酒不疵吝，身如秋葉輕。", "自言士處世，何必冰雪清。", "交游滿臺省，毀譽半王城。", "不肯效俯仰，畏高侮鰥惸。", "常思老伊潁，紫蟹羞吳秔。", "我輒抵掌和，音同磬隨笙。", "小人奉慈親，皆嘗小人羹。", "寒衣婦補綻，學績女娉婷。", "日欲江海去，心期楊柳青。", "衆木構大厦，豫章倚孤撐。", "如子足醫國，可容移疾行。", "丹書紫皇告，玉篆五嶽形。", "何必陶隠居，吞霞養純精。", "訪道自素約，諧心期暮齡。", "但恐牽俗緣，志大功不成。", "息交屏妻子，此語不須驚。"]'),
('ce8cf00b-de13-4911-8b5b-01c34825394b','玉溪歸逢甥李相如汴中','晁補之','宋','宋诗','song-poetry','','[]','蠻鄉俟天形，畏蠚復憚暑。',204,'全唐诗/poet.song.63000.json','["蠻鄉俟天形，畏蠚復憚暑。", "夢甥來萬里，竹響風動宇。", "如今真似夢，相對別恨吐。", "平生窘執轡，白面力如虎。", "誰令斗指日，江使墮漁罟。", "桃僵李爲仆，遺珮滿江渚。", "常憂抱石死，無復脚踏土。", "那知徼時願，起廢遇明主。", "曠調已遠跡，未用矜杜舉。", "但憂世議隘，亡弓不亡楚。", "吾甥學孔子，况乃父母魯。", "如聞四門闢，未信遡洄沮。", "上書閔魃旱，膏以神靈雨。", "北海自有人，高丘豈無女。", "爾壯觀爾能，吾歸固吾所。", "期甥二兒上，餘子不足數。", "何以喻吾心，酌此湘吳醑。"]'),
('51d6d52f-3ee4-476c-83e5-933fad3ba971','送學生李公裕兄弟赴省集','晁補之','宋','宋诗','song-poetry','','[]','閉門圍火談，開戶雪一尺。',156,'全唐诗/poet.song.63000.json','["閉門圍火談，開戶雪一尺。", "黄昏具盃酒，知君遠行役。", "君家三兄弟，頗謂各無敵。", "容父學知方，大道通四驛。", "吉父尤頡頏，天池觀水擊。", "仁父少而奇，乃是夜光璧。", "李侯有此子，便可卧安席。", "家居樂與餌，聊以止過客。", "豈無一束芻，空谷不可食。", "宵人操寵利，徒手捕蜴蜥。", "公等寧復然，烏黑鵠自白。", "屠龍業有用，未厭所從僻。", "富貴念昔時，城東雪中跡。"]'),
('03427e4d-ae45-4566-8df0-01aae3882da2','次韵太學舒博士堯文示同志','晁補之','宋','宋诗','song-poetry','','[]','北門望瀛關，一葦初莫渡。',156,'全唐诗/poet.song.63000.json','["北門望瀛關，一葦初莫渡。", "儒宮連案几，會合豈非數。", "蟬鳴幾何時，庭菊下白露。", "念當慰佳節，觴酌美無度。", "不然坐歲晚，流景急飛兔。", "區區人一馬，官舍勤早暮。", "經時枉見贈，彌月不能賦。", "竹齋行茗粥，寂莫當屢赴。", "此君安可得，霜雪不改故。", "詩如戰交地，高處要先據。", "牛羹君放飯，轑鼎吾亦飫。", "顧慚詠伐檀，無補餐已素。", "還家便却埽，況乃無戶屨。"]'),
('084e37c9-f6a2-45f8-b84d-0d91843cb335','次韵蘇翰林五日揚州石塔寺烹茶','晁補之','宋','宋诗','song-poetry','','[]','唐來木蘭寺，遺跡今未滅。',120,'全唐诗/poet.song.63000.json','["唐來木蘭寺，遺跡今未滅。", "僧鍾嘲飯後，語出饑客舌。", "今公食方丈，玉茗攄噫噎。", "當年卧江湖，不泣逐臣玦。", "中和似此茗，受水不易節。", "輕塵散羅麴，亂乳發甌雪。", "佳辰雜蘭艾，共弔楚纍潔。", "老謙三昧手，心得非口訣。", "誰知此間妙，我欲希超絕。", "持誇淮北士，湯餠供朝啜。"]'),
('55d295a6-a7c7-4f76-b2e2-ba1c14d4a1b7','題四弟以道橫軸畫','晁補之','宋','宋诗','song-poetry','','[]','黄葉滿青山，枯蒲靜寒水。',48,'全唐诗/poet.song.63000.json','["黄葉滿青山，枯蒲靜寒水。", "鳬雁下坡塍，牛羊散墟里。", "擔穫暮來歸，兒迎婦窺籬。", "虎頭無骨相，田野有餘思。"]'),
('3930a571-4dff-4283-b96d-18348c6c3e96','桂漿','晁補之','宋','宋诗','song-poetry','','[]','暑卧午呀呷，蠲煩何所投。',180,'全唐诗/poet.song.63000.json','["暑卧午呀呷，蠲煩何所投。", "巖桂割辛芳，石蜜滋甘柔。", "沃以火鼎沸，閟之冰井幽。", "三日出深冪，明瓊盎黄流。", "冰火離坎類，意比秫麥繆。", "辛甘既兩適，不湎亦銷憂。", "中年苦內熱，歲願西風秋。", "寒凉犯所畏，發散資爾謀。", "時時以觴客，三獻不一酬。", "緬思湘纍語，啜醨終所羞。", "北斗酌此漿，違世聊遠遊。", "恐復迷吾往，僕悲道阻脩。", "淮南歸來些，憭慄令人愁。", "百壺無此餞，夙志慕林丘。", "寧懷小山感，不爲桂枝留。"]'),
('276ce581-3466-4caa-810d-14cb7611c9d5','送舅氏楊通直令陽穀','晁補之','宋','宋诗','song-poetry','','[]','人言慎縣宰，頗似太丘君。',192,'全唐诗/poet.song.63000.json','["人言慎縣宰，頗似太丘君。", "客戶有訓遣，司官無訟聞。", "外家久寂莫，舅氏少辛勤。", "一邑何足道，高名誰與群。", "西來馬特特，冬晚雪紛紛。", "公朝道由砥，孤士跡如雲。", "過門苦地僻，下直迫日曛。", "深泥枉窮巷，寒罏對殘熅。", "感慨說宣子，飄零綴遺文。", "麟閣窘鉛槧，魚山失耕芸。", "遠情等匏繫，歸夢劇絲棼。", "山東接畿甸，陽穀近榆枌。", "吏昔猛豺虎，民如竄麖麏。", "幸逢寬大時，庶幾仁惠薰。", "自笑下士策，不殊野人芹。", "愛民宜百祿，本茂實當蕡。"]'),
('1c99d8e6-99ae-4807-87d4-4578207174db','贈王推官允中','晁補之','宋','宋诗','song-poetry','','[]','我生譬天星，睍睆但空譽。',228,'全唐诗/poet.song.63000.json','["我生譬天星，睍睆但空譽。", "學經羞輪扁，常恐老竄句。", "南游上會稽，弱冠肆遠步。", "便當期汗漫，如鳥鎩修羽。", "入宮又獨晚，謠諑遭衆嫮。", "坐令平生交，室冷氈不具。", "君公牆東客，清鑒美無度。", "風期山水意，千載見此遇。", "定疑丹青仙，方我以癡顧。", "豈繄才自疏，閱世真異趣。", "伐柯理無遠，要以一馬喻。", "古人本不死，方寸有佳處。", "三年禹河曲，日見車馬渡。", "何知謝剝啄，黄土衣易污。", "無人尚有子，獨載城下路。", "功名喧口實，簪組託肺腑。", "請看缾罌滿，取躓病不去。", "脫黏窺本初，須子遺所寓。", "怵迫倦東西，林間尚寬裕。"]'),
('0ce2455c-624e-4389-ada1-338e2ddd61c9','之京師展墓','晁補之','宋','宋诗','song-poetry','','[]','短轡馭羸馬，馳驅曹濟間。',168,'全唐诗/poet.song.63000.json','["短轡馭羸馬，馳驅曹濟間。", "商飈折勁木，蕭瑟道里寒。", "況復慕所天，惻愴摧心肝。", "游子歎時邁，慈母憐衣單。", "來時憑窗哭，五妹垂修鬟。", "季弟主菽粟，孺妻爨茅菅。", "悼我無令人，莫奉堂上歡。", "豈無萱草詩，終日倚門闌。", "念昔常獨立，所聞詩禮難。", "我尚未成人，遭罹此憂患。", "歲晏念墳墓，仳離百哀攢。", "何時奉靈車，辛苦向此還。", "親寡氣力微，傍人祝加餐。", "願言薄志節，苟生無形顔。"]'),
('31a203d8-8d33-4d94-b035-e4a4b8f3d4a2','同畢公叔飲城東','晁補之','宋','宋诗','song-poetry','','[]','西城昔相值，桃初兩三紅。',204,'全唐诗/poet.song.63000.json','["西城昔相值，桃初兩三紅。", "翩翩騖長陌，春風搖馬鬃。", "後君歸幾日，游絮已濛濛。", "解鞍不待憩，相命古原東。", "芍藥雖俗花，狂姿幸時供。", "平生於知己，千過不一逢。", "感君欲開口，清洟出霑胸。", "君如陶淵明，不爲五斗恭。", "胡爲青綸上，朱墨紛外蒙。", "棄官能從我，短後追田翁。", "銅斗釀秫麥，竹枝弋鳬鴻。", "何必悲無衣，縕黂聊御冬。", "九辯太高潔，五噫苦羈窮。", "置此無滑和，天情反其中。", "市藥非市名，名聞藥何庸。", "十漿饋五漿，猶畏聞者從。", "如何酆城畔，夜夜生長虹。"]'),
('49b2bf6f-1412-4572-b23c-4099f5aea175','題李秀才成季負日軒','晁補之','宋','宋诗','song-poetry','','[]','盧敖遊八極，末至北陰墟。',192,'全唐诗/poet.song.63000.json','["盧敖遊八極，末至北陰墟。", "卒然蒙谷幽，睹一奇丈夫。", "淚注而鳶肩，深目玄髭須。", "軒軒迎風舞，自得樂有餘。", "見敖默弗言，慢然下臂趨。", "敖私躡其後，若士意不愉。", "曰子亦何爲，迷繆至此乎。", "此雖窮荒北，尚或逢日烏。", "過是有玄關，晦墨不可居。", "語竟若欺魄，攝身沒空虛。", "始予讀秦記，疑是忽帝徒。", "今聆天隨言，乃與夸父俱。", "逐日下虞谷，力窮尚嗟吁。", "陽舒固物理，我亦安于于。", "若士獨何氣，幽沉山海隅。", "渾沌死已久，人生信多塗。"]'),
('04f37598-203d-4dc9-bd34-2ebb9ed27a59','次韵李成季感事','晁補之','宋','宋诗','song-poetry','','[]','吾廬無餘地，文字散堆案。',192,'全唐诗/poet.song.63000.json','["吾廬無餘地，文字散堆案。", "雖微清溪鶴，蓍畫亦幽玩。", "高人來何疏，午榻動成鼾。", "夢聞足音喜，不待搖枕喚。", "居貧少煙火，饘食尚須旰。", "出門兀何之，踉蹌從款段。", "吾人古遺隠，鳬足閔同患。", "負日持獻君，狐白不肯換。", "商歌叩牛角，長夜安得旦。", "颼飀滿屋風，黄葉散投幔。", "楚屈若靈龜，出處思過半。", "所從聊自知，何用詹尹算。", "不如天隨生，頭幘終日岸。", "況君擊莊缶，一念腸九轉。", "人方卧大室，子獨號其畔。", "寒山來助哭，咄爾勿嗟惋。"]'),
('7cdd4437-fbd7-4605-aebf-0f293bd040d5','同李主簿叔文飲北莊','晁補之','宋','宋诗','song-poetry','','[]','蕭條蓐收窮，疏樹失穠紺。',120,'全唐诗/poet.song.63000.json','["蕭條蓐收窮，疏樹失穠紺。", "北風動地起，雲攬紅日暗。", "李君邀我游，餚蔌治寒檐。", "相携二三子，欻若符節勘。", "愧非谷口隠，佳會良可暫。", "茅堂兀四壁，誰識此意淡。", "古徑無俗尋，陳編有幽瞰。", "一聆君子語，粱肉幾厭啗。", "歸來馬河北，寂寞晚舟纜。", "吾生事逃伏，優游亦何憾。"]'),
('62864915-7cd6-47ff-8fb8-e63738013bc2','夏季','晁補之','宋','宋诗','song-poetry','','[]','夏季百果繁，兔葵亦成實。',96,'全唐诗/poet.song.63000.json','["夏季百果繁，兔葵亦成實。", "獨有野石榴，幽花時熠熠。", "熠熠非獨好，芳榮頼午日。", "翩翩彼白蝶，彷彿粗采挹。", "睡餘起對此，嘉興亦蕭瑟。", "良非阡陌麗，敢競陽春出。", "無言以成蹊，上愧桃李質。", "幸當飽霜餘，萬顆富君室。"]'),
('fcbece31-41b4-416d-ba35-de428bc3bc85','曹州道中二首  其一','晁補之','宋','宋诗','song-poetry','','[]','天旱久不雨，四郊多狂風。',48,'全唐诗/poet.song.63000.json','["天旱久不雨，四郊多狂風。", "蕭蕭班馬鳴，落日大野中。", "君子守宮廷，至樂聖所同。", "喟予不逢辰，足跡道里重。"]'),
('228328ba-176e-4178-86a8-dd0814c27067','曹州道中二首  其二','晁補之','宋','宋诗','song-poetry','','[]','驅馬上高原，秋風吹客衣。',48,'全唐诗/poet.song.63000.json','["驅馬上高原，秋風吹客衣。", "感時有所懷，送目鴻雁飛。", "羸僮惑岐道，日暮相際稀。", "愧彼倦翔鳥，知還良庶幾。"]'),
('092093cd-deb4-4e2d-a262-cadc4e0ea5dd','病起呈李縣令希孝','晁補之','宋','宋诗','song-poetry','','[]','次公惡醒狂，得酒要自濁。',144,'全唐诗/poet.song.63000.json','["次公惡醒狂，得酒要自濁。", "病聞南鄰邀，不往亦踴躍。", "空床成展轉，假寐風雨惡。", "中虛氣襲逆，妄夢時可愕。", "每慚張隠居，凌旦發囊藥。", "曉來天境清，日出鳥語樂。", "家人語南軒，青杏已可嚼。", "復云竹齋前，階戺有迸籜。", "欣然欲舉手，紗帽未能著。", "平生李夫子，相得懷抱廓。", "何當戒長鬚，夙駕慰寂莫。", "杯杓恐不勝，快語聊一噱。"]'),
('2d823595-aa9c-436e-ad3c-0685202000e6','贈金堤劉承制景文','晁補之','宋','宋诗','song-poetry','','[]','漆園說海若，稷下談神州。',120,'全唐诗/poet.song.63000.json','["漆園說海若，稷下談神州。", "長劍堪倚天，語大世莫酬。", "少狂豈其然，及此日月流。", "稍知畫足非，萬事指顧休。", "夫子更高識，未沫於前修。", "乘流聊復駛，得渚正須留。", "蓋有幸遇魯，何能必爲周。", "徜徉下澤車，驚駭入谷騶。", "對酒尚青眼，吟詩將白頭。", "山陰論往事，陳迹詎能收。"]'),
('bad74663-99fc-4e8e-b6ed-270e002654ff','次韵四弟以道十二弟叔與法王唱和兼示無斁弟二首  其一','晁補之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','少時勇遊山，說山喜動色。',144,'全唐诗/poet.song.63000.json','["少時勇遊山，說山喜動色。", "中年謫南方，廬阜得深歷。", "當時不類謫，忘腰带之適。", "怪人肝鬲異，破賊喜折屐。", "只今竄林下，織衣而耕食。", "緬懷茲兩士，吾宗氣相得。", "吾春種桃時，子曉尋嵩日。", "似聞黄面子，爲採烏頭出。", "去年陟岱宗，一士世莫識。", "天門邀之下，傾倒意已極。", "斯人與人異，龍虎兩超忽。", "重尋亦無路，顛雨石崖坼。"]'),
('510271f5-523c-4d43-b9b7-997e5e0f60b7','次韵四弟以道十二弟叔與法王唱和兼示無斁弟二首  其二','晁補之','宋','宋诗','song-poetry','','[]','吾人伯仲間，一語可物色。',144,'全唐诗/poet.song.63000.json','["吾人伯仲間，一語可物色。", "氣自寡所諧，窮乃足所歷。", "家風藐五世，不肯適人適。", "意行無險易，又跣不著屐。", "文詞如苦李，慘腹人莫食。", "猶矜不傳妙，坐恐兒曹得。", "學憐新又新，老奈日復日。", "伯以最恬愉，何由採之出。", "無斁能寡言，猶堪謝前識。", "叔與氣尚豪，搘頤視屋極。", "斯文惡表襮，枯魚戒所忽。", "應如魯宮籀，藏壁俟其坼。"]'),
('a90fa52f-881a-4a66-9d17-2128af208c93','同劉景文登大安閣','晁補之','宋','宋诗','song-poetry','','[]','劉侯先將軍，忠義當代顯。',120,'全唐诗/poet.song.63000.json','["劉侯先將軍，忠義當代顯。", "喑噁指戎虜，却走自相踐。", "西坡坐首鼠，勢蹙不得免。", "天憐壯士窮，有子如此鮮。", "清時鑄農器，文字正須勉。", "行吟畔牢愁，憤悱亦足遣。", "時來躡雲梯，仰視天宇展。", "下俯河兩涯，牛馬細不辨。", "達生匪行怪，未用驚邑犬。", "官閑尚數臨，閟澤要清淺。"]'),
('4dcb2e2b-6fb4-46f3-99c7-7ed019b66543','次韵張著作文潛飲王舍人才元家時坐客戶部李尚書公擇光祿文少卿周翰大理杜少卿君章黄著作魯直','晁補之','宋','宋诗','song-poetry','','[]','霜雪埋百花，及時鬭春陽。',216,'全唐诗/poet.song.63000.json','["霜雪埋百花，及時鬭春陽。", "城南有高士，買屋入花藏。", "經時不出門，爲花日日忙。", "我居在何許，近止東數坊。", "亦有佳公子，連車換帷裳。", "隔牆蜂蝶喧，開戶草木香。", "仙人朱桃椎，髮綠童臉芳。", "此公不可見，此畫來遠方。", "竹倚屠蘇塢，柳拂轆轤床。", "素兒雖小小，亦足侑客觴。", "尚書廊廟具，氣若冰壺凉。", "忘年此賓主，吾黨有輝光。", "人生走塵土，歲月顔鬢蒼。", "曷不休沐暇，過此薰修房。", "宴坐二十年，非癡實難量。", "張侯不出家，在家說緣忘。", "尚擬問兩卿，携肴借紅粧。", "妍歌聽黄子，不飲亦清狂。"]'),
('aa22ecfa-256c-4332-b4da-ea0b540d4218','次韵范翰林淳夫送秦主簿覯','晁補之','宋','宋诗','song-poetry','','[]','高詞自班馬，短句亦陰何。',168,'全唐诗/poet.song.63000.json','["高詞自班馬，短句亦陰何。", "輸寫無窮已，懷山赴壑波。", "深耕待銍艾，療饑乃嘉禾。", "機雲共一時，未信來者多。", "老病愧群豪，魚山臨東阿。", "蘇公門下客，事業皆不磨。", "孫寶暫主簿，靈槎會窮河。", "它年九功敘，當使睦者歌。", "業虡置牙羽，管簫復森羅。", "鏞鐘欠一鐸，未害大樂和。", "却欲從浮海，珊瑚爛紅柯。", "龍門雖箭駛，此志未蹉跎。", "丹沙還黑髮，流景爾則那。", "仇池出一派，分江定有沱。"]'),
('7bb046be-af9b-4115-929a-65e586f05c57','次韵答秦覯見贈','晁補之','宋','宋诗','song-poetry','','[]','修身貴日新，如草陳葉換。',120,'全唐诗/poet.song.63000.json','["修身貴日新，如草陳葉換。", "請看絃上矢，歲月不可玩。", "文章得蛙釜，虎以皮遘難。", "茲事從古然，吾黨奚獨惋。", "秦君好學勇，决勝百馬汗。", "宵行委明月，屢得按劍盼。", "鄙夫晚更事，前猛窘新愞。", "憐君亦自喭，意滿懷不散。", "誰爲傾國媒，尚此瓊英粲。", "期君似椓罝，無以無人慢。"]'),
('7e8eee33-7dd2-4f1b-8a6a-45227f85b5e4','北京學直舍對客','晁補之','宋','宋诗','song-poetry','','[]','鳥聲落檐間，竹色在戶外。',120,'全唐诗/poet.song.63000.json','["鳥聲落檐間，竹色在戶外。", "解屨置几前，放杖當椅背。", "默然仰棟時，往與古初會。", "有時遺坐客，十問不一對。", "尚因呼乃覺，笑自謝頑昧。", "知非慕蘧子，事去等蜩蛻。", "一生所未免，飲食與眠睡。", "所以更頹然，可樂本非內。", "有心欲何用，橋起則形累。", "頼客同門生，曠蕩乃不愧。"]'),
('c2e6e2a6-a652-4ec5-b58f-59b622dae633','虛齋','晁補之','宋','宋诗','song-poetry','','[]','虛齋閉疏窗，竹日光耿耿。',48,'全唐诗/poet.song.63000.json','["虛齋閉疏窗，竹日光耿耿。", "更無司業酒，但有廣文冷。", "人憐出入獨，自喜往還省。", "時作苦語詩，幽泉汲修綆。"]'),
('a7a34b42-b7d4-4c97-a4ab-ab386fe9c5e9','直舍即事','晁補之','宋','宋诗','song-poetry','','[]','秋雲多重陰，凌旦亦可樂。',72,'全唐诗/poet.song.63000.json','["秋雲多重陰，凌旦亦可樂。", "虛齋坐亭午，寒雨依高閣。", "王官有憂責，霖潦河未落。", "孝先但欲眠，不奈弟子謔。", "黄花迫晚景，白露下叢薄。", "獨當慰佳節，得酒自斟酌。"]'),
('de606801-58ac-4c7c-b5b1-3a29196effdd','昨日雪已佳約李令希孝','晁補之','宋','宋诗','song-poetry','','[]','昨日雪已佳，今日雨亦好。',48,'全唐诗/poet.song.63000.json','["昨日雪已佳，今日雨亦好。", "冰膚解萬木，洗濯見枯槁。", "思君對此坐，孤詠廢幽討。", "明日尚相期，春禽聽清曉。"]'),
('7a6600d7-2437-417b-a693-4161c635b8cb','同文潛送况之諫議十四丈守潞過成季作','晁補之','宋','宋诗','song-poetry','','[]','午投李同年，下馬汗如洗。',120,'全唐诗/poet.song.63000.json','["午投李同年，下馬汗如洗。", "城南迫送客，雖懶聊爾耳。", "出門繚陂陼，白鳥起深葦。", "佛宮橫晚霽，窈窕間一水。", "借問客何人，諫垣有直氣。", "吾人浮丘伯，聊可與把袂。", "如此邂逅何，得酒亦佳事。", "官閒猶有守，旋折窘六轡。", "可憐千紅蕖，的皪姹晚市。", "便當夙駕行，秋風如箭駛。"]'),
('52bafae8-09c7-40b3-a3e6-88ea7ea9b923','送梅校理子明通守杭州','晁補之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金明池上柳，人折一枝春。',132,'全唐诗/poet.song.63000.json','["金明池上柳，人折一枝春。", "贈子意不淺，東游雲外身。", "人生半刺史，朱綬光四鄰。", "此豈經世懷，但慰垂白親。", "錢塘我舊遊，頗復識其人。", "不應山水改，但恐猿鳥新。", "章臺走馬客，冠蓋盡要津。", "竊祿我自慚，便面聊障塵。", "亦思一舟去，共醉西湖濱。", "時平自行樂，不爲千里蓴。", "歸來麒麟上，獻納當及辰。"]'),
('6c30ffad-44fa-41be-b915-827269d3e88b','送呂承奉至山從呂龍圖晉伯辟秦州機宜','晁補之','宋','宋诗','song-poetry','','[]','去日劇奔驥，新交非曩圖。',204,'全唐诗/poet.song.63000.json','["去日劇奔驥，新交非曩圖。", "憐君事業長，蔚若頤生鬚。", "表東海者誰，君世有顯儒。", "端委論百揆，鞭弭雄千夫。", "二陳詩禮伯，八荀紈綺雛。", "嘗聞達大家，可以濟八區。", "功名望聖世，忠孝自吾徒。", "我昔拜秦州，詞林炳於菟。", "見謂可與言，鋤荒而破觚。", "刳中不宿穢，味道因有腴。", "斯文望若人，顛沛一手扶。", "白頭遠綏邊，狐兔安足驅。", "汲黯在朝廷，永絕淮南覦。", "平叔不鬭羌，事正今日須。", "今君撰杖屨，還向府中趨。", "問訊不棄捐，寄聲亦疏迂。", "何當質疑義，賣劍老樵蘇。"]'),
('ba4e25db-4e5f-40d0-868d-e47e8bc75a1a','曉發樓子莊','晁補之','宋','宋诗','song-poetry','','[]','曉發樓子莊，淮山自茲近。',96,'全唐诗/poet.song.63000.json','["曉發樓子莊，淮山自茲近。", "春風似惱客，浪穩舟不進。", "長安一回首，堤柳千里潤。", "念當整帆席，快若冬蟄奮。", "微生謝拘窘，末路嗟鄙吝。", "林花一迎笑，岩鳥相借問。", "塵埃改顔鬢，堅白畏緇磷。", "江海慰高情，飄蓬自吾分。"]'),
('a0f9e45c-d2fb-48b5-893c-ea08a8c3d3f6','禮部移竹次韵李員外文叔','晁補之','宋','宋诗','song-poetry','','[]','東南之美者，見伐以直幹。',84,'全唐诗/poet.song.63000.json','["東南之美者，見伐以直幹。", "豈如此君疏，猶作此郎玩。", "此郎乃在此，無乃材亦散。", "平生吉甫頌，意鄙枚叔亂。", "坐狂得此冷，對竹頭幘岸。", "尚思殺青書，充宇白虎觀。", "恐此愧子猷，還成倚楹歎。"]'),
('28eff508-6da4-42ae-b4c5-df774d5db071','次開祖使君韵兼呈端叔大夫聖域長老','晁補之','宋','宋诗','song-poetry','','[]','神龍異凡馬，頭角要須斂。',216,'全唐诗/poet.song.63000.json','["神龍異凡馬，頭角要須斂。", "邦公七歲時，驚耳一語險。", "悟身非常住，風日過河減。", "崢嶸法雲窟，跳出有家範。", "金剛不吐焰，已落天魔膽。", "一派感慈中，無波寒湛湛。", "是波本非水，無以瓦礫點。", "低枝競聽法，草木有情感。", "作解受群邪，碔砆疑琬琰。", "居然身出定，面目本來儼。", "而我久塵勞，見之良內慊。", "周侯老詞句，太華聳而黯。", "自說少苦心，修塗肆窮覽。", "李侯遺世事，不琢元無玷。", "文采麗春葩，百牘交千槧。", "顧慚土炭嗜，畏疾非羞儉。", "望不見水端，譬河還少貶。", "請佩伯陽言，吾非勇於敢。"]'),
('ea21dfd0-13d4-4092-a4ed-ae77718fa2ce','次韵錢濟明贈感慈長老','晁補之','宋','宋诗','song-poetry','','[]','我聞棲禪人，一念超十地。',204,'全唐诗/poet.song.63000.json','["我聞棲禪人，一念超十地。", "云何別影事，未免依緣氣。", "譬如幻男女，機廢根隨廢。", "不然怖頭走，此病窮三世。", "邦公獅子吼，曾使諸天喜。", "廣說無說時，俱成甘露味。", "不知室久如，當有天來侍。", "城隅竹塢近，梵剎開嚴閟。", "以彼穴中空，清風自來萃。", "我生久更事，求愚不求慧。", "清風已說法，不用重宣偈。", "開祖照人姿，滄波白蘋際。", "居然九奏妙，往往魚龍戲。", "濟明經世才，彫松識寒歲。", "懷寶竟迷邦，此豈非良計。", "名山尋勝士，投老終深詣。", "我自所蘄廉，蟬葉真堪蔽。"]'),
('aa63e9f1-369f-494f-9e82-07d4d9608c04','送八弟無斁宰寶應','晁補之','宋','宋诗','song-poetry','','[]','窮邦迫秋成，霖雨厚土溼。',264,'全唐诗/poet.song.63000.json','["窮邦迫秋成，霖雨厚土溼。", "邅吾上淶水，濞洶三峽疾。", "邦人送之子，岸潦飲馬膝。", "淒淒屬方升，澹澹驚並集。", "衝湍順塗路，游波匯原隰。", "安知禾黍腐，轉覺蛙黽急。", "何由乾此潦，問天借九日。", "蕭蕭荆棘晚，亹亹霜霰密。", "之子向南州，銅章宰一邑。", "何須念宋遠，古謂跂余及。", "揚舲堤柳盡，把醆淮山入。", "封圻吳楚徼，郡縣秦漢襲。", "開門駔儈鬨，輳浦篙帆翕。", "平旦書百函，交衢客三揖。", "新湖容鼓鑄，甲令貴綏輯。", "之子搴詞科，聞詩不讀律。", "古來學爲吏，頗自吾儒出。", "足民與知方，求由有政術。", "鞭笞麏鹿駭，亦恐日不給。", "先君卓魯後，之子况早立。", "焚香閉閤坐，啾耳從潗濈。", "官忙尚偷閒，文字要嶪岌。"]'),
('4c7de15f-b15b-4440-8ab0-03b21496d4ba','和關承議彥遠水樂','晁補之','宋','宋诗','song-poetry','','[]','上盆五尺高，下盆二尺廣。',288,'全唐诗/poet.song.63000.json','["上盆五尺高，下盆二尺廣。", "咿呦蟻穴間，飛瀑一線響。", "關侯初爲此，避世挹蕭爽。", "晁子亦欣然，閉戶穿瓦盎。", "虛堂一畝靜，純白四隅敞。", "中央渾沌胚，鯈忽所求往。", "鑿竅令語言，豈但一成兩。", "危峰下俯瞰，石井黝然仰。", "奔泉决眥落，慘澹陰壑想。", "明珠溢盤盂，白露溼塵坱。", "聲音通大道，斷竹自誰賞。", "何曾戛擊闌，缾缶日夜長。", "初疑風隕籜，驟雨來莽蒼。", "乍似酒落槽，夜枕聽惚恍。", "鳴禽雜啁哳，物鬽亂肸蠁。", "相依欠林樾，見蔽頼帷幌。", "范侯驚側耳，李令笑抵掌。", "張侯助我懶，不憶稅歸鞅。", "雲間余仲弟，聊可樂吾黨。", "中和非外物，此理未宜罔。", "相勸戒勿傳，名字遍天壤。", "撞鍾鼎食事，老罷不知饗。", "但怪一世狂，端如轉車輞。", "能來解幅巾，爲子濯泚顙。"]'),
('82e555ad-e264-4f53-9b05-7093c8bb9d12','送君','晁補之','宋','宋诗','song-poetry','','[]','送君上馬時，不道朝罏燠。',48,'全唐诗/poet.song.63000.json','["送君上馬時，不道朝罏燠。", "春風入木心，皮肌發紅綠。", "春風良易暮，那得勤行路。", "且莫望南窗，胡蝶飛無數。"]'),
('5d1e0d44-7b7a-4acf-8761-33fca697d0d3','上馬','晁補之','宋','宋诗','song-poetry','','[]','上馬笑屬君，歸期在十日。',48,'全唐诗/poet.song.63000.json','["上馬笑屬君，歸期在十日。", "來時草白芽，歸時青鬰鬰。", "來嗔馬蹄急，歸嗔馬蹄緩。", "人心自如此，馬蹄終不變。"]'),
('c79306e6-527b-4446-a83b-2b0e2027cdd0','試院次韵文潛欲知歸期近呈天啟慎思','晁補之','宋','宋诗','song-poetry','','[]','眉山得張侯，心許出一手。',96,'全唐诗/poet.song.63000.json','["眉山得張侯，心許出一手。", "臨川見蔡子，千載慰邂逅。", "鄧君起南國，磊磊看三秀。", "譬如黄鍾陳，我尚瓦釜吼。", "欲知歸期近，喚馬牽出廐。", "官壺持餉婦，傾寫不漬口。", "千章輸明堂，勿問草澤有。", "群公自凜凜，水鏡照妍醜。"]'),
('c921a3cc-482b-4226-b8d3-f84f45153094','栽花招泗州叔父','晁補之','宋','宋诗','song-poetry','','[]','春園移春栽，芽蘗秔粒大。',72,'全唐诗/poet.song.63000.json','["春園移春栽，芽蘗秔粒大。", "東風日日吹，噴吐不暇裹。", "楊梢青猶未，桃萼紅尚可。", "田蔬美已最，村醑醇亦頗。", "少年慕立事，幸得能幾箇。", "艱難合歸來，茅屋聊共佐。"]'),
('30ad1397-1786-4b0d-8e4b-b8f65bfbc201','次韵閻秀才漢臣食兔','晁補之','宋','宋诗','song-poetry','','[]','兔誠中山族，中古稍分裂。',288,'全唐诗/poet.song.63000.json','["兔誠中山族，中古稍分裂。", "唐虞用大牲，雖有目未瞥。", "䨲孫能飛仙，飄忽天漢决。", "不逢易牙試，厥胄幾泯滅。", "羿弧殞陽烏，曾不弋在穴。", "王良馬慢忌，撲握幾奔掣。", "初遭赳赳子，鼎飪飫毛血。", "中逢宋鵲窘，饑吻啄原雪。", "叔世削格多，星迸失行列。", "蹄窮不得逸，如鼠限高闑。", "應憐蚌潛水，暴腹想江月。", "唇亡欲誰語，竟死猶結舌。", "肩尻弱易解，狼藉腥尺鐵。", "抽毫置筠管，復苦蠹魚齧。", "論功在冊府，微物推爾傑。", "剡藤光奪縑，抄記良瑣屑。", "北鄰閻夫子，尚忍資盃啜。", "得諸韓盧口，實以彊暴劣。", "作詩誇芳美，此譽寧所悅。", "不如狐膏臊，質賤甘棄絕。", "冢妖老通數，藤索夜空設。", "爾曾不及彼，就獲徒內熱。", "聆聲無聳耳，當學縮頸鼈。", "吾君阜萬物，沛若澤未竭。"]'),
('26230ec3-bbe9-4c9f-b231-cace111c31a1','和蘇翰林題李甲畫雁二首  其一','晁補之','宋','宋诗','song-poetry','','[]','畫寫物外形，要物形不改。',72,'全唐诗/poet.song.63000.json','["畫寫物外形，要物形不改。", "詩傳畫外意，貴有畫中態。", "我今豈見畫，觀詩雁真在。", "尚想高郵間，湖寒沙璀璀。", "冰霜已凌厲，藻荇良瑣碎。", "衡陽渺何處，中沚若煙海。"]'),
('8f434068-9778-4479-96cb-5d97423925e8','和蘇翰林題李甲畫雁二首  其二','晁補之','宋','宋诗','song-poetry','','[]','蕭條新湖秋，霜落洲渚潔。',72,'全唐诗/poet.song.63000.json','["蕭條新湖秋，霜落洲渚潔。", "蓮垂蘭杜死，菖莆見深節。", "慘澹沙礫姿，清波侶群鴨。", "往時吳興守，看畫憶苕霅。", "爲儀尚不污，孤高比雲月。", "聞在雪堂時，滿堂唯畫雪。"]'),
('32e7ce4d-5ea7-4373-8668-68df5fc9ddd1','秋竹','晁補之','宋','宋诗','song-poetry','','[]','秋風多煩冤，竹是歲寒物。',60,'全唐诗/poet.song.63000.json','["秋風多煩冤，竹是歲寒物。", "朝寒階玲瓏，暮寒階卹勿。", "翻然下一葉，未覺瘦崷崒。", "豈無陳根旁，寂莫衆頭屈。", "何時雷填填，看爾射地出。"]'),
('8b352fd2-46e2-46f7-9f3b-6a729fef3054','郊居與八弟無斁讀書','晁補之','宋','宋诗','song-poetry','','[]','坐狂得世捐，作官故不了。',288,'全唐诗/poet.song.63000.json','["坐狂得世捐，作官故不了。", "十年未弛負，半世不黔竈。", "居然顔玉雪，及是鬢蓬葆。", "碧山已焚魚，白水初種稻。", "瓜區可深隠，圭竇便却埽。", "之子懷世資，行修名譽好。", "避人本愉恬，坐我亦枯槁。", "頃求田野處，政以城郭擾。", "常時啜仳別，幸爾晏言笑。", "如蘭豈異臭，覆瓿本均好。", "不懲范釜塵，尚作韓編盜。", "斲輪元戒疾，紵絮非病少。", "莞爾勸之休，怡然守而嫪。", "翻思南遷久，祇幸北歸早。", "三已令奚慍，四至卿誠巧。", "所欣顛木蘗，莫羨姣人瞭。", "同氣靡間言，它人闕忠告。", "貧居無酒肉，窮巷有探討。", "葵作飽蓬蓬，茗澆憂悄悄。", "長閑味更永，競進念已剿。", "目鴻天蒼蒼，夢蝶日杲杲。", "蘅皋美新雨，藜杖邈高蹈。", "營齋直新徑，創檻俯幽沼。", "架以我園檀，茨之子官草。"]'),
('90cde991-9b1e-4272-b962-f265e726cd9a','用無斁八弟永城相迎韵寄懷','晁補之','宋','宋诗','song-poetry','','[]','平生殫千金，術似劉累僻。',276,'全唐诗/poet.song.63000.json','["平生殫千金，術似劉累僻。", "春風九軌道，無我迷陽跡。", "呼來著冠紞，野貌不改昔。", "易衣憐介弟，猶有布一尺。", "身慚崔浩短，胸次儼列戟。", "中天翥鸞鳳，我自無六翮。", "何曾客權貴，見謂貧盜璧。", "堂堂涑水翁，我在此人籍。", "不詆曲江賢，寧羞九年謫。", "艱難累吾母，鬢髮白一夕。", "獨此負吾心，敢言忠抱石。", "方時半千運，異昔陽九厄。", "譬馳羊腸坂，雙任臣子責。", "帝王所張弛，乾坤有闔闢。", "君敷皇極言，人詠蓼蕭澤。", "鳶魚競飛躍，風俗凜移易。", "已開公府閤，又置四郊驛。", "搜求逮田野，欣喜到僮役。", "雖微携手上，頗似破笯釋。", "川塗見吾弟，薪木詢我宅。", "憐君如我固，不歎玄尚白。", "薄飲盡餘醅，凝塵振粗席。", "我醉易成狂，欲起須君掖。"]'),
('4b927cbe-b534-4d4c-a265-3d8e08c233bf','次韵答葉學古','晁補之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔我遊武林，值子長江頭。',288,'全唐诗/poet.song.63000.json','["昔我遊武林，值子長江頭。", "我時方南轅，子亦將西舟。", "相見兩大笑，典衣上高樓。", "樓高不知暑，五月凝清秋。", "環觀四山明，俯視萬井稠。", "喧喧市中人，日暮歌吹浮。", "忘形與子飲，一醉餘無謀。", "湖上荷花生，黄鸝飛柳洲。", "翻然搖兩槳，下上逐輕鷗。", "不覺脫塵世，自謂逍遥遊。", "晚訪城隅寺，竹林森如幬。", "斫薪煮山茗，萧洒破百憂。", "脚懶厭廛闠，五日成淹留。", "肅肅太史家，門闌閑且幽。", "荒亭蔭疏桐，雀鬭聞啾啁。", "其人絕世賢，揶揄困時流。", "唯我與吾子，大軸更往投。", "幸聞一諾榮，不受萬戶侯。", "誰言王母桃，方朔不得偷。", "未幾子告別，西賓帝王州。", "吳船風雨夜，送子不勝愁。", "八月子獻書，高談夏商周。", "惜哉天下馬，驪牡煩推求。", "我濫鄉老薦，麻衣望前旒。"]'),
('d9659b82-f473-4ea1-b611-a4f1c324e594','次韵蘇公和南新道中詩二首  其一','晁補之','宋','宋诗','song-poetry','','[]','山園芙蓉開，寂莫歲云晚。',48,'全唐诗/poet.song.63000.json','["山園芙蓉開，寂莫歲云晚。", "公來無與同，念我百里遠。", "寒飈吟空林，白日下重巘。", "興盡還獨歸，挑燈古囊滿。"]'),
('c65e7531-c7b2-483a-93d3-62762be348d7','次韵蘇公和南新道中詩二首  其二','晁補之','宋','宋诗','song-poetry','','[]','讀公棲鴉詩，歲月傷晼晚。',48,'全唐诗/poet.song.63000.json','["讀公棲鴉詩，歲月傷晼晚。", "公胡不念世，蠟屐行避遠。", "羈鳥翔別林，歸雲抱孤巘。", "我才不及古，歎息襟淚滿。"]'),
('ccbd2c35-7e7e-4e7d-9905-95a871415f94','感懷追和柳子厚郊居歲暮韵','晁補之','宋','宋诗','song-poetry','','[]','殘暑夜如炊，曉風吹蕭索。',48,'全唐诗/poet.song.63000.json','["殘暑夜如炊，曉風吹蕭索。", "開門望林木，引蔓修籬落。", "所欣塵累遠，不恨生涯薄。", "心事少干雲，白頭成憶昨。"]'),
('c68d8279-061d-4252-9cb1-780cbd015b90','次韵閻甥伯溫池上八首  其一','晁補之','宋','宋诗','song-poetry','','[]','文饒論百揆，豪氣闊天宇。',48,'全唐诗/poet.song.63000.json','["文饒論百揆，豪氣闊天宇。", "歸來坐平泉，草木何足數。", "只今和文第，怪石幾風雨。", "達生要忘累，人取應我與。"]'),
('ebdb2f82-2e80-4903-bd71-d844604dbbfd','次韵閻甥伯溫池上八首  其二','晁補之','宋','宋诗','song-poetry','','[]','昔吾卜城東，今吾卜城中。',48,'全唐诗/poet.song.63000.json','["昔吾卜城東，今吾卜城中。", "祇畏盜賊迫，安知廛市同。", "畚鍤運渤海，操蛇應未窮。", "無乃遭此笑，君如北山翁。"]'),
('09e3fdad-029e-4566-8504-1ff6103c8717','次韵閻甥伯溫池上八首  其三','晁補之','宋','宋诗','song-poetry','','[]','誅茅斬惡木，衆卉方以朋。',48,'全唐诗/poet.song.63000.json','["誅茅斬惡木，衆卉方以朋。", "掘沙到沮洳，方復見此澄。", "客來恍異境，物象初不增。", "以此自誑目，果下能日乘。"]'),
('3446c575-8eeb-45f9-b72f-6686f948fef0','次韵閻甥伯溫池上八首  其四','晁補之','宋','宋诗','song-poetry','','[]','池深不可臨，際水作石磴。',48,'全唐诗/poet.song.63000.json','["池深不可臨，際水作石磴。", "塵埃攪百里，得此亦差勝。", "晨朝看雨坐，蛙喜律呂應。", "有兒不鼓篋，共此疏懶興。"]'),
('ca222105-ea90-44f7-92a1-df0bdd159f46','次韵閻甥伯溫池上八首  其五','晁補之','宋','宋诗','song-poetry','','[]','物養有得失，瘠地江河隈。',48,'全唐诗/poet.song.63000.json','["物養有得失，瘠地江河隈。", "亭檻但小草，山林自奇材。", "我有八極興，聊堪一席開。", "長嘯本造適，悲風爲誰來。"]'),
('1cf33479-4acd-4529-8502-e64d07732180','次韵閻甥伯溫池上八首  其六','晁補之','宋','宋诗','song-poetry','','[]','自從移居來，城市益啾擾。',48,'全唐诗/poet.song.63000.json','["自從移居來，城市益啾擾。", "如何跬步近，亦有鷺下沼。", "朅來欲騁騖，詰曲故百遶。", "人間南柯夢，方此猶復小。"]'),
('eac4113c-dcef-4d42-8a6d-c0049b06fd63','次韵閻甥伯溫池上八首  其七','晁補之','宋','宋诗','song-poetry','','[]','黄冠一奇士，教我漱華池。',48,'全唐诗/poet.song.63000.json','["黄冠一奇士，教我漱華池。", "茅檐夕堅坐，見月柳間低。", "水蟲時一出，細浪作鱗差。", "流觀起百慮，內視失羣疑。"]'),
('08d73a2b-ce60-4728-8a37-d9e4f230a648','次韵閻甥伯溫池上八首  其八','晁補之','宋','宋诗','song-poetry','','[]','平生惟親舊，相得懷抱敞。',48,'全唐诗/poet.song.63000.json','["平生惟親舊，相得懷抱敞。", "寧知老田里，三徑得還往。", "結廬在人境，此意陶令賞。", "但話北窗凉，何必羲皇上。"]'),
('ef43d9e7-dee5-42c6-9310-3c1a7cd1862d','次韵彥遠相州道中二首  其一','晁補之','宋','宋诗','song-poetry','','[]','自君之出矣，吾居關晝橫。',108,'全唐诗/poet.song.63000.json','["自君之出矣，吾居關晝橫。", "尚有楊李來，時能出門迎。", "少日所忿慉，壯年瞀雙睛。", "涉月在一床，幾成小冠盲。", "夫子竹林趨，世固溷高明。", "尚喜鞍馬間，經阿復緣泓。", "詩隨晚雨墮，迫戶有餘清。", "便擬釀白黍，相邀飯青精。", "重惜吾楊李，徂秋各南征。"]'),
('3d5c1e11-c5bd-4370-ba04-668cd91bd806','次韵彥遠相州道中二首  其二','晁補之','宋','宋诗','song-poetry','','[]','朝入一几縱，暮入一几橫。',108,'全唐诗/poet.song.63000.json','["朝入一几縱，暮入一几橫。", "黄卷值昔人，歡與相逢迎。", "孫子謝口語，阮生勞目睛。", "登亦豈必喑，籍猶未能盲。", "學非經世具，所貴自知明。", "仁義有不然，失時悲戰泓。", "一生屐幾量，況欲俟河清。", "動與道彌遠，靜於理逾精。", "君能問舍往，吾亦賣刀行。"]'),
('ce9b5a86-915e-4432-828f-c87b9b1ab8eb','永嘉縣君赴潁昌杜丈之喪送至鹿邑境上贈別','晁補之','宋','宋诗','song-poetry','','[]','二十年糠粃，相從無靦顔。',96,'全唐诗/poet.song.63000.json','["二十年糠粃，相從無靦顔。", "尊公抱至痛，白玉掩深菅。", "送子三百里，西風涕汍瀾。", "鄰喪罷相舂，況我五服間。", "憐子一女子，忘身赴憂患。", "但恨莫攀輀，賤生守微官。", "勿爲摻執悲，我居不求安。", "送死當大事，丈夫良獨難。"]'),
('823b7390-34f8-4521-a9db-3b7067e3cb9c','綴古詩語送無斁弟赴舉','晁補之','宋','宋诗','song-poetry','','[]','鮮民之生，靡瞻匪父。',193,'全唐诗/poet.song.63000.json','["鮮民之生，靡瞻匪父。", "母氏劬勞，寧不我顧。", "兄弟無遠，惟予與女。", "執子之手，此夕何夕。", "我心藴結兮，嗟予弟行役。", "二之日栗烈，飄風發發。", "子之清揚，麻衣如雪。", "載馳載驅，出宿於干。", "揆之以日，體無咎言。", "既差我馬，遠送于野。", "敦彼獨宿，于林之下。", "無衣無褐，不念昔者。", "陟彼高岡，或降于阿。", "瞻望弗及，獨寐晤歌。", "展轉反側，不平謂何。", "顯允君子，洵美且異。", "溫其如玉，干祿豈弟。", "春日載陽，薇亦作止。", "睍睆黄鳥，嚶其鳴矣。"]'),
('63b75add-0ad4-415a-87fc-0d959162aa7d','贈文潛甥楊克一學文與可畫竹求詩','晁補之','宋','宋诗','song-poetry','','[]','與可畫竹時，胸中有成竹。',120,'全唐诗/poet.song.63000.json','["與可畫竹時，胸中有成竹。", "經營似春雨，滋長地中綠。", "興來雷出土，萬籜起崖谷。", "君今似與可，神會久已熟。", "吾觀古管葛，王霸在心曲。", "遭時見毫髮，便可驚世俗。", "文章亦技爾，詎可枝葉續。", "穿楊有先中，未發猿擁木。", "詞林君張舅，此理妙觀燭。", "君從問輪扁，何用知聖讀。"]'),
('f9fb621a-67b1-4942-a62d-23d62750ce71','豆葉黄','晁補之','宋','宋诗','song-poetry','','[]','蒹葭蒼，豆葉黄。',138,'全唐诗/poet.song.63000.json','["蒹葭蒼，豆葉黄。", "南村不見岡，北村十頃彊。", "東家車滿箱，西家未上場。", "豆葉黄，野離離。", "鼠窟之，兔入畦。", "豕母從豚兒，豕啼豚咿咿，銜角復銜萁。", "豆葉黄，穀又熟。", "翁媼衰，餔糜粥。", "豆葉黄，葉黄不獨豆。", "白黍堪作酒，瓠大棗紅皺。", "豆葉黄，穰穰何膴膴。", "腰鐮獨健婦，大男往何許。", "官家教弓刀，要汝殺賊去。"]'),
('58b24376-c18f-4e86-aaa8-c602a85566bb','漁家傲','晁補之','宋','宋诗','song-poetry','','[]','漁家人言傲，城市未曾到。',84,'全唐诗/poet.song.63000.json','["漁家人言傲，城市未曾到。", "生理自江湖，那知城市道。", "晴日七八船，熙然在清川。", "但見笑相屬，不省歌何曲。", "忽然四散歸，遠處滄洲微。", "或云後車載，藏去無復在。", "至老不曲躬，羊裘行澤中。"]'),
('63d99e85-3d66-463f-beda-486d9f9db753','御街行','晁補之','宋','宋诗','song-poetry','','[]','雙闕齊紫清，馳道直如線。',96,'全唐诗/poet.song.63000.json','["雙闕齊紫清，馳道直如線。", "煌煌塵內客，相逢不相見。", "上有高槐枝，下有清漣漪。", "朱欄夾兩邊，貴者中道馳。", "借問煌煌子，中道誰行此。", "且復就下論，驄馬知雜事。", "官卑有常度，那得行同路。", "相效良獨難，且復東西去。"]'),
('b711bfab-39e1-45ba-a02b-f288e200b98c','和關彥遠秋風吹我衣','晁補之','宋','宋诗','song-poetry','','[]','海中群魚化黄雀，林烏移巢避歲惡。',341,'全唐诗/poet.song.63000.json','["海中群魚化黄雀，林烏移巢避歲惡。", "鄴王城上秋風驚，昔時城中鄴王第，只今蔓草無人行。", "但見黄河咆哮奔碣石，秋風吹灘起沙礫。", "翩翩動衣裳，游子悲故鄉。", "忽憶若耶溪頭，采薪鄭巨君。", "南風溪頭曉，北風溪頭昏。", "一行作吏，此事便廢。", "夢中葉落，覺有歸意。", "歸歟歸歟，吾黨成斐然。", "君今生二毛，我亦非少年。", "胡爲車如雞栖鄴城裏，朝風吹馬鬃，暮風吹馬尾。", "與人三歲居，如何連屋似千里。", "我則不狂，曾謂吾狂。", "不吾知，亦何傷，安能戶三尺喙家一吭。", "人亦有言，人各有志。", "吞若雲夢者八九，長劍耿介倚天外。", "有如陳仲舉，庭宇亦不治。", "吾乃今知貴不若賤無憂，富不若貧無求。", "負日之燠吾重裘，芹子之飫吾食牛。", "心戰故臞，得道故肥。", "吾封侯，匹夫懷璧將誰尤。", "歸歟歸歟，豈無揚雄宅一區。", "舍前青山木扶疏，舍後流水有菰蒲。", "今我不樂日月除，尺則不足寸有餘。"]'),
('6bd1ce1f-e71c-4140-b35b-8479b7e2376d','贈關澮關沼','晁補之','宋','宋诗','song-poetry','','[]','君不見杜侯昔爲歌行贈徐侯，大兒色清澈，小兒氣食牛。',189,'全唐诗/poet.song.63000.json','["君不見杜侯昔爲歌行贈徐侯，大兒色清澈，小兒氣食牛。", "往有關尹官仕周，其人有道其澤流。", "會稽竹箭無名久，文采關侯二兒秀，不然安取關尹後。", "何用黄雀青鷇蓬間飛，長觜飽滿短觜饑。", "何用城烏嗷嗷八九雛，端坐秦氏桂扶疏。", "淵也詩足興，功也禮足立。", "三年不見冠岌岌，何用春耕投種歎粟粒。", "功成裘氏九里溼君家，會稽山頭松樹清江楓。", "乃翁行采薪，所願溪上風。", "男兒封侯食肉勳業須少壯，勿學乃翁呻吟蕭屑所願在溪上。"]'),
('7d3c20c6-d1eb-46d8-bc31-280d1afe4a8c','贈王順之歌','晁補之','宋','宋诗','song-poetry','','[]','王郎見若不勝衣，眇然儒者未有奇。',375,'全唐诗/poet.song.63000.json','["王郎見若不勝衣，眇然儒者未有奇。", "我知王郎有奇處，議論濤海拏蛟螭。", "由周而來逮五季，故事本朝能盡知。", "不惟知之業有用，斟酌成敗中無疑。", "我聞昔時崔浩亦復爾，所懷百萬非熊羆。", "人才如此後來少，朝廷水鏡區妍媸。", "胡爲五十尚塵土，長翮似劍猶差池。", "愀然對我數白髮，追風逐日無由羈。", "三書自薦應不暇，五府交辟終何爲。", "邢侯胸中有王霸，不但遊談漢終賈。", "勇於吾道一臂扶，往不畏難憂助寡。", "似聞詩有雲龍期，云何計出柏馬下。", "豈非事君難進從古然，不然富貴終在天。", "堆金買玉患無玉，玉至自駭無因前。", "君不見東秦逐守拙難似，木石當前以身抵。", "接淅去齊未敢言，退飛過宋聊堪比。", "神形自問還自答，因拙得全方至此。", "少狂干世等畫蛇，老罷食功同履豨。", "向長畢事漸可涯，彭澤棄官從此始。", "山林不著一物隨，平生萬卷付群兒。", "收光牛背看屋壁，更不刮膜煩金鎞。", "遭時有用君當起，丹青宛轉麒麟裏。", "我行此計無贏輸，世事從來弈棋耳。"]'),
('3ba9c154-7867-4d23-b256-8f7b802315bd','游栖巖寺呈提刑學士毅夫兄','晁補之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飛樓壓城城跨野，黄河逶迤避條華。',394,'全唐诗/poet.song.63000.json','["飛樓壓城城跨野，黄河逶迤避條華。", "城南鳥道拱高巖，入谷車箱不容馬。", "解鞍初步石苔青，細泉鳴遶竹間亭。", "肩輿直上十八折，維以采絲雙巨絙。", "我行枉矢復蛇蹙，三步一呼勞我僕。", "前旌已作鶴穿雲，後隊方如蟻緣木。", "千條倒澗淙大壑，百丈層冰凍垂瀑。", "無雲而雲蒼翠橫，無風而風𠿕𧇠聲。", "崖窮東轉路忽平，長楊老柏森成城，朱欄碧砌上窈冥。", "蓮花三峰只對面，仙人玉女如相迎。", "却臨北嶺望吾郭，萬瓦一垤令人驚。", "孔侯翛然顧我語，高真之居隔風雨，下視人寰如此許。", "此中豈但蠻觸微，千古紛爭幾是非。", "我言人處世，此見釋氏義。", "人食地上穀，足固不離地。", "我今正在阿堵中，與君安得生兩翅。", "却憶隋文駕六龍，意比姬滿朝河宗。", "當時萬騎留山麓，登臨已卷長江東。", "翠微宮裏亦如此，依然古殿對喬松。", "何况山中携妓裴御史，猶唱當時霜月空。", "與君江南厭山水，香罏雙劍俱夢中。", "異鄉同宦對絕景，令我不指東飛鴻。", "立戒兵厨釀春酒，要看雪盡山花紅。", "不須墮淚似羊守，且可騎馬同山公。"]'),
('945d0c40-c02a-4418-9280-6ac1a8455e3e','聽閻子常平戎操','晁補之','宋','宋诗','song-poetry','','[]','嶧陽之孤桐，踣自霹靂斧。',132,'全唐诗/poet.song.63000.json','["嶧陽之孤桐，踣自霹靂斧。", "龍伏之靈林復古，斷文橫截絲百縷。", "下垂七軫如牛乳，上有明星稀可數。", "當軒拂拭待君鼓，君心有在君未語。", "仲尼昔時從師襄，頎然一人猶望羊。", "我獨懷之千古長，杖策不省頤之忘。", "去年河决瘡未補，今年赤地無禾黍，像龍焚尪亦何取。", "堂上平戎不敢聽，且激南風召時雨。"]'),
('1746d9db-7adb-49ef-addb-cc486f588da2','同楊希仲吳子進李希孝張景良北關納凉晚過大安寺','晁補之','宋','宋诗','song-poetry','','[]','君不見少陵翁，昔時亦厭在泥滓，青鞋布襪翁自喜。',374,'全唐诗/poet.song.63000.json','["君不見少陵翁，昔時亦厭在泥滓，青鞋布襪翁自喜。", "上關流水入城來，青蘋之末風未已。", "駕言出游我無酒，張侯爲致尊中旨。", "可憐築室甯封池，下有千房并萬蕊。", "官曹十九民事聒，況乃坐堂環榜捶。", "揚波沐髮安在哉，我曹官冷奚不來。", "日長飛鳥困塌翼，龜出仰喙魚張腮。", "南箕不哆少女默，焦暍坐恐昆蟲猜。", "楊君嘗攬轡，獨出無把袂。", "古藏大般若，中天立華厦。", "同游得吳李，張子亦予社。", "登臨物色爲我豪，長空吹雨來蕭騷。", "原爲起伏河出沒，霧作吞吐山卑高。", "君不見幕中羣公府曹掾，清談接武金閨彥。", "平明趨府罷亭午，寧有食頃坐閒燕。", "我曹放意誠崛奇，王事鞅掌慙周詩。", "嵇康不堪章服裹，此事恐得通人嗤。", "李侯挽我未宜下，世間一笑如此寡。", "鄙夫敢慕從事賢，少日采薪勤兩肩。", "草玄亦投閣，醉者墜不愕。", "安能學丁君，高舉似黄鶴。", "一廛平生事，百壺中慮廓。", "且當俛仰宇宙間，子欲觀海須觀瀾，所思安在良阻艱。", "李侯有嘉意，語若繭緒曳。"]'),
('0a40ca34-da52-4ae1-b87c-716105d235f0','同張子望顔伯儀上關納凉','晁補之','宋','宋诗','song-poetry','','[]','高閣無風華屋熱，正午四鄰還往絕。',304,'全唐诗/poet.song.63000.json','["高閣無風華屋熱，正午四鄰還往絕。", "張侯不厭過市煩，呼我柳隄鳴躞蹀。", "城如虯背卧逶迤，城上戍樓虬白鬐。", "一水貫來深宛轉，萬家圍去綠參差。", "囂塵塞眼那能避，未暇解衣聊埽地。", "可憐繫馬著垂楊，可憐臺榭對池塘。", "無限芳洲生杜若，芙蓉菡萏倚新粧。", "鴛鴦相對鸕鷀舞，飛去黄鸝獨無語。", "登槃未用伐蛟鼉，苦菜黄瓜亦堪數。", "張侯河目須垂膺，齒如明玉嚼寒冰。", "未須坐上白羽扇，談言自足驅青蠅。", "司業高情勿寂莫，仲宣從軍良可樂。", "欲看詩句出嵌崆，更饒酒量開磅礴。", "廣文憔悴獨何人，男兒三十四方身。", "相逢得意吐然諾，俸二百錢終不貧。", "野橋傴僂風吹髮，徙倚門關臨嵽嵲。", "江湖平日憶蘇侯，更詠夕陽明觀闕。", "人語喧喧未聽回，木蘭晚放水萍開。", "黄昏下馬天似漆，急雨傾屋翻狂雷。"]'),
('8c247405-9e95-491a-b23b-7b03c6fdd26f','開梅山','晁補之','宋','宋诗','song-poetry','','[]','開梅山，梅山開自熙寧之五年。',377,'全唐诗/poet.song.63000.json','["開梅山，梅山開自熙寧之五年。", "其初連峰上參天，巒崖盤{山斂}閡群蠻。", "南北之帝鑿混元，此山不圮藏雲煙。", "躋攀鳥道出薈蔚，下視蛇脊相夤緣。", "相夤緣，窮南山。", "南山石室大如屋，黄閔之記盤瓠行跡今依然。", "高辛氏時北有大戎寇，國中下令購頭首。", "妻以少女金盈斗，遍國無人有畜狗。", "厥初得之病耳婦，以盤覆瓠化而走。", "堪嗟吳將軍，屈死㹞㹞口。", "帝皇下令萬國同，事成違信道不容。", "竟以女妻之，狗乃負走逃山中，山崖幽絕不復人跡通。", "帝雖悲思深，往求輒遇雨與風。", "更爲獨力之衣短後裾，六男六女相婚姻。", "木皮草實五色文，武溪赤髀皆子孫。", "侏離其聲異言語，情黠貌癡喜安土，自以吾父有功母帝女。", "凌夷夏商間，稍稍病侵侮。", "周宣昔中興，方叔幾振旅。", "春秋絕筆逮戰國，一負一勝安可數。", "邇來梅山恃險阻，黄茅竹箭霪霧雨。", "南人顛踣斃溪弩，據關守隘類穴鼠。", "一夫當其阨，萬衆莫能武。", "欲知梅山開，誰施神禹斧。", "大使身服儒，賓客盈幕府。"]'),
('857c8420-7655-4bad-98fc-2fe55ad0c4d3','富春行贈范振','晁補之','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江北百里餘，漲沙不復生菰蒲。',96,'全唐诗/poet.song.63000.json','["錢塘江北百里餘，漲沙不復生菰蒲。", "沙田老桑出葉粗，江潮打根根半枯。", "八月九月秋風惡，風高駕潮晚不落。", "鼓聲鼕鼕櫓咿喔，爭湊富春城下泊。", "君家茅屋並城樓，不出山行不記秋。", "越舶吳帆亦何故，今年明年來復去。"]'),
('8c4b1814-69dc-4a86-9d93-cb94597a8537','胡戢秀才效歐陽公集古作琬琰堂','晁補之','宋','宋诗','song-poetry','','[]','君不見廬陵公，往爲學士修書日。',311,'全唐诗/poet.song.63000.json','["君不見廬陵公，往爲學士修書日。", "詔畀千金訪遺逸，遺文逸字往往出。", "故都易姓幾兵火，量臀鼎腹細詰詘。", "道人岣嶁空有聞，丘陵仙鬼事恍惚。", "共和十鼓記亡一，嶧山肉在無復骨。", "雲陽八體又瓜剖，至使漢童訛尉律。", "世儒詭正何足臧，公家安取千軸藏。", "仲尼猶及史之闕，有馬借人吾敢忘。", "題籤甲乙潁水陽，後來胡君癖膏肓。", "傾家自構琬琰堂，搜羅近出補厥亡。", "荒林圮冢見未嘗，南觀禹穴計渺茫，閉門睥睨在一床。", "常恨平生好古家無力，騎馬蹊田觀斷刻。", "中郎二字煩走驛，率更三日勞野食。", "長年囊褚況易擲，兒作摹朱婦遮壁。", "願從胡君丐無有，十百數中聊取仂。", "胡君今逸民，盱眙不見十五春。", "坐令鉛槧老壯士，朝廷豈無憂國人。", "曩時豪氣今誰在，會面只謀千日醉。", "聽君汗漫馳古先，世事無何付蟬蛻。"]');
